window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-037.json"] = [{"name":"灰眼短脚鹎","english_name":"Grey-eyed Bulbul","scientific_name":"Iole propinqua","overview":"灰眼短脚鹎（英文名：Grey-eyed Bulbul，学名：Iole propinqua），是雀形目鹎科伊俄勒短脚鹎属的鸟类。生活在东南亚的鸣禽，其自然栖息地为亚热带或热带湿润低地森林。在中国，灰眼短脚鹎主要分布在西南地区。","appearance":"体长17至19厘米，体重约26克。外观相对纤细，呈暗淡色调，头部较小。头顶至颈背为暗橄榄红褐色，眼上至眼上方、上脸及耳羽为烟灰色；背部至臀部为橄榄棕色，尾上覆羽深红棕色；翅膀橄榄棕色，外侧次级飞羽和初级飞羽边缘更亮的橄榄色，三级飞羽和内侧次级飞羽带青铜光泽；尾巴均匀深红棕色；下巴和喉咙为暗白色，羽毛稍显延长；中胸淡黄色，两侧和两胁为灰橄榄棕色，形成明显的斑块；腹部奶油色，带有橄榄棕色调，下尾羽统一为赤褐色。虹膜清澈灰至白色，与黑色眼睑边缘形成对比；喙上颚黑褐色，下颚淡蓝灰色；腿为粉棕色到紫棕色。雌雄相似，幼鸟整体较成鸟暗淡，虹膜呈浅棕色。","call":"发出独特的响亮、扁平且非常鼻音的‘uuu-wit’或‘berret’叫声，第二声重读但不上扬；在交趾支那（亚种innectens）叫声略为不同，‘whii-it’和更平的‘wowh’或‘weeao’。偶尔发出柔和的哨音。叫声不如Alophoixus物种嘈杂。","habits":"偏好常绿热带次生林及灌丛，栖息于阔叶常绿和混合落叶林及其边缘，也能适应（甚至偏好）次生林和受扰动的植被，尤其是竹子或藤本植物丰富的环境，尤其在林间空地、道路、小径和河流附近。活动高度自低地至海拔1000米，偶尔可达1500米。主要以果实和昆虫为食，通常单独或成对活动，但在结果树上有时会形成较大的群体。在树冠层和中层觅食，不下降至地面。相对羞涩，不易察觉。","breeding":"在泰国考艾国家公园，筑巢季节从中一月持续至至少五月初；两个巢穴中分别在三月和四月发现含卵。巢位于约10米高的Dipterocarpus gracilis枝丫中。巢为整洁的杯状结构，由叶片和蜘蛛网以及马尾状真菌菌丝粘合而成，内部衬有木质攀缘植物的细小气根。每巢含三个蛋，蛋壳为偏白色，散布少量深色斑点，集中在较宽的一端。仅雌鸟筑巢和孵卵，但雄鸟协助喂养雏鸟和保护巢穴。","identification":"与黄臀灰胸鹎相比，灰眼短脚鹎具有更红棕色的下尾羽，翅膀更偏橄榄色，下体带黄色调，眉纹更灰。","protection":"IUCN：LC（无危）。在当地相对常见，但由于识别问题可能经常被忽视。在中国南部可能并不普遍。鉴于其在严重退化或恢复中的栖息地中生存的能力，总体上应该是安全的。","distribution":"分布于东南亚，包括中国的西南地区。","other":"目前承认五个亚种。"},{"name":"棕臀短脚鹎","english_name":"Buff-vented Bulbul","scientific_name":"Iole crypta","overview":"棕臀短脚鹎（英文名：Buff-vented Bulbul，学名：Iole crypta），是雀形目鹎科伊俄勒短脚鹎属的鸟类。常见于南缅、泰国西南部、马来半岛、苏门答腊及周边岛屿。其自然栖息地为热带湿润低地森林，由于栖息地丧失而面临威胁。","appearance":"中等体型（20-20.5厘米），外观单调，具长而细的喙。头部顶部暗橄榄褐色，眼周烟灰色渐变为耳羽的灰棕色；上体呈暗橄榄褐色，尾羽覆羽深红棕色；翼橄榄褐色，次级飞羽外缘带亮红橄榄色；尾羽统一深红棕色；下体颜色从苍白奶油色的腹部到带有灰棕色中心的尾下覆羽不等；眼睛灰白色；上喙深粉角质色，下喙基部淡粉色至灰色；腿黄色至粉棕色。幼鸟与成鸟相似，但喙色浅，翼羽和次级飞羽边缘色淡，眼睛浅棕色。","call":"发出‘er-whit’或‘wher-it’的音乐性叫声，第二个音符更尖锐、更金属质感，类似黄眉绿鹎的叫声，但音调更高，鼻音较少。也发出平缓的‘whirr’声。最常见的叫声为‘cherrit’、‘chewit’、‘bueik’或‘whe-ic’，接近灰眼短脚鹎的叫声，但更丰富，持续时间略长，带轻微上扬的语调，有时以短暂系列发出，间杂尖锐的哨音。","habits":"广泛食性，以果实和昆虫为食。主要吃无花果（Ficus属），包括榕树，以及马来西亚半岛Kerau地区研究的25种无花果中的17种，果径平均范围5.4-27.4毫米。在婆罗洲吃水果和浆果（如Trema orientalis和Cissus）。在苏门答腊的标本胃中含有果皮和种子。昆虫食物包括直翅目昆虫和双翅目幼虫。在森林内部冠层和中间层觅食，偶尔在林缘下降至较低处，在结果的灌木丛中觅食，但从不下降至地面。敏捷追逐受惊的猎物，对经过的昆虫做短距离飞扑。","breeding":"在马来半岛的繁殖期为4月至7月，有报告称自1月起开始繁殖，但在3月观察到发育良好的幼鸟。每窝产2枚卵，由双方共同照顾离巢雏鸟。关于繁殖的其他信息缺乏。","identification":"与灰眼短脚鹎的区别在于脸部纯灰色与深色头部形成更鲜明对比，尤其在眉毛部分，翅膀较不橄榄色，下体颜色较不含红棕色，尾下覆羽无红棕色调，喙更大。与黄眉绿鹎相比，叫声更尖锐、更金属质感。","protection":"IUCN：NT（近危）。由于低地森林正在从巽他群岛消失，种群可能正在减少。然而，该物种对严重退化栖息地的容忍意味着它不会立即面临灭绝风险；实际上，在边缘、受扰和次生森林中至少与在成熟森林中一样常见，因此可能是从选择性伐木中获益最大的鹎类之一。全面的森林清除对其不利。","distribution":"远东地区：马来半岛、安纳巴斯群岛（马来半岛东部）、印度尼西亚苏门答腊岛、巴图群岛（苏门答腊中部西部）、廖内群岛（苏门答腊中部东部）、邦加岛和勿里洞岛（苏门答腊南部东部）以及北纳土纳群岛（婆罗洲西北部）。","other":"曾被分类在Hypsipetes和Microscelis属。黄臀灰胸鹎原被认为是棕臀短脚鹎的同种，直到2017年IOC将其分类为独立物种。别称包括crested olive bulbul、dull-brown bulbul和Finsch's olive bulbul。"},{"name":"黄臀灰胸鹎","english_name":"Charlotte's Bulbul","scientific_name":"Iole charlottae","overview":"黄臀灰胸鹎（英文名：Charlotte's Bulbul，学名：Iole charlottae），是雀形目鹎科伊俄勒短脚鹎属的鸟类。原生于婆罗洲，主要栖息于低地森林及其边缘地带，适应力较强，能在退化和再生的林木环境中生存。其显著特征为淡色的眼睛、黄色的下体以及清洁的白色喉部。","appearance":"中等体型，约20至20.5厘米长，体重20至28克。头部暗红橄榄棕色，上体呈淡橄榄棕色，翼上具微弱的青铜光泽。下巴和喉咙呈暗白色，胸部中心同喉部颜色，两侧和侧腹为灰橄榄棕色，形成明显斑块。腹部浅奶油色，尾下覆羽同腹部颜色但中央部分为灰棕色。眼睛灰色，上喙深粉角质色，下喙基部逐渐变为淡粉色。腿为黄至粉棕色。幼鸟与成鸟相似，但喙色较淡，翼覆羽和次级飞羽边缘较淡，眼色为浅棕色。","call":"发出较为沙哑的‘jeet！’声和鼻音的‘jee-wit！’声，以及重复的系列叫声：‘wee-jy-jy-jy！’。","habits":"生活在常绿阔叶林、边缘和次生林。在马来西亚半岛Pasoh地区，无论是在成熟森林还是20年再生地，其捕获率无明显差异。常见于森林边缘、宽阔道路和林间小径，尤其在新生长的树丛中（如Macaranga）。分布于低地至海拔900米。","breeding":"在马来西亚半岛的繁殖季节为4月至7月，有报告称自1月起开始，但在苏门答腊3月已有发育良好的幼鸟。一窝产2枚卵，双亲共同抚养幼鸟。关于繁殖行为的其他信息尚缺。","identification":"与非常相似的灰眼短脚鹎区别在于更纯净的灰色面部与深色帽状头部对比更鲜明，尤其是眉纹，翅膀较不橄榄色，下体少有黄色调，尾下覆羽无赤褐色，喙部较大。","protection":"IUCN：NT（近危）。虽然种群可能正在下降，但由于低地森林的丧失，但因其能容忍重度退化的栖息地，目前暂无灭绝的直接风险。","distribution":"分布于婆罗洲和Banggi（北婆罗洲东北部）。在马来西亚半岛、苏门答腊等地均有记录。","other":"原被归类于Criniger属，2017年被国际鸟盟（IOC）从棕臀短脚鹎中分离出来。"},{"name":"黄腹鹎","english_name":"Sulphur-bellied Bulbul","scientific_name":"Iole palawanensis","overview":"黄腹鹎（英文名：Sulphur-bellied Bulbul，学名：Iole palawanensis），是雀形目鹎科伊俄勒短脚鹎属的鸟类。以橄榄棕色上体和引人注目的黄色腹部为显著特征。","appearance":"中等体型，头部至背部呈橄榄棕色，逐渐过渡至较为褐色的冠羽，可轻微竖起形成小冠。黄色腹部与橄榄色胸部相接，喉部白色。眼睛淡橙色，与Ash-fronted Bulbul相似，但具有黄色腹部和淡色眼睛。","call":"发出简单而鼻音十足的'chewp!'叫声。","habits":"栖息于山地森林及其边缘地带，偏好亚热带或热带湿润低地森林环境。","identification":"与Ash-fronted Bulbul相比，黄腹鹎拥有黄色腹部和淡色眼睛，易于区分。","protection":"IUCN：LC（无危）","distribution":"仅分布于菲律宾西南部的巴拉望岛。","other":"曾被归类于Criniger、Hypsipetes和Ixos等属，别称包括金眼鹎和橄榄鹎，后者名称需与Iole virescens区分开。"},{"name":"黄腹冠鹎","english_name":"White-throated Bulbul","scientific_name":"Alophoixus flaveolus","overview":"黄腹冠鹎（英文名：White-throated Bulbul，学名：Alophoixus flaveolus），是雀形目鹎科冠鹎属的鸟类。主要分布在喜马拉雅山脉东部至缅甸和泰国西部的东洋界。以鲜明的羽色和独特的鸣叫而著称，具有蓬松竖立的羽冠，上体呈深褐色，下体鲜亮的柠檬黄色，喉部白色明显。","appearance":"体型略大，约22厘米，重量介于38-54克。拥有结实的喙和细长的羽冠，有时前倾。成鸟头部带有青铜橄榄色的冠羽，面颊灰白，耳羽灰色并带有白色条纹；背部青铜橄榄色，翅膀和尾巴红棕色；喉咙白色，从胸部到尾下覆羽均为明亮的黄色。虹膜棕色，喙多为淡蓝灰色，腿银灰色或淡铅灰色。雄雌相似，幼鸟羽色更偏棕色，翅膀更偏红色，下体颜色暗淡，接近棕色，喙色更深。","call":"黄腹冠鹎非常嘈杂，常见其发出一系列短促鼻音的叫声，没有明显的歌声。最常听到的是响亮、短促、尖锐的单个‘nyak’声，重复率不一，通常较慢；受惊时会发出更高音调的‘yap’声，通常由多个个体交替或合唱；也会发出尖锐上升的‘shree-shree-shree’声，以及一系列由慢到快、音调渐高的金属质感鼻音。","habits":"生活在原始和次生常绿森林的下层或中层，海拔600-1200米，冬季偶尔降至低地，在灌木丛和开阔地带觅食。以果实为主食，包括浆果，也会捕食昆虫。冬季形成紧密的小群，穿梭于植被中，类似某些画眉的行为，通常在地面3米以内觅食。","breeding":"繁殖期为4月至7月。巢由两性共同建造，外部由枯叶和竹叶构成，内部则用蕨根和弹性茎固定，放置于地面0-3米处，通常低于1米，藏于浓密的低矮植被中，靠近溪流。每窝产3-4枚卵，可能由两性共同孵化，孵化期约为13天，雏鸟由双亲喂养。","identification":"与白喉冠鹎非常相似，但分布范围很少重叠。白喉冠鹎的喉部更白、更突出，下体颜色更深，整体羽色偏暗棕色。","protection":"IUCN：LC（无危）；在中国南部较为罕见，但在尼泊尔、印度东北部、不丹和缅甸的适宜生境中非常常见，能适应森林的一定程度的退化和碎片化。","distribution":"主要分布在喜马拉雅山脉东部至缅甸和泰国西部，繁殖区域与非繁殖区域差异不大，冬季部分个体会下降至低地。","other":"历史上，白喉冠鹎曾被归入Trichophorus（现为Criniger的同义词）属，直到2009年才被转移到Alophoixus属。其别名包括灰额冠鹎、灰额鹎、白喉冠鹎和灰头冠鹎，但不应与同名的其他物种混淆。"},{"name":"白喉冠鹎","english_name":"Puff-throated Bulbul","scientific_name":"Alophoixus pallidus","overview":"白喉冠鹎（英文名：Puff-throated Bulbul，学名：Alophoixus pallidus），是雀形目鹎科冠鹎属的鸟类。由Robert Swinhoe于1870年首次描述。主要分布在东南亚，常见于中南半岛及中国的云南、贵州、广西和海南等地，栖息于海拔1500米以下的山坡、山谷、溪畔的开阔次生阔叶林、季雨林、雨林或平坝散生树丛中。该物种模式产地在海南岛。","appearance":"白喉冠鹎体型较大，长约23厘米，上体呈橄榄色，下体黄色，喉咙部位有蓬松的白色羽毛。其外观与黄腹冠鹎相似，但下体颜色较暗淡。脚黑色，眼睛和喙为棕色。雄鸟和雌鸟在外表上无法区分。幼鸟与成鸟类似，但上体和下体颜色略浅，更明亮，喉咙羽毛较短，眼睛可能更暗淡。","call":"白喉冠鹎的鸣叫声音尖锐刺耳，群体中的叫声非常响亮和嘈杂，常发出‘churt churt churt…’或‘chutt-chutt-chutt…’的叫声，有时也会发出较弱的‘twee, twee, twee’声。","habits":"白喉冠鹎通常结成小群生活，性格活跃，会大胆围攻猛禽。它们常加入混合鸟群，主要在较低的林层活动。饮食以浆果为主，偶尔捕食昆虫，如蝉，也会吸食花蜜，但不如Hypsipetes属物种频繁。它们在森林中层觅食，经常以3-6只的小群出现。","breeding":"繁殖期为2月至9月。在泰国的观察显示，三只成鸟共同喂养幼鸟，表明合作繁殖是常见的策略。巢是一个深而整洁的杯状结构，由干树叶制成，内衬细小的木质藤本植物的空中根，用蜘蛛网和真菌菌丝的黑发状纤维固定。巢位于小树苗的水平枝叉或倒下的大树枝上，高度在0.5至15米之间。每窝产卵2-3枚，蛋色为白色到浅奶油色，带有深红褐色斑点。孵化期为12-14天，雏鸟期为10-11天。","identification":"与黄腹冠鹎相比，白喉冠鹎的下体颜色较暗，喉部羽毛更为蓬松，头部两侧颜色较暗。与白喉褐冠鹎的区别在于下体颜色更深，通常带有更强的黄色调。","protection":"IUCN：LC（无危）","distribution":"分布于东南亚，特别是在中国南部（云南、贵州、广西、海南）和缅甸南部、泰国大部分地区及老挝北部。在繁殖季节，它们可能更倾向于在森林内部的特定区域活动。","other":"白喉冠鹎能够容忍一定程度的栖息地干扰，因此被认为没有面临重大威胁。"},{"name":"白喉褐冠鹎","english_name":"Ochraceous Bulbul","scientific_name":"Alophoixus ochraceus","overview":"白喉褐冠鹎（英文名：Ochraceous Bulbul，学名：Alophoixus ochraceus），是雀形目鹎科冠鹎属的鸟类。常见于低地森林。其特征为橄榄褐色调，具蓬松白色喉部和飘逸的顶冠。分布于中南半岛及中国东南沿海区域，被列入《世界自然保护联盟》名录。","appearance":"体型介于19至22厘米，体重约35至54克。体色以橄榄褐色为主，头顶部有一撮半竖立的羽毛形成顶冠，喉咙部位的羽毛呈白色且常膨胀。脸部灰白或灰褐色，耳羽灰褐，头部上方红褐色，与脸部颜色界限分明。背部橄榄棕色，尾上覆羽稍带赤褐色，翅膀橄榄棕色，边缘较亮。尾巴深色，略带橄榄棕色，尖端较淡。下巴和喉咙白色，与脸部色彩对比明显。胸部及腹部灰褐色，侧面及腹侧较暗，羽毛边缘呈暗黄奶油色，有时微带黄色。下尾覆羽均匀浅黄褐色。虹膜颜色从深棕到暗红，变化可能与性别有关。喙上颌深棕色，边缘及下颌较淡灰色或银色。腿色从肉色到紫棕色。雄鸟平均比雌鸟大，虹膜可能更红。幼鸟翅膀和尾巴比成鸟更赤褐色，虹膜较暗。","call":"发出一系列响亮、刺耳的‘chek’声；其多变的歌声悦耳且有旋律感。","habits":"栖息于低地至海拔1670米的常绿阔叶林，偏好成熟或再生至密闭树冠结构的森林。主要以浆果和其他果实为食，偶尔捕食昆虫。通常结成4至8只的小群，活跃于树冠下层或中层，偶尔出现在树冠。","breeding":"繁殖期为2月至6月。筑巢为深杯状，悬挂在树枝上，由细枝和干叶构成，内衬黑丝纤维。每窝产卵2至3枚，少见4枚，卵壳粉白带有深红色斑点，尺寸约为25mm x 17.5mm。孵化和育雏期信息未知。","identification":"与近缘的白喉冠鹎相似，但体型较小，上体颜色更深、更偏褐色，下体颜色较暗淡，顶冠较短。与白喉冠鹎的区别在于体型略小、顶冠更短、上体颜色更暗且少橄榄色，下体无黄色调。","protection":"IUCN：LC（无危）","distribution":"分布于东南亚从缅甸南部经越南南部至马来半岛，以及苏门答腊岛。","other":"最近被发现与本南白喉褐冠鹎在羽毛和鸣叫上有差异，之前认为是同一种。"},{"name":"褐颊冠鹎","english_name":"Brown-cheeked Bulbul","scientific_name":"Alophoixus bres","overview":"褐颊冠鹎（英文名：Brown-cheeked Bulbul，学名：Alophoixus bres），是雀形目鹎科冠鹎属的鸟类。体型较大的鹎科冠鹎属鸟类。其特征包括头部带有棕色羽冠，喉咙白色，背部呈绿褐色，胸部和腹部为脏黄色。这种鸟主要分布在爪哇岛和巴厘岛的低地和中海拔森林中。鸣声多变，结合粗糙的‘krawk’音符与更为音乐性的‘chu-kit’旋律。","appearance":"褐颊冠鹎的长度介于19至23厘米，体重在29至44克之间，雄鸟通常较重，可达41至46克，而雌鸟约为51至52克。其最显著的特征是短小而不显眼的羽冠。成年个体的脸部和眼盖呈灰褐色，上身主要为橄榄棕色，翼覆羽为橄榄棕色，边缘略带橄榄绿色，而次级飞羽内部边缘更偏红褐色。尾巴为栗棕色，下巴和喉咙白色，胸部为淡灰褐色，带有宽大的淡黄色羽缘，两胁和腹部为奶油黄色，下腹和臀部橙褐色。虹膜深红棕色，喙基部蓝灰色，腿脚粉红色。","call":"鸣唱由间隔开的尖锐或鼻音组成的系列，穿插着较为刺耳的嘶哑音。声音多样，有时包含快速连续的刺耳音节，如grek-grek-grek-grek-grek。","habits":"褐颊冠鹎栖息在低地和山地森林中，高度低于1500米。它们通常是留鸟，表现出异常的领地性。以各种昆虫为食，包括甲虫、蝽象、蜻蜓、豆娘和白蚁。单独或成对觅食，偶尔加入混合物种群。在果木丛和树下层寻找食物，可能表明动物性猎物在其饮食中占有重要地位。","breeding":"繁殖季节几乎全年都有，在爪哇西部和中部，筑杯状巢于低矮植被中，通常产两个蛋。具体繁殖细节未知。","identification":"与灰颊冠鹎的区别在于缺乏后者特有的丰富旋律哨音，声音更为刺耳。","protection":"IUCN：EN（濒危）。尽管是限制分布物种，但在爪哇和巴厘岛森林中普遍且数量稳定。贸易作为笼鸟可能构成潜在威胁。","distribution":"分布于爪哇岛和巴厘岛，主要栖息在低地和山地森林。","other":"曾被归入Lanius和Criniger属，2009年移至Alophoixus属。曾用名包括灰颊冠鹎和灌木鹎。"},{"name":"巴拉望冠鹎","english_name":"Palawan Bulbul","scientific_name":"Alophoixus frater","overview":"巴拉望冠鹎（英文名：Palawan Bulbul，学名：Alophoixus frater），是雀形目鹎科冠鹎属的中型鸟类，主要分布于菲律宾西南部的巴拉望岛及邻近岛屿的低地和山麓森林。其最显著的外部特征是黄色腹部、橄榄绿色背部、棕色翅膀和尾巴、灰色脸颊以及白色喉咙。","appearance":"体长约22.7厘米，具有厚实的身体和短小的羽冠。头部为棕色，脸颊为灰色，眼上有一条窄眉纹和眼睑，耳羽处有白色的羽轴纹。上体包括臀部为橄榄绿色，翅膀和尾巴呈红棕色，喉咙为淡灰色并带有黄色条纹，中央腹部和下尾覆羽为黄色，向侧翼逐渐变为橄榄色。喙基部黑色，尖端珍珠灰色，眼睛栗色，腿脚为肉黄色。两性相似。","call":"叫声特征包括三声下降的高音调，或是先发出一串颤音，随后是一连串干涩的断音。","habits":"独居或成对出现。生活习性的具体细节尚未充分描述，包括其饮食习惯和觅食行为。栖息于低地和山麓森林及其边缘。","breeding":"繁殖相关细节未知。","identification":"与黄腹鹎的区别在于更大的体型、灰色的面部和喉咙、短小的羽冠、更粗壮的喙以及栗色的虹膜。巴拉望冠鹎曾被认为与褐颊冠鹎和灰颊冠鹎属于同一物种，但与褐颊冠鹎在基因上存在差异（并非姐妹种），且耳羽覆盖层呈灰色而非棕色；喉部的白色较弱，界限不那么明显；腹部的黄色略浅；叫声包括刺耳的责骂音（至少三种）。与灰颊冠鹎相比，巴拉望冠鹎腹部的黄色更明亮、更干净；尾下覆羽是黄色而非肉桂色；背部到尾部和翅膀的绿色更强。","protection":"IUCN：LC（无危）。此物种受地域限制，仅存在于具有高度生物重要性的巴拉望EBA区域，该区域面临严重的威胁，主要是由于栖息地破坏和退化。尽管普遍认为种群数量稳定且总体常见，但贸易笼鸟可能比栖息地的改变和丧失构成更大的威胁。","distribution":"分布于菲律宾西部的Calamians、Palawan和Balabac。在巴拉望岛上，它是当地特有的物种。","other":"2010年之前，被认为是黄腹鹎的一个亚种。"},{"name":"灰头冠鹎","english_name":"Yellow-bellied Bulbul","scientific_name":"Alophoixus phaeocephalus","overview":"灰头冠鹎（英文名：Yellow-bellied Bulbul，学名：Alophoixus phaeocephalus），是雀形目鹎科冠鹎属的鸟类。色彩鲜艳、易于识别的鹎科鸟类。其特征包括亮柠檬黄色腹部、雪白喉部、蓝灰色头部和绿色背部。分布于马来半岛、苏门答腊和婆罗洲的低地和山地森林中。","appearance":"体长20-20.5厘米，体重23-40克。拥有明亮的柠檬黄腹部，雪白喉咙，蓝灰色头部，绿色背部。脸部颜色鲜明，与眼睛形成对比。头顶至颈部暗蓝灰色，背部暗橄榄绿带绿调。尾巴均匀带有橄榄色，下体鲜亮金黄色。雌雄相似，幼鸟虹膜浅棕色，上喙尖端角棕色。","call":"发出粗犷干燥的声音，包括压抑的、略带嗡嗡声的“whi’ee whi’ee whi’ee”和沙哑的“cherrit-berrit”。偶尔会发出响亮的“chack”，特别是在飞行时。","habits":"栖息于常绿阔叶林、成熟的树种植园旁的森林以及森林与沿海植被过渡区。偏好成熟森林，有时进入泥炭沼泽森林。海拔从低地至1000米。以果实和昆虫为食，通常单个、成对或小群体活动，偶尔加入混合物种群。频繁访问地面。","breeding":"繁殖期为4月至8月。推测可能有领域性。每窝产2枚卵。","identification":"通过缺乏羽冠、蓝灰色头部和鲜亮腹部与其他类似颜色的鹎科鸟类区分。四个亚种在外观上有细微差异。","protection":"IUCN：LC（无危）。在整个分布范围内普遍常见。在新加坡已灭绝至少五十年。","distribution":"分布于马来半岛、苏门答腊（包括Mentawai Islands）、Bintang、Riau、Lingga Islands、Bangka、Belitung、Natuna Islands以及婆罗洲。","other":"在Pasoh研究森林，长期雾网捕获显示它是次于短尾雅鹛的第二常见留鸟，表明高密度人口。"},{"name":"灰颊冠鹎","english_name":"Grey-cheeked Bulbul","scientific_name":"Alophoixus tephrogenys","overview":"灰颊冠鹎（英文名：Grey-cheeked Bulbul，学名：Alophoixus tephrogenys），是雀形目鹎科冠鹎属的鸟类。体型较大的鹎科鸟类，广泛分布在马来半岛至大巽他群岛的低地和中海拔森林中，包括边缘地带、再生林、种植园和花园。其特征性的灰色脸颊和棕色短冠使其在众多鹎中独树一帜。","appearance":"体长19至23厘米，体重29至44克。头部有短而不起眼的棕色冠羽，脸部呈灰色，喉咙白色，背部橄榄绿褐色，胸腹部为脏黄色。两性相似，但雌鸟略小。幼鸟特征不详，但缺乏成鸟的冠羽外观，虹膜棕色，下颚部分淡黄色。gutturalis亚种上体颜色更偏棕，耳罩更灰，胸腹色深，缺乏亮丽色调。","call":"鸣唱多变，旋律优美，由一系列哨音组成，通常先有几个短促的平调哨音，随后是几个上扬或下滑的相同哨音，有时以尖锐的责骂声结尾。兴奋时，会连续发出变化多端的哨音和干涩的颤音。","habits":"常栖息于成熟阔叶常绿林、潮汐沼泽林、混合落叶林及其边缘，也出现在异种植物种植园如合欢树、可可树和油棕榈中。偏好低地至海拔1150米的环境，偶尔可达1500米。是杂食性鸟类，既吃水果也吃昆虫。通常单独或成对觅食，有时加入混合物种群。","breeding":"繁殖期在北泰国为4月至7月，在马来半岛为1月至7月，婆罗洲则记录于2月、4月、5月和6月。巢为标准杯状，置于低矮植被中，每次产卵2枚，蛋壳呈粉红色带紫色和红色斑点。","identification":"与黄腹冠鹎和白喉褐冠鹎相比，其冠羽较短且不明显。与灰头冠鹎的区别在于其冠羽更短，下体颜色更暗淡。gutturalis亚种的羽毛颜色与指名亚种有显著差异。","protection":"IUCN：VU（易危）。在马来半岛可能被视为近危，但在其大部分范围内常见到非常常见。尽管贸易作为笼鸟的潜在威胁较大，但目前认为其数量稳定。","distribution":"分布于马来半岛至大巽他群岛，包括苏门答腊东部和婆罗洲（除高地外）。在马来半岛南部，它是亚山地斜坡上最常见的Alophoixus种类。","other":"最近从褐颊冠鹎中分离出来，成为独立物种。"},{"name":"本南白喉褐冠鹎","english_name":"Penan Bulbul","scientific_name":"Alophoixus ruficrissus","overview":"本南白喉褐冠鹎（英文名：Penan Bulbul，学名：Alophoixus ruficrissus），是雀形目鹎科冠鹎属的鸟类。但遗传分析显示两者关系并不密切，在羽毛和鸣叫上有显著差异。本南白喉褐冠鹎分布于婆罗洲山区，偏好原始森林或成熟次生林。","appearance":"体长约19至22厘米，整体呈橄榄棕色，具松软的冠羽和膨大的白色喉部。雄雌相似，幼鸟上体更偏栗色，虹膜为深红色，喙灰色，腿和脚粉棕色。fowleri亚种的冠羽灰带棕，耳羽和下体更偏灰色，上体和胸部不如其他亚种红栗色。","call":"主要发出响亮干燥的‘chek’音，歌声悦耳婉转，由一系列旋律优美的笛声组成，通常以几声刺耳音开头。","habits":"栖息于低山和高山森林的中下层，常在小群中活跃，喜结伴觅食，以直径3至6毫米的山地无花果、浆果和其他果实为主食，包括Schefflera、Gironniera、Litsea cubica、Callicarpa等植物。","breeding":"繁殖信息了解甚少，仅知在3月底发现蛋，5月底有刚离巢的幼鸟，以及12月初、2月初和3月底有处于繁殖状态的个体。","identification":"与灰颊冠鹎相比，本南白喉褐冠鹎颜色更深，尤其是下体，有更显眼的白色喉部和较长的冠羽。","protection":"IUCN：LC（无危）","distribution":"分布于婆罗洲的山脉区域，包括加里曼丹岛的Meratus山脉，高度范围从305米至2650米，但在金马伦山以外的地方最高海拔不超过1800米。","other":"最近从白喉褐冠鹎分离出来成为独立物种，基于分子数据和形态学差异。"},{"name":"黄眉鹎","english_name":"Yellow-browed Bulbul","scientific_name":"Acritillas indica","overview":"黄眉鹎（英文名：Yellow-browed Bulbul，学名：Acritillas indica），是雀形目鹎科黄眉鹎属的鸟类，别称金眉鹎。拥有醒目的黄色眉纹和纯净黄色的脸部，眼大而黑。广泛分布于印度南部和斯里兰卡的森林地带，常在湿润地区出没，常见于成对或小群活动。","appearance":"体长约20厘米，体重27至34克。头部明亮的纯黄色，眼周、脸部和喉咙鲜艳的黄色，耳羽橄榄绿色带黄斑。头顶及背部橄榄绿色，略带青铜色光泽，翅膀和尾巴颜色更鲜绿。初级飞羽内缘棕色（基部黄色），尾羽内缘淡黄色。全身下方全黄，形成明显的双色调外观。虹膜浅红或深红色，喙黑色，腿黑色、蓝灰色或石板色。雌鸟比雄鸟略显暗淡，面部更灰暗。幼鸟较成鸟暗淡，橄榄黄色较多，脸颊有淡淡的棕色条纹，两胁较暗，下巴、喉咙和腹部黄色带白色，胸部灰黄色；翅膀和披肩带有红褐色调。","call":"鸣声由欢快的哨音与滑音交织而成，包括短暂、明亮、响亮的无滑音铃音，有时以几声清脆的音符结束，有时包含一些干燥的呼噜颤音。叫声包括清澈甜美、询问式的'wheep'声，常成对出现，有时近似双音节't-wheep'；也频繁发出更平淡、鼻音重的'nyek-nyek'声，以及在警报时较为刺耳的'chaink chaink'声。","habits":"栖息于山地和低海拔的森林边缘、次生林、咖啡种植园遮阴区、灌木丛及偶尔花园中，偏好湿度较高的环境。活动于树冠下的较低和中间层次，成对或小群活动，曾报道在斯里兰卡形成多达60只的单一物种群。经常伴随混合物种群，时常成为其核心。主要食物为果实、种子和多种昆虫，包括蜘蛛和飞虫。取食时通常在幼树顶或侧枝上，或通过短距离空中突袭捕捉。","breeding":"繁殖期主要在一月至五月，有时延长至九月；在斯里兰卡主要是四月至五月。巢由草、枯叶和苔藓构成，以蛛网固定，内衬根须。巢形似吊床，位于幼树或灌木的水平叉上（约1.5至4.5米高），有时隐藏不佳。每窝产卵2至3枚，孵化和育雏期信息未知。","identification":"黄眉鹎的黄色眉纹和全身的双色调外观是显著的辨识特征，与同属物种有明显区别。","protection":"IUCN：LC（无危）","distribution":"主要分布于印度南部的西高止山脉和斯里兰卡，从低地到海拔2000米（最佳生境约为1000至1500米），有时接近海平面。","other":"在西方高止山脉和斯里兰卡的适宜林地内普遍常见或非常常见。"},{"name":"钩嘴鹎","english_name":"Hook-billed Bulbul","scientific_name":"Setornis criniger","overview":"钩嘴鹎（英文名：Hook-billed Bulbul，学名：Setornis criniger），是雀形目鹎科钩嘴鹎属的鸟类。在远东地区的特有种，主要分布在印尼苏门答腊岛、邦加岛（东部）和婆罗洲的低地森林中。其最显著的特征是拥有一个长而弯曲的银色喙。","appearance":"体型约20厘米，体重介于26至35克。上体呈丰富棕色，下体由胸部的偏白到腹部的淡黄色过渡，具有优雅的白色眉纹。头部无冠羽，颊部黑色，耳羽淡灰棕色。尾巴长且微圆，尾端外侧羽毛有明显白色尖端。下腹部至两胁部为明显的灰色，虹膜深棕色，喙及腿均为黑色。雄雌外观相似，幼鸟特征未详述。","call":"会发出一系列尖锐的责备声，包括鼻音的‘jyaw, jyaw’声和快速干燥的咔哒声。","habits":"通常单独、成对或小群体活动，栖息于森林中层和下层。在Borneo的低地森林、废弃的橡胶种植园以及某些特定生态交错带中发现。以果实为主食，包括小型浆果，偶尔也会捕食小甲虫、蜻蜓、蚂蚁和蜘蛛等昆虫。","breeding":"在Borneo，有记录显示在8月有携带食物的个体，以及在5月有新出巢的幼鸟。繁殖行为在9月被观察到，涉及低头和展翅颤动的动作。其他繁殖信息未知。","identification":"通过其独特的面部图案、强健且明显弯曲的长喙以及白色眉纹进行识别。在Borneo和Sumatra的低地森林中，与同属物种的区别在于其特有的长而弯曲的喙。","protection":"IUCN：VU（易危）","distribution":"分布于印尼的Sumatra、Bangka岛（东部，南Sumatra）和Borneo。在Borneo，常见于Tanjung Puting国家公园，但在其他保护区较为稀少。","other":"尽管在Borneo局部地区较为常见，但在Sumatra却十分罕见。由于森林砍伐和火灾，其生境面积已大幅减少。"},{"name":"丝背鹎","english_name":"Hairy-backed Bulbul","scientific_name":"Tricholestes criniger","overview":"丝背鹎（英文名：Hairy-backed Bulbul，学名：Tricholestes criniger），是雀形目鹎科丝背鹎属的鸟类。体型小巧，上部棕色，下部脏黄色，拥有大而深色的眼睛，眼圈黄色，外观似鹎又似鵙。常见于成熟或次生森林，低地至海拔约1000米。在马来半岛、苏门答腊和婆罗洲分布。","appearance":"体长16-17厘米，体重12-21克，橄榄色背部，黄色腹部，尾部略圆，喙部有强壮的须状羽，腿脚小而弱。头部有独特的淡黄色颊斑，耳羽呈暗黄褐色，顶部橄榄棕色，背部有长达50毫米的发丝状羽。尾巴亮红棕色，尖端白色，喉部奶油白，胸侧灰色，两胁橄榄色，腹下黄色。雄雌相似，雌鸟平均比雄鸟小，幼鸟虹膜灰至灰褐色。","call":"反复发出警戒声“chee-chuu”，并给予柔和上升的哨音。","habits":"栖息于常绿森林，包括成熟的和再生至闭合冠层状态的森林，有时在竹林中。通常在森林较低层和中间层活动，有时单独，更常见成对出现，偶尔小群，不超过五只。加入混群觅食，以果实和节肢动物为食，捕食昆虫时的行为类似鵙。","breeding":"繁殖季节为2月至8月，关于繁殖细节信息未知。","identification":"与其它鹎相比，丝背鹎有更强壮的喙部须状羽，背部的发丝状羽，以及独特的黄色眼圈和脸颊斑点。","protection":"IUCN：LC（无危）","distribution":"主要分布在马来半岛、苏门答腊岛和婆罗洲的成熟森林类型中，也出现在次生森林和竹林中。","other":"丝背鹎能适应相当剧烈的栖息地碎片化，其生存似乎无即时威胁，但在低地森林的大规模清除可能已导致数量大幅下降。"},{"name":"金冠鹎","english_name":"Seram Golden Bulbul","scientific_name":"Hypsipetes affinis","overview":"金冠鹎（英文名：Seram Golden Bulbul，学名：Hypsipetes affinis），是雀形目鹎科短脚鹎属的大型鸣禽。其最显著特征为橄榄绿色上体和醒目的黄色尾端三分之一部分。该物种仅限于印度尼西亚摩鹿加群岛中的塞拉姆和安汶岛，栖息于低地至山麓森林。","appearance":"体长约22-24厘米，体重约46克。头部橄榄色，具有一条细黄线沿喙眼间延伸。上体橄榄绿，尾部末端鲜黄。下体均匀黄色。雄雌相似，幼鸟特征未详述。喙长而重，腿色深石板灰。","call":"鸣唱由尖锐高音哨声组成，尾音下降：“WEE-WEE-WEE-WEE-WOO-WOO”。也会发出柔和的喋喋声和粗糙音符。","habits":"栖息于塞拉姆岛从海平面到海拔1045米的常绿阔叶林和轻度退化森林，甚至小花园和次生林。全年留居于此，活动范围广泛，从林下层至亚树冠层均有其踪迹。","breeding":"一月第二周在塞拉姆发现筑巢，巢位于亚山地森林下层，离地面约2米，主要由绿色苔藓和少量枯叶构成的开放式杯状巢。巢高约20-30厘米，直径15厘米。具体繁殖信息有限。","identification":"在塞拉姆和安汶范围内，其双色尾羽是唯一特征。与其他种类的区别在于体型、颜色和鸣叫。","protection":"IUCN：LC（无危）。在塞拉姆常见，受Manusela国家公园保护。","distribution":"分布于澳新界的印尼摩鹿加群岛中东部，具体为塞拉姆和安汶岛。","other":"最近曾被认为是苏拉金冠鹎和布鲁金冠鹎的同种。"},{"name":"苏拉金冠鹎","english_name":"Sula Golden Bulbul","scientific_name":"Hypsipetes longirostris","overview":"苏拉金冠鹎（英文名：Sula Golden Bulbul，学名：Hypsipetes longirostris），是雀形目鹎科短脚鹎属的鸟类。以其长喙和鲜明的黄色腹部而著称。该物种仅分布于菲律宾的苏拉群岛，是当地唯一的鹎种。其自然栖息地为低地的亚热带或热带湿润森林。","appearance":"成鸟体长约23-24厘米，头部和上体呈橄榄绿色，下体黄色，胸部带有橄榄色阴影，两胁橄榄色明显。虹膜红褐色至暗红色，喙黑色或深棕色，基部及边缘略浅，腿淡紫棕色或深肉色，足掌粉红色，爪灰色。雌雄相似，但雌鸟的虹膜可能较暗淡。幼鸟特征未详述。","call":"发出一系列沙哑的颤音，以及尖锐的摩擦声和柔和的‘鞭打’声，还有泡泡般的叫声。","habits":"常以对或小群出现在低地和山麓的森林、边缘和种植园中。以水果和昆虫为食，具体觅食策略未知。活动范围从海平面到至少1200米的高度。","breeding":"巢中发现两枚卵，时间为10月至11月，除此之外繁殖信息未知。","identification":"与其他金冠鹎的区别在于更长的翅膀，胸部橄榄色与黄色喉咙的对比更强烈，上体颜色更少黄色，尾下覆羽黄色边缘较窄，鸣唱短语显著更短，缺乏交替音节系列，且呼叫词汇似乎不同。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏拉群岛（东部，印尼苏拉威西岛）。","other":"曾被归类于Criniger和Alophoixus属，曾与布鲁金冠鹎及金冠鹎视为同种，现已确认为独立物种。"},{"name":"布岛金冠鹎","english_name":"Buru Golden Bulbul","scientific_name":"Hypsipetes mysticalis","appearance":"成年布鲁金冠鹎体长约21厘米，全身呈现均匀的橄榄绿色，拥有黄色的耳羽区，下巴及腹部颜色略浅，尾巴相对短小。雌雄外观相似，雏鸟特征未详述。","call":"鸣唱开始时发出几声柔和的‘pip’或‘chek’音，随后爆发出一系列变化多端的哨音，如‘WEE-WEE-WEE-WEK-pewee-pewee-WEE-WEE’，叫声包括干燥的‘chek’音和沙哑的‘chirrrik’声。","habits":"布鲁金冠鹎以独对或小群形式栖息于森林、退化森林、边缘地带及种植园，活动范围从海平面至山麓地带。它们全年居住于布鲁岛，未观察到迁徙行为。","breeding":"繁殖期在2月，已知巢中含两个卵，具体繁殖细节有待进一步研究。","identification":"与前同种分类的中南寿带明显不同，缺乏黄色尾部，耳羽区为黄色，下体强烈橄榄绿，暗褐色或黑色虹膜（需验证），性成熟个体间无明显差异。","protection":"IUCN：LC（无危）。布鲁金冠鹎为限制分布物种，仅限于布鲁岛。数量较为常见，具体数目未知但被认为稳定。尽管布鲁岛沿海低地的大部分森林已被砍伐，北部所剩原始森林寥寥无几，但山区仍保持较大程度的原始状态。","distribution":"分布于印尼摩鹿加群岛中西部的布鲁岛。","other":"布鲁金冠鹎曾被归类于Criniger和Alophoixus属，曾与苏拉金冠鹎及金冠鹎视为同种，现已确认为独立物种。"},{"name":"厚嘴短脚鹎","english_name":"Seychelles Bulbul","scientific_name":"Hypsipetes crassirostris","overview":"厚嘴短脚鹎（英文名：Seychelles Bulbul，学名：Hypsipetes crassirostris），是雀形目鹎科短脚鹎属的常见鸟类，为塞舌尔群岛特有种。广泛分布于马埃岛、普拉兰岛、拉迪格岛和西尔霍特岛及周边一些小岛。","appearance":"厚嘴短脚鹎是一种中等体型的灰色鸟类，具有醒目的厚重喙，头顶黑色，略带光泽，脸颊、耳羽和后冠橄榄绿斑驳。上体橄榄棕色，边缘橄榄绿色，翅膀橄榄棕色，飞羽边缘呈绿色，尾部橄榄棕色，末端边缘污白色。下体较淡橄榄色，腹部中央黄色，下腹黄白色，两胁微带棕色。虹膜红褐色，喙鲜橙色，腿鲜橙色、深黄色或黄褐色。雄雌相似，雌鸟平均比雄鸟小。幼鸟飞羽栗色，冠羽边缘深橄榄绿色，眼黄色至黄褐色，喙黑褐色，腿暗褐色。","call":"鸣唱为一系列嘎嘎声、口哨声和叽叽喳喳的音符，结构和持续时间变化大，通常由一对中的一个成员在显眼的栖木上发出。叫声包括单个的‘chek’声，间隔5到10秒的粗糙、呻吟般的‘nyeer’声，以及快速的‘ak-ak-ak-ok-ok-ok-ak’聊天声，持续超过30秒，通常由一对或家庭群合唱，有时会引发邻近群体的类似回应。","habits":"生活在各种有木质成分的生境，包括森林、灌木丛、村庄和种植园。主要在树冠和灌木丛中觅食，偶尔在下层植被中。以果实、花朵、节肢动物和鸟蛋为食，可能也吃花蜜。它们成群活动，有时多达15只聚集在结果的树上。主要在树枝和树干上捕食昆虫，也会从空中捕捉飞行的昆虫。很少在地上觅食，除非是吃掉落在地上的大型果实。","breeding":"繁殖季节主要在9月至次年1月的雨季，偶尔在其他月份也有记录。筑巢由一对中的一个成员或双方共同完成，巢由草条、死叶、棕榈纤维、小枝、树皮碎片、苔藓和藤蔓碎片构成，内部衬有粗糙的纤维。每次产卵2枚，孵化期约15天，雏鸟由双亲共同照料至少初期，离巢期为21天。幼鸟在离巢后一周内仍被成鸟喂养。","identification":"与其他鹎属物种相比，厚嘴短脚鹎拥有显著的厚重喙和黑色顶冠，以及橄榄绿色的上体和下体颜色。与Grand Comoro bulbul和莫岛短脚鹎非常相近，但可以通过其独特的叫声和分布区域进行区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在塞舌尔群岛的马埃岛、普拉兰岛、拉迪格岛和西尔霍特岛以及周边一些卫星岛屿。","other":"适应了人类活动影响下的生境变化，常见于多个保护区，包括普拉兰国家公园、莫恩塞舍洛瓦国家公园和拉迪格特别保护区。"},{"name":"绿短脚鹎","english_name":"Reunion Bulbul","scientific_name":"Hypsipetes borbonicus","overview":"绿短脚鹎（英文名：Reunion Bulbul，学名：Hypsipetes borbonicus），是雀形目鹎科短脚鹎属的鸟类。特有于留尼汪岛。体长约22厘米，灰褐色为主，头部具黑色顶冠，眼周淡色，喙长橙色，性状类似毛里求斯短脚鹎，但体型略小，眼色明显。过去曾广泛分布，现今数量因猎捕而显著减少。","appearance":"绿短脚鹎是一种中到大型的灰褐色鹎，具淡色眼圈，长橙色喙，头顶黑色光泽，与颈部形成鲜明对比。雄雌相似，平均而言雌鸟可能稍小。幼鸟体羽较淡，初级飞羽和尾羽呈锈色。成鸟上体深绿橄榄色，带棕色条纹，臀部微泛肉桂色，下体暗灰色至脏黄色，翼橄榄褐色。","call":"鸣唱单调但变化丰富，由一系列嘎嘎声、金属音和刮擦音组成，常自高枝发出。叫声包括‘chek’音和长‘mew’声。","habits":"栖息于湿润森林、次生林及异域树种主导的森林，多见于中高海拔。以果实为主食，亦摄取花朵、花蜜及少量昆虫。独居、成对或家庭小群活动，有时多对会聚集于食物源，形成4至10只的嘈杂群体。主要在中层林冠觅食，偶尔落地捡拾掉落的果实。","breeding":"繁殖信息有限，已知在南部夏季筑杯形巢，雌鸟产两枚卵。","identification":"与毛里求斯短脚鹎相似，但可通过橙色喙和淡色眼区轻松区分。","protection":"IUCN：NT（近危）","distribution":"绿短脚鹎仅分布于印度洋的留尼汪岛（Réunion，位于马斯克林群岛西部）。","other":"绿短脚鹎曾被大量猎捕食用，导致数量大幅下降。目前受法律全面保护，数量有所恢复。"},{"name":"毛里求斯短脚鹎","english_name":"Mauritius Bulbul","scientific_name":"Hypsipetes olivaceus","overview":"毛里求斯短脚鹎（英文名：Mauritius Bulbul，学名：Hypsipetes olivaceus），是雀形目鹎科短脚鹎属的特有种鸟类。中等体型的暗灰色鸟，具有黑色顶冠和胡萝卜色的喙，仅见于印度洋的毛里求斯岛。主要栖息于残存的湿润森林、次生林和一些以外来树种为主的森林中，现在大多局限于中高海拔地区。","appearance":"该鸟体长25至27厘米，体重介于69至79克之间，雌雄外观相似。特征为醒目的粉橙色喙，松散且尖锐的可竖立冠羽。头部橄榄灰绿色，带深色条纹；顶冠和颈背非常深的橄榄绿至黑色，略带光泽；脸颊、耳羽和后顶冠上半部橄榄灰绿色；后颈暗橄榄灰绿色，带深色条纹；背部深绿橄榄色，带褐色条纹；臀部稍棕暖色；尾巴和翅膀橄榄棕色，次级飞羽和三级飞羽边缘绿灰；喉咙、胸部和两侧暗绿灰色；腹部黄灰色；后侧淡肉桂色；下尾覆羽脏黄色，羽轴棕色；虹膜深红棕色；喙粉色至橙色，通常远端较暗；腿橙黄色或粉红色。幼鸟在离巢后不久会换羽，此时外观类似成鸟但更灰暗，缺乏成年鸟的鲜艳特征。","call":"鸣声为一系列杂乱但多变的咔嗒、金属和刮擦音，常自高枝发出。叫声包括“chek”音和长“mew”。","habits":"毛里求斯短脚鹎主要食用果实、节肢动物和小型脊椎动物，偶尔也会吃花和花蜜。它取食多种本土和引入的水果，以及葡萄、苹果、木瓜、桑葚、覆盆子和樱桃等。它也以花蜜为食，曾在异国的牵牛花和本地的Nuxia上观察到其采食花朵的行为。它捕食的动物主要是树栖昆虫，包括叶䗛、直翅目（如灌木蟋蟀）、蝉、鳞翅目（成虫和幼虫）和蜻蜓。原生的昼行壁虎（Phelsuma）占所识别动物食物的30%，可能因为体积大而构成较高比例的食物量。通常单独、成对或家族群活动，最多见到八只一起。严格树栖，极少从地面觅食。通过在叶片基部、树枝和笨拙的飞扑捕食动物猎物，有时会冲入密集的树叶中追捕被惊扰的小昆虫。","breeding":"繁殖期在南半球夏季，雌鸟会在由草和根制成的巢中产下两枚粉红色的蛋，孵化期为14至16天。","identification":"与雄性毛里求斯鹃鵙相比，毛里求斯短脚鹎可通过橙色喙和许多其他细节轻松区分。","protection":"IUCN：VU（易危）","distribution":"分布于印度洋的毛里求斯岛，属于马斯克林群岛中部。","other":"曾经受到森林转变为茶园和入侵杂草的影响，以及蟹猴的捕食威胁。1970年代中期，只剩下约200对，但随后的保护措施阻止了其数量的继续下降。1993年统计有280对。"},{"name":"马岛短脚鹎","english_name":"Malagasy Bulbul","scientific_name":"Hypsipetes madagascariensis","appearance":"马岛短脚鹎拥有中等体型，全身主要为灰色，头部顶戴黑色帽状羽冠，喙部呈现鲜明的橙色。与之相似的马岛鹃鵙相比，其具有更明显的橙色喙和黑色帽状羽冠，而非暗色兜帽。灰白的下体使其区别于所有本地的莺鸟。","call":"这种鸟类非常善于鸣叫，经常发出哀怨的叫声和长而沙哑的歌声。","habits":"马岛短脚鹎栖息于多种含树木成分的环境中，包括森林、灌木丛、人类居住区和种植园。它们常以群体形式出现，偶尔与其他鸟类种类组成混合觅食群。","identification":"与马岛鹃鵙相比，马岛短脚鹎具有橙色的喙和黑色的帽状羽冠。此外，其灰白的下体将其与所有莺鸟区分开来。","distribution":"马岛短脚鹎分布于非洲东南部，包括科摩罗群岛、奥尔达布拉（西南塞舌尔）、马达加斯加及其周边一些卫星岛屿。"},{"name":"科摩罗短脚鹎","english_name":"Grande Comore Bulbul","scientific_name":"Hypsipetes parvirostris","overview":"科摩罗短脚鹎（英文名：Grande Comore Bulbul，学名：Hypsipetes parvirostris），是雀形目鹎科短脚鹎属的鸟类。拥有黑色顶冠和胡萝卜色的喙，仅分布于科摩罗群岛的大科摩罗岛（Ngazidja）中部和高山地区。在潮湿森林、相邻种植园和次生环境中常见。","appearance":"成年科摩罗短脚鹎体长约25厘米，平均体重约56.9克。头部顶部、颈背黑色微光泽，耳羽和脸颊为褐色橄榄绿，背部橄榄绿色，具不规则棕色斑点，腹部呈淡黄色，尾部和翅膀橄榄棕色。喙橙色，腿黄褐色或淡赭石色。雌雄相似，但雌鸟通常比雄鸟小。幼鸟颜色较暗淡，喙浅棕色。","call":"其叫声为一系列单调响亮的鼻音，如“swok-swuk-tchik-tchuk-waa-waa-tchuk-tchak-tchuk-tchik”，速度和强度可变，兴奋时声音更高。主要的猫叫声为穿透力强的鼻音‘swaaaay’或‘waaa’。","habits":"主要栖息于海拔500至1850米的自然森林，包括林间空地和退化区域。以浆果、水果（如Tambourissa sp.、Solanum mauritianum和Rubus rosifolius）和昆虫为食。常成群结队活动，有时加入混种群落。在树冠上层觅食，高度高于同类的Madagascar Bulbul。","breeding":"繁殖季节不详，已知在九月初开始筑巢，十一月观察到幼鸟。巢为厚实的杯状，由苔藓、蕨类、枯叶和茎构成，高悬于地面8米处。巢的尺寸大于Madagascar Bulbul。","identification":"与Madagascar Bulbul相比，科摩罗短脚鹎体型稍大，腿部比例更短，羽毛色泽偏绿或黄绿色，尤其是腹部。叫声更尖锐、响亮且音调更低。","protection":"IUCN：NT（近危）。估计成熟个体不足1万，且数量被认为正在减少。受农业开垦威胁，无法适应重度改造的栖息地。","distribution":"分布于科摩罗群岛的大科摩罗岛（Grand Comoro）的La Grille和Mt Karthala山峰，海拔500至1850米的森林中。"},{"name":"莫岛短脚鹎","english_name":"Moheli Bulbul","scientific_name":"Hypsipetes moheliensis","overview":"莫岛短脚鹎（英文名：Moheli Bulbul，学名：Hypsipetes moheliensis），是雀形目鹎科短脚鹎属的鸟类。特有种于印度洋的莫岛（Mohéli）。栖息于亚热带或热带湿润的山地森林中，直到2011年之前被归类为科摩罗短脚鹎的一个亚种，与塞舌尔短脚鹎有亲缘关系。","appearance":"这是一种中等体型、灰绿色的鸟，头部有黑色顶冠，喙呈胡萝卜色，翼羽暗灰褐，背部橄榄绿，尾部暗灰色，腹面黄白色。两性相似，幼鸟初级飞羽橙褐色，其余部分与同龄个体相似。比科摩罗短脚鹎大，喙更厚重，胸腹颜色一致，仅腹部稍带黄色。","call":"鸣声为一系列刺耳且粗糙的音符，通常从高枝发出，与Madagascar Bulbul类似但音调略低。叫声包含长而尖锐的音节。","habits":"栖息于莫岛中部山脉的森林残片和相邻的种植园及次生地带，海拔主要在200至790米之间。以浆果、异域Rubus rosifolius果实和其他水果为食，也会捕捉昆虫，如蚂蚁，有时通过空中捕食。常成群活动，群内喧闹。","breeding":"繁殖信息未详述。","identification":"与Madagascar Bulbul外观非常相似，但体型略大，喙较大，羽毛带橄榄色调，尤其背部明显，腹面带淡黄色调。在退化栖息地中，两者在中海拔重叠。","protection":"IUCN：EN（濒危）；种群估计少于2500成熟个体（或<1000对），且数量正在减少。限制分布物种，仅存在于科摩罗群岛。在残存的有限森林中常见，但因身份识别问题，其状况直至最近才明朗化。森林缺乏正式保护，面临农业开垦威胁。。IUCN：EN（濒危）；种群估计少于2500成熟个体（或<1000对），且数量正在减少。限制分布物种，仅存在于科摩罗群岛。在残存的有限森林中常见，但因身份识别问题，其状况直至最近才明朗化。森林缺乏正式保护，面临农业开垦威胁。。","distribution":"分布于科摩罗群岛西部的莫岛（Mohéli），海拔200至790米的山地森林。"},{"name":"黑短脚鹎","english_name":"Black Bulbul","scientific_name":"Hypsipetes leucocephalus","overview":"黑短脚鹎（英文名：Black Bulbul，学名：Hypsipetes leucocephalus），是雀形目鹎科短脚鹎属的鸟类。中等体型鸣禽，通体以深色为主，具极短羽冠，喙与脚呈朱红色，长尾与长喙赋予其修长轮廓。头色因分布区差异呈白、灰或黑色，常集成大群喧闹穿梭于结果树间。主要栖息于常绿阔叶林与混交落叶林，亦频繁光顾园林与低地林。极善鸣叫，曲目丰富，能发出吱嘎、猫叫、喋喋、哨音等多种声响。","appearance":"体长23.5–26.5厘米。体型显大，羽冠蓬松呈碎羽状，尾宽阔略呈叉形，展尾时略似卷尾属（Dicrurus）。指名亚种头全白，上体黑褐，腰略淡，下体烟灰，腹与尾下覆羽具白尖；虹膜棕至暗棕，眼圈橙；喙深橙带红，足橙。雌雄同色，雌略小。幼鸟无羽冠，通体暗褐，喙足色暗，下体灰褐具斑驳，翼缘锈色，换羽后与成鸟难辨。各亚种体色由灰至黑连续变化：psaroides 通体石板灰，头顶与颊纹近黑；nigrescens 更深，无额灰斑；concolor 近黑；ambiens 更乌亮；sinensis 似前但下体有时显灰，偶见额前白羽；stresemanni 头胸白而体羽乌灰；leucothorax 与前者野外难辨；nigerrimus 通体黑，飞羽缘灰；perniger 乌亮带墨绿辉光，喙足珊瑚红。","call":"极喧闹，栖止或飞行时半持续鸣叫，群鸟发出尖锐、鼻音、吱吱喳喳的混声。常见高音短促“nyurk”“nurrit”，急促重复，间以下滑鼻哨“nyeeer”或上扬“hwiiii”。飞行时发“nyerk”“nyack”。雄鸟独栖树顶反复鸣唱，曲目包括鼻音“snyur-khwit”或金属铃音“skyurt-vee-yurt”，区域差异明显。","habits":"栖息于海拔600–2100米的中山带，偶至3200米，繁殖季偏好高大破碎的栎、松、杜鹃林，冬季下至低地常绿与混交林、次生灌丛，偶因果实或恶劣天气降至平原（约100米）。部分种群为留鸟，部分迁徙，迁移距离与食物丰歉相关。非繁殖季可集百只大群，白头型与黑头型通常分群。多在冠层顶部觅食，极少下至林下或地面。主食浆果、无花果等果实，兼食花蜜与昆虫，喜在开花或结果树梢啄食，亦从树顶飞捕甲虫、螳螂、蜂蝇等。","breeding":"繁殖期4–7月。巢为浅杯状，由细根、小枝、竹叶、树皮外覆蛛网、苔藓构成，内衬草茎、松针、兽毛等，置于2–15米水平枝叉间，通常高7–10米，多单株孤立树营巢。每窝2–3枚卵，偶4–5枚；雌鸟独孵，雄鸟在巢旁持续鸣唱，孵化及育雏期未详。","identification":"本种与同属其他种区别在体色虽多变，但均具朱红喙足、蓬松短羽冠及长尾。白头型与黑头型野外易分，与卷尾区别在喙足色红且无卷尾之显著叉尾与金属羽色。各亚种间依头色、体羽深浅及分布区识别。","protection":"IUCN: LC（无危）。","distribution":"繁殖于阿富汗东北、巴基斯坦北部、喜马拉雅山脉经中国西南至华东，台湾及海南；非繁殖期迁至缅甸、泰国、老挝、越南北部，偶至柬埔寨及马来半岛北部。中国大陆见于云南、四川、陕西南部、华东诸省及海南、台湾。","other":"本种曾被视为马岛短脚鹎复合种，亦曾与方尾黑鹎归为同种；亚种分化复杂，呈灰、黑、白头三型交错分布，需结合鸣声等进一步研究以厘清关系。"},{"name":"方尾黑鹎","english_name":"Square-tailed Bulbul","scientific_name":"Hypsipetes ganeesa","overview":"方尾黑鹎（英文名：Square-tailed Bulbul，学名：Hypsipetes ganeesa），是雀形目鹎科短脚鹎属的优雅的暗色鸣禽，拥有鲜亮的红色喙。与黑鹎外观极为相似，但分布区域并不重叠。其主要分布于印度西南部和斯里兰卡的低山森林地带。","appearance":"方尾黑鹎全身呈深炭灰色，头部乌黑发亮，刚换羽时略带绿光。脸颊和耳羽为石板棕色，背部蓝灰而中央尤其深沉，翅膀和尾巴为暗褐色。翼覆羽、次级飞羽、最内侧初级飞羽和尾羽基部边缘为蓝灰色。下体为淡石板灰色，腹部最浅。尾下覆羽石板棕色，带有暗色轴线和白色边缘。虹膜红棕色或橙色，略带暗色。喙鲜红，略带橙色。腿黄色至红色，爪黑色。雄雌同形同色，幼鸟较成鸟颜色更浅，下体更淡，飞行羽和尾羽边缘呈浅肉桂色，腿色更暗，虹膜黄棕色，喙尖和鼻孔周围有黑色斑点。humii亚种体型略大，色泽略淡，喙更大。","call":"方尾黑鹎的鸣唱为响亮高音的“chi-chik-chik！”声，常发出类似感冒猫咪的鼻音‘喵’声，声音粗犷。歌曲包含缓慢的高音颤音，如‘chur-chik-chik！’，以及更长版本的旋律，有时混入清脆的‘seep’音符。","habits":"常见于低地和丘陵森林及林缘，非繁殖季节时常结成大群。在印度，栖息于各种森林类型，包括重度退化的森林与人工林混合区，海拔1000至2600米，非繁殖期会降至500米。在斯里兰卡，栖息于湿带区低地和相邻的中海拔山丘，至少可达1600米，季节性迁移到干燥区或更高海拔。以果实、种子和昆虫为食，经常加入混合鸟群或形成数十到数百只的单种群。","breeding":"繁殖期为2月至5月和7月至9月（斯里兰卡），3月至6月（印度）。在斯里兰卡，巢为小而杂乱的杯状，由枯叶、根和苔藓构成，内部铺有细纤维，置于树叉高处（通常5至8米），部分位于与主林隔离的狭窄地带。在印度，巢小巧，主要由苔藓构成，内衬细草和苔藓根须，置于粗枝旁，或寄生植物密集的枝条中。每窝产卵2枚，有时3枚，平均孵化成功率约46%，离巢成功率约53%，约24%的卵能成功孵化并离巢，巢穴失败主要是因为捕食。","identification":"方尾黑鹎与黑鹎的主要区别在于缺乏眼后和耳羽上的黑色条纹，以及鸣声的不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度西南部和斯里兰卡。在印度，常见于西高止山脉南部，包括尼尔吉里斯和佩里亚尔国家公园。在斯里兰卡，广泛分布于高海拔地区。","other":"方尾黑鹎的生存能力较强，能在小片森林碎片中生存，且具有一定的流动性，短期内不太可能因森林砍伐受到威胁。"},{"name":"菲律宾短脚鹎","english_name":"Philippine Bulbul","scientific_name":"Hypsipetes philippinus","overview":"菲律宾短脚鹎（英文名：Philippine Bulbul，学名：Hypsipetes philippinus），是雀形目鹎科短脚鹎属的小型鸣禽，分布于菲律宾北部、东部和南部。其特征为暗褐色上部，淡色腹部，橙棕色喉部和胸部带有浅色条纹，头部深色并带有微弱的灰色条纹。","appearance":"中等体型，上体呈暗褐色，腹部颜色较浅，喉部和胸部为橙棕色并带有淡色条纹。头部深色，具隐约的灰色条纹。喙较长，黑色。与纹胸鹎相似，但体型更小，喙更短，冠部灰白，喉部和胸部橙棕色更显温暖色调。","call":"鸣唱由短而响亮的口哨式短语组成，略带金属质感。也会发出下降的尖叫和叽叽喳喳的声音。","habits":"栖息于低地和山地森林，以及较为开阔的林木地带。在棉兰老岛的基坦格拉德山，海拔500至2,250米的原始森林中，数量众多。繁殖季节延长，至少到五月仍可见到卵巢成熟的雌鸟。在较低海拔听到领地鸣唱，而在更高海拔则可能正忙于繁殖活动。","breeding":"在棉兰老岛，菲律宾短脚鹎的雏鸟记录于四月底，繁殖季节持续到五月。繁殖期间，较高海拔的鸟群保持沉默，可能正在参与繁殖活动。","identification":"与纹胸鹎相比，体型较小，喙短，冠部灰白，喉部和胸部橙棕色更为鲜艳。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾的北部、东部和南部，包括棉兰老岛等地。","other":"直到2010年，民都洛短脚鹎, 米岛短脚鹎和棉兰短脚鹎都被认为是菲律宾短脚鹎的亚种。"},{"name":"民岛短脚鹎","english_name":"Mindoro Bulbul","scientific_name":"Hypsipetes mindorensis","appearance":"上体与胸部呈深褐色，腹部颜色较浅。拥有相对较长且粗壮的黑色喙，头部灰色并带有轻微条纹。与白眉黄臀鹎相比，民都洛短脚鹎具有白色面部特征。","call":"鸣声包括刺耳的嘶哑叫声和模糊的哨音旋律，叫声响亮，易于识别。","habits":"栖息于菲律宾民都洛岛的低地至山地森林，偏好湿润环境。具体迁徙行为及飞行特点尚未详细记录。","breeding":"关于繁殖行为的具体信息较少，但推测与同属其他物种相似，包括营巢、交配及育雏等过程。","identification":"与同域的白眉黄臀鹎区分明显，主要通过白色面部、头部条纹及叫声差异辨识。","protection":"IUCN：LC（无危）","distribution":"仅分布于菲律宾民都洛岛（Mindoro）及附近Semirara岛，为该地区特有种。","other":"曾被分类至Ixos属，2010年前被认为是菲律宾短脚鹎的一个亚种。"},{"name":"米岛短脚鹎","english_name":"Visayan Bulbul","scientific_name":"Hypsipetes guimarasensis","overview":"米岛短脚鹎（英文名：Visayan Bulbul，学名：Hypsipetes guimarasensis），是雀形目鹎科短脚鹎属的鸟类。主要分布在菲律宾中西部的低地和山地森林。曾被认为是菲律宾短脚鹎的一个亚种，直到2010年才被确认为独立物种。","appearance":"上部暗棕色，冠部灰棕色条纹，腹部白色，尾根下白色，喉部和胸部呈温暖的红棕色。比Negros Jungle-Flycatcher和白臀啸鹟大，拥有更长的喙，喉部无白色。体型中等，适应多种林地环境。","call":"其鸣唱为金属质感的上下起伏旋律，结尾杂乱无章，还会发出尖锐的叫声。","habits":"栖息于低地和山地森林，也适应次生林、灌木丛和耕作地带（需有树荫覆盖）。在海拔高达2000米的地方均可发现。","identification":"与Negros Jungle-Flycatcher和白臀啸鹟相似，但体型更大，喙较长，且喉部无白色标记。","protection":"IUCN：尚未评估（无正式评价，但因其适应力强，被认为较为常见）","distribution":"分布于菲律宾中西部的吉马拉斯省、马斯巴特岛、班乃岛、内格罗斯岛、蒂考岛和Verde岛。"},{"name":"棉兰短脚鹎","english_name":"Zamboanga Bulbul","scientific_name":"Hypsipetes rufigularis","overview":"棉兰短脚鹎（英文名：Zamboanga Bulbul，学名：Hypsipetes rufigularis），是雀形目鹎科短脚鹎属的中型鸟类。主要分布在菲律宾的棉兰老岛西部（包括扎莫博安加半岛和拉纳奥省）、巴西兰岛及马拉迈岛。其自然栖息地为低海拔的热带湿润森林，近年来因栖息地丧失而数量减少。","appearance":"该物种体型中等偏大，长度约24厘米，体重平均为59克，介于48至71克之间。上体橄榄棕色，冠羽深褐色带灰色条纹，翅膀呈棕色，飞行羽的外缘有橄榄色边缘。尾巴棕色，带有模糊的橄榄色边缘。下巴、喉咙和胸部呈现温暖的红棕色，腹部、臀部覆羽和翼下覆羽为白色，略带黄色。两性外观相似，雄鸟可能比雌鸟稍大。幼鸟未详述。","call":"发出简单的单音节叫声，如“chuk”、“tweer”和“choik”，与白眉黄臀鹎类似。其歌曲被认为较为单调，为‘chigur-chigur-chigur-chigur-chigur’，音调在‘chi’处上升，在‘gur’处下降。还发出较快的‘chli-chli-chli’，通常以每2秒约10个音节的系列形式出现。","habits":"常在果实丰富的树木间觅食，可能以昆虫补充其饮食，具体细节未知。通常以小群体出现在森林的上层和中层，经常在树冠处被观察到。","breeding":"关于繁殖行为的信息目前缺失。","identification":"与菲律宾短脚鹎相比，棉兰短脚鹎体型明显更大，喉咙缺乏明显的条纹。","protection":"IUCN：NT（近危）。该物种为限定范围种类，仅存在于棉兰老岛和东维萨亚斯生态区。尽管在其有限范围内被认为是常见的，但最近的调查记录很少，表明它可能相对较少见。据报道，在拉纳奥湖周围曾大量出现，但现在数量似乎有所下降。由于菲律宾其他地区的快速生境破坏导致森林动物急剧减少，许多物种濒临灭绝的风险增加。需要进一步的调查来评估该物种是否面临相同的命运。目前尚未在任何保护区中发现，需在扎莫博安加半岛建立合适的保护区。","distribution":"分布于菲律宾西南部的扎莫博安加半岛至棉兰老岛西部和巴西兰岛。","other":"历史上，棉兰短脚鹎曾被分类在Ixos和Iole属中，甚至被认为是菲律宾鹎的一个亚种。2010年，它被重新归类回到Hypsipetes属。"},{"name":"纹胸鹎","english_name":"Streak-breasted Bulbul","scientific_name":"Hypsipetes siquijorensis","overview":"纹胸鹎（英文名：Streak-breasted Bulbul，学名：Hypsipetes siquijorensis），是雀形目鹎科短脚鹎属的鸟类。体型较大，主要栖息于菲律宾塔布拉斯岛、Romblon、宿务岛和Siquijor的热带低地湿润森林及灌木丛。其特征为上身暗棕色，腹部淡色，胸部与喉咙呈暖棕色且带有浅色条纹。头部黑冠可竖起成尖刺状。与菲律宾短脚鹎相比，体型更大，喙更长，喉部与胸部颜色更淡。","appearance":"纹胸鹎长约26.5厘米，具有醒目的黑头印象，背部至颈项深橄榄棕色，边缘灰白，臀部较淡；翅膀及尾巴同为深橄榄棕色，翼羽和次级飞羽顶端泛白，尾羽尖端模糊的淡黄褐色。下巴与喉咙白色，边缘带棕；上胸灰色，伴有深棕色条纹和暗白色轴线，下胸、腹部及尾下覆羽淡灰色，略带淡黄褐色，尤其是腹部，侧面呈淡褐色。虹膜深棕色，上颚黑色或暗角质色，下颚暗棕色或淡角质色，腿黑棕色。性别相似，幼鸟未详述。不同亚种在颜色和大小上有所差异。","call":"声音由刺耳的嘈杂声组成，包括尖锐的鞭打般的“whit”音符，常以复杂短语呈现，如“whit pu whit tooer whit whee-er”或“pu-er whit pu-er whit”。部分亚种能发出响亮而粗哑的尖叫。","habits":"栖息于各种森林环境，包括森林边缘、次生林和空旷地带，适应海拔全范围。在Siquijor、Tablas和Romblon，纹胸鹎广泛分布于开放灌木和森林环境。小群活动于森林各层。","breeding":"繁殖记录显示，筑巢行为发生在6月，具体细节未知。","identification":"与菲律宾短脚鹎相比，纹胸鹎体型更大，喙较长，头顶黑色，喉部与胸部颜色更淡。不同亚种间存在显著差异，特别是在冠羽颜色、背部色彩、喉咙色调和体型大小上。","protection":"IUCN：EN（濒危）。在Siquijor、Cebu和Tablas Island，森林覆盖率极低，仅剩少量残存。面临的主要威胁是栖息地丧失，包括砍伐、农业转化和采矿活动。","distribution":"分布于菲律宾中北部和中部的塔布拉斯岛、Romblon、宿务岛和Siquijor。","other":"曾被归入Iole和Ixos属，2010年重新分类至Hypsipetes属。可能面临来自白眉黄臀鹎和菲律宾短脚鹎的竞争。"},{"name":"黄鹎","english_name":"Yellowish Bulbul","scientific_name":"Hypsipetes everetti","overview":"黄鹎（英文名：Yellowish Bulbul，学名：Hypsipetes everetti），是雀形目鹎科短脚鹎属的鸟类。亦被称为Everett's bulbul、plain-throated bulbul或yellow-washed bulbul。其科学命名纪念了英国殖民行政官员兼动物收藏家Alfred Hart Everett。主要分布在菲律宾的米沙鄢群岛东部、棉兰老岛和苏禄群岛。","appearance":"体型中等，体长24至25.5厘米，体重介于51.9至69.8克之间。头部橄榄绿色，羽端较亮且偏黄，形成略带条纹的外观。上体黄色橄榄色，翅膀和尾巴更橄榄色，飞羽边缘偏黄。喉部和上胸橙棕色，腹部中央、尾下覆羽、尾腹面的羽毛轴以及腕关节处的羽毛均为绿染的鲜黄色。两性相似，雄鸟平均比雌鸟大。幼鸟未详细描述，可能较成鸟颜色暗淡。","call":"叫声为长音‘peeeee’或‘peeeeee-yuk’。鸣唱旋律优美，例如在棉兰老岛，表现为清晰下降的两秒哨声系列，最后一音上升。","habits":"栖息于低海拔森林、森林边缘和次生林，高度低于1000米，偏好完整森林。以果实和可能的昆虫为食，具体饮食细节不明。通常小群体活动，有时加入混合物种群，活动于森林各层，常在上层林下或中层。","breeding":"生殖季节为3月至6月期间观察到的性腺增大现象。缺乏其他繁殖信息。","identification":"与菲律宾短脚鹎区别在于腹部颜色，黄鹎腹部呈黄色而非白色。不同亚种间可能存在颜色差异。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾的东部米沙鄢群岛、棉兰老岛及苏禄群岛。","other":"卡米金鹎曾被认为是黄鹎的一个亚种，但现在被认为是独立物种。"},{"name":"栗耳短脚鹎","english_name":"Brown-eared Bulbul","scientific_name":"Hypsipetes amaurotis","overview":"栗耳短脚鹎（英文名：Brown-eared Bulbul，学名：Hypsipetes amaurotis），是雀形目鹎科短脚鹎属的鸟类。简称: 栗耳鹎，体型较大的灰色鹎科鸟类。分布广泛，从日本延伸至菲律宾远北部，包括朝鲜、台湾以及中国东北、河北、浙江、上海等地。其最显著的特征是耳覆羽及颈侧的栗色。","appearance":"栗耳短脚鹎体长27至29厘米，重60至90.6克。头部略显隆起，冠羽延长且尖锐，形成轻微的冠状。成鸟的冠羽和颈背灰白色，边缘灰白；耳羽和颈部侧面为栗色；上体暗灰带浅灰白尖端；翅膀和尾巴较背部稍棕。下体灰色，腹中部有逐渐增大的白色斑点；腿和臀部灰棕色；尾下覆羽深灰，边缘宽白。虹膜红棕色至深棕色；喙深棕至黑色；腿深棕至棕粉。雌雄相似，幼鸟比成鸟更棕，缺乏银灰色彩。不同亚种在胸部带纹、腹部颜色和上体的橄榄色边缘上有细微差异。","call":"叫声喧闹，全年都能听到响亮的“shreep”和“weesp”声。在菲律宾，叫声被描述为刺耳的“pee-yuk”，或是下降加速的系列音调，如“pee-yuk p-uk p-uk p-uk”。","habits":"栖息于低地和山麓的落叶、混合和常绿森林，繁殖季节可达海拔1600米（偶尔2100米）。冬季出现在开阔的农业地带，有树木丛和树篱。常见于郊区、城市、公园和花园。以多种浆果为主食，包括冬青、柑橘类水果和叶菜；访问花园觅食茶花和其他花朵中的花蜜。也会吃昆虫和蜘蛛。通常群体活动，从枝头摘食浆果。在冬季喂食器处表现得非常活跃且具有优势。","breeding":"繁殖期为4月至7月，有时延续至8月。在树、灌木、藤蔓或人造结构的下层枝条1.5至4.5米高处筑杯状巢。每窝产3至5枚蛋，通常为四枚；孵化期13至14天；雏鸟离巢期10至11天；家庭会在领地上再停留两个月。","identification":"与栗背短脚鹎相比，栗耳短脚鹎的耳覆羽和颈侧栗色较为明显，但整体色调更偏向灰色。不同亚种在细节上有所差异，如胸部的颜色和宽度，以及喉部和上体的色彩。","protection":"IUCN：LC（无危）。在整个日本普遍且显眼，特别是在较小的离岸岛屿上。韩国局部常见，台湾罕见，菲律宾常见。在中国非繁殖季节常见。在北海道东南部，平均2公里的样线中，从混合森林中的0.3只到住宅区的1.0只不等。近年来，它已扩展至城市区域，在城市中心甚至繁殖。","distribution":"繁殖区域：日本至菲律宾北部。非繁殖区域：中国东部（江苏南至福建可能），冬季迁徙途经东北。","other":"被认为是日本的害鸟，因其会损害商业水果和蔬菜作物。作为多种植物种子的传播媒介。"},{"name":"白头短脚鹎","english_name":"White-headed Bulbul","scientific_name":"Hypsipetes thompsoni","overview":"白头短脚鹎（英文名：White-headed Bulbul，学名：Hypsipetes thompsoni），是雀形目鹎科短脚鹎属的鸟类。这独特的灰褐色鹎，以纯白色头部、玫瑰红色喙和橙色臀部最为显眼。分布于缅甸和泰国西北部，栖息于山地森林边缘及次生林。","appearance":"体长约20厘米，体重约42克。头部、上颈及喉部均为纯白色，仅在眼周有细黑纹环绕形成部分黑眼圈；背部均匀呈淡烟灰色，翅膀和尾巴为中灰色，边缘泛淡灰蓝；胸部至腹部淡烟灰色，臀部和尾下覆羽明显红栗色；虹膜浅黄色或棕黄色，眼睑边缘鲜亮朱红色或橙红色；喙珊瑚红色，尖端淡黄色或角质色；腿珊瑚红色，爪角质棕色或带橙色。雌雄相似，幼鸟整体偏棕色，头最初呈暗灰棕色，逐渐转白。","call":"发出尖锐的喋喋不休、略似鹦鹉般的叫声，群居时尤为嘈杂。鸣唱为一系列重复而刺耳的两音节短语。","habits":"偏好海拔900至2135米的开阔森林和森林边缘地带，冬季会降至低海拔，最低曾见于150米处。以昆虫为主食，通常成小群活动，最多可达20只，栖息于枯树上，飞行高度较高。","breeding":"繁殖季节为3月至7月，在泰国北部。筑巢于低至2米的矮坡，巢由草籽茎、草叶和竹叶构成，隐藏于低矮的土坎中，有时位于陡峭清理过的斜坡上的植物茎上，离地面仅数厘米。一窝产2至4枚蛋，孵化和育雏期未知。","identification":"与相似的白头品种相比，体型和喙较小，缺乏蓬松的冠羽和喉羽，羽毛颜色更淡，尾下覆羽色彩丰富。叫声比更为尖锐和嗡嗡声。","protection":"IUCN：LC（无危）","distribution":"分布于缅甸北部至丹那沙林南部及泰国西北部。","other":"曾被归类于单型的Cerasophila属，现基于分子系统发育研究归入Hypsipetes属。别名包括Bingham's bulbul和brown-vented bulbul。"},{"name":"卡米金鹎","english_name":"Camiguin Bulbul","scientific_name":"Hypsipetes catarmanensis","overview":"卡米金鹎（英文名：Camiguin Bulbul，学名：Hypsipetes catarmanensis），是雀形目鹎科短脚鹎属的鸟类。现已被确认为独立物种。其主要特征为深橄榄棕色的体羽和较大的黄色喙部。","appearance":"卡米金鹎体型较大，通体呈暗橄榄棕色，喙部颜色较浅。相较于黄鹎，卡米金鹎的色彩更为暗淡，黄色调更少，喙部亦显得更大。","call":"其鸣唱由一系列中音阶下降的音符组成，结尾时会突然跳回较高音。此外，也会发出刺耳的嘶叫声和鼻音尖叫。","habits":"卡米金鹎活跃于森林和林缘地带，常以大群形式活动，群体间互动频繁，鸣声嘹亮。它们栖息于低地森林及次生林，海拔高度从150至1700米。","identification":"与黄鹎相比，卡米金鹎颜色更深，黄色部分更少，喙部更大，是识别两者的关键。","protection":"IUCN：NT（近危）","distribution":"仅分布于菲律宾的卡米金岛（Camiguin Sur，位于棉兰老岛北部，菲律宾南部）。"},{"name":"桑岛金冠鹎","english_name":"Sangihe Golden Bulbul","scientific_name":"Hypsipetes platenae","overview":"桑岛金冠鹎（英文名：Sangihe Golden Bulbul，学名：Hypsipetes platenae），是雀形目鹎科短脚鹎属的鸟类。大型、显眼的橄榄色和黄色的鹎科鸟类，体型类似鸫鸟，拥有长而粗壮的喙。主要分布在印度尼西亚苏拉威东北部的桑岛山地森林中，以独特的黄色羽饰和橄榄绿色的羽毛著称。","appearance":"成年桑岛金冠鹎体长约21-22厘米，全身几乎统一的橄榄绿色，除了醒目的黄色眉纹、眼圈、耳羽和喉部，以及尾羽基部。雌雄外观相似。幼鸟色彩较暗淡，虹膜颜色较浅。","call":"鸣唱由两部分组成，首先是一系列上升的鼻音，接着是高音的口哨声，通常表现为“kwee-kwee-kwee-kwee-DEEP-pDEEP-pDEEP”。叫声包括‘bwit’和类似鸫鸟的‘puk’音。","habits":"桑岛金冠鹎偏好广阔的常绿阔叶林内部或轻度林地，活动范围从海平面到约900-1000米的海拔高度。它们通常以3-6只的小群体出现，偶尔可达十只，很少出现在次生林或种植园。","breeding":"关于其生长繁殖的信息尚未记录。","identification":"通过其显著的黄色羽饰和较大的体型，可以将其与较小、颜色更棕色的桑岛啸鹟区分开来。","protection":"IUCN：CR（极危）","distribution":"桑岛金冠鹎仅分布于印度尼西亚苏拉威东北部的桑岛山区。"},{"name":"托岛金冠鹎","english_name":"Togian Golden Bulbul","scientific_name":"Hypsipetes aureus","overview":"托岛金冠鹎（英文名：Togian Golden Bulbul，学名：Hypsipetes aureus），是雀形目鹎科短脚鹎属的中等体型的鸣禽。体型与鸫相似，拥有橄榄色头部及上体，深色眼睛，全身黄色的下体，以及强壮的长喙。该物种仅分布于印度尼西亚的托岛群岛，生活在低地和丘陵地带的森林与种植园中。","appearance":"成鸟拥有暗橄榄绿的头部和上体，臀部及上尾覆羽略显亮丽，喉部和下体呈金黄色，眼周较淡，尾羽边缘黄色。两性外观相似。幼鸟颜色较为暗淡，虹膜颜色较浅。","call":"其鸣唱由一系列快速尖锐的音符开始，随后是一串响亮的短哨声，逐渐加速并在后半部分消退，叫声中常带有鼻音的“chup”声。","habits":"通常以小群体活动，偏好低地和丘陵地带的森林环境，偶尔出现在种植园。其活动范围广泛，善于飞行。","breeding":"具体繁殖细节未知，但推测与同科其他物种类似，涉及筑巢、产卵和育雏。","identification":"与柠黄仙鹟和黄胸噪刺莺相比，体型更大，喙更粗壮。通过声音、色彩和分布地可区分。","protection":"IUCN：LC（无危）","distribution":"仅分布于印度尼西亚托岛群岛，位于苏拉威西东北部与东部之间。","other":"曾被认为与五种其他鹎同种，后被独立分类。"},{"name":"邦盖金冠鹎","english_name":"Banggai Golden Bulbul","scientific_name":"Hypsipetes harterti","overview":"邦盖金冠鹎（英文名：Banggai Golden Bulbul，学名：Hypsipetes harterti），是雀形目鹎科短脚鹎属的鸟类。体型近似鸫鸟大小，以橄榄色头部和上部、均匀黄色下部为显著特征。邦盖群岛的特有种，也是当地唯一存在的鹎。其分布范围限于低地和丘陵地带的森林、边缘和种植园，常以成对或小群体形式活动。","appearance":"体长23至24厘米，体型大而显眼，整体呈橄榄色，拥有长喙、弱化的口角须和短腿。胸部为深橄榄色，与明显的黄色喉部形成对比，上部颜色略深，尾下覆羽宽大黄色，但仅在下方明显。雌雄相似，幼鸟特征未详述。","call":"鸣唱变化多样，包含几个引子音符后突然转为悦耳的chrrreeyoo或chreewee，随后是旋律且带喉音的che-chrrreeyee-doo，其中最后一音较低。主要叫声同样悦耳，为chrreewee，使用了大多数歌曲中的相同主题，此外还发出不悦耳的churring声。","habits":"栖息于从未受干扰的原始森林到混合种植园和退化灌木丛的各种生境，海拔高度从海平面至至少900米。通常以3至4只的小群出现，可能形成多达十只的单一物种群体。食性包括果实和昆虫，具体饮食策略未知。","breeding":"繁殖信息未记录。","identification":"与其他金冠鹎（如苏拉金冠鹎）的区别在于更长的翅膀、胸部橄榄色与黄色喉部对比更为鲜明、上部颜色较淡、尾下覆羽黄色边缘较窄、更短的歌唱短语、缺乏交替音节系列以及不同的叫声词汇。","protection":"IUCN：LC（无危）。邦盖金冠鹎的分布局限于邦盖群岛，属于限制范围的亚种。在邦盖和苏拉群岛特有鸟类区中，该亚种被认为普遍常见。人口数量不明，但由于它能适应退化生境和种植园，因此相信其种群稳定。","distribution":"分布于澳新界，具体在印尼的邦盖群岛（位于印尼苏拉威西岛东部）。","other":"曾被视为与其他五种金冠鹎同种，后被独立出来，归入由Nicholas Vigors于1831年引入的Hypsipetes属，目前该属共有25种。"},{"name":"哈岛金冠鹎","english_name":"Halmahera Golden Bulbul","scientific_name":"Hypsipetes chloris","overview":"哈岛金冠鹎（英文名：Halmahera Golden Bulbul，学名：Hypsipetes chloris），是雀形目鹎科短脚鹎属的鸟类。这种体型接近鸫鸟大小的物种，拥有橄榄绿的上部和鲜黄的腹部，以及独特的暗色眼睛。主要分布于印尼北摩鹿加群岛的莫罗泰、哈马黑拉和巴坎岛屿。","appearance":"成年哈岛金冠鹎体长约20厘米，体重38至42克，上体为均匀的橄榄绿色，下体黄色，喉部颜色稍淡。雄雌外观相似，幼鸟色彩较暗淡，虹膜颜色较浅。喙较长，嘴缘毛较弱。","call":"其鸣唱为一系列8至15个高音调、下降的哨音，持续约0.5秒，声音类似“WE-WEE-WEEE-WEEE-WEEEW”或“chikwi-chikwi-chikwidilyu”。此外，还会发出细薄、高音的‘tsee’声和粗糙的‘weerrrr’叫声。","habits":"通常成对或小群出现在原始森林、退化林、种植园和红树林中，栖息于低地和较低的山丘地带。它们的饮食以浆果为主，观察到它们常常在少于十只的小群体中活动。","breeding":"繁殖信息有限，但在哈马黑拉岛上，九月份观察到鸟类处于繁殖状态，并记录到在巢中的活动。","identification":"大型橄榄绿与黄色相间的鹎，喙长，嘴缘毛弱。与其他鹎属物种相比，其特有的鸣唱和外观特征有助于识别。","protection":"IUCN：LC（无危）。这是一种地域限制性的物种，仅限于北摩鹿加群岛的三个岛屿。根据近期调查，哈马黑拉岛上的数量相对较多，估计种群稳定，但具体数量未知。","distribution":"分布于印尼北摩鹿加群岛的莫罗泰、哈马黑拉和巴坎岛屿。","other":"曾被认为与五个其他鹎种同种，但现在被归类于Hypsipetes属，该属共有25个物种。"},{"name":"奥比岛金冠鹎","english_name":"Obi Golden Bulbul","scientific_name":"Hypsipetes lucasi","overview":"奥比岛金冠鹎（英文名：Obi Golden Bulbul，学名：Hypsipetes lucasi），是雀形目鹎科短脚鹎属的鸟类。体型与鸫相似，具厚重喙，上体橄榄绿，下体黄色。以黄颊部和喙旁的黄色斑块最为显著，使深色眼睛在脸部尤为突出。此物种仅限于印度尼西亚的奥比岛，常见于森林、边缘、灌木丛和种植园中的成对或小群活动。","appearance":"体长约21厘米，成鸟拥有浅橄榄绿色的背部、颈部和头部，面部、耳羽覆盖和喉部均为淡黄色，带有黑色标记从喙延伸至脸颊。虹膜深棕色，喙淡橄榄绿色（基部较暗），腿和脚蓝灰色。雌雄外观相似，幼鸟描述未知。","call":"三种鸣声已被记录：连续3-4个鼻音‘too-too-too...’音符，单音节的下降再上升、高音调‘TSEEoooeeee’或‘tweeuwip’持续0.7秒，以及尖锐的‘zoo-WIT’声，重复规律。还有一种独特的、刺耳的2-3音符叫声，可转写为‘pic pic piie’。","habits":"生活在亚热带或热带湿润低地森林，常在成对或小群体中发现，栖息于森林、边缘、灌木地和种植园。","identification":"与黑颏啸鹟相比，其喉部无鳞状纹，腹部纯黄色，面侧黄色。鸣声与蓝脸鹦鹉类似，但缺乏后者粗糙或刺耳的品质。","protection":"IUCN：LC（无危）。此物种为限制分布种，仅在北马鲁古EBA内的单一岛屿上发现。最近的调查中被认为是相对常见的，尽管尚未估计数量，但相信在缺乏相反证据的情况下，种群数量稳定。","distribution":"仅分布于北马鲁古群岛的奥比岛。","other":"曾被认为与另外五种鹎同种，统称为金冠鹎，目前在分类上已独立。"},{"name":"灰短脚鹎","english_name":"Ashy Bulbul","scientific_name":"Hemixos flavala","overview":"灰短脚鹎（英文名：Ashy Bulbul，学名：Hemixos flavala），是雀形目鹎科灰短脚鹎属的鸟类。分布于印度次大陆、东南亚及中国西南部。其特征是具有羽冠，头顶颜色随亚种而异，耳羽呈粉褐色，上体接近灰色，喉部白色，翼部在合拢时呈深褐色，大覆羽边缘的浅色形成近黄色斑纹。栖息于山麓开阔林及灌丛的中低层。","appearance":"灰短脚鹎中等体型，长约20厘米，体重27.2至35.2克。具有明显的羽冠，冠羽经常竖起，形成圆形的顶冠；喉部羽毛常膨出。标准亚种头顶深灰，面颊黑色，耳羽淡棕色，上体灰色，尾部暗棕色带橄榄绿边缘；翅膀暗棕色，内侧飞羽和大覆羽边缘亮金黄色，带有橄榄色调，形成显著的翼斑；下体白色，胸部冷灰色。虹膜深红棕色，喙黑色，腿暗棕色或暗红角色，足底黄白色，爪黑棕色。雌雄相似，幼鸟色泽稍淡，上体更偏棕色，翼部金色较暗，喙色较淡。不同亚种在头部颜色、上体色调和下体颜色上有差异。","call":"灰短脚鹎的鸣唱由一系列短促、杂乱的金属颤音组成，穿插尖锐的哨音和微弱的嗡鸣声。叫声多变，包括刺耳的叽喳声和悦耳的管状音符。","habits":"栖息于多种林木环境，包括常绿阔叶林、松林、竹林边缘和附近的种植园，常见于山间溪谷和丘陵地带，高度在700至1600米之间，偶尔下降至邻近平原和农田。在繁殖季节外，偶尔会降至海平面。以水果、昆虫和其他各类食物为食，常在花丛和果实中觅食，也会捕捉空中飞过的昆虫。成对活动于繁殖季节，非繁殖季则形成多达30只的群体。在所有层次觅食，但多集中于中层或亚冠层。","breeding":"繁殖期为4月至7月。巢为紧凑的杯状结构，由草、枯叶和竹叶构成，内部铺垫粗草茎，置于低矮灌木、低树、蕨类或藤蔓丛中，离地面1至2米高处，有时高达12米。一窝通常产3枚蛋，有时2枚，罕见4枚；孵化期13至14天；双亲共同喂养雏鸟，具体抚育期未知。","identification":"与同属其他物种相比，灰短脚鹎具有独特的羽冠和明显的黄色翼斑。不同亚种在头部颜色、上体色调和下体颜色上有所区别。","protection":"IUCN：LC（无危）","distribution":"分布于印度次大陆、缅甸、中国西南部、泰国西部、东北部、中南半岛。在尼泊尔、印度东北部（如阿萨姆邦和梅加拉亚邦）、缅甸北部常见；在孟加拉国东北部（锡尔赫特）和历史记录中的缅甸东部较为普遍；在泰国北部、老挝和越南局部地区较为常见；1997年首次在柬埔寨东南部（Dak Dam）被记录。","other":"灰短脚鹎在东南亚山地森林中常被狩猎部落猎捕，但由于广泛的地理分布和对重度退化栖息地的适应性，它目前面临灭绝的威胁不大。"},{"name":"灰黑短脚鹎","english_name":"Cinereous Bulbul","scientific_name":"Hemixos cinereus","overview":"灰黑短脚鹎（英文名：Cinereous Bulbul，学名：Hemixos cinereus），是雀形目鹎科灰短脚鹎属的鸟类。体型中等至较大的鸣禽，属于鹎科。其显著特征包括明亮的白色喉咙和低矮蓬松的羽冠。分布于东南亚的马来半岛山区、印尼苏门答腊岛及婆罗洲。羽毛颜色为灰棕色，胸前有灰色的阴影，最明显的特征是眼、喉咙与喙基之间独特的暗色斑块。","appearance":"成年灰黑短脚鹎体长约20.5至21厘米，体重介于27.2至35.2克之间。头部和上颈部呈灰褐色，有突出的淡灰色羽尖，眼睛下方的区域为暗黑色，耳羽和颈部两侧为浅棕灰色。上半身颜色较深的灰棕色，翼羽和尾羽有淡灰色边缘。下巴和喉咙为白色，与脸部形成鲜明对比，胸部和两胁为均匀的灰棕色。腹部至尾下覆羽为灰白色，虹膜颜色随年龄和可能性别而变，从深棕色到棕红色。嘴为黑色，腿为暗绿色至板岩黑色。雌雄外观相似，幼鸟与成鸟相比，面部图案不那么明显，虹膜颜色较暗，腿部颜色更浅。","call":"灰黑短脚鹎的声音虽不悦耳，却多变，会发出鼻音的哀怨“wheers”，高音的“deees”，以及重复单调的“djeer, djeer, djeer”。群体成员间会发出一系列响亮的‘tree-tree-tree’，呻吟的‘whear’，尖锐的‘chiap’，以及双音‘wheesh-wheesh’哨声。歌曲短暂而甜美，为‘beelee-bear beelee burlee’。","habits":"主要栖息于山地和亚山地常绿阔叶林，偶尔也会出现在低地地区。社会性较强，经常以单种或混合物种群出现，特别是在结果树周围。以果实、浆果和种子为主食，也捕食昆虫。在觅食时，它们会在树冠层、中间层和边缘活动，水果通常在鸟停驻时采摘或在短暂的悬停飞行中抢夺。昆虫则从枝条上摘取或在短距离空中追捕。","identification":"灰黑短脚鹎其他灰短脚鹎属成员相比，它的脸和颊部的黑色较少，翅膀和尾巴有橄榄黄色的边缘，以及明亮的黄色臀部和尾下覆羽。","protection":"IUCN：LC（无危）","distribution":"分布于马来半岛山区、印尼苏门答腊岛以及婆罗洲的山地范围。在婆罗洲的凯拉特山国家公园、马里奥盆地保护区和卡扬门塔朗国家公园等地均有记录。在马来半岛，于弗雷泽山和卡梅隆高地等山区常见。"},{"name":"栗背短脚鹎","english_name":"Chestnut Bulbul","scientific_name":"Hemixos castanonotus","overview":"栗背短脚鹎（英文名：Chestnut Bulbul，学名：Hemixos castanonotus），是雀形目鹎科灰短脚鹎属的鸟类。因上体呈现栗褐色而得名。留鸟，广泛分布于中国南部（贵州、广西、湖南、江西、福建、广东、香港、海南岛）和越南北部的低山丘陵地区的次生阔叶林、林缘灌丛、稀树草坡灌丛及地边丛林等生境中。其头顶黑色略具羽冠，下体白色，具有独特的外观。","appearance":"这种鸟体型略大，长约21厘米。上体栗褐色，下体污白色。头顶黑色，略具羽冠，使其在同类中易于辨识。通常成小群至中群活动，有时与其他鸟种混群。","call":"鸣叫声独特，为连续的三音节旋律，最后一个音节为柔和、嘶哑的哨声。此外，还发出一系列喋喋不休的啁啾声与咯咯声。","habits":"栗背短脚鹎常成对或小群活动于乔木树冠层，也常在林下的灌木和小树上觅食。它们主要栖息在低山丘陵地区的次生阔叶林、林缘灌丛和稀树草坡灌丛及地边丛林等生境中。它们属于杂食性，主要以植物性食物为食，包括洋伞果、核果、乌饭果等植物果实与种子，同时也会食用鞘翅目、双翅目、鳞翅目、膜翅目、直翅目等昆虫。","breeding":"繁殖期通常在4月至6月，栗背短脚鹎会在小树或灌木枝桠上营建杯状巢。每窝产卵3-5枚，卵的颜色为洋红色，表面覆盖有紫色斑纹。","identification":"栗背短脚鹎的上体栗褐色和黑色羽冠是其显著特征，易于与其他物种区分开来。与灰短脚鹎的区别在于上体颜色和羽冠的差异。","protection":"IUCN：LC（无危）。栗背短脚鹎虽为中国特有鸟类，但在其分布范围内种群数量并不普遍，需注意保护。","distribution":"在中国主要分布于南部地区，包括贵州、广西、湖南、江西、福建、广东、香港和海南岛等地。在国际上，其分布延伸至越南北部。","other":"栗背短脚鹎曾被认为是灰短脚鹎的亚种，但现已独立为一个物种。"},{"name":"黑领鹎","english_name":"Black-collared Bulbul","scientific_name":"Neolestes torquatus","overview":"黑领鹎（英文名：Black-collared Bulbul，学名：Neolestes torquatus），是雀形目鹎科黑领鹎属的鸟类。独特的鹎科鸟类，以其类似伯劳的外观著称。头部前方至颈部呈灰色，一条宽阔的黑色带纹从嘴基延伸，穿过眼睛和耳朵，形成环颈状图案，与奶油白色下体形成鲜明对比。背部和翅膀橄榄色，尾羽深棕色，边缘橄榄绿。成鸟约16厘米长，雄鸟体重20-23.5克，雌鸟20-27克，无明显性别差异。幼鸟色泽较暗淡，头顶绿色，部分羽毛边缘浅色，翼上覆羽尖端带淡色斑点，胸带不显眼。","appearance":"成年黑领鹎头部至颈部灰，黑色颈带从眼部环绕至耳部，向下延伸至两侧颈部并加宽，覆盖上胸部，形成明显的颈饰。上体橄榄绿，尾羽深褐色，边缘橄榄绿，翅膀亮橄榄绿，飞羽边缘黄绿色，翼弯黄色。下体奶油白色，耳羽淡黄色，下胸淡黄色，侧胸和两胁灰，下腹橄榄绿晕染。虹膜深棕色，喙绿黑色或深橄榄绿，腿黑色。雌雄相似，无大小差异。幼鸟较为暗淡，头顶绿色，部分肩羽边缘浅色，翼上覆羽尖端淡色，形成不规则条纹，胸带模糊。","call":"发出快速高音的尖利叫声“chet-cherit-rit-rit-rit”，以及旋律优美、音调起伏的流利歌声，听起来像“choo-oo-cheloo-eo-loo”，比类似的黑眼鹎更甜美。","habits":"黑领鹎以成对形式居住在树木茂密的高草地上，散布着灌木丛。它们在这一区域内定居，不进行大规模迁徙。飞行特点和活动模式尚需进一步研究。","breeding":"关于黑领鹎的繁殖信息目前资料有限。","identification":"与相似的黑眼鹎相比，黑领鹎具有更为显著的黑色颈带，叫声更甜美的特征，易于区分。","protection":"IUCN状态未知。","distribution":"黑领鹎分布于赤道非洲，具体包括加蓬南部和东南部，刚果和刚果民主共和国西部，刚果民主共和国南部至安哥拉中部，卢旺达，刚果民主共和国东部，以及刚果民主共和国伊德吉维岛，从近卡博博山向南至马伦古高地。"},{"name":"非洲河燕","english_name":"African River Martin","scientific_name":"Pseudochelidon eurystomina","overview":"非洲河燕（英文名：African River Martin，学名：Pseudochelidon eurystomina），是雀形目燕科河燕属的鸟类。带有蓝色或绿色光泽，尤其是头部，背部和翅膀更显绿色。成鸟拥有红色眼睛和橙红色大喙，幼鸟羽毛较暗淡。非洲河燕在刚果地区的森林河流上空活动，迁徙模式独特，分别在刚果民主共和国的沿海区域和内陆的刚果河流域繁殖。","appearance":"成年非洲河燕体长约14厘米，通体蓝黑色或紫黑色，背部带绿光，翅膀和背部颜色更绿。尾部黑色呈方形，中央羽毛略尖，翼下覆羽为烟灰色。喙大而橙红，眼红，眼周粉红色，脚棕色。雌雄外观相似，幼鸟羽毛较暗，呈烟灰色。","call":"非洲河燕发出一系列粗糙的叫声，包括刮擦般的‘skeer-skeer’声，群体叫声嘈杂。它们的叫声包括空中展示时的清脆声音以及群飞时的‘kee-r-r’和‘chee-chee’等短促、不悦耳的声音。","habits":"非洲河燕栖息于森林覆盖的河流、沼泽和沿海灌木丛地带。它们在高空中集体觅食，以飞行中的昆虫为食，如蚂蚁、蝴蝶、蛾子、甲虫和其他小型昆虫。迁徙期间，它们会经过加蓬和刚果共和国的沿海地区。","breeding":"非洲河燕在刚果民主共和国的刚果河及其支流乌班吉河沿岸繁殖，时间大约为每年的2月至3月。在加蓬和刚果共和国的沿海地区也有繁殖记录。它们在沙滩上挖掘洞穴筑巢，每窝产3枚蛋，但具体的孵化和育雏周期尚不清楚。","identification":"非洲河燕与白眼河燕相比，具有更宽的喙和较小的眼睛，表明它们的觅食生态可能不同。在外观上，非洲河燕的头部和背部带有明显的蓝绿色光泽，尾部方形，这些都是辨识特征。","protection":"IUCN：DD（数据缺乏）","distribution":"非洲河燕主要分布在刚果民主共和国的刚果河及其支流乌班吉河沿岸，冬季迁徙至加蓬和刚果共和国的沿海地区。在加蓬的甘巴地区和刚果共和国的康库阿蒂保护区有繁殖记录。","other":"非洲河燕在刚果民主共和国被当地人大量捕食，这可能对其种群造成压力。"},{"name":"白眼河燕","english_name":"White-eyed River Martin","scientific_name":"Pseudochelidon sirintarae","overview":"白眼河燕（英文名：White-eyed River Martin，学名：Pseudochelidon sirintarae），是雀形目燕科河燕属的鸟类。此物种仅由1968年在泰国发现的标本所知，此后再无确切记录，可能已濒临灭绝。其最显著特征为白色的眼环和宽阔的绿黄色喙。分布区域不明，疑似在泰国、中国西南部或东南亚的河谷地带繁殖。","appearance":"白眼河燕为中等体型的燕子，约18厘米长，全身大部分为黑色，带有蓝绿色光泽，臀部白色。背部有绿色光泽，尾羽中央有两条极长的羽毛，可达9厘米，末端略宽。头部较背部颜色更深，下颌处有黑色绒毛。眼睛白色，喙宽阔，黄绿色，上喙尖端黑色，脚大且强健。雌雄外观相似，幼鸟更显褐色，无长尾羽。","call":"该物种在冬季保持沉默，繁殖季节的叫声未知。","habits":"白眼河燕栖息于淡水湖附近，冬季在芦苇丛中过夜，可能为迁徙性鸟类。推测其繁殖地可能位于泰国北部、中国西南部或东南亚的河谷，偏好沙丘和岛屿筑巢，森林覆盖的区域为其觅食场所。飞行时姿态优雅，偏好空中捕食昆虫。","breeding":"关于繁殖的详细信息未知，推测可能在4月或5月季风来临前于河流沙丘筑巢。冬季时，它们会与家燕一起栖息在芦苇丛中。以昆虫为食，可能捕食较大体型的昆虫。","identification":"通过白色眼环、宽阔的绿黄色喙和极长的中央尾羽可以辨识白眼河燕。与非洲河燕相比，其嘴部更宽，眼睛更大。","protection":"IUCN：CR（极危）","distribution":"已知仅在泰国中部越冬，具体繁殖区域不明，可能在中国西南部、泰国北部或东南亚的河谷地带。","other":"白眼河燕可能是泰国唯一的特有种鸟类之一，自1980年后未再有确凿记录，可能存在性已极为脆弱。"},{"name":"方尾锯翅燕","english_name":"Square-tailed Saw-wing","scientific_name":"Psalidoprocne nitens","overview":"方尾锯翅燕（英文名：Square-tailed Saw-wing，学名：Psalidoprocne nitens），是雀形目燕科锯翅燕属的鸟类。带有独特的绿色光泽，以及方形的尾部末端。广泛分布在安哥拉、喀麦隆、中非共和国、刚果、刚果民主共和国、象牙海岸、赤道几内亚、加蓬、加纳、几内亚、利比里亚、尼日利亚和塞拉利昂。","appearance":"成年方尾锯翅燕体型约为11厘米，体重约10克。其羽毛大多呈深褐色，带有绿色光泽；翅膀和尾部为黑褐色，尾部呈现方形，边缘略有凹陷。下颚和喉部为灰褐色，翼下的覆羽为黑褐色并带有轻微光泽。雌雄外观相似，幼鸟则颜色较淡。中央亚种（centralis）的喉部为黑褐色，带有绿色光泽。","call":"叫声为一系列短促、高音的吱吱声和哨声。","habits":"方尾锯翅燕主要栖息在低地原始森林和次生林中，偶尔在更开阔的环境中也能发现其踪迹。它们常在森林空地或树冠上空觅食，有时也会出现在村庄和耕地上。以甲虫、苍蝇、飞蚁和白蚁为主要食物来源。飞行时较为弱小且飘忽不定。","breeding":"繁殖季节通常在旱季末期到雨季开始时，具体时间为：利比里亚的10月至次年5月，喀麦隆的1月至7月，加蓬的7月至次年3月，卡宾达的8月，刚果民主共和国的2月、5月以及7月至10月。筑巢时会在垂直的河岸挖掘长达0.3至2米的洞穴（包括矿井和路堑），巢室内部铺垫苔藓和地衣。每窝产2枚蛋，偶尔发现的4枚蛋可能是两只雌鸟共同在同一个巢中产卵的结果；关于孵化和育雏期的信息尚不明确。","identification":"与同属其他物种的区别在于尾部末端为方形而非叉状。叫声和飞行姿态也是辨识的重要依据。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在非洲中部和西部，包括安哥拉、喀麦隆、中非共和国、刚果、刚果民主共和国、象牙海岸、赤道几内亚、加蓬、加纳、几内亚、利比里亚、尼日利亚和塞拉利昂。"},{"name":"山地锯翅燕","english_name":"Mountain Saw-wing","scientific_name":"Psalidoprocne fuliginosa","overview":"山地锯翅燕（英文名：Mountain Saw-wing，学名：Psalidoprocne fuliginosa），是雀形目燕科锯翅燕属的鸟类。亦被称为山地粗翼燕或喀麦隆山粗翼燕，是燕科锯翅燕属的一种鸟类。全身呈暗褐色至黑色，翅膀深色，尾部分叉。仅分布于赤道几内亚的比奥科岛及邻近的喀麦隆山。","appearance":"全长约12厘米，体重11至14克。羽毛颜色为暗淡的巧克力棕色，翅膀颜色更深，尾部适度分叉，翼下的覆羽呈烟灰色。雌雄外观相似，幼鸟颜色较浅。与黑锯翅燕幼鸟相似，但山地锯翅燕全身颜色更深。","call":"发出短促而悦耳的“shu-shu”声。","habits":"常群居于森林边缘和高山草原地带。海拔分布广泛，从海平面到3000米高度皆可见其踪迹。以悠闲的方式飞行，频繁俯冲滑翔，有时会在低空飞行。食性未知。","breeding":"繁殖季节为10月至次年3月，通常单独筑巢，但也曾记录到10至15对群体。巢穴由苔藓和地衣紧密编织而成，位于悬崖、峡谷或洞穴的壁架上。一窝产2枚卵，孵化和育雏期信息未知。","identification":"与叉尾锯翅燕相比，羽毛颜色更偏棕色且较为暗淡；与蓝锯翅燕（亚种 petiti）的区别在于翅膀下方颜色更深，尾巴分叉程度较小。","protection":"IUCN：LC（无危）","distribution":"分布在喀麦隆西部（喀麦隆山）和比奥科岛。在尼日利亚东部的奥布杜高原和曼比拉高原也有记录，但具体状况不明。"},{"name":"白头锯翅燕","english_name":"White-headed Saw-wing","scientific_name":"Psalidoprocne albiceps","overview":"白头锯翅燕（英文名：White-headed Saw-wing，学名：Psalidoprocne albiceps），是雀形目燕科锯翅燕属的鸟类。而雌鸟的头部呈灰褐色，喉部颜色较淡。分布于东非、中非的广阔地带，包括安哥拉、布隆迪、刚果民主共和国等地。","appearance":"体长约13厘米，体重约11至14克。雄鸟具有独特的白色冠羽、额部、侧面头部、下巴和喉咙，黑色的眼纹自喙延伸至耳羽，其余羽毛呈褐黑色，略带绿色光泽；尾巴适中分叉；翼下覆羽呈灰褐色。雌鸟与雄鸟相似，但头部的白色部分较少，喉咙颜色不那么纯净，尾巴更短。幼鸟头部无白色，喉部为灰褐色，尾巴亦短。","call":"不甚爱鸣叫，发出轻快的啾啾声。","habits":"偏好开阔地带，如常绿森林边缘、开放的林地和耕作区。其飞行风格独特，深沉的翼拍与快速的方向变换，区别于其他燕类较为僵硬的飞行模式。","breeding":"关于繁殖习性的具体细节资料有限。","identification":"雄性白头锯翅燕的白色头部和黑色眼纹是辨识关键。与雌鸟及幼鸟相比，雄鸟的特征更为鲜明。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部和中部，包括安哥拉、布隆迪、刚果民主共和国、埃塞俄比亚、肯尼亚、马拉维、卢旺达、南苏丹、坦桑尼亚、乌干达和赞比亚。"},{"name":"蓝锯翅燕","english_name":"Black Saw-wing","scientific_name":"Psalidoprocne pristoptera","overview":"蓝锯翅燕（英文名：Black Saw-wing，学名：Psalidoprocne pristoptera），是雀形目燕科锯翅燕属的鸟类。小型的燕子。其独特的黑色外观带有蓝色光泽，拥有长长的分叉尾巴。分布于非洲东部至南部，从尼日利亚、埃塞俄比亚到安哥拉、津巴布韦北部及莫桑比克北部。繁殖季节会进行局部迁移，如南非的亚种holomelaena会在非繁殖季迁往莫桑比克。","appearance":"成年蓝锯翅燕长约13-15厘米，具有分叉的尾巴。全身黑色，带有蓝色光泽。性别相似，但雌鸟有较短的外侧尾羽，翅膀锯齿状边缘不明显。幼鸟呈棕色，光泽少，尾巴较短。不同亚种在体型、尾部形状、尾叉深度、翼长、光泽颜色和覆羽颜色上有所差异。","call":"叫声不高调，包括高音的“see-see”声，holomela亚种的叫声被描述为“chirr-chirr-cheeeu”，orientalis亚种的叫声为“tseeu-tseeu-tsee-ip”。此外，还有报警声“chirp”和求偶期间的“hui”声。","habits":"栖息于开阔的林地、灌木丛、森林、河谷、村庄、种植园，有时在山地草原和沼泽地。偏好湿润环境，常见于水源附近。在清晨和黄昏最活跃，以甲虫、蝇类和膜翅目昆虫为食，通常单独或小群体活动，飞行高度平均7米，飞行弱而飘忽。","breeding":"繁殖期一般在局部雨季，如喀麦隆的4-6月和10-11月，加蓬的4-7月等。巢穴长30-60厘米，由两性共同挖掘，常在垂直的沙土或粘土岸壁上，巢室铺有干草和苔藓。每窝产卵1-3枚，通常2枚，由雌鸟单独孵化约19天，雏鸟由双亲喂养，约24-27天后离巢。","identification":"与白头锯翅燕相似，但头部全黑，尾巴更长。不同亚种在颜色和体型上有细微差别，如holomelaena亚种的覆羽为白色，orientalis亚种的覆羽为白色且尾巴分叉更深。","protection":"IUCN：LC（无危）。在部分地区普遍且数量众多，但在刚果盆地、苏丹西部、东非平原、赞比亚南部和津巴布韦中部并不常见。虽然不大量利用人工巢址，但自然栖息地的丧失可能对其造成影响。","distribution":"繁殖区域从尼日利亚东部至埃塞俄比亚南至安哥拉、津巴布韦北部和莫桑比克北部。holomelaena亚种在南非东南部至开普省繁殖。非繁殖季候，holomelaena亚种迁往北面。","other":"蓝锯翅燕的多个亚种有时被视为独立物种，尤其是东部的四个亚种，包括指名亚种pristoptera，可能被划分为东部粗翼燕，学名为P. orientalis。"},{"name":"叉尾锯翅燕","english_name":"Fanti Saw-wing","scientific_name":"Psalidoprocne obscura","overview":"叉尾锯翅燕（英文名：Fanti Saw-wing，学名：Psalidoprocne obscura），是雀形目燕科锯翅燕属的鸟类。又称Fanti锯翅燕或Fanti粗翅燕，小型燕科鸟类。其最显著的特点是全身闪烁着均匀的绿色羽毛，尾部长而深叉，被誉为燕中最美的之一。分布于非洲低地，自塞内加尔至喀麦隆西部。","appearance":"叉尾锯翅燕体长约17厘米，重约9至10克。全身羽毛呈暗绿光泽，翅膀和尾部黑色，带有绿色光泽，尾部特别长且深叉。雌鸟尾部较短，幼鸟羽毛呈暗褐色，尾部亦短。两性相似，仅雌鸟尾部略短。","call":"叫声不频繁，主要发出轻微的吱吱声和颤音，包括短促鼻音上升和下降的吱吱声以及干涩的颤音。飞行中也会发出类似单音，远处几乎听不到。","habits":"主要栖息于开阔地带，包括轻度林地，靠近水源。常见于清理区、常绿森林边缘、开阔林地和耕作区附近。优雅的飞行者，通常在空中捕食昆虫，如甲虫，常在水面或草地低空飞行。","breeding":"繁殖期间，会在垂直河岸的60厘米深的洞穴中筑巢，每次产卵两个。主要在西非南部低地繁殖。","identification":"与Pristoprocne pristoptera相比，叉尾锯翅燕尾部更长，羽毛呈深绿色光泽，下翼覆羽为暗褐色。与Square-tailed锯翅燕不同，后者尾部明显较短，末端方形。","protection":"IUCN：LC（无危）；在冈比亚、塞拉利昂、象牙海岸和尼日利亚等地局部常见，但在利比里亚罕见至不常见。","distribution":"分布于非洲，从塞内加尔和冈比亚向东至喀麦隆中部和南部。"},{"name":"灰腰燕","english_name":"Grey-rumped Swallow","scientific_name":"Pseudhirundo griseopyga","overview":"灰腰燕（英文名：Grey-rumped Swallow，学名：Pseudhirundo griseopyga），是雀形目燕科灰腰燕属的唯一成员。其分布广泛，遍及非洲众多国家，包括安哥拉、贝宁、博茨瓦纳、布基纳法索等地。以其独特的灰褐色臀部和细长的尾巴而著称。","appearance":"灰腰燕体长约14厘米，体重8至12克。头部顶部至颈背为深棕色，背部和翅膀呈现光泽的暗蓝色，臀部和上尾覆羽呈灰棕色。尾巴深叉，暗棕色并带有蓝光泽，下体全白，新鲜羽毛时从下巴到胸部有粉红色调。与其它燕科鸟类相比，它拥有深深分叉的尾巴而无白色斑点，以及灰色臀部。雌雄相似，幼鸟更显棕色，腹部和侧翼灰色，其余下体白色，略带淡黄色至粉红色调，靠近胸部和颈部较灰，尾巴较短。梅尔比纳亚种（emmelbina/em）的臀部比指名亚种更暗。","call":"灰腰燕并不十分善鸣，其歌声微弱，类似叽叽喳喳声，飞行中也会发出嘶哑的“chraa”声。","habits":"灰腰燕栖息于开阔地带，如泛滥平原、草原、稀树草原或开阔林地，通常靠近水源，海拔高度可达东非约2200米，马拉维2300米。它们常在烧过或清理过的地面觅食，夜间在芦苇丛或裸露地面休息。迁徙模式尚不完全清楚，但会在雨季离开繁殖地，形成多达200只的小群，有时甚至达到3000只。在刚果河和埃塞俄比亚为留鸟，西非和中非部分地区存在局部迁移，加纳比亚在11月至2月出现，利比里亚为部分迁徙，尼日利亚偶见。东非季节性数量变化明显，津巴布韦通常4月至10月出现，干旱年份则全年可见。","breeding":"繁殖主要发生在旱季，偶尔会利用有利条件繁殖：西非11月至5月，埃塞俄比亚3月至4月和12月，东非5月、7月至10月和3月（高峰8月至9月），安哥拉8月至9月，赞比亚和莫桑比克7月至9月，津巴布韦7月至11月（高峰7月至8月），南非5月至12月（高峰6月至8月）。单独或小群体繁殖，3至10对组成，有时与刚果沙燕相邻。在开阔地带挖掘长达1米的斜向地洞，如沙洲、沙丘、犁过的田地、高尔夫球场等，也使用鼠穴、旧翠鸟或蜂虎的洞穴以及白蚁丘中的孔洞。巢室以草衬垫。每窝产卵1至5枚（赤道附近2至3枚），孵化和离巢期未有记录。若雨季来临，巢穴常被洪水淹没。","identification":"与西方毛脚燕和白腰雨燕相比，灰腰燕具有灰色而非白色的臀部，以及更长、更纤细的尾巴。与白腰雨燕的区别在于后者具有明显的白色臀部。","protection":"IUCN：LC（无危）","distribution":"灰腰燕广泛分布于非洲，包括但不限于安哥拉、贝宁、博茨瓦纳、布基纳法索、布隆迪、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、斯威士兰、埃塞俄比亚、加蓬、冈比亚、加纳、几内亚、几内亚比绍、肯尼亚、利比里亚、马拉维、马里、莫桑比克、纳米比亚、尼日尔、尼日利亚、卢旺达、塞内加尔、塞拉利昂、南非、苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。","other":"灰腰燕在一定程度上适应性强，虽然不使用人造巢穴，但有时会在与人类聚居地相关联的田野和其他地点筑巢。"},{"name":"白背燕","english_name":"White-backed Swallow","scientific_name":"Cheramoeca leucosterna","overview":"白背燕（英文名：White-backed Swallow，学名：Cheramoeca leucosterna），是雀形目燕科白背燕属的唯一物种。其最显著的特征是白色的背部，被黑色的翅膀和尾巴包围。分布于澳大利亚大部分地区，偏好草甸环境，能在沙质悬崖、河岸等地挖掘巢穴。","appearance":"成年白背燕平均长度约15厘米，头部带有斑驳的灰色顶冠，上眼眉白色，眼睛周围呈灰色。脸部有一条深色条纹从眼窝延伸至颈后。背部及部分胸部白色，腹部、翅膀和尾巴黑色。尾羽深叉，翼尖弯曲且尖锐，喙短且黑，腿脚灰。眼睛有突出的暗色虹膜。两性羽毛颜色相似，但在幼年期，白背燕的色彩较淡。","call":"鸣声为颤音，飞行中亦会发出尖锐的‘check’声。","habits":"白背燕栖息于开阔地带，常出现在草地和低矮灌木上方。它们在垂直的土崖上挖掘水平隧道筑巢。食性以昆虫为主，通过空中捕食。巢穴面临来自狐狸和猫的捕食威胁。","breeding":"繁殖期通常在7月至12月，雨季开始后。可单独或成群筑巢，有时多达80对。巢穴由干燥的草和叶子构成，位于沙质悬崖、河岸、矿坑或采石场的自挖洞穴中。每窝产卵4至5枚，偶尔6枚，具体孵卵和离巢时间未知。","identification":"与仙子燕、树燕和迎燕相比，白背燕的白色部分位于背上而非臀部，且后者的背部全黑。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚（除北部和塔斯马尼亚州东南部），在内陆降雨后，其分布范围可能覆盖整个澳大利亚南部，包括沙漠区域。","other":"由于土地清理和采矿导致的栖息地扩张，白背燕的种群数量估计正在增加。"},{"name":"马岛原燕","english_name":"Mascarene Martin","scientific_name":"Phedina borbonica","overview":"马岛原燕（英文名：Mascarene Martin，学名：Phedina borbonica），是雀形目燕科原燕属的鸟类。小型燕科鸟类，广泛分布在马达加斯加及马斯克林群岛。具有灰褐色上体和灰白至白色的下体，其下体有明显的黑色条纹。马岛原燕在繁殖季节于岩石裂缝、建筑物或洞穴中筑巢，主要以飞行中的昆虫为食。其分布范围包括马达加斯加、毛里求斯和留尼汪岛。","appearance":"马岛原燕体长约15厘米，翼展平均117毫米，体重约23.9克。上体呈深褐色带淡色条纹，下体灰褐色至白色，喉咙和下腹部尤为明显，全身密布黑色条纹。尾巴略呈叉状，长度约54.6毫米，尾下覆羽棕色，边缘白色。翅膀黑褐色，喙和腿黑色。眼睛深褐色，喙长平均11.3毫米。雄雌相似，幼鸟胸部条纹较模糊，翼羽末端有白色尖端。Madagascan亚种比指名亚种颜色更浅，喙更大，胸部条纹更密集，下腹部和尾下覆羽有细线纹。","call":"马岛原燕的鸣唱为颤音的“siri-liri siri-liri”，通常在飞行或栖息时发出；另有联系叫声“chip”，以及繁殖和争斗时的叫声。","habits":"马岛原燕广泛适应各种栖息地，包括开放和半开放地带，如水库、森林、灌木丛、草地、稻田，海拔从海平面到2400米。它们在毛里求斯和留尼汪岛主要活动于200至500米之间，而在马达加斯加则遍及整个岛屿。冬季时，马达加斯加亚种会迁移到非洲大陆较低海拔地区。","breeding":"繁殖期在马达加斯加为8月至11月，在毛里求斯和留尼汪岛为9月至12月。成群结队繁殖，每群约3至20对。巢由树枝和其他植物材料制成，内衬柔软物质和羽毛，筑于岩石裂缝、草丛、屋顶、建筑物、地下通道或洞穴中。每窝产卵2枚（马达加斯加和毛里求斯），或2至3枚（留尼汪岛）。孵化期和育雏时间未知，但雏鸟孵化时裸身盲眼，由雌鸟独自孵化，双亲共同喂养。","identification":"马岛原燕比普通燕体型大，下体有条纹，飞行更为有力。与条纹燕的区别在于背部和头部为褐色而非蓝橙色。Madagascan亚种与指名亚种相比，颜色更浅，尾下覆羽白色，胸部条纹更明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于马达加斯加和马斯克林群岛（毛里求斯、留尼汪岛），非繁殖季节迁徙至东非。在非洲东部、莫桑比克、赞比亚、马拉维、肯尼亚和坦桑尼亚大陆有零星记录，偶尔大量出现在莫桑比克和马拉维。","other":"马岛原燕在遭遇热带气旋时可能遭受重大损失，但总体而言，种群数量稳定。在毛里求斯受到法律保护，但在马达加斯加和非洲大陆国家仅有一般鸟类保护立法。"},{"name":"布氏原燕","english_name":"Brazza's Martin","scientific_name":"Phedinopsis brazzae","overview":"布氏原燕（英文名：Brazza's Martin，学名：Phedinopsis brazzae），是雀形目燕科 Phedinopsis 属的鸟类。体型小巧，长约12厘米，上身灰褐色，下身白色带深色条纹，胸羽带有棕色调。性别相似，幼鸟胸部条纹较淡，背部和翅膀边缘呈红褐色。分布于非洲刚果至刚果民主共和国中部和安哥拉东北部，常见于森林边缘河流附近。","appearance":"布氏原燕体型小，总长12厘米，重约13克。羽毛上身深褐色，头部颜色最深，从肩胛到上尾覆羽有模糊的深色条纹；翅膀和尾巴深褐色，尾巴末端平直；下身白色，带有粗厚的黑色条纹，胸部有时呈现灰色或棕色。翼下覆羽深褐色。性别外观一致。幼鸟上身羽毛边缘苍白，背部和翅膀尖端红褐色，下巴和喉咙呈灰色，下身条纹更加模糊。","call":"布氏原燕的鸣唱由一系列频率逐渐增加的短音组成，随后是一连串复杂的嗡嗡声，有时以数个咔哒声结束。歌声开始轻柔，逐渐增强，但最后的咔哒声较为柔和。","habits":"布氏原燕栖息于低地热带河流附近的陡峭河岸，如刚果河，或安哥拉高地的沙岸河流，这些地方适合作为其巢穴。它们能够适应开放的草原生境，夜间不在繁殖季节时会在此休息。以飞行中的昆虫为食，包括白蚁，可在河流或开阔的草原上狩猎。常与其他燕子形成混合群。","breeding":"繁殖季节为7月至10月，正值干季末期，但河水水位尚未高涨至引发洪水的程度。巢穴通常位于森林河流的垂直河岸，有时形成小型松散的群体，巢穴之间可能相距较远。巢由软材料如羽毛或干草堆砌，位于50厘米长的隧道尽头。每窝产三枚白色蛋，尺寸约为18.5毫米×11.25毫米，重量1.5克。孵化时间和雏鸟离巢时间未知，但如同其他燕子，雏鸟出生时裸体且盲眼。","identification":"布氏原燕下身显著的深色条纹是其与其他燕子的主要区别。与条纹较少的Riparia属物种相比，其下身条纹更明显。与马岛原燕相比，布氏原燕较小，背部颜色更单一，喉部和胸部的条纹更细腻，但二者无地域重叠。","protection":"IUCN：LC（无危）","distribution":"布氏原燕的分布范围覆盖了刚果、刚果民主共和国南部和安哥拉东北部，最近的记录显示其分布向北延伸至刚果民主共和国西部（萨隆加国家公园），向南扩展至安哥拉西部（库安扎苏省卡松格地区）。","other":"尽管布氏原燕曾被IUCN列为数据不足，但最新的研究显示它实际上分布广泛且数量众多，自2008年起被列为无危物种。"},{"name":"非洲褐喉沙燕","english_name":"Brown-throated Martin","scientific_name":"Riparia paludicola","overview":"非洲褐喉沙燕（英文名：Brown-throated Martin，学名：Riparia paludicola），是雀形目燕科沙燕属的鸟类。分布广泛，遍布非洲大陆。其特征为橄榄棕色的背部，白腹，灰棕色的喉部和胸部，腹部和尾下覆羽呈淡白色。与灰色喉部的和马岛褐喉沙燕曾被视为同一种类。","appearance":"成年非洲褐喉沙燕体长约12厘米，重8.5至10.7克，翼展26至27厘米。头部、耳羽和上体呈灰褐色，最深色出现在初级飞羽，眉线黑色棕色，尾巴暗灰棕色。下体颜色由灰白色下巴和喉咙，浅灰棕色胸部和侧腹，至灰白色腹部和白色尾下覆羽组成。上翼覆羽和腋羽淡灰棕色。喙黑色，眼睛棕色，腿黑色。幼鸟上体羽毛边缘呈淡黄灰色或淡赤黄色，尤其是臀部和上尾覆羽，三级飞羽有宽的淡黄色边缘，胸部和侧腹带暖棕色调。不同亚种之间在体型和棕色色调上有细微差异。","call":"发出微弱的颤音歌曲，连续在飞行中吟唱，安顿在栖息地后变为对话式的低音。还有一种尖锐的警报叫声。","habits":"栖息于河流、湖泊和其他水体附近，特别是在繁殖季节。也会在草地、灌木丛、沙丘、污水处理厂、芦苇床、湿地、稻田和河口觅食。海拔范围广泛，从海平面到东非的3000米，甚至在东刚果民主共和国的卡里斯姆比山达到3700米。非繁殖季节的群体会在芦苇床中过夜。","breeding":"繁殖季节因地区而异，一般在旱季的南非，雨季的东非；在摩洛哥为10月和12月至3月，尼日利亚10月至2月，埃塞俄比亚几乎任何月份（记录显示11月至3月和7月至9月），东非主要在3月至7月，赞比亚和津巴布韦6月至9月，马拉维6月至7月，莫桑比克11月至12月；在南非多数月份繁殖（主要在自由州、夸祖鲁-纳塔尔东部2月至10月，西南开普9月至12月高峰，东开普11月至1月）。通常以3至12对的小群体繁殖，有时多达500对，洞穴紧密相邻；偶尔单独繁殖。巢穴由双方共同挖掘，轮流工作，大约3周完成，通常长度30至80厘米，有时超过150厘米，距离地面0.8至3米，在如河流、湖泊、道路、采石场、坑、峡谷或矿渣堆的岸边；有时利用旧的椋鸟或蜂虎的巢穴，记录中有一巢位于排水管中；扩大的巢室用草、毛发和羽毛铺垫。一窝产2至4枚白色蛋，尺寸15.3至18.7毫米×10.5至13.8毫米；孵化由双方进行，主要由雌鸟承担，持续约12天；双方都喂养雏鸟，雏鸟在约20至25天后离巢；离巢后的幼鸟会与父母一起待几天。野外记录的最长寿命约为5年。","identification":"非洲褐喉沙燕与崖沙燕最为相似，但可通过其较暗的背部、较小的体型和更急促、颠簸的飞行来区分。没有胸带，尾部没有白色斑块，与岩燕的区别在于体型较小且尾部缺乏白色。与河岸燕相比，喉部为棕色，无胸带，跗跖无羽毛。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲，包括东非和中非的高原湿地，在马达加斯加东部和中部高地的湿地中也有记录，密度可达每1.5平方公里8对（拉穆比亚地区）和大约每公顷1对（坦波凯塔的安卡佐贝）。在几个保护区及其周边被发现，包括马罗杰伊、拉诺马法纳、扎哈梅纳和曼塔迪亚国家公园。"},{"name":"灰喉沙燕","english_name":"Grey-throated Martin","scientific_name":"Riparia chinensis","overview":"灰喉沙燕（英文名：Grey-throated Martin，学名：Riparia chinensis），是雀形目燕科沙燕属的鸟类。小型燕科鸟类，体型较小，全身呈灰色至棕色，腹部为淡白色，喉部及上胸部为灰褐色，无明显胸带。分布广泛，从塔吉克斯坦、阿富汗至印度次大陆，延伸到中国南部、台湾及菲律宾北部。在沼泽、河流、湖泊等近水环境常见。","appearance":"灰喉沙燕体长约10-11厘米，上体为鼠灰色或淡灰棕色，下体较淡，喉部至胸部颜色从奶油棕色过渡至鼠灰色，与其余淡色下体形成对比。尾部相对短，末端平截或微分叉。成年与幼年在色彩上有细微差别，幼鸟的冠部较淡，翼覆羽、三级飞羽及背部边缘有淡黄色，喉咙和胸部带有粉红至淡黄色调，胸部有轻微的带状痕迹。","call":"其鸣唱被描述为略显粗糙且不甚悦耳的啾啾声，通常在飞行中发出，偶尔在短暂的停歇时也会鸣叫。叫声包括短促、清脆的'chyip, chyip'声，以及激烈、金属质感、快速的'sputtering kr’r’r’r’'声，开始响亮后逐渐减弱。","habits":"栖息于河流、湖泊、湿地附近，迁徙模式随地区而异，部分区域为留鸟，部分进行局部迁移。群体觅食，以双翅目昆虫、蚊子、摇蚊、蚜虫为主食，有时可达数千只聚集，尤其在傍晚时分。飞行特点为弱而颤动。","breeding":"繁殖季节因地区降雨而异，一般在10月至次年2月，少数至5月。巢穴由软土或沙土挖掘而成，入口通道可达150厘米长，巢内铺垫干草和细根，有时用羽毛装饰。每窝产卵2-4枚白色蛋，孵化及喂养由双亲共同承担，雏鸟约21天离巢，之后数日仍依赖父母。","identification":"与崖沙燕区别在于尾端无白色斑点，与非洲褐喉沙燕区别在于喉部及胸部浅灰褐色，无深色胸带。在巴基斯坦，可通过较窄的侧腹棕色区分。","protection":"IUCN：LC（无危）。在印度次大陆最为常见，但由于湿地排水、大坝建设和河流流量调控，部分地区数量有所下降。","distribution":"分布于塔吉克斯坦、阿富汗、印度次大陆至中国南部、台湾、菲律宾北部。在中国主要见于1000米以下的低海拔地区，但在某些地方可达4600米高度。","other":"灰喉沙燕曾被认为是褐喉沙燕的亚种，现已单独成为一个物种。"},{"name":"刚果沙燕","english_name":"Congo Martin","scientific_name":"Riparia congica","overview":"刚果沙燕（英文名：Congo Martin，学名：Riparia congica），是雀形目燕科沙燕属的鸟类。广泛存在于刚果河及其支流乌班吉河沿岸，分布区域十分局限，主要在刚果民主共和国边境附近的河流地带。以森林中的沙岸为栖息地，形成群落筑巢。","appearance":"刚果沙燕长约11厘米，背部呈浅棕色，头部顶部颜色稍深，翅膀亦为暗色。眼周有一条暗色线条。腹部白色，胸部为淡棕色，与崖沙燕明显区别的无显著的狭窄胸带。喙部黑色，腿脚棕色。性别相似，幼鸟背部、臀部和翅膀上的羽毛尖端略显淡色。","call":"刚果沙燕的叫声至今尚未被记录。","habits":"这种非迁徙性的鸟类以河流上空的小型昆虫为食，如蚋和各种蝇类，通常在河流上空或附近开阔地带捕食。它常以小群体形式活动，有时会与其他燕子混群，尤其是在冬季迁徙而来的崖沙燕群中。","breeding":"刚果沙燕在二月和三月期间集体繁殖，每对鸟会在河岸沙丘中挖掘隧道，入口大约离河面1米高，巢穴位于隧道末端。关于其繁殖生物学的细节知之甚少，但可能与崖沙燕类似。","identification":"刚果沙燕与崖沙燕相比，体型较大，胸部的条纹较模糊，崖沙燕有明显的白色喉部，而刚果沙燕的喉部颜色较暗。与非洲褐喉沙燕的区别在于后者具有深色喉部。","protection":"IUCN：LC（无危）","distribution":"刚果沙燕仅分布于刚果河及其支流乌班吉河沿岸，主要在刚果民主共和国边境附近，以及刚果境内桑加河沿岸，但其确切状态尚不确定。"},{"name":"崖沙燕","english_name":"Sand Martin","scientific_name":"Riparia riparia","overview":"崖沙燕（英文名：Sand Martin，学名：Riparia riparia），是雀形目燕科沙燕属的鸟类。俗名: 水燕子、土燕、灰沙燕，上体呈褐色，下体白色，具有特征性的褐色胸带。广泛分布于全球，包括欧洲、地中海地区、亚洲至太平洋，以及北美洲。在冬季迁徙至东非、南非、南美和印度次大陆。","appearance":"成年崖沙燕体长约12厘米，翼展89-111毫米，体重10.2-18.8克。背部灰褐色，与较暗的翅膀形成对比；喉部白色，与明显的褐色胸带区分开来。幼鸟上体边缘呈肉桂色或乳白色，喉部带有粉红色调。尾巴中等长度，末端略呈叉状，两性相似，但可通过抱窝斑或泄殖腔突起区分性别。","call":"崖沙燕的叫声为连续的颤音，飞行时尤为明显，变成夜间栖息时的对话声。当察觉到猛禽、乌鸦或其他潜在威胁时，会发出刺耳的警报声。","habits":"崖沙燕生活在靠近水域的开阔低地，如河流、湖泊或海洋附近，避免森林和无法找到适宜筑巢环境的地区。它们在春季最早到达繁殖地，通常在3月底出现在英国，比家燕稍早。主要以小昆虫为食，如蚊虫和其他水生阶段的飞虫。","breeding":"崖沙燕在水边的沙质土壤或河岸砂岩上集群筑巢。巢穴深度可达60-130厘米，每巢产卵3枚，孵化期约为17天。雏鸟在巢中停留26-28天。","identification":"与其他燕科鸟类相比，崖沙燕的棕色背部、白色喉部、小巧的体型和快速、急促的飞行方式使其容易识别。仅非洲南部的斑沙燕与其相似，但后者在夏季不会与崖沙燕共存。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括整个欧洲、地中海国家、亚洲至太平洋，以及北美洲。非繁殖区域覆盖东非、南非、南美和印度次大陆。","other":"在全球范围内，崖沙燕并不罕见，但在某些地区面临栖息地丧失和碎片化的威胁。"},{"name":"淡色沙燕","english_name":"Pale Martin","scientific_name":"Riparia diluta","overview":"淡色沙燕（英文名：Pale Martin，学名：Riparia diluta），是雀形目燕科沙燕属的小型鸟类。小型褐背白腹的燕类，喉胸具窄褐色带，与崖沙燕极为相似；繁殖于中亚至中国、南亚高原的砂质河岸，海拔可达4500米，冬季迁至南亚南部及东南亚，成群在开阔湿地、草场及农田上空捕食飞虫。","appearance":"体长约12厘米。指名亚种上体淡灰褐色，飞羽及尾羽色更深，尾浅叉；下体污白色，胸带淡褐且界线模糊；翼下覆羽褐色；后趾跗跖被羽。两性同型，幼鸟上体羽缘淡色。各亚种以体型、上体羽色深浅及胸带宽度、颜色区分：gavrilovi 上体及胸带均较指名亚种深；transbaykalica 体型大，上体暗且带红褐色，头部更褐；indica 体型最小；fohkienensis 略大于 indica，羽色亦较深；tibetana 羽色比指名亚种更暗。","call":"鸣声为短促、带摩擦感的啭鸣；在繁殖群上空飞行时发出硬质的“ret”或“brrit”声。与崖沙燕相比，其叫声多为干燥的连串音，带更明显的颤音质感。","habits":"栖息于开阔原野，常伴水域，在与崖沙燕同域分布的干旱草原中，离水源稍远；最高记录至喜马拉雅山脉约4500米。夜宿苇丛。北部种群具迁徙性，冬季南迁；指名亚种主要越冬于印度北部，亦记录至埃及；fohkienensis 在中国南部越冬。觅食时结群，与雨燕科及其他燕类混飞。飞行快速而飘忽，翼拍浅而急促。","breeding":"繁殖期11月至翌年5月，主高峰2–4月。集群营巢，每群通常150–200巢。巢筑于河岸、湖岸或路堑的砂质隧道末端，以草、羽衬垫。印度记录每窝3–4枚卵，中国4–7枚；在藏东北3400米研究中，9巢平均4.9枚，卵白色具光泽，约19.0×13.4毫米；双亲共同孵卵约15天，育雏期约23天，巢成功率达89.5%；观察到的19巢中有2巢出现合作繁殖，由1只雄鸟协助亲鸟。","identification":"与崖沙燕最似，但上体更淡偏灰，下体更污白，胸带较淡且界线不清，面颊斑下缘略模糊；鸣声亦稍异。不同亚种间可依体型、上体颜色及胸带特征区分，见“外形特征”。","protection":"IUCN: LC（无危）","distribution":"繁殖区：指名亚种分布于哈萨克斯坦南部及东南部、吉尔吉斯斯坦北部、乌兹别克斯坦东部及南部、塔吉克斯坦西部；越冬于印度西北部及尼泊尔。indica 繁殖于巴基斯坦北部及印度西北部。fohkienensis 繁殖于中国中部及东部，越冬于中国南部并可能至印度支那北部。tibetana 繁殖于青藏高原，越冬于印度及不丹西部。","other":"曾被视为崖沙燕的亚种，后因形态、鸣声差异及同域繁殖且遗传数据支持而独立成种。亚种 indica 的归属因繁殖生境差异受质疑，或应归入崖沙燕。"},{"name":"马岛褐喉沙燕","english_name":"Madagascar Martin","scientific_name":"Riparia cowani","overview":"马岛褐喉沙燕（英文名：Madagascar Martin，学名：Riparia cowani），是雀形目燕科沙燕属的鸟类。主要分布在马达加斯加山区东部。曾被视为非洲褐喉沙燕的一个亚种。","appearance":"马岛褐喉沙燕体型较小，通体呈深浅不一的棕色，腹部白色，尾部略带叉状。上体羽毛边缘灰黄或淡黄褐色，尤其在臀部和上尾羽处更为明显。头冠、耳羽和上体颜色为灰褐色，翅膀最暗，面部黑色偏褐色，尾巴呈暗灰褐色。下方有灰色至白色的下巴和喉咙，淡灰褐色的胸部和两肋，腹部灰白，尾下覆羽白色，翼下覆羽和腋羽呈淡灰褐色。成鸟与雌鸟外观相似，而幼鸟上体有较淡的羽毛边缘。","call":"常见发声为飞行中发出的短促、略微下降的颤音颤鸣。","habits":"栖息于各种开阔生境，包括沼泽、稻田、其他农业地带、次生林和山地灌木丛。主要出现在中高海拔地区，低地罕见。常群居，飞翔时可见，有时与其他燕子或雨燕混群。飞行弱且飘忽。","breeding":"关于繁殖细节的报道有限。","identification":"与崖沙燕区别在于棕色的喉咙而非白色，无胸带，且跗跖无毛。与马岛原燕相比，体型更小、色彩更单一，腹部无条纹，头部更小且圆润，翼下羽毛颜色更均匀，飞行速度更快。","protection":"IUCN：LC（无危）","distribution":"主要分布于马达加斯加东部山区。","other":"过去曾被归入非洲褐喉沙燕，后因形态差异和鸣叫的不同而独立为种。"},{"name":"斑沙燕","english_name":"Banded Martin","scientific_name":"Neophedina cincta","overview":"斑沙燕（英文名：Banded Martin，学名：Neophedina cincta），是雀形目燕科 Neophedina 属的小型鸟类。体型略大，呈棕色与白色相间，胸带显著，眼上具一白色条纹。广泛分布于非洲，自喀麦隆至埃塞俄比亚南至南非开普地区，偏好草甸、湿地及近水开阔地带。","appearance":"斑沙燕长约15-17厘米，体重19-30克。头部黑色眼线明显，眼上具白色条纹，背部与翅膀呈深褐色，尾部方形。腹部白色，胸带棕色，幼鸟胸带较淡，上体羽缘泛红至奶油色。性别相似，但幼鸟特征略有差异。","call":"发出尖锐的颤音鸣唱，有时以颤音结束；亦发出响亮的叽喳声和短促的“chip”、“chrip”、“kip”叫声。","habits":"栖息于开放生境，如农田、草原和稀树草原，通常靠近水源。以昆虫为主食，常在草地上空飞行捕食。飞行缓慢且不规则，频繁停歇。","breeding":"繁殖季节在不同区域各异，筑巢于垂直河岸或堤坝的洞穴中，巢穴长达60-90厘米，偶尔利用白蚁洞穴、废弃的椋鸟巢穴或排水管。每窝产卵2-5枚，由双亲孵化及喂养，孵化期未记录，小鸟出巢需21-24天，最长寿命至少4年。","identification":"与崖沙燕相比，体型更大，翼下具白色斑块，尾部方形。不同亚种在体型和羽色上有细微差别。","protection":"IUCN状态未提及。","distribution":"非洲广泛分布，从喀麦隆和刚果民主共和国至埃塞俄比亚，南至南非的开普地区。南部分布种群为迁徙性，冬季向北迁移。","other":"曾被归入Riparia属，遗传研究后单独置于Neophedina属。"},{"name":"双色树燕","english_name":"Tree Swallow","scientific_name":"Tachycineta bicolor","overview":"双色树燕（英文名：Tree Swallow，学名：Tachycineta bicolor），是雀形目燕科树燕属的鸟类。以其独特的巢穴选择而著称。主要在开放的田野、草地和沼泽地带活动，但在繁殖季节会利用树木中的空洞或人工巢箱筑巢。分布范围覆盖了北美的大部分地区，从北至阿拉斯加，冬季则迁徙至巴拿马附近。雄鸟背部呈明亮的蓝绿色，雌鸟和幼鸟则色彩较为暗淡。","appearance":"双色树燕体长约13厘米，体重介于16至25克之间。雄鸟上部羽毛闪耀着蓝绿色光泽，腹部纯白，尾羽略显交叉。雌鸟的羽毛颜色较暗淡，背部偏绿色，而幼鸟的上部羽毛呈褐色，胸部带有灰棕色模糊的条纹。","call":"双色树燕的叫声包括三部分：啾啾声、哀鸣和咕噜声，这些声音可能单独发出，也可能组合在一起，形成复杂的交流信号。","habits":"双色树燕是迁徙性鸟类，夏季在北美繁殖，冬季迁徙至墨西哥、中美洲和加勒比海地区。它们偏好栖息于近水的沼泽和开阔的田野，常在非繁殖季节形成大规模的群体。它们主要以昆虫为食，偶尔食用少量果实，飞行技巧高超，能精准捕捉空中飞虫。","breeding":"双色树燕通常在树洞或人工巢箱中筑巢，有时会形成松散的集群。繁殖期从早春开始，持续到夏末。它们的社会结构一般是单配偶制，尽管约8%的雄鸟会实行一夫多妻制。雌鸟负责孵化纯白色的蛋，通常为四至七个，孵化期约为两周。雏鸟出生后大约18至22天就会离巢。","identification":"与紫绿树燕相比，双色树燕的臀部和脸颊两侧不会出现大面积的白色。雌鸟和幼鸟的辨识主要依赖于羽毛的颜色和亮度。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在北美，从北至阿拉斯加，南至美国中部。冬季迁徙至美国南部直至南美北部，包括墨西哥、中美洲、加勒比海地区。","other":"双色树燕由于其研究价值，被视为生态学中的模型物种，尤其是在气候变化影响、生态毒理学、生命史理论、交配系统、生理学和行为学等领域。"},{"name":"红树燕","english_name":"Mangrove Swallow","scientific_name":"Tachycineta albilinea","appearance":"红树燕体型较小，长约11-12厘米，重约14克。成鸟上体金属蓝绿色，尾部和飞羽黑色，具显著白色臀部和翼下覆羽，下体白色，有时略带暗色羽轴线。嘴小而黑，长约11毫米。虹膜深棕色，跗跖和趾颜色从黑色到棕褐色。成年个体尾部仅轻微分叉。雌雄相似，但雌鸟尾巴稍长，翅膀略短。幼鸟上体灰褐，下体灰褐带白色洗染，偶尔上体有微弱绿光。","call":"红树燕的叫声被描述为卷曲的'jeerrrt'或'chriet'，其鸣唱通常表现为柔和的颤音，还使用短促尖锐的警报声。","habits":"红树燕偏好相对静止的开阔水域，如河流或湖泊附近，飞行路径直接而低，常在水面快速拍打翅膀并滑翔。在繁殖季节之外，它们可能成群结队觅食。在两次觅食之间，经常可见其在水边栖息。它们的巢穴通常建在靠近水源的自然或人造洞穴中，如树桩或枯木中，偶尔会在人工巢箱中筑巢。巢由草、细茎、苔藓和少量叶子构成，深度几厘米，通常位于低于2米的高度，但仍高于典型洪水水位。","breeding":"红树燕的繁殖期大约从1月持续至7月，在5个月的繁殖季内通常会育两窝。它们是社会性一夫一妻制，但存在额外配偶繁殖现象。每窝产3至5枚白色卵，孵化期17天，平均卵尺寸为17.3mm×12.8mm，重约1.6克，孵化率约60%，由双亲喂养23至27天至离巢。每次繁殖通常只有1只幼鸟成功离巢。","identification":"红树燕与其他Tachycineta属燕子的区分点在于其蓝色背部、白色臀部和下体，以及眼上方的白色超眶纹。最接近的物种是双色树燕、紫绿树燕和白翅树燕，但这些物种在地理分布、体型、臀部颜色和面部特征上有所不同。","protection":"IUCN：LC（无危）","distribution":"红树燕主要分布在中美洲，从墨西哥东部和西海岸至巴拿马，常见于低海拔的红树林、河流、湖泊等水域附近。","other":"红树燕在2002年首次在美国佛罗里达州被记录到，尽管它通常是其分布区内的全年居民，但仍可能存在一些季节性的迁移。"},{"name":"秘鲁树燕","english_name":"Tumbes Swallow","scientific_name":"Tachycineta stolzmanni","overview":"秘鲁树燕（英文名：Tumbes Swallow，学名：Tachycineta stolzmanni），是雀形目燕科树燕属的鸟类。主要分布在南美洲的秘鲁西北部和厄瓜多尔西南部沿海地带。该鸟种以前被认为是红树燕的亚种，但在生态习性和外观上存在显著差异，现已确认为独立物种。尽管在当地较为常见，但对其生物学特性和行为的研究仍十分有限。","appearance":"秘鲁树燕是最小的树燕属成员，体长约为11.5至12厘米。其上体颜色为暗蓝褐色到蓝绿色，具有独特的白色眼上纹，从喙基延伸至上眼处。喙短而粗，下体白色，胸部有淡淡的棕色细纹。最明显的特征是白色的臀部，这有助于将其与蓝白南美燕区分开来，蓝白南美燕的上体更呈天蓝色，缺乏白色臀部。幼鸟上体主要为淡褐色，随着年龄增长逐渐显现出蓝绿色的羽毛。","habits":"秘鲁树燕偏好沙漠环境，常以成对或小群体的形式出现，通常在荒凉的栖息地上空盘旋或栖息于灌木丛顶。它们的活动范围覆盖了干燥的草原、沿海盐湖和农田等生境。","breeding":"关于秘鲁树燕的繁殖习性的具体信息尚待进一步研究，但根据树燕属的一般习性，它们可能在靠近大型开阔水域的洞穴中筑巢。","identification":"秘鲁树燕与蓝白南美燕在外表上有明显区别，尤其是后者缺乏白色臀部，且上体颜色更偏天蓝色。此外，蓝白南美燕主要在高地筑巢，而秘鲁树燕则栖息于沿海平原。","protection":"IUCN：LC（无危）","distribution":"秘鲁树燕主要分布在南美洲的秘鲁西北部和厄瓜多尔西南部，尤其在沿海地区最为常见。"},{"name":"白翅树燕","english_name":"White-winged Swallow","scientific_name":"Tachycineta albiventer","overview":"白翅树燕（英文名：White-winged Swallow，学名：Tachycineta albiventer），是雀形目燕科树燕属的鸟类。南美洲热带低地常见的树燕。其特征为蓝绿色光泽背部，飞行中或停歇时可见明显的白色翼斑。分布于哥伦比亚至阿根廷北部，常见于河流湖泊上空低飞捕食。","appearance":"成年白翅树燕长约14厘米，体重约14至17克，拥有蓝绿色反光的上体，白色腹部和臀部，翅膀除白色翼斑外为黑色。头部通常比背更显蓝色，喙和腿均为黑色。雌雄相似，但雌鸟翼斑上的白色略少。幼鸟颜色较暗淡，下体偏灰，翼上的白色较少。","call":"发出尖锐的‘zreeed’声，为连续上升的嗡鸣。","habits":"栖息于低地水域附近，如河流或湖泊，常在水面低飞捕食昆虫。以小群体或成对出现，喜停歇于水边的枯枝上。大部分地区全年留居，但在最南端的部分地区会迁徙。","breeding":"在树洞、岩石间或人造结构中筑巢，巢内铺垫其他鸟类的羽毛和种子。每窝产卵3至6枚，卵呈白色，大小约为17至20毫米×13至14.6毫米，重约1.9克。成对独立筑巢，巢位通常离水面几米高。","identification":"与红树燕、秘鲁树燕、白臀树燕和白腰树燕的区别在于翼斑更大，且地理分布不重叠或季节性共存。白翅树燕可通过翼上的大面积白色区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲，自哥伦比亚至阿根廷北部。在巴西和阿根廷南部，仅在南半球夏季出现。"},{"name":"白腰树燕","english_name":"White-rumped Swallow","scientific_name":"Tachycineta leucorrhoa","overview":"白腰树燕（英文名：White-rumped Swallow，学名：Tachycineta leucorrhoa），是雀形目燕科树燕属的鸟类。腰部白色明显，与白翅树燕和白臀树燕有明显区别。分布于南美洲，自玻利维亚至巴西中部和南部，延伸至阿根廷中部和东部。","appearance":"白腰树燕体长约13厘米，体重介于17至21克之间。头部和上体具有蓝绿色光泽，尤其在非繁殖季节更偏绿蓝色。翅膀黑色，内侧次级飞羽、三级飞羽和大覆羽尖端呈白色，随年龄增长而逐渐褪色。尾巴黑色，微叉状。下体和翼下覆羽白色，腰部白色特征显著。喙、腿和脚黑色，虹膜棕色。雄雌相似，幼鸟较为暗淡，胸部灰暗。","call":"鸣唱柔和，常被描述为咕噜声或断续的颤音，通常在黎明飞行时发出。报警声为快速而无调性的\"zzt\"声。","habits":"栖息于开放或半开放地带，靠近水源，如林缘、人类聚居区。也出现在干燥的稀树草原、退化的前森林地带和季节性泛滥的草地。繁殖季节后形成数百只的大群。觅食时单独或小群体行动，以飞行中的昆虫为食，如苍蝇、甲虫、飞蚁、直翅目和鳞翅目昆虫。","breeding":"繁殖期在巴西为10月至12月，在阿根廷为10月至翌年2月。巢由植物纤维构成，内衬毛发和羽毛，筑于树洞、死木、废弃建筑的檐下或围栏柱孔中。每窝产4至7枚蛋，孵化期15至16天，雏鸟离巢期21至25天。平均寿命约2.12年，雄鸟略长于雌鸟。","identification":"与白臀树燕的区别在于白腰树燕额头有白色条纹，且体型稍大。白臀树燕在非繁殖季节保持蓝绿色上体光泽。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，包括玻利维亚、巴西中部和南部、阿根廷中部和东部、乌拉圭、巴拉圭、秘鲁。非繁殖季节可能北迁至秘鲁东南部、玻利维亚北部和巴西东北部。","other":"偶尔遭受紫辉牛鹂的巢寄生，影响巢的成功率。"},{"name":"白臀树燕","english_name":"Chilean Swallow","scientific_name":"Tachycineta leucopyga","overview":"白臀树燕（英文名：Chilean Swallow，学名：Tachycineta leucopyga），是雀形目燕科树燕属的鸟类。典型的南美洲树燕，以昆虫为食。其特征为上部深蓝金属色，下部白色，最显著的是白色臀部，体长约13.5厘米。新世界最南部的燕子之一，繁殖于智利南部和阿根廷。","appearance":"成年白臀树燕上体呈深蓝色金属光泽，下体白色，拥有明显的白色臀部。尾巴略呈叉状，翼和尾为黑色，内侧次级飞羽和覆羽尖端带有白色。翅膀下的覆羽和辅助羽灰色。喙和腿均为黑色。雌雄相似，幼鸟颜色较暗淡，背部和翼覆羽光泽较弱，上尾覆羽黑色尖端带白，通常有狭窄的白色眉纹。","habits":"栖息于从海岸到安第斯山脉的山麓地带，常出现在水边和城镇附近，偏好与稍小的蓝白南美燕共处。它们是季节性繁殖者，筑巢于自然或人造洞穴中，通常单独筑巢，偶尔成群。飞行路径低而直接，主要以飞行昆虫为食。","breeding":"繁殖期一般从9月至次年2月，尤其是在南美洲的最南端。在智利，每年可育成2至3窝雏鸟。每窝产4至6枚白色卵，卵大小约为17.8-21毫米×13-14.3毫米，重量约2克。","identification":"与白臀树燕最为相似的是白臀燕，但后者额头为白色，上体更偏蓝色，翅膀下方覆羽为灰色。两者繁殖范围几乎不重叠。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美洲的南锥体区域，包括阿根廷、智利和福克兰群岛。迁徙时北至玻利维亚、巴西、巴拉圭和乌拉圭，可能还包括秘鲁。"},{"name":"金色树燕","english_name":"Golden Swallow","scientific_name":"Tachycineta euchrysea","overview":"金色树燕（英文名：Golden Swallow，学名：Tachycineta euchrysea），是雀形目燕科树燕属的鸟类。原生于加勒比海岛国多米尼加共和国和海地的希斯帕尼奥拉岛，曾广泛分布于牙买加，现于牙买加已灭绝。以青铜绿色至铜色上体和金绿色光泽著称，分布于孤立的山地森林，主要由希斯帕尼奥拉松构成的环境中。","appearance":"体长约12厘米的小型燕子，雄鸟上体及头部两侧具强烈的金属光泽，呈铜褐色至青铜色，翅膀和尾巴为暗青铜绿色，尾部略呈叉状；下体白色，翼下覆羽暗色带青铜绿边缘。雌鸟相似但色彩较暗淡，胸及偶尔喉部和下尾覆羽有灰褐色斑点。幼鸟颜色更暗淡，胸部有广泛的灰褐色斑点。","call":"发出柔和的双音节叫声，常被描述为“tchee-weet”，重复播放。","habits":"栖息于希斯帕尼奥拉岛的山地森林，偏好开阔地带，偶尔出现在森林和城镇上空。筑巢于死树桩、洞穴、房屋檐下、近期烧毁的区域，以及巢箱中，以细小的植物纤维、丝线、棉花和羽毛为材料。","breeding":"繁殖季节在4月至7月间，通常每窝产2至4枚白色或奶油白色蛋，无斑点，平均重量约为1.7克。雌鸟负责孵卵，孵化期17至20天，雏鸟大约在孵化后24至27天离巢。","identification":"与双色树燕相似，但后者上体呈现蓝绿色而非金色，尾部叉度较小，颈部侧面无白色斑块。亚种sclateri具有更深的尾部叉度，翅膀较长，喙较小，头部和尾上覆羽呈蓝绿色，翅膀和尾巴为蓝黑色。","protection":"IUCN：VU（易危）","distribution":"分布于希斯帕尼奥拉岛（多米尼加共和国和海地），曾在牙买加分布，现已在当地灭绝。","other":"历史上，金色树燕在牙买加的19世纪常见，但在20世纪80年代早期之后，最后一次明确的观察记录显示其可能已经灭绝。"},{"name":"紫绿树燕","english_name":"Violet-green Swallow","scientific_name":"Tachycineta thalassina","overview":"紫绿树燕（英文名：Violet-green Swallow，学名：Tachycineta thalassina），是雀形目燕科树燕属的鸟类。相对较小的北美双色树燕，以其独特的色彩而著称。成年雄鸟面部洁白，上体呈现迷人的蓝绿色光泽，尾部上方带有紫色调。雌鸟和幼鸟上体颜色较暗淡，有时仅呈灰色。在空中飞翔时，可见两侧臀部延伸至背部的白色斑块，犹如鞍袋。广泛分布于北美西部的开放生境中，常在草地或水塘上空觅食。紫绿树燕繁殖范围北至阿拉斯加，冬季则主要迁徙至墨西哥和中美洲北部。","appearance":"紫绿树燕体型小巧，翼尖长而锐利，尾部稍呈叉状。雄鸟头部和背部呈现柔软的丝绒绿或绿青铜色，颈部集中有淡淡的紫罗兰色光泽，形成横跨项背的条带。雌鸟和幼鸟上体颜色较暗，有时仅呈灰褐色。两性均具有部分或全部白色的耳羽，几乎环绕眼睛，尤其在成年雄鸟中更为显著。臀部两侧有白色斑块，有时接近，形成连续的白色带。尾部深凹。亚种brachyptera的翅膀比其他亚种短。","call":"紫绿树燕的叫声主要包括'chee-chee'和twitter两类。'chee-chee'叫声常见于个体间的互动，如觅食、飞行追逐或接近巢穴时，可能用于社会凝聚。Twitter叫声通常与求偶展示和领地建立有关，仅在飞行中听到，可能涉及雄鸟陪伴雌鸟或短暂的同类领土争斗。","habits":"紫绿树燕主要栖息于山区针叶林，偏好在难以触及的地点筑巢，如枯木上的啄木鸟旧巢洞。它们主要分布在北美西部，从阿拉斯加中部到墨西哥高地，罕见于落基山脉以东。冬季则主要在墨西哥至中美洲南部过冬。紫绿树燕群体性很强，觅食、迁徙和远离巢穴时经常结成数百只的大群。","breeding":"紫绿树燕既可单独筑巢，也可形成多达25对的群体。繁殖期间，雌鸟通常在废弃的啄木鸟巢洞、悬崖裂缝或鸟箱中产下4到6枚卵。它们倾向于返回同一繁殖地点。像大多数燕子一样，紫绿树燕以飞行中的昆虫为食。","identification":"紫绿树燕与双色树燕外观相似，但上体更显绿色光泽，脸部白色几乎环绕眼睛，尾部较短且分叉不明显。两者在某些重叠范围内共存，但在筑巢习性上有所不同，双色树燕更愿意使用鸟箱且出现在东部更易接近的地点。","protection":"IUCN：LC（无危）","distribution":"紫绿树燕主要分布于北美西部，繁殖区从阿拉斯加中部和加拿大西部南至墨西哥高原，冬季迁徙至墨西哥南部至中美洲的危地马拉、萨尔瓦多和洪都拉斯。","other":"紫绿树燕的三个亚种分别为T. t. lepida、T. t. brachyptera和T. t. thalassina，后两者主要在墨西哥繁殖。"},{"name":"巴哈马树燕","english_name":"Bahama Swallow","scientific_name":"Tachycineta cyaneoviridis","overview":"巴哈马树燕（英文名：Bahama Swallow，学名：Tachycineta cyaneoviridis），是雀形目燕科树燕属的鸟类。主要分布在巴哈马群岛的松树林地带。其上身呈绿色至蓝绿色，翼部和尾部深蓝色，腹部白色。雌鸟较雄鸟颜色略淡，腹部白净程度不及雄鸟。该物种仅限于巴哈马群岛，属于当地特有种。","appearance":"巴哈马树燕具有中等体型，长约15厘米，尾部分叉明显且较长。成年鸟头部和背部金属绿色，翼部和尾羽呈现蓝绿色至深绿蓝色，腹部纯白。雌鸟颜色较为暗淡，尾部分叉不如雄鸟深。幼鸟颜色较暗，尾部分叉较浅，上胸侧部有棕色斑块。","call":"叫声包括轻微的‘chet’声或连续的‘chet-chet’声，以及细薄的‘tsi-tsip’声。歌唱声是一连串丰富、清澈的音符，悦耳动听。","habits":"巴哈马树燕偏好松树林地带，但也可见于城镇和田野上空。它们主要以飞行中的昆虫为食，利用开阔地带觅食。迁徙模式尚不完全清楚，但在非繁殖季节会出现在东部巴哈马群岛和特克斯及凯科斯群岛。","breeding":"繁殖期在巴哈马群岛的松林中，利用大红腹啄木鸟遗留的洞穴筑巢，巢材包括松针、桉树树枝和草，内部铺垫其他鸟类的羽毛。每窝产卵通常三枚，孵化期约15天，雏鸟离巢时间大约22天。","identification":"与双色树燕的区别在于，巴哈马树燕尾部分叉更深，翼下覆羽白色，而双色树燕尾部仅微凹，翼下覆羽灰暗。此外，两物种在头侧颜色和上体色调上有差异。","protection":"IUCN：EN（濒危）","distribution":"繁殖于巴哈马群岛北部的安德罗斯岛、大巴哈马岛、阿巴科岛和新普罗维登斯岛。冬季分布于东部巴哈马群岛和特克斯及凯科斯群岛。偶尔作为迷鸟出现在南佛罗里达、佛罗里达群岛和古巴，以及南美洲。","other":"巴哈马树燕受到伐木和开发计划的威胁，种群数量稀少，对其自然历史了解有限。"},{"name":"紫崖燕","english_name":"Purple Martin","scientific_name":"Progne subis","overview":"紫崖燕（英文名：Purple Martin，学名：Progne subis），是雀形目燕科崖燕属的鸟类。也是北美洲最大的燕子。以暗黑色为主，雄鸟具有蓝紫色金属光泽，在近距观察下可见。雌鸟和未成年个体则呈现灰褐色，腹部斑驳。紫崖燕主要在东部北美繁殖，依赖人类提供的巢箱居住，而在西部地区则利用天然树洞或仙人掌中的空洞筑巢。冬季迁徙至南美的亚马逊盆地。","appearance":"紫崖燕身长平均约20厘米，翼展可达38厘米，是北美洲最大的燕子。雄鸟全身呈深黑色，带有蓝紫色到海军蓝或深紫色的金属光泽，在某些光线下甚至会呈现出绿色。雌鸟和亚成鸟则颜色较淡，背部有金属光泽，下部偏浅色，腹部有斑点。亚成年雌鸟与成年雌鸟相似，但背部更棕色，缺乏金属光泽；亚成年雄鸟外观像雌鸟，但在换羽过程中，胸部随机出现黑色羽毛。","call":"紫崖燕非常善鸣，其声音包括清脆的啾啾声、咯咯声、咔哒声和呱呱声。它们的叫声被描述为喉音丰富，具体表现为'tchew-wew'、'pew pew'、'choo'、'cher'、'zweet'和'zwrack'。雄鸟的求偶歌喉音浓重，还有黎明歌曲和繁殖季节结束时的次级鸣叫。","habits":"紫崖燕栖息于开阔地带，从加拿大中部的阿尔伯塔省向南延伸至美国东部。它们在东部北美的开阔地带繁殖，西部海岸从不列颠哥伦比亚省到墨西哥也有分布。它们偏好在巢穴中筑巢，包括自然形成的洞穴或人造巢箱。在东部，紫崖燕几乎完全依赖人类提供的巢箱，形成群体，靠近人类居住。西部种群倾向于利用树木上的啄木鸟洞或仙人掌中的空洞。冬季，它们迁往南美的亚马逊盆地。","breeding":"紫崖燕一般每年只繁殖一次。每窝产4至6枚蛋，雌鸟每天产一枚蛋，直到倒数第二枚蛋产出后开始孵卵，整个孵化期大约持续15至16天。幼鸟在出生后26至32天离巢。离巢后的幼鸟仍能得到双亲长达一个月的照顾。","identification":"紫崖燕的雄鸟与其他燕子相比，是唯一拥有深色腹部的燕子。雌鸟与其它燕子的颜色模式类似，但体型较大，颈部有明显的棕色或灰色项圈。亚成年雄鸟与雌鸟颜色模式相似，但头部和下部有变化数量的深蓝色羽毛，项圈通常不如雌鸟明显。","protection":"IUCN：LC（无危）","distribution":"繁殖区遍布北美洲和中美洲，非繁殖区位于南美东部，主要在亚马逊盆地过冬。","other":"紫崖燕历史上曾经历严重的人口下降，这与欧洲椋鸟的引入和扩散有关。目前，东部种群几乎完全依赖于人类提供的巢箱，这种做法正在逐渐减少，因为提供巢箱的‘房东’多数年龄较大，年轻一代对此缺乏兴趣或资源。"},{"name":"古巴崖燕","english_name":"Cuban Martin","scientific_name":"Progne cryptoleuca","overview":"古巴崖燕（英文名：Cuban Martin，学名：Progne cryptoleuca），是雀形目燕科崖燕属的鸟类。与雌鸟和幼鸟的灰褐色胸部和白色下部形成鲜明对比。","appearance":"成年古巴崖燕长约18.5厘米，具叉状尾和宽阔的翅膀，体重约40克。雄鸟呈光泽蓝黑色，腹部下部为白色。雌鸟和幼鸟较暗淡，胸部和侧翼为灰褐色，腹部下部为白色。雄鸟与加勒比崖燕的区别在于前者腹部深色，而后者腹部有明显白色斑块。","call":"其鸣叫包括高音的“twick-twick”声和强烈的旋律颤音。","habits":"古巴崖燕群居，常在开阔地带，尤其是水边，如沼泽和城镇上空觅食。它们以甲虫、异翅目昆虫和蜻蜓为食，飞行时交替拍打和滑翔。","breeding":"繁殖季节为4月至8月，它们在松散的群体中筑巢，有时单独筑巢。巢由植物纤维构成，置于树洞、啄木鸟旧巢、岩石空腔或人造结构中，如管道或建筑物的空隙。每窝产卵3至5枚，孵化和离巢期未详细记录。","identification":"雄性古巴崖燕与加勒比崖燕的区分点在于腹部颜色；而雌鸟和幼鸟难以与同类物种区分，但古巴崖燕平均胸部棕色更局限。在3月至9月期间，加勒比和紫崖燕不在古巴崖燕范围内，有助于排除混淆。","protection":"IUCN：LC（无危）","distribution":"繁殖于古巴（含卡约罗曼岛）和青年岛，非繁殖期分布未知，可能在南美洲（库拉索岛有记录）。","other":"尽管被认为是古巴和青年岛的特有种，偶尔也有报道在佛罗里达州发现迷鸟。"},{"name":"加勒比崖燕","english_name":"Caribbean Martin","scientific_name":"Progne dominicensis","overview":"加勒比崖燕（英文名：Caribbean Martin，学名：Progne dominicensis），是雀形目燕科崖燕属的鸟类。以钢铁蓝色的身体、白色腹部和叉状尾巴为显著特征。在繁殖季节广泛出现，冬季则可能迁徙至南美洲东北海岸。","appearance":"成年雄性加勒比崖燕拥有光泽的钢铁蓝或紫蓝色上身，白色下腹部，以及适度分叉的尾巴。雌鸟和幼鸟外观相似，但前额呈烟灰色，喉部和胸部为灰色或灰棕色。翅膀和尾巴具有黑色底色，带蓝紫色光泽。","call":"叫声包括刺耳的“churr”声，嗡嗡的“zwick-zwick”声，以及音乐般的嗡嗡鸣叫。","habits":"常见于开阔地带近水区域，如沼泽和城镇，常成群活动，最多可达二十只，有时与其它燕子和马丁混群。它们在空中捕食昆虫。","breeding":"在洞穴、河岸或建筑物中筑巢，或利用旧啄木鸟的洞穴。每窝产3-6枚蛋，孵化期约15天，幼鸟需26-27天离巢。","identification":"雄性紫崖燕全身紫蓝色，缺乏白色腹部，易于区分。雌鸟和幼年的紫崖燕和加勒比崖燕相似，但紫崖燕胸部通常更淡，有鳞片状图案。","protection":"IUCN：LC（无危）","distribution":"繁殖于大安的列斯群岛和小安的列斯群岛（除古巴）。冬季分布于南美洲东北海岸。","other":"在多米尼加共和国被称为Golondrina Grande，在海地称为Irondel Nwa和Hirondelle a Ventre Blanc。"},{"name":"墨西哥崖燕","english_name":"Sinaloa Martin","scientific_name":"Progne sinaloae","overview":"墨西哥崖燕（英文名：Sinaloa Martin，学名：Progne sinaloae），是雀形目燕科崖燕属的鸟类。腹部白色，尾部微叉，翼下覆羽和腋羽灰褐色，雌鸟色彩较暗淡，喉部及上胸部灰棕色，腹部纯白，与深色胸部分界明显。分布于墨西哥西部Sierra Madre Occidental山区的松林和橡树林中。","appearance":"体型较大，尾部略呈叉状，雄鸟整体呈蓝黑色光泽，下腹部至尾下覆羽纯白，翼下覆羽和腋羽灰褐色；雌鸟上体颜色较暗，喉部至侧胸灰棕色，腹部纯白，与深色胸部分界鲜明。幼鸟似成年雌鸟，但上体有蓝色羽毛，胸羽也有蓝色羽毛。","habits":"偏好开放的松林和橡树林，通常在大树枯木和悬崖附近筑巢。活动范围广泛，高海拔和山脚地带常见，常单个或小群出现，与其它燕子混群。在池塘和湖泊边饮水。","breeding":"繁殖习性资料稀少，一般在三月至八月间于繁殖地的小群体中被观察到，筑巢于树洞中。具体繁殖细节未知。","identification":"与加勒比崖燕非常相似，但雄鸟腹部更宽，雌鸟喉部和上胸部颜色更深，腹部与胸部对比更强烈。两者在繁殖季节分布不重叠。","protection":"IUCN：VU（易危）","distribution":"繁殖于墨西哥西部Sierra Madre Occidental山区，从东北索诺拉向南至哈利斯科和米却肯州。冬季分布未知，可能在南美洲内陆。"},{"name":"灰胸崖燕","english_name":"Grey-breasted Martin","scientific_name":"Progne chalybea","overview":"灰胸崖燕（英文名：Grey-breasted Martin，学名：Progne chalybea），是雀形目燕科崖燕属的鸟类。大型热带低地燕子。广泛分布于中美洲至南美洲，北起墨西哥南部，南至阿根廷中部，是新热带区分布最广的Progne属物种之一。其上体呈暗蓝钢色，喉部和胸部为暗灰色，腹部白色，雌雄相似，与北美紫崖燕的雌鸟极为相像。","appearance":"成年灰胸崖燕体型较大，总长度约16-18厘米，具有深叉尾和宽阔的翅膀。成年雄鸟上体光泽蓝黑色，喉部、胸部和两侧为灰棕色，与白色的下腹部形成鲜明对比。雌鸟比雄鸟颜色稍淡，喉部较浅。幼鸟上体呈暗褐色，下体前部灰暗，逐渐过渡到纯白。","call":"灰胸崖燕的叫声为类似‘chew-chew’的咕噜声，与近缘种加勒比燕的叫声相似。","habits":"灰胸崖燕适应性强，常见于城镇、村庄、开阔和半开阔地带，有高树和其他提供巢穴的结构。它们在各种半开放生境中筑巢，包括自然洞穴和人类提供的巢穴，如建筑物檐下或排水管。完全以昆虫为食，飞行中捕食。","breeding":"繁殖期，灰胸崖燕会在洞穴中筑巢，通常选择河岸、建筑或旧啄木鸟洞。每次产卵2-4枚，孵化期约为15-16天，幼鸟在巢中约22天后离巢。","identification":"与南美崖燕、秘鲁崖燕区别在于灰胸崖燕胸部偏灰，腹部纯白。与紫崖燕雌鸟的区别在于其额头和颈侧的灰色围脖较暗，下体颜色更深。","protection":"IUCN：LC（无危）","distribution":"繁殖于中美洲至南美洲，北起墨西哥北部，南至阿根廷中部，广泛分布于整个区域。部分群体在东部墨西哥繁殖后迁徙，而最南部的群体，从巴拉圭和巴西中部至阿根廷，也会在繁殖后向北迁徙。","other":"灰胸崖燕有三种亚种，其中一种在西部墨西哥定居，另两种分布更广，覆盖了从东部墨西哥至南美洲中部。"},{"name":"加岛崖燕","english_name":"Galapagos Martin","scientific_name":"Progne modesta","overview":"加岛崖燕（英文名：Galapagos Martin，学名：Progne modesta），是雀形目燕科崖燕属的鸟类。其深蓝黑色的羽毛使其在外表上与紫崖燕极为相似，但体型较小。雌鸟和幼鸟呈现褐色调，背部带有蓝紫色光泽。数量稀少，全球估计不足1000只。","appearance":"雄性加岛崖燕全身深蓝黑色，而雌鸟和幼鸟主要为褐色，背部有蓝紫色调。飞行时可见三角形翼尖和凹叉状尾巴。雄鸟翼长平均124.9毫米，尾长63.2毫米；雌鸟翼长平均120.5毫米，尾长59.0毫米。喙、虹膜和脚趾颜色分别为黑色、棕色和棕黑色。","habits":"生活在加拉帕戈斯群岛的干燥灌木丛、季节性湿润的草地、牧场及严重退化的森林边缘地带。通常以昆虫为食，成对或小群体活动。","identification":"与紫崖燕非常相似，主要通过体型大小区分。雌鸟和幼年紫崖燕的腹部较淡，颈部有浅色颈环，这是与加岛崖燕的主要区别。","protection":"IUCN：EN（濒危）","distribution":"南美洲厄瓜多尔的加拉帕戈斯群岛。"},{"name":"秘鲁崖燕","english_name":"Peruvian Martin","scientific_name":"Progne murphyi","overview":"秘鲁崖燕（英文名：Peruvian Martin，学名：Progne murphyi），是雀形目燕科崖燕属的鸟类。主要分布在秘鲁西部及智利北部。雄鸟羽毛呈亮蓝色，而雌鸟则以灰褐色为主，背部中央至翅膀带有蓝黑色。这种燕子数量不多，其生存状态被评估为脆弱。","appearance":"秘鲁崖燕体型较小，性二色性明显。雄鸟全身蓝黑发亮，雌鸟则全身灰暗，背部和翅膀部分呈现蓝黑色。尾部浅叉，上体羽毛在阳光下可见轻微蓝光反射。雌性秘鲁崖燕的臀部和头部为烟灰色，与蓝黑色的背部和翅膀形成对比。成年雄鸟的全长约16.5至17厘米，体重平均33.8克；雌鸟体重略重，平均36.5克。","habits":"秘鲁崖燕偏好低地沙漠和沿海地带，通常单独或小群出现，远离其他燕子种类。它们常在较高空飞翔，飞行时既能轻松滑翔也能有力俯冲。有时会停歇在农业山谷上方的沙漠斜坡上。主要以昆虫为食。","identification":"雄性秘鲁崖燕与紫崖燕相似，但紫崖燕体型更大，尾巴分叉更深。雌性秘鲁崖燕与灰胸崖燕和褐胸燕的区别在于前者腹部颜色统一为烟灰色，而后者腹部带白色或淡色。此外，雌性秘鲁崖燕的臀部和头部也是烟灰色，与背部和翅膀的蓝色形成鲜明对比。","protection":"IUCN：NT（近危）","distribution":"秘鲁西部和智利北部，主要栖息于低地沙漠和沿海地区。"},{"name":"南美崖燕","english_name":"Southern Martin","scientific_name":"Progne elegans","overview":"南美崖燕（英文名：Southern Martin，学名：Progne elegans），是雀形目燕科崖燕属的鸟类。在南美洲发现的燕科崖燕属鸟类。体长约17厘米，其深紫色光泽的羽毛使其在外形上与同属的紫崖燕极其相似，但南美崖燕的体型略大，尾部分叉更深。分布于阿根廷和玻利维亚南部，冬季会迁徙至亚马逊盆地西部。","appearance":"雄性南美崖燕全身呈现深邃的钢蓝色光泽，翅膀和尾巴更显黑色，尾部分叉明显。与极其相似的紫崖燕相比，其尾巴稍长且分叉更深（野外难以区分）。雌鸟具有较为暗淡的上体，下体呈灰褐色，羽毛边缘泛白，形成鳞片状外观，下尾羽覆有白色，带有暗色羽轴。幼鸟外形类似成年雌鸟。","call":"其鸣唱为短暂的咕噜声，同时还会发出尖锐的接触叫声和警报声。","habits":"南美崖燕栖息于多种生境，包括热带湿润低地森林、热带湿润山地森林、热带干燥低地草原、高海拔草地以及城市区域。它们在特定季节与其它类似的马丁种群共存，这使得识别变得困难。","identification":"雄性南美崖燕与紫崖燕几乎无法区分，而雌鸟可通过其腹部的鳞片状斑纹与紫崖燕和灰胸崖燕相区别。与紫崖燕相比，南美崖燕的尾巴更长且分叉更深。","distribution":"南美崖燕主要分布于南美洲，具体包括玻利维亚南部（自科恰班巴省南部和圣克鲁斯西部）和阿根廷大部分地区（一般南至圣克鲁斯）。冬季迁徙至亚马逊西部盆地，可能最北可达苏里南。"},{"name":"棕胸崖燕","english_name":"Brown-chested Martin","scientific_name":"Progne tapera","overview":"棕胸崖燕（英文名：Brown-chested Martin，学名：Progne tapera），是雀形目燕科崖燕属的鸟类。与Bank Swallow相似但体型更大、更修长。广泛分布于南美洲，包括巴拿马在内的低地开阔地带，常在水边活动。","appearance":"成年棕胸崖燕长约16厘米，体重介于30至40克之间。头部和背部呈沙褐色，翅膀与尾巴颜色较深，尾部略呈叉状；下巴、喉咙和腹部为白色，胸部带有不甚明显的棕色横带；尾羽下方覆羽长且白。幼鸟的喉咙侧面偏灰褐色，尾部形状更方。两性外观相似。","call":"发出一系列粗哑、咕噜声的歌声；接触叫声为‘chu-chu-chip’。","habits":"栖息于树木环绕的开阔地带或半开阔地带，靠近水源或人类居住区，包括城镇。活动范围包括草地、林间空地、河流和农田。最高可达海拔约1600米，迁徙中的fusca亚种可达到4000米。以飞虫、甲虫、蜜蜂、蚂蚁、白蚁、蝽象、蜻蜓、蝴蝶和蛾类为食。","breeding":"繁殖期在委内瑞拉为4月至6月，在哥伦比亚为3月至5月；在南方则为11月至3月。筑巢于白蚁巢、土壁、树洞、桥下或建筑物内，偶尔使用棕灶鸟的旧巢。每窝产3至5枚蛋，通常为4枚，由雌鸟孵卵，孵化期14至15天。幼鸟约28天后离巢，之后数日仍留在巢附近。","identification":"与崖沙燕相比，棕胸崖燕体型明显更大，尾部形状和颜色分布有细微差异。","protection":"IUCN：LC（无危）；一般常见，但在厄瓜多尔较为少见。","distribution":"广泛分布于南美洲，包括阿根廷、玻利维亚、巴西、智利、哥伦比亚、哥斯达黎加、厄瓜多尔、法属圭亚那、圭亚那、巴拿马、巴拉圭、秘鲁、波多黎各、苏里南、美国、乌拉圭、委内瑞拉，并且是智利和福克兰群岛的迷鸟。","other":"在繁殖季节结束后，会形成由数百乃至数千只鸟组成的大型群落，有时与其它燕子混群。"},{"name":"蓝白南美燕","english_name":"Blue-and-white Swallow","scientific_name":"Pygochelidon cyanoleuca","overview":"蓝白南美燕（英文名：Blue-and-white Swallow，学名：Pygochelidon cyanoleuca），是雀形目燕科 Pygochelidon 属的鸟类。广泛分布在中美洲至南美洲的燕科鸟类。其背部呈钢蓝色或紫蓝色，腹部洁白，最显著的特点是黑色的尾下覆羽与白色腹部形成鲜明对比。体型较小，尾部略呈叉状，翅膀较短。在繁殖区域内常驻，南部种群具有迁徙习性。","appearance":"蓝白南美燕成鸟上身呈光泽的钢蓝至紫蓝色，翅膀和尾部为黑色边缘带钢蓝，腹部白色，侧面和两翼下方带有灰色调。尾部短而微叉，翅膀比迁徙燕子更短更宽。雄雌外观相似，但雌鸟白色较为暗淡，带浅黄色色调。幼鸟上半身为灰棕色，有蓝光泽，下半身偏白色，带浅黄色调，尾巴不如成鸟叉开明显。","call":"发出嗡嗡的dzzzhreeee叫声。","habits":"生活在开放地带，包括乡村、城镇、农场和森林空地。在中美洲为高地鸟类，在其它区域可从低地至海拔4,000米。以小群体出现，主要食物为飞行中的昆虫，常见于白蚁群飞时聚集。飞行时姿态起伏不定，常停歇在电线或树枝上。","breeding":"巢穴由双亲共同建造，位于树洞、岩缝或桥梁等自然或人造洞穴中。南方种群每窝产卵可达六枚，北方为二至三枚，由双亲孵化约15天。雏鸟由双亲喂养26天至离巢，但会返回巢中与父母共眠长达两个月。一年可能育有两窝。","identification":"与红树燕、双色树燕和紫绿树燕相似，但其黑色尾下覆羽是区别标志。此外，与淡脚南美燕也有相似之处，后者喉部呈粉棕色，侧面颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，包括哥斯达黎加、巴拿马以及南美洲广泛区域。","other":"适应性强，受益于热带地区的人类扩张，栖息地和食物资源增加。"},{"name":"黑领燕","english_name":"Black-collared Swallow","scientific_name":"Pygochelidon melanoleuca","overview":"黑领燕（英文名：Black-collared Swallow，学名：Pygochelidon melanoleuca），是雀形目燕科 Pygochelidon 属的鸟类。这种小型燕子以它独特的黑白相间羽毛和深叉尾著称，常见于布满巨石的河流旁，尤其偏爱急流和瀑布附近。其分布范围主要在南美洲，包括哥伦比亚东部至委内瑞拉中部，圭亚那和巴西北部，以及亚马孙雨林东南部和阿根廷东北部。","appearance":"成年黑领燕体长约14厘米，体重介于10至12克之间。它们拥有光泽的蓝黑色头部和上身，黑色的翅膀和尾巴，腹部白色，胸前有一条蓝黑色的颈环，尾羽下覆羽也是蓝黑色，翼下覆羽呈黑褐色。雌雄外观相似，幼鸟比成鸟颜色更暗淡，下体脏白色，尾羽较短。","habits":"黑领燕栖息在河流环境中，偏好位于急流和瀑布附近的岩石地带，活动高度通常不超过树梢。它们单独或小群体活动，快速低飞于水面之上，或在河面和森林上方缓慢盘旋，偶尔滑翔时翅膀会保持低于水平线。黑领燕的食谱包括苍蝇、甲虫、蚂蚁、寄生黄蜂和同翅目昆虫，它们会在急流中单独或小群觅食。","identification":"黑领燕的识别特征在于其独特的羽毛图案和深叉尾，使其在燕科鸟类中易于辨认。它们常与更为广泛分布的白斑燕一同出现。","protection":"IUCN：LC（无危）。尽管全球范围内并不受威胁，但在某些地区如巴西的米纳斯吉拉斯州，黑领燕被认为是极危物种。","distribution":"黑领燕分布于南美洲的特定区域，包括哥伦比亚东部（维查达省、瓜伊尼亚省、瓦佩斯省）、委内瑞拉西南部、中部和东南部（亚马逊省、玻利瓦尔省）、圭亚那、巴西亚马逊雨林地区（主要是内格罗河上游区域，阿帕马州，以及亚马逊河以南的马德拉河、塔帕若斯河、欣古河和托坎廷斯河流域，以及巴西东南部巴伊亚州、米纳斯吉拉斯州中部和北部的孤立记录）、以及巴拉圭东北部（马德雷德迪奥斯河）、阿根廷东北部（伊瓜苏瀑布边境）和阿根廷东北部（米西奥内斯省）。"},{"name":"褐腹南美燕","english_name":"Brown-bellied Swallow","scientific_name":"Orochelidon murina","overview":"褐腹南美燕（英文名：Brown-bellied Swallow，学名：Orochelidon murina），是雀形目燕科 Orochelidon 属的鸟类。分布于委内瑞拉至玻利维亚安第斯高地的燕科鸟类。拥有深虹彩蓝色的头部和背部，灰褐色的喉部与腹部，以及相对较长且深分叉的尾羽。","appearance":"指名亚种的雄鸟具有黑色与蓝绿色的光泽冠，上半身呈现深色光泽；翅膀和尾巴为深棕色，尾巴适中分叉；下半身为烟灰棕色，尾羽黑色；翼下覆羽灰棕色。与蓝白南美燕相比，褐腹南美燕在大小和整体黑暗外观上有所不同，与安第斯燕相比，它的腹部颜色更深，尾羽分叉更大。雌鸟颜色较为暗淡，幼鸟比成鸟更暗淡，有棕色的喉咙，灰白色的下体，尾巴较短。亚种meridensis的上半身比指名亚种更蓝，雄鸟尾羽呈金属深蓝色，雌鸟为棕色；亚种cyanodorsalis的上半身有钢蓝色光泽，尾羽为黑色。","habits":"褐腹南美燕成群出现于森林和空地，特别是在悬崖和滑坡的筑巢地点周围。它们的活动范围在海拔2500-4000米之间，分布海拔通常高于蓝白南美燕，但存在不少重叠。","identification":"与蓝白南美燕和安第斯燕相比，褐腹南美燕在体型、色彩和尾羽形状上有明显区别。具体辨识要点在于其更深的腹部颜色和更为显著的尾羽分叉。","protection":"IUCN状态未提供。","distribution":"南美洲：从委内瑞拉西部至玻利维亚中部。主要分布于安第斯高地，位于2500-4000米的海拔范围内。"},{"name":"淡脚南美燕","english_name":"Pale-footed Swallow","scientific_name":"Orochelidon flavipes","overview":"淡脚南美燕（英文名：Pale-footed Swallow，学名：Orochelidon flavipes），是雀形目燕科 Orochelidon 属的鸟类。从委内瑞拉到玻利维亚均有分布。具有独特的肉桂粉色喉部和较暗的侧腹，与更常见的蓝白南美燕形成鲜明对比。通常以小群出现，靠近森林地带，而非人类居住区附近。","appearance":"这种小型燕子上身呈深蓝色光泽，下身白色，拥有肉桂粉色喉咙，黑色侧腹和深蓝色下尾覆羽。其尾巴略凹，喙黑色，嘴内粉红色，虹膜深棕色，脚趾和跗跖为淡粉色。成鸟和幼鸟相似，但幼鸟的下尾覆羽边缘有淡色或白色。整体长度约11.4-12厘米，平均重量约为10.6克。","call":"其鸣叫常被描述为‘dzreet’声，与蓝白南美燕的叫声相比更为干燥，还有一种颤音‘trilled tre-e-e-ed’，其歌声是一系列颤音和细弱的鸣叫声，听起来既嘈杂又悦耳。","habits":"栖息于亚热带或热带湿润山地森林，海拔高度从2400米至3000米，有时因恶劣天气会降至更低海拔。它们是空中捕食昆虫的专家，飞行迅速、低且不规则，经常回溯路线。通常成群活动，由10-15只组成，有时可达50只。","breeding":"繁殖季节可能在7月至9月，雄鸟此时处于繁殖状态。它们可能在苔藓洞穴或道路中形成的洞穴中筑巢，偏好在亚热带和热带山地森林中，避免开阔地。关于孵化和育雏的细节尚不清楚。","identification":"与蓝白南美燕区别在于较小的体型、黑色侧腹和更快更直接的飞行方式。此外，它们的叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲，从委内瑞拉西部至玻利维亚中部，主要在安第斯山脉东部坡面，偶尔在中央安第斯山脉两侧均有记录。海拔分布从2000米至3500米不等。"},{"name":"安第斯燕","english_name":"Andean Swallow","scientific_name":"Orochelidon andecola","overview":"安第斯燕（英文名：Andean Swallow，学名：Orochelidon andecola），是雀形目燕科 Orochelidon 属的鸟类。中等体型的燕科鸟类，主要分布在南美洲的安第斯山脉高海拔区域，自秘鲁中部至阿根廷西北部。这种燕子以深蓝色光泽的背部和灰褐色臀部及下体为显著特征，常被发现于开阔地带，如岩石斜坡、普纳草原和沼泽地，偶尔也会在村落周边活动。","appearance":"安第斯燕是一种中型燕，成鸟的上体呈蓝黑色或绿黑色，臀部和尾羽覆羽带棕色，脸部侧边、喉部和胸部为灰褐色，腹部至尾下覆羽逐渐转为较淡的灰白色。翼下覆羽和腹侧同样为灰褐色。幼鸟的羽毛较为暗淡，尾羽覆羽呈锈褐色，翼下覆羽有苍白的锈色晕染。总长度约13.5厘米，翼展平均115.7毫米，尾长平均56毫米，喙长平均9.4毫米，跗跖长平均11.3毫米，体重平均17克。","habits":"安第斯燕偏好在高海拔的开放地带活动，如岩石斜坡、普纳草原和沼泽地。它们通常以成对或小群体飞行，飞行速度快而低。它们的觅食范围覆盖水域上方，或围绕着群居的哺乳动物。由于其独特的栖息地选择，安第斯燕的活动范围高于大多数燕类。","identification":"与安第斯燕可能在同一生境中出现的有蓝白南美燕和褐腹南美燕。蓝白南美燕喉部、胸部和腹部纯白，背部更蓝，臀部与背部颜色相同。褐腹南美燕全身下方均匀暗色，尾部分叉更深，臀部颜色更深。安第斯燕幼鸟的臀部锈色，与美洲燕的幼鸟区别明显。","protection":"IUCN：LC（无危）","distribution":"安第斯燕主要分布在南美洲的安第斯山脉高海拔区域，包括秘鲁中部到阿根廷西北部，以及智利北部和玻利维亚的部分地区。"},{"name":"黑顶南美燕","english_name":"Black-capped Swallow","scientific_name":"Atticora pileata","overview":"黑顶南美燕（英文名：Black-capped Swallow，学名：Atticora pileata），是雀形目燕科白斑燕属的鸟类。分布于中美洲的高山区，自墨西哥南部至萨尔瓦多西部，常见于城镇周边、松栎林和开阔地带。其最显著特征为小而深色的身体与明显的厚叉尾。","appearance":"黑顶南美燕体型较小，上半身呈暗褐色或黑色，略带蓝色光泽，下半身为纯白色。头部顶部略暗，形成不显眼的帽状，但与背部颜色相近，不易分辨。成鸟喉部与上胸部有棕色斑点，腹部洁白，两翼下方灰褐，臀部及尾下覆羽为深黑色。雌雄相似，幼鸟色泽较淡，喉部和胸部可能带有浅肉桂色，上半身有淡肉桂色斑纹。","habits":"栖息于海拔较高的松栎森林和开阔地区，飞行迅速，有时停歇于电线上。以昆虫为食，活动范围广泛，包括城镇、乡村和森林。黑顶南美燕似乎全年居住在繁殖区域内，具有较强的适应性。","breeding":"筑巢于洞穴中，包括河岸、岩石裂缝、建筑缝隙，尤其是旧石造建筑的裂缝。繁殖季节为3月至6月，具体繁殖行为尚不明确。","identification":"与其他燕子区别明显，尤其是其快速飞行和深叉尾。与双色树燕、紫绿树燕和中北美毛翅燕相比，黑顶南美燕尾部更深叉，无白色臀部，上半身无明显蓝色或绿色光泽。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥南部至萨尔瓦多西部，主要在高海拔的松栎森林地区。"},{"name":"白斑燕","english_name":"White-banded Swallow","scientific_name":"Atticora fasciata","overview":"白斑燕（英文名：White-banded Swallow，学名：Atticora fasciata），是雀形目燕科白斑燕属的鸟类。独特的中等体型燕子，以其闪亮的蓝黑色羽毛、明显的白色胸带和深叉状尾巴著称。常见于南美洲亚马逊河流域的热带低地森林近水区域。","appearance":"白斑燕具有蓝黑色光泽的羽毛，胸部有一条醒目的白色带，翅膀边缘有细微的白色条纹，大腿也是白色，但在野外不易察觉。其尾部深叉，两性相似，但雌鸟平均体重略重。幼鸟颜色较暗淡，偏棕色，羽毛较短且颜色较浅。成年鸟平均长度约为15厘米，翼展92至108毫米，体重介于12至16克之间。","call":"鸣叫声被描述为‘ti-ti-tur’，同时也会发出类似‘z-z-z-z-ee-eep’的嗡嗡声，通常在飞行中发出。","habits":"常出现在河流附近的热带低地森林，偏好黑水河与白水河区域。它们一般不会飞到海拔800米以上，但在哥伦比亚可高达1400米。以昆虫为食，通常单独或小群体飞行，采取快速的Z字形或环形路径觅食。","breeding":"在洞穴中筑巢，可能自行挖掘或利用废弃的巢穴，巢由干草构成。每窝产4至5枚白色卵，尺寸约为18.5 x 12.8毫米。通常独自或在小型群体中繁殖。","identification":"与黑领燕有重叠分布，但后者下体为白色，胸前有一条深色带，与白斑燕的白色胸带形成鲜明对比。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊流域，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。"},{"name":"白腿燕","english_name":"White-thighed Swallow","scientific_name":"Atticora tibialis","overview":"白腿燕（英文名：White-thighed Swallow，学名：Atticora tibialis），是雀形目燕科白斑燕属的鸟类。但在野外观察较为困难。分布于中美洲和南美洲，自巴拿马至厄瓜多尔西部，及亚马逊雨林西部地区。","appearance":"白腿燕体型小，约重10克，全身呈深褐色。两性相似，幼鸟与成鸟区别仅在于腹部边缘的淡色羽毛。尾巴略呈叉状，背部颜色稍浅，而腿部的白色羽毛簇在停歇时可见，但飞行中难以察觉。三个亚种中，minima体型最小，griseiventris则有较灰的下部羽毛。","call":"白腿燕在觅食时通常发出\"zeet-zeet\"的叫声。","habits":"白腿燕偏好低地和山麓地带，常在森林边缘、水域附近以及农场和道路周围活动。它们以空中捕食昆虫为主，常见于成对或小群活动。虽然能在人类活动区域附近觅食和筑巢，但不会在人造结构中筑巢。","breeding":"白腿燕在树洞或河岸废弃的洞穴中筑巢，巢由干草垫成。关于繁殖期、求偶、交配等细节尚不清楚。","identification":"白腿燕是其分布范围内唯一的小型全暗色森林燕子。与之相似的红翎毛翅燕体型更大且颜色更浅，而褐腹南美燕上体有蓝紫色光泽，臀部无亮色，且通常仅出现在海拔2500米以上。","protection":"IUCN：LC（无危）。白腿燕因分布范围广泛，虽具体数量和趋势不明，但仍被视为低优先级保护对象。","distribution":"中美洲至南美洲，从巴拿马到厄瓜多尔西部，亚马逊雨林西部。具体而言，minima亚种分布在巴拿马、哥伦比亚和厄瓜多尔西部；tibialis亚种在巴西东南部；griseiventris亚种在哥伦比亚南部、委内瑞拉东南部、厄瓜多尔东部、秘鲁东部和巴西西部。","other":"由于广泛的分布，白腿燕被认为是低优先级保护物种。"},{"name":"中北美毛翅燕","english_name":"Northern Rough-winged Swallow","scientific_name":"Stelgidopteryx serripennis","overview":"中北美毛翅燕（英文名：Northern Rough-winged Swallow，学名：Stelgidopteryx serripennis），是雀形目燕科毛翅燕属的小型鸟类。其最显著的外部特征是背部呈棕色，喉咙和胸部有淡褐色斑纹，腹部逐渐变为白色。该鸟分布于北美洲大部分地区，南至加拿大南部，北至美国中部，中北美洲以及墨西哥。在繁殖季节倾向于单独或小群栖息在洞穴或裂缝中，包括人类建筑中的结构。","appearance":"中北美毛翅燕体型较小，长度约12.5-14.5厘米，重量在10.3-18.3克之间。成鸟上部灰褐色，下部灰白至乳白色，喉咙颜色较浅，有时带有微弱的肉桂色或红褐色。尾巴形状方正。雄鸟的外侧初级飞羽边缘硬化，无终端小羽片，且形成微小钩状突起。雌鸟外侧初级飞羽的边缘硬化，延长为明确的裸露尖端，但并不弯曲。幼鸟与成鸟相似，但具有红褐色翼条。","call":"发出短促、刺耳的‘zeep’声，也被描述为粗糙、低沉的‘bzzt’声，常双倍重复。叫声与银行燕类似。","habits":"偏好开阔地带，常在近水区域活动，以空中捕食为主，飞行技巧高超，可在低空飞行，尤其擅长在田野和狭窄沟壑上空飞行。主要食物为飞行中的昆虫，偶尔从水面捕食漂浮的昆虫。繁殖期间，它们选择在河岸、桥梁下的洞穴或裂缝中筑巢，而非集体繁殖。","breeding":"繁殖季节一般从五月持续到七月中旬，但随地区而异。巢穴通常利用其他物种挖掘的洞穴，长度20-200厘米，高度0.2-30米。巢由雌鸟收集纤维材料如草、树叶、根须、树枝、树皮和松针构建，再铺上草垫。每次繁殖产下4-8枚光泽洁白的卵，平均尺寸约为20×14毫米，孵化期为16-18天，主要由雌鸟负责。","identification":"与银行燕相比，中北美毛翅燕喉部和胸部的颜色较暗淡。与红翎毛翅燕相似，但后者臀部颜色更鲜明，两者分布区域略有重叠。","protection":"IUCN：LC（无危）","distribution":"分布于北美洲大部分地区，南至加拿大南部，北至美国中部，中北美洲以及墨西哥。冬季迁徙至美国墨西哥湾沿岸和中美洲。","other":"适应人类环境良好，有时会在人造结构中筑巢。"},{"name":"红翎毛翅燕","english_name":"Southern Rough-winged Swallow","scientific_name":"Stelgidopteryx ruficollis","overview":"红翎毛翅燕（英文名：Southern Rough-winged Swallow，学名：Stelgidopteryx ruficollis），是雀形目燕科毛翅燕属的鸟类。小型燕科鸟类，由法国鸟类学家Louis Vieillot于1817年首次正式描述。以暗褐色为主色调，拥有黑色翅膀和尾巴，灰白色臀部，喉咙和上胸部呈红棕色，下腹部黄色，尾部略带叉形。该物种在中美洲和南美洲广泛分布，从哥斯达黎加到阿根廷北部和乌拉圭，也见于特立尼达岛。","appearance":"成鸟长约13.5厘米，体重约15克。全身大部分呈暗灰色至褐色，头部颜色比背部稍深，臀部较淡，翅膀和尾巴为黑褐色，具有独特的弯曲状外侧初级飞羽，尾部末端平直。喉部和上胸部为肉桂色，下腹部黄白色，下覆羽白色，翼下覆羽暗灰褐色。雌雄相似，但雌鸟外侧初级飞羽缺少弯曲状结构。幼鸟的喉部颜色较为暗淡，背部羽毛边缘有浅色条纹。","call":"发出类似‘suree’的上滑音调叫声，巢穴附近会听到含糊的啾啾声或嗡嗡声，叫声比北方同类更低沉、柔和。","habits":"栖息于开阔地带，尤其靠近水域，如田野、河流和湖泊旁，也会出现在森林空地和河流边。通常生活在海拔1000米以下，局部地区可达2000米，记录最高可达3600米。在哥斯达黎加，一般比其北方近亲栖息地海拔低。主要以飞虫为食，如双翅目昆虫、鞘翅目昆虫、异翅目昆虫和飞行蚂蚁等，单独或小群体觅食，飞行直接，翼拍缓慢而有节奏。","breeding":"繁殖季节在中美洲和特立尼达为3月至6月，在哥伦比亚为2月至7月。单胎繁殖。独居或形成小而松散的群体，对入侵者表现出攻击性。巢由干草、叶子和羽毛构成，建于河岸、采石场或道路切割处的洞穴或旧巢穴中，有时利用其他物种如鵙科鸟类挖掘的洞穴。一窝产卵4-6枚，中央美洲产卵数为4-6枚，特立尼达为3-6枚，南方地区为3-5枚。孵化由雌鸟承担，持续15-18天；幼鸟由两性喂养，离巢时间为18-21天；离巢后幼鸟仍留在巢址附近，继续被喂养数日，至少25天。","identification":"与中北美毛翅燕相比，红翎毛翅燕颜色更加均匀，尤其是臀部颜色更为明显，喉部颜色更亮。可通过飞行时的明亮臀部和肉桂色喉咙进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，从哥斯达黎加至南美东南部，包括特立尼达岛。","other":"南部种群S. r. ruficollis为迁徙性，冬季向北移动，而北部种群S. r. aequalis则为留鸟。"},{"name":"棕头燕","english_name":"Tawny-headed Swallow","scientific_name":"Alopochelidon fucata","overview":"棕头燕（英文名：Tawny-headed Swallow，学名：Alopochelidon fucata），是雀形目燕科棕头燕属的鸟类。头部呈独特棕红色，常见于南美洲开阔地带，尤其是接近水源的草地和稀树草原。分布范围从委内瑞拉南部至玻利维亚中部、巴西南部直至阿根廷北部。","appearance":"棕头燕体长约12厘米，体重约13-15克。成鸟头部具深红棕色额、眉纹和颈背，与灰褐色的冠部形成对比。耳羽、头侧、喉部及胸部为肉桂色，其余上体为灰色，臀部略淡，与深棕色近方形尾部和翅膀形成鲜明对比。下体为淡白色，两胁为淡灰褐色。幼鸟头部色泽较淡，呈黄色调。","call":"棕头燕发出柔和的颤音叫声，描述为treeeeb。","habits":"栖息于开放和半开放的热带及亚热带环境，尤其偏好靠近小水体、河流附近的林间空地和湿地。活动范围通常限于海拔1600米以下。以昆虫为食，如甲虫、蝇类和膜翅目昆虫，常在地面附近飞行觅食，有时成对或小群活动。","breeding":"繁殖季节因地域而异，北部种群可能在5月至6月，南部种群则从9月至11月。巢杯状，由叶、羽毛和草构成，通常位于河岸、溪流或沟渠的隐蔽洞穴中。每窝产4-5枚白色卵，尺寸约为17-19毫米×12-13.9毫米，平均重量1.5克。","identification":"与红翎毛翅燕相比，棕头燕体型较小，头部颜色更暗，且臀部颜色差异不大。红翎毛翅燕的臀部颜色较背部和尾巴明显浅色。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲，包括玻利维亚至巴西中南部和南部，延伸至阿根廷北部。繁殖区域包括东南委内瑞拉、中央和南部巴西、东部玻利维亚、除西北部以外的巴拉圭全境，以及东北阿根廷。在乌拉圭和阿根廷中部部分区域作为繁殖季居民。"},{"name":"家燕","english_name":"Barn Swallow","scientific_name":"Hirundo rustica","overview":"家燕（英文名：Barn Swallow，学名：Hirundo rustica），是雀形目燕科燕属的鸟类。俗名: 观音燕、燕子、拙燕，全球分布最广泛、数量最多的燕科鸟类之一，拥有最大的自然分布范围，遍及六大洲，甚至南极洲亦有记录。其特征为蓝背、深叉尾，上体钢蓝色，下体从橙红到淡黄色，胸带明显。在北半球繁殖，南半球越冬，与人类关系密切，常在人造结构如谷仓、桥梁下筑巢，利用人类建筑的优势扩大其生存范围。","appearance":"体型中等（17-19厘米），具显著的长叉尾。雄鸟上体钢蓝色，胸偏红，具蓝色胸带，腹部白色至淡黄色。雌鸟相似，但光泽略逊，尾流稍短。幼鸟色泽较暗，腹部偏白，尾流更短。","call":"鸣叫包括\"witt\"或\"witt-witt\"声，兴奋时发出响亮的\"splee-plink\"声。报警时，对猫等地面威胁发出尖锐的\"siflitt\"声，对猛禽发出\"flitt-flitt\"声。","habits":"偏好开阔地带，如牧场、草地和农田，接近水源。夏季迁徙至北半球繁殖，冬季南迁至南半球越冬。群居，尤其在大型木质结构中，每年在同一地点筑巢。食性为昆虫，善于空中捕食。","breeding":"繁殖期为4-7月，一年繁殖两窝。雌雄共同筑巢，巢由泥、草、毛发构成，坚固耐用，通常位于人类居住结构中。每窝产卵2-7枚，双亲共同孵化和育雏。","identification":"与洋斑燕相比，腹部更为纯净的白色，尾形长，具蓝色胸带。与金腰燕区别在于腰色不同，后者下体有黑色纵纹，上胸和喉无栗色。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆和北美洲，越冬于南美洲、非洲南部、中东、印度、东南亚等地。","other":"家燕的迁徙能力惊人，曾有从英国到南非的记录。"},{"name":"赤胸燕","english_name":"Red-chested Swallow","scientific_name":"Hirundo lucida","overview":"赤胸燕（英文名：Red-chested Swallow，学名：Hirundo lucida），是雀形目燕科燕属的鸟类。小型、非迁徙性，广泛分布于西非、刚果盆地及埃塞俄比亚等地。其特征为拥有光泽蓝黑色上体、白色下体以及醒目的砖红色喉部、前额及上胸部。","appearance":"赤胸燕体型娇小，尾长而分叉，翼尖而弯曲。其上体呈现光泽的钢蓝色，翅膀和尾巴为黑色，尾巴中度分叉，内侧尾羽上有大块白色斑点（除中央一对）。喉部、前额和上胸部为红褐色，被一条较窄的深蓝色带环绕，其余下体为白色。雌鸟尾部较雄鸟短，幼鸟色泽较淡，红褐色区域颜色更浅，尾巴较短。","call":"其鸣唱为微弱但清晰响亮的啾啾声。","habits":"赤胸燕栖息于多种开阔地带，包括草地、稀树草原、沼泽、河流与湖泊周边、森林空地以及人类居住区。它们常见于低地，但在埃塞俄比亚的海拔可达1800至2750米。赤胸燕主要为留鸟，但在西非某些地区会进行局部移动，如加纳、贝宁雨季期间，以及多哥1月至4月间成群出现，但在9月至12月较少见。饮食以白蚁为主，单独、成对或小群体觅食，有时会形成40只以上的群落，常与其他燕科鸟类一同活动。飞行迅速，频繁转向，与家燕相似。","breeding":"繁殖期在不同地区有所差异，例如塞内加尔为3月至7月和12月，冈比亚为3月至6月，毛里塔尼亚为7月至8月，马里为8月至9月，尼日尔为9月至10月，多哥为3月至4月、6月至8月和12月，刚果民主共和国为2月至5月和8月至9月，埃塞俄比亚为4月至6月，可能还包括2月。筑巢方式为独居或小规模松散群体，巢由泥丸混合草制成，内部铺垫干草和羽毛，置于白蚁丘、岩石、桥梁、门廊、屋檐下或建筑物内，尤其是横梁上，有时会重复使用旧巢。一窝通常产3至4枚卵，关于孵化和雏鸟离巢期的信息尚不详。","identification":"与家燕极为相似，但红胸燕具有更窄的蓝色胸带、较短的尾流苏，成年个体略小。幼鸟与家燕幼鸟较为接近。","protection":"IUCN：LC（无危）","distribution":"赤胸燕主要分布在非洲的西非、刚果盆地和东北部地区，包括中部和西部非洲以及埃塞俄比亚。在刚果民主共和国、加纳、贝宁、多哥、尼日利亚、加蓬等地均有记录，特别是在低地，但在埃塞俄比亚的分布可达海拔1800至2750米。","other":"赤胸燕易于利用桥梁筑巢，因此随着此类结构的增多，其种群数量可能正在增长。"},{"name":"安哥拉燕","english_name":"Angola Swallow","scientific_name":"Hirundo angolensis","overview":"安哥拉燕（英文名：Angola Swallow，学名：Hirundo angolensis），是雀形目燕科燕属的鸟类。原生于非洲热带地区。以蓝色上体、栗色前额和喉部、狭窄的暗色胸带以及灰色下体为显著特征。在开放的草地、农田和湿地边缘可见到单个、成对或群体的安哥拉燕，既是常驻鸟也是非洲内部的迁徙鸟。","appearance":"成年安哥拉燕体长约15厘米，体重介于16至19克之间。额头、喉咙和上胸部呈深栗色，而冠部和背部闪耀着钢蓝色。飞行羽和尾羽为黑色，尾羽带有大的白色斑点。雌雄相似，幼鸟的羽毛颜色可能较为暗淡。","call":"安哥拉燕的鸣叫声为典型的弱音啾啾声，类似于其他燕子的叫声。","habits":"安哥拉燕栖息于各种开阔地带，直至森林边缘，无论是自然形成的还是人类活动影响的环境。它们以飞行中的昆虫为食，可单独或成群觅食，发出微弱的啾啾声。","breeding":"其繁殖季节和种群数量受所居住地区的条件影响，一些个体可能会进行迁徙。具体繁殖习性包括筑巢、交配和育雏等细节尚需进一步研究。","identification":"与安哥拉燕相似的物种包括体型更大、尾羽更长的家燕，后者具有完整的胸带和白色的下体；埃塞俄比亚燕则拥有浅黄色（而非栗色）的喉咙和白色（而非灰色）的下体。","protection":"IUCN：LC（无危）","distribution":"安哥拉燕广泛分布于非洲中南部，包括加蓬、安哥拉西部、刚果民主共和国中部和东部、乌干达、肯尼亚西部、坦桑尼亚、马拉维北部和赞比亚北部。","other":"安哥拉燕曾被认为与红胸燕是同一物种，但现在通常被视为独立的物种，是包括家燕、红胸燕、太平洋燕、欢迎燕、白喉燕和埃塞俄比亚燕在内的复杂物种群的一部分。"},{"name":"洋燕","english_name":"Pacific Swallow","scientific_name":"Hirundo tahitica","overview":"洋燕（英文名：Pacific Swallow，学名：Hirundo tahitica），是雀形目燕科燕属的鸟类。是东南亚及太平洋地区常见的留鸟，分布范围北达日本南西诸岛。该鸟体型中等，尾略分叉，上体具钢蓝光泽，额、喉及上胸呈栗色，下体灰色，常栖于海岸、城镇及人类建筑物附近，已适应利用人造结构营巢。","appearance":"成鸟全长约11–14厘米，体重11–19克。上体黑褐色带钢蓝色光泽；额、耳羽、喉及上胸栗色，下体自浅灰至暗灰色不等，中央及下腹常较白；尾下覆羽黑褐色具白色羽缘，尾略分叉，多数亚种尾羽具白色次端斑。雌雄同色。幼鸟整体较暗，栗色区浅淡，尾较短，上体褐色具淡色羽缘。","call":"鸣声为快速而多变的悦耳与粗哑音节混合，类似家燕但更富变化；常见叫声包括尖锐的“pseeep”汽笛声、柔和的“whit”联络声及连串“brrrt”颤音。鸣唱多见于繁殖期，其他叫声全年可闻，飞行或停栖时均可发出。","habits":"洋燕为典型空中食虫鸟，栖息于海岸、内陆水域及人类聚落周边，活动高度多在5–30米，低于家燕。常在开阔地、森林边缘、草地及道路上空觅食，主食飞蚁、蝇类、甲虫及白蚁等，猎物个体相对较大。日间活动，中午高温时多停栖阴凉处。非迁徙性，但繁殖后可见短距离岛屿间游荡。","breeding":"繁殖期因地而异：马来半岛1–8月、菲律宾3–10月、安达曼群岛5–6月等。巢由雌雄共同以泥丸筑成半杯状，置于岩壁、桥梁、屋檐等突出处，离地1–6米，偶高达2000米。每窝2–5枚卵，多为3枚；卵淡乳白至粉白色具红褐斑；孵化期15–17天，仅雌鸟孵卵；雏鸟17–22天出飞，育雏由双亲共同承担，常一年两窝。","identification":"与家燕相比，洋燕尾叉较浅，无完整黑色胸带，尾下覆羽黑褐具白缘。与山燕无地理重叠，后者上体具绿色光泽。与塔希提燕亦不重叠，后者前额栗色范围更小，下胸至腹黑色，尾羽无白斑。与迎燕在越冬地新喀里多尼亚仅边缘重叠，欢迎燕尾流更长，下体更白。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：安达曼群岛、缅甸与泰国南部沿海、柬埔寨、越南南部、马来半岛、苏门答腊、爪哇、婆罗洲、菲律宾、苏拉威西、新几内亚、俾斯麦群岛、所罗门群岛、瓦努阿图、新喀里多尼亚、斐济、汤加及日本南西诸岛、台湾。非繁殖区：多为留鸟，偶见游荡至香港及东部波利尼西亚岛屿。","other":"洋燕曾被视为与山燕、塔希提燕及迎燕同种，现已分立。因适应人造建筑，20世纪中后期以来在马来半岛、泰国等地显著向内陆及高海拔扩展。"},{"name":"山燕","english_name":"Hill Swallow","scientific_name":"Hirundo domicola","overview":"山燕（英文名：Hill Swallow，学名：Hirundo domicola），是雀形目燕科燕属的鸟类。主要分布在印度南部和斯里兰卡的山区，以海岸线为伴，近年来逐渐向森林高海拔地区扩散。曾被认为是洋燕的一个亚种。","appearance":"成年山燕体长约13厘米，背部呈蓝色，翅膀和尾巴颜色较暗，面部和喉部为红褐色，腹部灰暗。幼鸟整体颜色较淡，上体更偏棕色，红褐色部位色泽较浅。雄雌外观相似，无明显差异。","habits":"山燕常栖息于开阔地带，如草地、水库和高山茶园，海拔高度通常超过500米，低海拔地区极为罕见。它们以空中追逐昆虫为生，飞行迅速，动作与尾部较短的家燕类似。","breeding":"山燕在悬崖峭壁下或人造结构如建筑物、桥梁和隧道下构建杯状巢穴，使用泥球筑巢，内部铺设柔软材料，每窝产卵可达四枚。繁殖生态研究在印度喀拉拉邦的寂静谷国家公园和Muthikkulam保护区森林进行过。","identification":"与家燕相比，山燕具有较短且分叉程度较低的尾巴，胸前无黑色带纹，上体光泽为蓝绿色而非钢铁蓝，且下体颜色为脏白带灰。与洋燕相似，但后者上体光泽为钢铁蓝。","protection":"IUCN状态未知。","distribution":"主要分布于印度南部和斯里兰卡的山区，包括海岸线附近的高海拔地区。"},{"name":"迎燕","english_name":"Welcome Swallow","scientific_name":"Hirundo neoxena","overview":"迎燕（英文名：Welcome Swallow，学名：Hirundo neoxena），是雀形目燕科燕属的鸟类。主要分布在澳大利亚和新西兰，包括澳大利亚大陆、塔斯马尼亚及其附近岛屿。拥有长而分叉的尾巴，上体深色，下体浅色，胸部和面部呈锈色。在澳大利亚比家燕少见，后者有较暗的胸带且下体更淡。迎燕常见于开阔地带，如公园、运动场、湿地等，常大量栖息于围栏和电线杆上。","appearance":"体长13-17厘米，体重12-17克。头部前额锈色至栗色，冠部和背部光泽钢蓝色；翅膀和尾部黑褐色，尾部分叉深，内侧尾羽有白色斑点（除中央一对）；喉部和上胸部锈色至栗色，其余下体灰白，侧翼和下翼覆羽带棕色；下尾覆羽灰棕色，末端暗色，边缘浅色。雌鸟尾部较短，幼鸟颜色较暗淡，尾部更短，锈色部位颜色较浅。carteri亚种仅在体型上略大。","call":"鸣唱为混合的啾啾声和颤音；联络叫声为'seet'，并伴有尖锐的警报声'twsee'、'sweert'或'tit-swee'。","habits":"栖息于开阔乡村、海岸、农田和人类居住地，通常靠近水源。形成群体，数量可达500只。西澳大利亚和新西兰的部分个体为留鸟或部分迁徙；东部澳大利亚的个体部分迁徙，非繁殖季节访问北澳大利亚，包括托雷斯海峡，同时在南部包括塔斯马尼亚过冬。主要迁徙时间为2月至3月和8月至9月。成鸟会回到同一地点连续繁殖。","breeding":"繁殖期为7月至翌年4月，峰值9月至10月，内陆早于沿海；新西兰8月至2月，每年2-3窝。独居或松散群居，巢间距0.1-1米；巢由泥土颗粒和草混合制成，内部铺干草、根须、毛发、羊毛和羽毛。巢建于垂直表面，距地面0.3-7.6米，多在人工环境如涵洞、桥梁、码头、矿井、水箱、建筑物内壁或外墙、屋檐下。每窝产2-7枚卵，平均4或5枚，孵化期14-19天，平均15.6天。幼鸟喂养频率17-24次/小时，离巢期18-23天，平均20.6天。平均成功离巢率74%，繁殖成功率53%。","identification":"与洋燕相比，下体颜色较浅，尾羽内侧有斑点而非边缘，外侧尾羽较长；与家燕的区别在于缺乏喉咙下方的蓝色带。雌鸟尾部较短。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在澳大利亚、塔斯马尼亚、Lord Howe和诺福克岛、新西兰及其北部外围岛屿；非繁殖期迁徙至澳大利亚内陆和北部，以及新喀里多尼亚。","other":"自20世纪中期以来，迎燕的分布范围已从澳大利亚扩展至新西兰。首次在新西兰被记录是在1958年的北岛，到1965年遍布整个北岛。近几十年来，在新几内亚、新喀里多尼亚和其他岛屿群也有非繁殖个体的记录。"},{"name":"白喉燕","english_name":"White-throated Swallow","scientific_name":"Hirundo albigularis","overview":"白喉燕（英文名：White-throated Swallow，学名：Hirundo albigularis），是雀形目燕科燕属的鸟类。小型燕科鸟类，拥有独特的白色喉部和完整的钢蓝色胸带，活跃于南部非洲的开放地带和草甸，以桥梁和水坝等人类建造结构提供的巢穴机会而繁盛。","appearance":"体长14-17厘米，体重16-29克。头部前方有一小块赤褐色，上体呈光泽的钢蓝色；翅膀为暗褐色，尾部深蓝黑色，尾叉明显，内侧尾羽有白色斑点；下体灰白色，喉部纯白，胸前有一条钢蓝色宽带，逐渐变细至中心；翼下覆羽白色。与相似种如家燕、赤胸燕和安哥拉燕相比，其特征在于白色喉部和赤褐色前额，与珠胸燕的区别在于胸带和前额颜色。雌鸟尾巴较短，幼鸟色彩较淡，前额颜色较浅，胸带呈棕色。","call":"鸣声为快速的颤音，叫声包括尖锐的“chit”声和鼻音及吱吱声。","habits":"偏好成对或成群觅食，常见于草地、轻林地和泛滥平原，常在围栏或水边的柱子上停歇。迁徙期间，从南非洲向北和西北迁移至安哥拉、赞比亚和刚果民主共和国东南部。","breeding":"繁殖期一般为8月至翌年4月，高峰期在10月至12月，可能有两次或多次繁殖。巢为开放的杯状，由泥丸构成，内衬根须、毛发、干草和羽毛，通常固定在悬垂下方，靠近水源，如岩壁、涵洞、水坝、水箱、桥下、门廊、屋檐或天花板下，或废弃建筑内。一窝产卵2-5枚，通常3枚；孵化期15-16天；雏鸟由双亲喂养，离巢期20-21天；幼鸟离巢后仍会返回巢中休息12天以上。最老记录个体年龄为9岁11个月。","identification":"通过白色喉部和黑色胸带与相似物种区分，雌鸟比雄鸟尾巴略短，幼鸟色彩较暗淡。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从马拉维南部和津巴布韦至南非南部（除西北部）；已知在赞比亚和纳米比亚繁殖（可能规律性），安哥拉中部有单个繁殖报告待确认。非繁殖季节，来自南非的群体向北和西北迁移至安哥拉、赞比亚和刚果民主共和国南部，可能到达坦桑尼亚。"},{"name":"红额燕","english_name":"Ethiopian Swallow","scientific_name":"Hirundo aethiopica","overview":"红额燕（英文名：Ethiopian Swallow，学名：Hirundo aethiopica），是雀形目燕科燕属的鸟类。长尾燕，分布广泛，自贝宁至布基纳法索，遍及喀麦隆、中非共和国、刚果民主共和国等地，甚至远至以色列、肯尼亚、尼日利亚和乌干达。其生境多样，常见于开阔地带，接近水源或人类居住区。","appearance":"红额燕具有光泽的蓝色上体和白色下体，喉部呈淡黄褐色，胸部两侧有深色斑点，但无完整的胸带。嘴上方有一小块砖红色斑块。与赤胸燕和家燕相似，但喉部颜色为黄褐色而非砖红色。与线尾燕相似，但不具备完整的红色顶冠，且尾羽流苏较短。","habits":"红额燕栖息于各种开放生境，偏好靠近水体或人类聚居地。它们非迁徙性，广泛分布于非洲东北部和中部。","breeding":"红额燕在悬崖和建筑物上筑巢繁殖。","identification":"需与线尾燕、赤胸燕和家燕区分，主要通过喉部颜色和尾羽特征识别。","distribution":"分布于非洲东北部和中部，具体包括贝宁、布基纳法索、喀麦隆、中非共和国、刚果民主共和国、科特迪瓦、厄立特里亚、埃塞俄比亚、加纳、几内亚、以色列、肯尼亚、马里、尼日尔、尼日利亚、塞内加尔、索马里、苏丹、坦桑尼亚、多哥和乌干达。"},{"name":"线尾燕","english_name":"Wire-tailed Swallow","scientific_name":"Hirundo smithii","overview":"线尾燕（英文名：Wire-tailed Swallow，学名：Hirundo smithii），是雀形目燕科燕属的小型鸟类。其显著特征为两根细长的尾羽，如同电线般延伸，赋予其独特外观。分布于撒哈拉沙漠以南的非洲地区，亚洲南部的印度地区亦有其踪迹。线尾燕通常为留鸟，但在印度和巴基斯坦的部分群体冬季会向南迁移。在中国，仅云南德宏有其记录，为中国的鸟类新发现。","appearance":"线尾燕体长约18厘米，拥有光泽蓝的背部，鲜明的白色腹部和红褐色的头部。最引人注目的是其尾部末端两根异常长而纤细的羽毛，雌鸟个体的这两根羽毛较短。幼鸟的冠羽呈棕色，尾部和背部颜色较为暗淡，缺乏成鸟的金属光泽。","call":"发出一系列清脆的‘chirrickweet chirrickweet’声，伴有‘chit-chit’的飞行叫声，巢边带幼鸟时的‘chichip chichip’警报声，以及‘twit’、‘pwee’和‘che’的其他叫声。","habits":"栖息于草地、湿地、开阔灌木地、耕作区及人类居住地附近，常在湖泊、河流、运河和稻田等水体附近活动。主要以飞虫、甲虫、鳞翅目昆虫等为食，单独或小群觅食，有时与其他燕子和雨燕混群。飞行迅速，低空捕食，偶尔在地面捕食昆虫。","breeding":"繁殖期随地区而异，一般在雨季开始时，如在塞内加尔为1月至5月和7月至12月。通常独居繁殖，偶尔在同一地点有几对共存，但巢穴并不聚集。巢由双方共建，用泥和干草制成，内部铺以草、根须和羽毛，筑于墙壁、屋檐下或近天花板处，高度30厘米至15米。每窝产卵2至4枚，孵化期13至19天，由雌鸟承担。雏鸟由双亲喂养，约15至24天后离巢。","identification":"与其他燕子相比，线尾燕的两根显著的长尾丝是辨识的关键。亚洲种H. s. filifera比非洲种H. s. smithii体型更大，尾部更长。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲和亚洲南部。在非洲，从西非的冈比亚到南非均有分布，亚洲则见于印度次大陆和东南亚。中国仅在云南德宏有记录。","other":"线尾燕在过去一个世纪左右的时间里，由于利用人造巢址和新建筑物的建设，其分布范围有所扩大。"},{"name":"蓝燕","english_name":"Blue Swallow","scientific_name":"Hirundo atrocaerulea","overview":"蓝燕（英文名：Blue Swallow，学名：Hirundo atrocaerulea），是雀形目燕科燕属的鸟类。小型燕科鸟类，分布于非洲中南部，从刚果民主共和国东南部到南非东部，冬季迁徙至刚果东北部、乌干达和肯尼亚西部。拥有亮丽的金属蓝羽毛和极长的尾流，体长18-25厘米，体重约13克。","appearance":"蓝燕雌雄羽色相近，全身覆盖着虹彩般的蓝色羽毛，反射出金属光泽，尾羽特别长，尤其在雄鸟身上更为显著，形成细长的流苏。体侧和臀部可见白色羽毛，翅膀呈金属深蓝色，泛绿光，尾部黑色，饰有蓝绿色和白色条纹。幼鸟颜色较暗，喉部褐色，雌鸟尾羽较短。","call":"发出单调而哀婉的歌声，叫声包括安静的‘choop-choop’声、高音警报声、飞行中的‘chip chip’声，以及快速的‘chip-pu-pu’、‘rip-rip’和‘reap-reap’。","habits":"栖息于高降雨量的山地草地，冬季偏好开阔草地，有灌木和树木的地方。飞行迅速，主要在低空捕食，食物以昆虫为主。在繁殖季节，成对占据巢穴，具有强烈的领地意识，积极驱赶入侵者。","breeding":"繁殖期从2月开始，持续至翌年3月。巢由两性共同建造，位于地下旧洞穴的墙或顶，通常为开放的杯状，用泥和草混合制成，内部铺有毛发、草、根须和羽毛。每次产卵2-4枚，正常为3枚，孵化期14-17天，通常15-16天，由雌鸟负责，小鸟留巢20-26天。","identification":"蓝燕以其独特的金属蓝色彩和极长的尾流与其它燕子区分，特别是在光线不足时，可能与蓝锯翅燕混淆，但蓝燕的色泽更鲜明。","protection":"IUCN：EN（濒危）","distribution":"繁殖于刚果民主共和国东南部、坦桑尼亚中部至南非东部；非繁殖期迁至刚果东北部、乌干达和肯尼亚西部。","other":"面临栖息地破坏威胁，导致种群数量下降。保护措施包括监测繁殖种群、控制外来植物扩散和评估火的影响。"},{"name":"白喉蓝燕","english_name":"White-bibbed Swallow","scientific_name":"Hirundo nigrita","overview":"白喉蓝燕（英文名：White-bibbed Swallow，学名：Hirundo nigrita），是雀形目燕科燕属的鸟类。美丽的燕科燕属鸟类，以其独特的亮白色喉部和深蓝色光泽的羽毛著称。广泛分布于非洲，从塞拉利昂至乌干达西部，刚果民主共和国南部到安哥拉北部。","appearance":"成年白喉蓝燕长约12厘米，重15至22克。全身大部分覆盖着钢蓝色带有紫色光泽的羽毛，喉部有一块明显的白色斑块。翅膀黑色，带有紫色光泽；尾巴几乎呈方形，黑色中带蓝色光泽，内侧羽片有白色斑点（除中央一对）。下翼覆羽黑色。两性外观相似。幼鸟比成鸟颜色暗淡，更偏棕色。","call":"鸣叫声包括柔和的高音颤音，以及飞行中的\"weetch\"声、\"vwhit vwhit\"声和轻柔的\"whit\"声。","habits":"栖息于雨林中的河流和溪流旁，也可见于红树林、港口、陆地突出部分和泻湖。全年留居，可能有局部迁徙。主要以双翅目昆虫，尤其是马蝇（Tabanidae），以及甲虫（Coleoptera）、蜻蜓目、白蚁（Isoptera）和膜翅目昆虫为食。通常成对或小群觅食，偶尔形成超过40只的大群。飞行快速，频繁地翻滚，偶尔滑翔。","breeding":"主要在旱季繁殖，当河流水位较低时，如塞拉利昂的3月，利比里亚的10月至3月，加纳的1月和6月，尼日利亚的1月至2月和8月，喀麦隆的1月至2月和6月，加蓬的1月至3月和6月至8月，刚果民主共和国的1月至2月、7月和12月，以及安哥拉的3月至4月和8月，有时会连续繁殖两次。巢由双方共同建造，大约需3周时间，是一个开放的杯状巢，由泥球构成，内衬树皮、草和羽毛，通常建在离水面1至3米（有时仅10厘米）的地方，距离河岸超过5米，位置可能在岩石、倒下的树木、悬垂的树枝或悬崖上，也会利用人造地点如桥、码头、翻转的独木舟或靠近水源的房屋屋顶。每窝产2至3枚蛋，偶尔4枚；孵化由雌鸟负责，持续15天以上；幼鸟由双方喂养，约在17至18天后离巢，家庭成员会在一段时间内保持在一起。","identification":"白喉蓝燕的辨识要点在于其独特的深蓝色带有紫色光泽的羽毛和白色的喉部斑块。与同属其他物种相比，其尾部近乎方形，内侧羽片的白色斑点也是识别特征之一。","protection":"IUCN：LC（无危）。在当地常见，记录的密度为每公里河流1至2个巢。最近在乌干达Semliki河一侧有记录，但是否在那里繁殖尚不清楚。偶尔利用人造巢址，如桥梁，这一习惯可能正在增加。","distribution":"分布于非洲的塞拉利昂至乌干达西部，刚果民主共和国南部和安哥拉北部。","other":"白喉蓝燕对入侵者表现出攻击性，成对的鸟儿会守护在巢址周围有限的区域内。"},{"name":"斑翅燕","english_name":"Pied-winged Swallow","scientific_name":"Hirundo leucosoma","overview":"斑翅燕（英文名：Pied-winged Swallow，学名：Hirundo leucosoma），是雀形目燕科燕属的小型鸟类。以独特的钢蓝色上体和翼上的白色斑块著称。常见于西非的森林边缘、灌木丛和河流附近。","appearance":"斑翅燕长约12厘米，头部至颈后部和上体呈光泽的钢蓝色，翅膀上有显著的白色斑块，尾巴略呈叉状，黑色并带有蓝绿色光泽，翼羽内侧有白色斑点（除中央一对外）；喉部和下体白色，胸部侧面有一蓝斑。雌鸟的尾巴比雄鸟短，幼鸟较暗淡，头部棕色，尾巴更短。","call":"发出短暂的“chut”声，但在大多数情况下它们并不特别善鸣，通常仅在栖息时鸣叫。","habits":"栖息于多种环境，包括林地草原、森林空地和河流，不避人类，常见于城镇。它们是部分迁徙性鸟类，雨季期间会迁至加纳和尼日利亚北部，非繁殖季节可在塞内加尔和多哥找到。它们快速而敏捷地飞行，利用飞行中的急转弯和俯冲捕捉空中昆虫。","breeding":"繁殖期从4月或5月开始，持续到6月。由双亲共同筑造浅泥巢，内部铺垫草或纤维。筑巢耗时约一个月，但经常重复使用旧巢。巢穴有时靠近褐胸燕的巢。常见于建筑物或屋檐下，甚至有一个极端案例是在井下4.6米处。每窝通常有4枚纯白色的蛋，偶尔也有3枚。蛋的尺寸约为19.7mm×13.1mm，重量1.77克。","identification":"与迁徙的普通家燕相比，斑翅燕有白色翼斑，而普通家燕有白色臀部，翼上无白色。雌鸟和幼鸟的尾巴比雄鸟短，颜色较为暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于非洲，自塞内加尔和冈比亚至尼日利亚，包括贝宁、布基纳法索、喀麦隆、科特迪瓦、冈比亚、加纳、几内亚、几内亚比绍、马里、尼日尔、尼日利亚、塞内加尔、塞拉利昂和多哥。","other":"进化上，斑翅燕在燕属内占据基础位置，与珠胸燕关系最近。"},{"name":"白尾燕","english_name":"White-tailed Swallow","scientific_name":"Hirundo megaensis","overview":"白尾燕（英文名：White-tailed Swallow，学名：Hirundo megaensis），是雀形目燕科燕属的鸟类。以其独特的白色腹部和尾巴而著称，主要分布在埃塞俄比亚南部的山区。这种燕子又被称为Benson's swallow，以纪念命名它的鸟类学家Constatine Walter Benson。白尾燕因其种群数量持续下降，目前全球仅存不到10,000只成年个体，被 IUCN 列为易危物种。","appearance":"白尾燕体长约13厘米，重约11克。雄鸟上身呈亮泽的钢蓝色，翅膀黑色并带有蓝光；尾巴略呈叉状，内侧羽毛全白，带黑色羽轴条纹，外侧羽毛内侧白色；喉咙和下体均为白色。雌鸟光泽较弱，尾巴更短，白色较少。幼鸟颜色较淡，飞行羽、三级飞羽和上尾覆羽边缘呈浅色，尾羽甚至比雌鸟更短、更暗。","call":"白尾燕的叫声特征未知。","habits":"白尾燕栖息于开放的半干旱草原，有刺槐（Acacia）灌木丛，有时也在村庄附近。主要活动在海拔1500至1700米之间，偶尔下至990米，最高可达2400米。它们通常成对活动，可能有局部迁移，因数量会有所波动。饮食包括甲虫（Coleoptera），在开花树木周围觅食，飞行快速优雅。","breeding":"白尾燕在主雨季4月至6月繁殖，也可能在1月至2月期间繁殖。巢为小型开口杯状，由泥巴筑成，内衬草和动物毛发，通常建在村庄茅屋的屋顶横梁上或水井墙壁上，也会在白蚁丘和涵洞中筑巢。每窝产3至4枚纯白色蛋，平均3.5枚（样本量=19），孵化期为16至17天。","identification":"白尾燕与灰腰燕相似，但后者尾部无白色，容易区分。也可能与西方毛脚燕混淆，但白尾燕尾部有白色，而非明显的臀斑。","protection":"IUCN：VU（易危）","distribution":"白尾燕主要分布于非洲埃塞俄比亚南部山区，具体在Yabello和Mega地区。","other":"白尾燕面临的主要威胁是植被清除用于放牧牲畜，以及人类活动导致的栖息地丧失。Yavello保护区于1985年指定部分区域保护这一物种，但保护区尚未正式设立或管理。保护目标是确定其栖息地需求，了解其分布范围受限的原因，以及评估灌木清除对种群的影响。"},{"name":"刚果燕","english_name":"Black-and-rufous Swallow","scientific_name":"Hirundo nigrorufa","overview":"刚果燕（英文名：Black-and-rufous Swallow，学名：Hirundo nigrorufa），是雀形目燕科燕属的鸟类。直译: 黑棕燕，小型而美丽的燕科燕属鸟类。其上体、臀部和面部呈蓝黑色，下体包括颏部、喉部和腹部则均匀地呈现深红色。该物种主要分布于非洲中部的安哥拉、刚果民主共和国和赞比亚的miombo生态系统中。","appearance":"刚果燕拥有蓝黑色的上体、臀部和脸部，其颏部、喉部以及腹部呈现出一致的深红色。在飞行中，可见其翼下覆羽同样为深红色。幼鸟相比成鸟色彩较为暗淡。该物种的体形较小。","habits":"刚果燕通常以单个或成对的形式出现在草原和稀树草原地带，偏好于沼泽边缘、河流附近及半淹没区域。它们的栖息地多位于非洲的miombo生态系统中。","identification":"与相似的红喉燕相比，刚果燕具有更深的臀部颜色且下体的红色更为浓郁。其他类似的燕子体型较大，尾巴较长，臀部为红色，翼下覆羽颜色较浅。","distribution":"刚果燕的分布范围涵盖了安哥拉中西部至刚果民主共和国南部直至赞比亚东部，其分布区域贯穿了从安哥拉的库安扎苏尔省到刚果民主共和国南部以及赞比亚东部的广大区域。"},{"name":"珠胸燕","english_name":"Pearl-breasted Swallow","scientific_name":"Hirundo dimidiata","overview":"珠胸燕（英文名：Pearl-breasted Swallow，学名：Hirundo dimidiata），是雀形目燕科燕属的小型鸟类，以独特的双色羽毛著称，上体呈现钢蓝色，下体为淡色。常见于非洲南部至中南部的草甸、灌木丛、农田和开阔林地，通常靠近水源。部分种群迁徙至南非南部过冬，其余地区则为留鸟，存在一些尚不明了的迁徙模式。","appearance":"成年珠胸燕体长约13厘米，重10至15克。雄性珠胸燕上体光泽蓝亮，翅膀黑色带微蓝光泽；尾部轻微分叉，黑色，一般无白色边缘；腹部灰白色，胸部有灰色阴影，尾下覆羽尖端深色。雌性珠胸燕尾部较短，光泽略偏绿色。幼鸟颜色较暗淡，次级飞羽内侧有白色尖端，尾羽较短。marwitzi亚种体型较小，颜色更深。","call":"珠胸燕的叫声为连续的叽叽喳喳声，特征明显。","habits":"珠胸燕主要栖息于干燥的灌木丛、农田和林间空地，常在人类居住区附近活动。其飞行迅速直接，主要以空中飞行的昆虫为食。","breeding":"珠胸燕在天然洞穴或人造结构（如建筑物、涵洞和矿井）中筑碗状泥巢，内部加固以草或毛发，铺以柔软内衬。有时会利用大条纹燕的旧巢。每窝产卵2至3枚纯白色蛋，由雌鸟单独孵化约16至17天。幼鸟由双亲共同喂养，约20至23天后离巢，但初次飞行后数日内仍会返回巢穴过夜。","identification":"珠胸燕与西方毛脚燕和灰腰燕的区别在于缺乏明亮的臀部色彩。此外，其尾部无白色标记，是与相似的Hirundo属物种区分的关键特征。","protection":"IUCN：LC（无危）","distribution":"珠胸燕的繁殖区域位于非洲南部，从中南部的安哥拉、刚果南部和坦桑尼亚向南延伸。在南非西南部的许多个体冬季会迁徙至更北的地区。"},{"name":"岩燕","english_name":"Eurasian Crag Martin","scientific_name":"Ptyonoprogne rupestris","overview":"岩燕（英文名：Eurasian Crag Martin，学名：Ptyonoprogne rupestris），是雀形目燕科岩燕属的鸟类。体型较大、结实的岩燕，整体灰褐，飞时腋部黑褐对比强烈，尾方且具显著白斑。广泛分布于南欧、西北非、小亚细亚、高加索、伊朗至蒙古及中国西部、北部和中部山区，冬季南迁至地中海沿岸、北非、中东及南亚。","appearance":"体长14–15厘米，体重17–33克。头顶至上背褐灰色，翼和尾暗褐；尾方形，除最内及最外两对外，其余尾羽内翈具白斑。颏及喉淡色并具暗斑，胸淡棕黄，渐变为褐灰腹部及褐黑色尾下覆羽；翼下覆羽近黑色。两性同色。幼鸟羽缘具浅黄色，喉部色泽较淡且斑驳不明显。","call":"鸣唱为轻柔的啁啾声。常见叫声包括联络声“prrrt”；警戒声“zrrr”、“gsigsi”；兴奋声“whee”；攻击声“rrr”。空中追逐同类时会发出连串音节。","habits":"栖息于山地、岩壁及沿海悬崖，亦见于人类建筑物附近。欧洲分布自海平面至2500米，多在500–1000米的山谷东北或西南坡；亚洲可达4500米以上。觅食紧贴崖壁或峡谷、林地、村庄上空；非繁殖期亦利用农田、草地、岩岸、沼泽及湖泊。北方种群迁徙，南方多为留鸟；秋季和春季直布罗陀海峡可见大批过境。觅食范围巢周约1.5千米，冬季约1.5平方千米；直布罗陀夜宿群体可远达5千米觅食。","breeding":"繁殖期5–8月，可育两窝。通常成对或小群繁殖，西班牙平均4.5–6.1对，巢间距10–80米，偶见60对等大型群。与高山雨燕、金腰燕、家岩燕及暗色岩燕等混群营巢。雌雄共建巢，9–20日完成，巢为泥丸筑成的开放半杯，内垫草及羽毛，置于岩缝、桥下或建筑物上，距地6–25米，常重复利用。每窝2–5枚卵，多为3–4枚，孵化期13–17天，几乎全由雌鸟承担；雏鸟留巢24–27天，离巢后亲鸟继续喂养14–21天。","identification":"与非洲岩燕相比，本种体色更深且通常体型更大；与崖沙燕相比，体型更大，上体、翼下及尾下覆羽颜色更深，尾具白斑且缺少胸带。","protection":"IUCN: LC（无危）","distribution":"繁殖区：南欧（法国南部、德国南部、奥地利、罗马尼亚以南）、西北非（摩洛哥至突尼斯及利比亚东北部）、小亚细亚、高加索、近东（南至以色列）、伊朗、俄罗斯南部（至西南西伯利亚）、蒙古北部，以及喜马拉雅山脉（巴基斯坦至不丹）和中国西部、北部及中部。越冬区：地中海地区、北非及东北非（含毛里塔尼亚、塞内加尔）、中东及南亚。迷鸟记录至芬兰及不列颠群岛。","other":"曾被视为与属内其他种同种，但因繁殖区重叠而独立。中亚及摩洛哥南部种群虽曾建议分为centralasica及theresae亚种，但变异不恒定，目前视为单型种。"},{"name":"灰喉燕","english_name":"Pale Crag Martin","scientific_name":"Ptyonoprogne obsoleta","overview":"灰喉燕（英文名：Pale Crag Martin，学名：Ptyonoprogne obsoleta），是雀形目燕科岩燕属的鸟类。主要栖息在北非和西亚，东至巴基斯坦。灰喉燕以山地为主要繁殖地，但也出现在低海拔地区，尤其是岩石地带和城镇周边。通常远离水源活动，体型长约12-13厘米，羽色主要为棕色，上胸部和翅膀下方色调较淡，飞行时尾巴展开显露出白色斑点。雌雄外观相似，但幼鸟上体和飞羽边缘呈淡色。","appearance":"灰喉燕身长约为12-13厘米，上体呈浅棕色，背部颜色逐渐变淡，尾部短而方形，除中央和最外侧羽毛外，其余尾羽尖端有小白斑。喉咙、上胸和翅膀下覆羽为淡灰色，腹部为脏白色。眼睛棕色，喙小且主要是黑色，腿为棕粉色。翼长平均为13厘米，尾长平均为4.8厘米。两性外观相似，但幼鸟的上体和飞羽边缘有淡色边缘。","call":"灰喉燕的鸣声为模糊的啾啾声，还有其他叫声包括类似家燕的trrt声，鼻音的vick声，以及高音的twee联系叫声。","habits":"灰喉燕栖息在悬崖、峡谷和洞穴等地形，高达海拔3700米，但在低地也有发现，尤其在有岩石或建筑的地方。它们利用人造结构替代自然悬崖筑巢，常见于埃及的沙漠城镇如阿斯旺附近。在非繁殖季节，它们可能会向低海拔迁移，或进行局部移动。","breeding":"灰喉燕通常单独筑巢，有时形成松散的小群落。它们积极保卫巢区，防止同类和其他物种侵入。巢由双方共同建造，使用数百个泥球制成，内部铺有羽毛和干草等柔软材料。巢可建在岩石峭壁、裂缝、建筑物上，被重复使用。一窝通常产2-3枚蛋，父母轮流孵化16-19天，之后共同喂养雏鸟。","identification":"灰喉燕比大多数非洲燕更暗淡，与非洲岩燕、沙燕等同属物种相比，它更小、更淡、喉咙更白。与岩燕相比，灰喉燕更小，尾部斑点较小。与纯色岩燕相比，灰喉燕的下体更亮。与沙燕相比，灰喉燕更健壮，尾部有白色斑点，没有胸部带纹。","protection":"IUCN：LC（无危）","distribution":"灰喉燕繁殖于北非、中东直至阿富汗和巴基斯坦的适宜生境。它们主要居住于此，但在某些地区，如沙特阿拉伯南部的个体，会迁往埃塞俄比亚和非洲之角过冬。在巴基斯坦，灰喉燕的亚种P. f. peloplasta与纯色岩燕的繁殖范围重叠，但纯色岩燕繁殖地海拔较低。在北非，灰喉燕占据沙漠生境，而岩燕则在山区。","other":"灰喉燕在19世纪70年代开始在以色列南部的房屋上繁殖，显示了其适应人类环境的能力。在非繁殖季节，它们可能聚集多达300只的群体在食物丰富的地区，如农田、湿地和污水处理厂。"},{"name":"非洲岩燕","english_name":"Rock Martin","scientific_name":"Ptyonoprogne fuligula","overview":"非洲岩燕（英文名：Large Rock Martin，学名：Ptyonoprogne fuligula），是雀形目燕科岩燕属的鸟类。燕科体型粗壮的褐羽留鸟，背部深褐、腹面较浅，尾略呈叉状并具醒目白斑，栖于干旱地区的峡谷、陡崖、城镇，亦见村落。常成对或小群活动，冬季聚大群。鸣声短而干涩。远观易与沙燕属“Riparia”混淆，但白斑尾为其特征；与红喉岩燕分布几无重叠。","appearance":"体长11–14厘米，体重16–30克。指名亚种（P. f. fuligula）头顶至上背深土褐色，翼、尾更暗；尾方形，除中央及外侧1–2对外，其余尾羽内翈具白斑。颏、喉淡粉肉桂色，延至上胸及覆腿羽；腹及尾下覆羽深灰褐。两性同色。幼鸟上体羽缘泛浅黄。亚种anderssoni较指名型更淡、更灰且略小；pretoriae则略大且更淡。","call":"通常寡言，偶发短促干涩颤音“chrrr”；亦有一声下滑“tsee”。繁殖期雄鸟鸣唱为徐缓而悦耳的长串啭鸣，含吱吱哨音、干哑咯咯声及咯咯颤音。飞行联络声为短促“chrrr”，遇巢捕食者时发出急促“tsee”警报。","habits":"栖于山地、悬崖、峡谷、海岸及城镇建筑，海拔可达3300米，多见于干旱荒漠。留鸟，局部数量随食物波动。非繁殖期成群，夜栖建筑上可数百只。飞行缓慢，常沿崖壁或建筑滑翔；觅食贴近崖面及地面，亦随草地火灾捕食。晨昏活跃，傍晚仍觅食。食物为双翅目、鞘翅目、半翅目、膜翅目（含飞蚁）等飞行昆虫，偶落地取食。常与雨燕科及其他燕科混群。","breeding":"繁殖期因地而异：西非5–7月及10–12月；埃塞俄比亚1–3月及10–12月；东非全年，各地有峰；安哥拉2月；赞比亚2–4月与7–11月；津巴布韦1–4月与8–11月；南部非洲8月至翌年4月（峰9–1月），卡拉哈里雨后随时繁殖，一年可育3窝。单对或松散小群（约40对）营巢，巢域具攻击性。巢为直径约150毫米、深50–70毫米的开放半杯或全杯，以泥丸外筑、内衬植物纤维与羽毛，贴于岩壁突出处、水坝、桥洞或屋檐横梁；旧巢连续使用，非繁殖期亦作夜栖。每窝2–3枚白底黑至栗色斑卵，集中于钝端，17.1–19.5×12–14毫米；隔日产卵，双亲孵卵16–18天，雏鸟22–29天离巢，仍就近扑飞数日，亲鸟继续喂19天。巢偶被非洲白腰雨燕及小雨燕侵占。已知最老环志个体6年9个月。","identification":"与沙燕属（Riparia）区别：非洲岩燕尾具白斑且无胸带。与红喉岩燕及灰喉燕区分：前者体型更小、上体更深、喉部粉黄褐与胸腹灰褐分界明显；后者体型稍小、羽色更淡、喉胸色浅。三者分布区极少重叠。亚种间差异主要为羽色深浅及体型大小。","protection":"IUCN: LC（无危）。分布广泛且总体常见，博茨瓦纳和纳米比亚较稀少。开普敦密度约每平方千米5对。因专性巢址需求局部稀少，但亦利用农场建筑繁殖。与雨燕存在巢位竞争，尚无显著种群影响。","distribution":"繁殖区：安哥拉西北及西南部、纳米比亚大部、博茨瓦纳、南非西部至南部、津巴布韦西南、莫桑比克南部（Lebombo山脉）至南非东部。非繁殖期局部游荡，形成小群。","other":"系统分类上，非洲岩燕常与灰喉燕及红喉岩燕被视为超种“Rock Martin”。分子系统学显示其与属内其余四种（红喉岩燕、灰喉燕、岩燕、纯色岩燕构成姐妹群关系。"},{"name":"纯色岩燕","english_name":"Dusky Crag Martin","scientific_name":"Ptyonoprogne concolor","overview":"纯色岩燕（英文名：Dusky Crag Martin，学名：Ptyonoprogne concolor），是雀形目燕科岩燕属的鸟类。以其全身近黑色的外观著称。主要分布在印度次大陆至中国西南部和泰国北部、越南、老挝的部分地区。该物种在印度德干高原首次被发现。","appearance":"纯色岩燕长约13厘米，体型宽大，翼展宽阔，尾部短而方正，尾羽末端有小白斑点。上体呈烟熏般的褐色，下体略淡，喉部和胸前有暗褐色条纹。成鸟和幼鸟颜色相似，但幼鸟的喉部更淡，羽缘带有红褐色。喙小而主要为黑色，腿呈棕色。","call":"纯色岩燕的叫声柔和，通常发出'chit-chit'的声音，无论是休息还是飞行中。","habits":"纯色岩燕栖息于多崖的山区，偏好在山谷、山前开阔地带或沿河流飞行捕食。它不迁徙，主要在中国云南南部和西藏东南部的1000-2000米海拔处活动。它以空中飞行捕食昆虫为主，如金龟子、蚊子、姬蜂等。","breeding":"繁殖季节为5月至7月，纯色岩燕在靠近水体的山崖或岩壁缝隙中筑巢。巢由混合羽毛的小泥丸堆砌成半球形，内部铺设细软的杂草和羽毛。通常成对单独筑巢，偶尔形成松散的群体。每窝产卵3至5枚。","identification":"与非洲岩燕属其他物种相比，纯色岩燕具有更暗的下体颜色和较小的白色尾斑。飞行时速度较慢，但在需要时能迅速加速。","protection":"IUCN：LC（无危）","distribution":"纯色岩燕主要分布于印度次大陆至中国西南部，包括泰国北部、越南和老挝的部分地区。在中国，主要分布在云南南部和西藏东南部。","other":"尽管其自然繁殖地为悬崖峭壁，纯色岩燕也适应了利用人类建筑作为替代巢址，如旧堡垒、桥梁和城市中的石制建筑。"},{"name":"西方毛脚燕","english_name":"Western House Martin","scientific_name":"Delichon urbicum","overview":"西方毛脚燕（英文名：Western House Martin，学名：Delichon urbicum），是雀形目燕科毛脚燕属的鸟类。又称: 毛脚燕、普通毛脚燕，小型，迁徙性，以其蓝黑上体、显著的白色臀部和纯白下体为特征。分布广泛，自欧洲、北非至亚洲帕拉尔地区繁殖，冬季则迁移至撒哈拉以南非洲及热带亚洲。与人类关系密切，常在建筑下缘筑巢。","appearance":"成年西方毛脚燕体长约13厘米，翼展可达26至29厘米，体重平均18.3克。上体呈钢蓝色，具白色臀部和下体，包括白色翅膀下部；腿短，覆有白色绒毛。眼棕色，喙小且黑，趾及裸露腿部粉红色。雌雄相似，幼鸟较暗，部分翼羽具白色尖端和边缘。两个亚种存在差异，但主要体现在尾部形状和白色臀部的大小上。","call":"发出柔和的颤音鸣叫，包括雄鸟全年歌唱的旋律啾啾声，以及硬质的‘chirrrp’接触叫声和尖锐的‘tseep’警报声。","habits":"偏好开阔地带，如牧场、草地和农田，尤其近水区域。城市环境中，若空气清洁，亦能在市中心筑巢。与树相关联，提供食物和栖息地。在繁殖季节返回欧洲，迁徙途中在大水域捕食昆虫，白天迁徙。1974年瑞士阿尔卑斯山脉的大规模死亡事件揭示了极端天气对其生存的影响。","breeding":"春季返回繁殖地，巢建于建筑下沿，由两性共同使用泥球和软材料筑造。每窝产4至5枚白色卵，孵化期14至16天，幼鸟需22至32天离巢，之后一周仍受父母喂养。每年通常有两窝，巢可重复使用并维修。","identification":"与烟腹毛脚燕相比，西方毛脚燕胸部纯白而非烟灰色，白色臀部区域更大，尾部开叉更深。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆温带地区，东至中蒙古和叶尼塞河，及北非部分地区。越冬于撒哈拉以南非洲及东南亚。在中国北方有分布记录。","other":"与家燕有杂交记录，显示其与Hirundo属遗传距离可能不大。"},{"name":"烟腹毛脚燕","english_name":"Asian House Martin","scientific_name":"Delichon dasypus","overview":"烟腹毛脚燕（英文名：Asian House Martin，学名：Delichon dasypus），是雀形目燕科毛脚燕属的小型鸟类。具有黑色上体和白色的腰，下体沾有灰色调，分布于喜马拉雅山脉到日本，冬季迁徙至东南亚等地。","appearance":"烟腹毛脚燕体长约12厘米，重约18克，上体呈有光泽的深蓝色，下体白色沾染灰色调，尾巴略呈叉状，翅膀和尾部为暗褐色。成年鸟的上翼覆羽较短，尾羽黑色带棕色，腿上有白色羽毛覆盖，翼下覆羽为灰褐色。幼鸟外观较暗淡，下体沾有灰褐色，三级飞羽尖端白色，尾部形状更方。三个亚种主要在大小和色彩上有所不同。","call":"烟腹毛脚燕的鸣唱为柔和的金属颤音或嘶嘶声，叫声为尖锐的接触声。","habits":"烟腹毛脚燕主要栖息于山地山谷和海岸悬崖，冬季则向低海拔开放或丘陵地带迁移。它们通常在悬崖下的洞穴或裂缝中筑巢，也会选择大型人造建筑如寺庙、桥梁、酒店或发电站。迁徙模式主要是季节性的，部分鸟群会迁至东南亚过冬。","breeding":"繁殖期为3月至10月，南方则为4月至7月，每窝产2至6枚蛋，通常3至4枚，由两性共同孵卵和喂养幼鸟。巢由泥球构成，内部铺有草或羽毛，有时未完全封闭，仅顶部开口。","identification":"烟腹毛脚燕与北方毛脚燕和尼泊尔毛脚燕相似，但腹部沾有灰色调，介于两者之间。与小白腰雨燕相比，其尾羽较短，翅膀更宽，身型更圆润。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚南部和东部，冬季迁徙至远东地区。在中国中东部、青藏高原繁殖，冬季南迁至东南亚、菲律宾及大巽他群岛。"},{"name":"黑喉毛脚燕","english_name":"Nepal House Martin","scientific_name":"Delichon nipalense","overview":"黑喉毛脚燕（英文名：Nepal House Martin，学名：Delichon nipalense），是雀形目燕科毛脚燕属的鸟类。非迁徙性，主要分布在喜马拉雅山脉至越南西北部。其最显著的特征是蓝色的头部侧面延伸至眼下方，黑色的喉咙和白色的腹部。在海拔1,000至4,000米的河谷和山脊上筑巢，通常在悬崖下的悬垂处集体繁殖。","appearance":"成年黑喉毛脚燕体长约13厘米，上身蓝黑色，下身白色，拥有独特的纯白色臀部。尾巴和翅膀上方为棕色，下翼为灰色。腿和脚呈棕粉色，覆有白色羽毛。眼睛为棕色，喙为黑色。雌雄外观相似，幼鸟光泽较弱，喉咙颜色较暗，下体呈淡黄色。与亚洲和普通毛脚燕相比，黑喉毛脚燕具有更广的头部黑色区域，黑色的臀部羽毛和方形的尾巴。","call":"这种燕子偶尔会发出短暂的‘chi-i’声，除此之外，它通常较为安静。","habits":"黑喉毛脚燕生活在海拔1,000至4,000米的河谷和山脊地带，主要活动在低于3,000米的高度。它们群居，以飞虫为食，常与其他燕子一起飞翔捕食。繁殖期从3月至7月，有时会繁殖两次。","breeding":"繁殖季节，它们在悬崖下的悬垂处集体筑巢，巢由泥球构成，内部铺有草和羽毛。每窝产3至4枚白色蛋，孵化和喂养幼鸟的工作由双方共同承担，具体时间未知，但可能与普通毛脚燕相近。","identification":"与亚洲和普通毛脚燕相比，黑喉毛脚燕有更广泛的头部黑色区域，黑色的臀部羽毛和方形的尾巴，这三点是辨认的关键。","protection":"IUCN：LC（无危）","distribution":"黑喉毛脚燕主要分布在喜马拉雅山脉，从印度西北部至尼泊尔，再到缅甸北部、越南北部以及中国的部分地区。在中国，它们主要见于云南西南部和西藏东南部。","other":"尽管分布范围广泛，但在某些地区，如尼泊尔，黑喉毛脚燕的数量相当可观。"},{"name":"白腹毛脚燕","english_name":"Siberian House Martin","scientific_name":"Delichon lagopodum","overview":"白腹毛脚燕（英文名：Siberian House Martin，学名：Delichon lagopodum），是雀形目燕科毛脚燕属的小型鸟类。其显著特征为蓝黑色上体，宽阔的白色臀斑及雪白的下体。幼鸟在夏末秋初时期较成鸟颜色暗淡。该物种曾被认为是西方毛脚燕的亚种，现已独立为一单独物种。繁殖于东北亚的岩石地带，包括俄罗斯东北部、蒙古和中国北部，越冬于东南亚，如缅甸、老挝、越南和柬埔寨。","appearance":"成年白腹毛脚燕具有鲜明的蓝黑色背部，其最突出的特征是巨大的白色臀斑和纯白色的腹部。幼鸟相比成鸟，上体颜色较为暗淡，下体色彩略显污浊。与烟腹毛脚燕极为相似，但可通过更宽大的白色臀斑、更明亮的白色下体以及略微更大的体型加以区分。","call":"发出柔和的咕噜声。","habits":"白腹毛脚燕通常群居繁殖，偏好在建筑物屋檐下筑泥巢。它们在开阔和半开阔的环境中觅食，尤其偏爱水体附近及邻近的田野，飞行时翅膀拍打轻盈。","breeding":"繁殖季节，白腹毛脚燕会聚集形成群体，利用泥土构建巢穴，常选址于建筑物的屋檐下。具体繁殖行为包括求偶、筑巢、交配、产卵、孵化及育雏等过程。","identification":"与西方毛脚燕相比，白腹毛脚燕拥有更为显著的白色臀斑，这是辨识两者的要点。同时，白腹毛脚燕的下体更为洁白，体型稍大。","protection":"IUCN：LC（无危）","distribution":"繁殖于东北亚的岩石地带，包括俄罗斯东北部、蒙古和中国北部。越冬区域延伸至东南亚，覆盖缅甸、老挝、越南和柬埔寨。","other":"历史上，白腹毛脚燕曾被视为西方毛脚燕的亚种，但基于形态学和声音差异，现已被确认为独立物种。"},{"name":"大纹燕","english_name":"Greater Striped Swallow","scientific_name":"Cecropis cucullata","overview":"大纹燕（英文名：Greater Striped Swallow，学名：Cecropis cucullata），是雀形目燕科斑燕属的鸟类。以它独特的深蓝色上部羽毛、橙色臀部和栗色头冠著称。分布于非洲赤道以南地区，主要栖息于南非、纳米比亚和津巴布韦南部。","appearance":"大纹燕体长18–20厘米，体重19–35克。头部前额和头顶呈暗栗色，颈侧和后颈颜色较浅，背部光泽深蓝，臀部和较短的上尾覆羽淡栗色。翅膀和尾巴为棕色，外侧尾羽延长形成流线型，内侧尾羽有白色斑点，除最内侧两对外。下体淡黄色带细密的褐色条纹（近距离可见），尾下覆羽淡黄色，翼下覆羽淡黄色。与小纹燕相比，体型更大，头顶颜色更深，下体条纹更细。雌鸟尾部比雄鸟短，幼鸟色泽较暗淡，头顶更黑，臀部颜色更浅，内侧次级飞羽和翼覆羽有棕褐色尖端，尾部较短。","call":"鸣唱以几个‘chrrp’音开始，逐渐下降至颤音结尾；也会发出‘chrrp’声和哀怨的‘wheep’声。","habits":"常见于草地和湿地，但也可在其他生境发现，尤其是在迁徙期间。通常群居，有时与其他燕子混群。偏好干燥的开阔地带，如草原，偏好山地和丘陵，避免林木茂密地区，但常在人类居住区附近被发现。","breeding":"繁殖季节主要在11月至翌年3月在纳米比亚，11月至翌年4月在博茨瓦纳，8月至翌年3月在津巴布韦，9月至翌年5月在南非（高峰期10月至12月）。可能有多至三窝，记录显示一巢可有四窝。独巢繁殖，但单个建筑上可能有多个巢。雄鸟通过空中展示和鸣唱吸引雌鸟；唱歌时会仰头并膨胀喉部羽毛。巢由两性共同建造，需时2-3周，为封闭式，有管状入口，由泥球构成，内衬草和羽毛。通常附着于岩石面、洞穴、树、桥、涵洞、矿井或谷仓等建筑物的水平表面高处。巢可重复利用于同季和连续数季。一窝产2-4枚卵，通常3枚；孵化由雌鸟单独承担，周期16-20天，多数为18天；雏鸟异步孵化，由两性喂养，离巢期23-30天；幼鸟离巢后返回巢穴继续停留9-22天。巢损失原因包括恶劣天气、寄生虫侵扰（如 Hippoboscid flies (Ornithomya)）、巢从波纹屋顶坠落，以及被其他物种侵占，如非洲白腰雨燕、和聊天鸟（Myrmecocichla 和 Thamnolaea属）。已知最老的记录为6岁5个月。","identification":"与较小的小纹燕区别在于后者具有更重更深的下体条纹、更深的红色臀部，以及栗色而非淡黄色耳羽。小纹燕偏好较为封闭的生境。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于安哥拉和纳米比亚至津巴布韦南部，至南非南部；非繁殖期向北迁至安哥拉北部、赞比亚、刚果民主共和国南部和坦桑尼亚西南部。"},{"name":"小纹燕","english_name":"Lesser Striped Swallow","scientific_name":"Cecropis abyssinica","overview":"小纹燕（英文名：Lesser Striped Swallow，学名：Cecropis abyssinica），是雀形目燕科斑燕属的鸟类。如更少而细的腹部条纹，尤其是在喉部和耳羽区，外观更为开放。","appearance":"小纹燕体长15至19厘米，体重16至27克。其头部至颈背部、耳羽覆盖和颈部呈红栗色，背部光泽深蓝色，臀部和较短的上尾覆羽为红栗色；翅膀和尾巴黑褐色，外侧尾羽形成长流苏，内侧尾羽有白色斑块，除最内侧两对外；腹部白色带有宽咖啡色条纹，条纹在喉咙和上胸处最为密集；下尾覆羽白色带淡黄色调；下翼覆羽淡黄色。与大纹燕相比，小纹燕体型较小，冠部颜色较浅，腹部条纹更大胆。雌鸟尾巴比雄鸟短，幼鸟较为暗淡，冠部颜色更深，臀部颜色较浅，翼覆羽和内侧二级飞羽有淡褐色尖端，尾巴较短。","call":"小纹燕的鸣唱有力，开始时有吱吱声，随后是下降的鼻音；同时发出嘶哑的‘cheeew’叫声。","habits":"小纹燕在草甸、林地和耕地上空成对或小群觅食，通常在比大纹燕更低的海拔高度活动。它们的飞行较为强劲，类似于家燕。","breeding":"繁殖季节主要在雨季，南赤道以北主要集中在3月至7月/8月（例如在塞内加尔和冈比亚为3月和7月，在利比里亚从4月开始，在塞拉利昂为3月至5月，在多哥和尼日利亚为3月至7月，在加纳和埃塞俄比亚为3月至8月，在苏丹为7月至8月），但在加蓬可能全年都有繁殖活动；东非大部分地区为2月至8月和10月至12月；安哥拉为1月至2月和6月至11月，刚果民主共和国为7月至10月，赞比亚西部为5月至8月，东部地区为9月至4月，马拉维为7月至2月，纳米比亚和博茨瓦纳北部为3月至10月，津巴布韦多数月份都有繁殖活动，但主要集中在9月至1月（unitatis和ampliformis两种可能在范围内重叠，但前者在8月至5月繁殖，高峰期在8月至12月，后者在3月至10月繁殖）；莫桑比克为5月至8月和10月至12月，在南非为8月至5月（高峰期为11月至12月），可能有二次繁殖。筑巢由双亲共同承担，耗时可达7周，巢为封闭的碗形，有入口通道，由泥丸制成，内衬草和羽毛；通常位于地面数米以上，固定在洞穴、岩石、河岸、悬崖、树、建筑物（室内或屋檐下）、门廊、涵洞、矿井、井或桥下的水平面上；有时会利用旧的燕子巢作为基础，然后封闭并添加通道；也会向巢箱添加通道；巢被重复使用，有时由不同的个体使用。每窝产卵2至4枚，通常为3枚；仅由雌鸟孵化，持续14至21天；雏鸟由双亲喂养，每小时3至9次喂食，离巢时间为17至28天；幼鸟离巢后几天内会返回巢中栖息。有时巢会被非洲白腰雨燕和桂红蚁䳭占用。已知最老的记录为5年11个月。","identification":"小纹燕与大纹燕相比，腹部条纹更重更深，臀部颜色更深，头部色彩更亮。","protection":"IUCN：LC（无危）","distribution":"小纹燕广泛分布于非洲中南部地区，从塞拉利昂和苏丹南部到南非东部。"},{"name":"褐胸燕","english_name":"Red-breasted Swallow","scientific_name":"Cecropis semirufa","overview":"褐胸燕（英文名：Red-breasted Swallow，学名：Cecropis semirufa），是雀形目燕科斑燕属的鸟类。最显著的特征是砖红色的臀部和下体，上体呈深蓝色，头部侧面有金属蓝斑块覆盖耳朵和眼睛。这种燕子在赤道附近常驻，于其分布范围的北部和南部湿季繁殖。","appearance":"褐胸燕体型较大，全长约24厘米，体重25至40克。头部和上体光泽蓝黑色，颈部侧面、臀部及下体为栗色；翅膀和尾巴为蓝黑色，外侧尾羽形成长长的流苏。翼下覆羽淡栗色，尾羽内侧有白色斑点（除中央两对）。雌鸟比雄鸟尾部稍短，幼鸟颜色较暗淡，翼下覆羽和次级飞羽尖端呈浅黄色，尾部更短。","habits":"褐胸燕在稀疏林地、草地、湿地边缘和其他开阔地带飞行，飞行强劲，频繁俯冲和改变方向。它们通常在干燥开阔的乡村栖息，但在树木较多的区域被类似种类的燕子所替代。它们利用铁路桥等人类建造的结构筑巢。","breeding":"褐胸燕在雨季繁殖，如在西非的4月至8月，在刚果民主共和国的4月至7月和10月至12月。巢由两性共建，呈壶状，入口长而管状，用泥制成，内部铺以草、毛和羽毛。巢址多样，包括离地面1米内的悬壁、岩面、桥下、房屋横梁等。每窝产卵1至6枚，平均3枚，由雌鸟孵卵，孵化期16天，雏鸟在23至25天后离巢，之后继续在巢中休息长达15天。","identification":"褐胸燕与塞内加尔燕区别在于翼下前部的颜色（前者为黄褐色，后者为白色），以及塞内加尔燕有淡色喉部。与金腰燕的区别在于尾羽上的白点和缺乏红领。","protection":"IUCN：LC（无危）","distribution":"褐胸燕分布于撒哈拉以南非洲大部分地区，从东非角到纳米比亚北部和安哥拉南部，东部至莫桑比克，西部从塞内加尔至刚果北部，东部至乌干达、肯尼亚西南部和坦桑尼亚西北部。在南非为夏季候鸟，7月至3月间筑巢，多数个体迁徙至赤道非洲。"},{"name":"塞内加尔燕","english_name":"Mosque Swallow","scientific_name":"Cecropis senegalensis","overview":"塞内加尔燕（英文名：Mosque Swallow，学名：Cecropis senegalensis），是雀形目燕科斑燕属的鸟类。大型燕科鸟类，以其锈红色腹部、浅色喉部和飞行时显眼的白色翼下边缘为显著特征。主要分布在非洲次撒哈拉地区，尤其是在西部地区最为常见。虽然不进行长距离迁徙，但会随雨季移动。","appearance":"塞内加尔燕体长21至23厘米，重量38至54克，冠部和背部呈光泽的深蓝色，面部两侧和头部侧面形成白色领圈，臀部暗红褐色，喉咙和上胸部淡红褐色，其余下部较深。雌鸟与雄鸟相似，但尾流线较短；幼鸟颜色较暗，呈棕色。非常浅的下翼覆羽与深色飞羽形成鲜明对比。","call":"其鸣唱为鼻音、哼唱和吱嘎声的混合曲调，叫声包括鼻音‘nyaa’接触叫声，独特的管状‘pyuuuu’声和‘mew’与‘weh’声。","habits":"栖息于草地、灌木丛、森林边缘，尤其是摩帕尼树林，河流、农耕区及人类居住区附近。海拔可达约2800米。它们在空中捕食昆虫，如蚂蚁、白蚁翅膀和苍蝇，通常在地面以上2至30米的高度活动。","breeding":"在西非雨季前和期间繁殖，如塞内加比亚的7月至10月和12月，加纳的1月、4月至7月和10月，尼日利亚的5月至8月等。巢由双方共同建造，需时长达4周，呈葫芦状，入口为长隧道，由泥巴制成，内衬草和羽毛。巢址多选在树洞中，尤其是猴面包树，也可能在河岸、白蚁丘、悬崖、桥下、涵洞或建筑物内外。","identification":"与红胸燕的幼鸟容易混淆，但塞内加尔燕缺少后者特有的深色‘耳瓣’和淡色前部下翼。与褐胸燕相比，体型更大，尾流线更短，下翼覆羽更白，尾部无白色斑点；与金腰燕相比，体型更大，喉咙和下翼覆羽颜色更淡，下尾覆羽红褐色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲，从毛里塔尼亚南部和塞内加尔向东至西苏丹西部，南至纳米比亚、博茨瓦纳北部、津巴布韦、莫桑比克和南非东北部。在南非，它们偏爱密集的阔叶林，如摩帕尼树林，也出现在米奥诺森林，散布着猴面包树和铅木。"},{"name":"金腰燕","english_name":"Red-rumped Swallow","scientific_name":"Cecropis daurica","overview":"金腰燕（英文名：Eastern Red-rumped Swallow，学名：Cecropis daurica），是雀形目燕科斑燕属的小型鸟类。又名: 赤腰燕，最显著特征为亮栗红色腰羽，与蓝黑色上体形成强烈对比，腹面密布黑色纵纹。该种广泛分布于南亚、东南亚及东亚，自印度西北部向东延伸至日本，向南可达小巽他群岛；北方族群具迁徙性，南方族群多为留鸟。","appearance":"体长 16–19厘米，体型粗壮，尾长而深叉，飞行缓慢且飘逸。成年雌雄同色：额、头顶至背呈钢蓝或蓝绿色，腰部栗红；尾上覆羽栗色，外缘具黑蓝色光泽；喉至上胸密布粗黑纵纹，腹部白色或淡棕，密布黑色纵纹；尾羽黑褐具蓝光，外侧尾羽显著延长。幼鸟羽色较暗，腰羽色淡，尾叉较浅，翼覆羽与三级飞羽具淡黄褐色端斑。","call":"鸣声为柔和细碎的啭鸣；联络叫声为短促尖细的“pin”或拖长似麻雀的“quitsch”。南方亚种的叫声较北方亚群更带金属颤音，略显尖锐而少粗哑。","habits":"栖息于开阔且近水的环境，如丘陵、山谷、稻田、林缘、村镇及农田，海拔范围从海平面至约 3900 米。北方族群春季北上繁殖，秋季结群南下越冬，可与其他燕类及雨燕混群；南方族群多为留鸟。觅食时低空掠过水面或高空盘旋，捕食飞虫，包括蝉、蚊及双翅目昆虫，亦会趋近草地火灾捕食惊起的昆虫。","breeding":"繁殖期因地区而异：北方 4–8 月，日本 6–7 月，南方亚群 4–7 月。巢为泥丸砌筑的壶状或曲颈瓶状结构，常附于岩壁、桥洞、屋檐或室内天花板下，内衬干草及少量羽毛。每窝 2–6 枚卵，白色具光泽，偶见淡红细斑；卵大小随地区略异。孵化期及育雏期尚缺数据。","identification":"与家燕、洋燕区别：二者腰羽均无栗红色，胸腹无显著纵纹。棕嘴斑腰燕下体及腰羽呈暗栗色，纵纹极弱。斯里兰卡燕下体全栗色，腰羽同色，与本种差异明显。亚种间差异：指名亚种 daurica 具完整栗色领环；japonica 领环中断，腰羽隐约具细纹；striolata 领环常中断，腹面纵纹更粗；mayri 与 stanfordi 纵纹最宽，后者具明显黑色腿斑；vernayi 下体带显著棕色调，腰羽无纹。","protection":"IUCN: LC（无危）。金腰燕分布广泛且能适应人工巢址，整体种群稳定，日本自 1950 年代起北扩至北海道。","distribution":"繁殖区：自印度西北部向东至中国东北、朝鲜半岛及日本；喜马拉雅山系至缅甸北部；华南、台湾及菲律宾；东南亚大陆至印尼爪哇、小巽他群岛（东至帝汶）。非繁殖区：印度南部、斯里兰卡、东南亚大陆及岛屿，北方迁徙个体可远达新几内亚、北澳大利亚，亦曾迷鸟至北欧。","other":"分类曾长期混乱，现今将“斑腰燕”复合体的各亚种并入金腰燕。棕嘴斑腰燕与斯里兰卡燕原被视作本种亚种，现已独立成种。"},{"name":"斯里兰卡燕","english_name":"Sri Lanka Swallow","scientific_name":"Cecropis hyperythra","overview":"斯里兰卡燕（英文名：Sri Lanka Swallow，学名：Cecropis hyperythra），是雀形目燕科斑燕属的鸟类。原作为金腰燕的亚种，现在被认定为独立物种。其最显著的外部特征是整个下体呈现深栗红色，且尾部分叉明显。","appearance":"成年斯里兰卡燕体长约13-14厘米，上部呈非常暗的蓝黑色光泽，下体和臀部为深栗色，几乎无条纹，胸部无明显的栗色颈环。尾羽较短，不如金腰燕延长。雄鸟和雌鸟外观相似。幼鸟色彩较为暗淡，尾羽更短，条纹更少。","call":"未提供具体描述。","habits":"栖息于斯里兰卡低地和山脚的各种开阔地带，包括农田和轻度森林覆盖区。通常以单个、成对或小群体出现。觅食行为类似其他斑燕种类，单独、成对或小群活动，与其它燕子混群。飞行缓慢，频繁滑翔和翱翔，既在低空植被上觅食也在高空活动。","breeding":"繁殖季节主要在3月至7月，但也记录到11月至1月。通常单独繁殖，有时几个配对形成松散群体。雄鸟在雌鸟周围盘旋并发出叫声，雌鸟停歇时，雄鸟可能靠近并唱歌，有时展示尾羽。巢由两性共同建造，封闭式，入口为隧道状，由泥团构成，偶尔混入少量干草，内部铺垫羽毛、毛发、植物绒毛、叶子或干草。巢通常固定在自然或人造水平面下方，如悬崖、岩石表面、洞穴、涵洞、桥梁等。巢在同季和连续季节重复使用。每窝产卵2-3枚，由两性共同孵化，但无更多细节。","identification":"无标记的深红褐色下体和臀部是与岛上所有其他燕子种类区分的关键。与金腰燕相比，尾羽更短，无明显的胸后颈环。","protection":"IUCN：LC（无危）。限制范围物种，仅在斯里兰卡生态区发现。普遍认为数量较多，目前未知有重大威胁。","distribution":"东洋界：斯里兰卡，仅限于该国。","other":"无"},{"name":"西非燕","english_name":"West African Swallow","scientific_name":"Cecropis domicella","appearance":"拥有显著的白色或粉褐色腹部，少有条纹，这一特征与相近种如金腰燕有所区别","distribution":"西非燕的地理分布覆盖了非洲西部，具体从塞内加尔河盆地一直延伸到东苏丹。","other":"现为非洲金腰燕亚种。"},{"name":"斑腰燕","english_name":"Striated Swallow","scientific_name":"Cecropis striolata","overview":"斑腰燕（英文名：Striated Swallow，学名：Cecropis striolata），是雀形目燕科斑燕属的鸟类。俗名: 粗纹燕，典型的燕科鸟类，拥有鲜明的特征，如深蓝的背部、橙色的腰部和带有细黑斑点的淡色下体。分布于东南亚至东北印度和台湾，偏好开阔的丘陵地带和农业区。","appearance":"成鸟斑腰燕长约19厘米，重约22克。头顶和背部呈光泽的钢蓝色，颈后可能有模糊或缺失的红褐色环，臀部栗色，有细条纹，尾羽黑色带蓝光泽，尾深深分叉。脸颊白色带浅褐色条纹，下体白色带浓密条纹，尤其在喉部密集。雌雄相似，幼鸟色泽较暗，背部偏棕色，红褐色部位较淡，翅膀覆羽和三级飞羽有浅色尖端，尾羽较短。","call":"其鸣唱柔和，为轻快的颤音；叫声包括飞行中的\"pin\"或\"quitsch\"。","habits":"栖息于开阔的丘陵地带、河流峡谷、森林空地、农田和人类居住区，海拔可达约2560米。主要以飞行昆虫为食，如蚊子和蝉，单独或小群体觅食，飞行高度较低或沿悬崖面，有时高飞。部分种群迁徙，如mayri和stanfordi亚种冬季南移。","breeding":"繁殖期在4月至7月，单独或小群体繁殖，巢由泥球构成，有长隧道，内部铺干草和羽毛，附着于岩石面、洞穴顶、桥梁、建筑物等。每窝产3-5枚蛋，通常4枚，孵化和育雏期未知。","identification":"与金腰燕相似，但体型更大，条纹更重，颈环不明显。斑腰燕颈侧的棕栗色延伸较少，与金腰燕的连环颈环和不完整的蓝色边缘不同。斑腰燕腰侧常有纵纹，末端可成点斑，而金腰燕腰侧无纵纹或无点斑。","protection":"IUCN：LC（无危）","distribution":"分布自东北印度、缅甸、泰国到东南亚，菲律宾、台湾和印尼，排除马来半岛。在中国大陆，云南南部常见，台湾普遍。","other":"在一些地区，如东南亚，由于人工巢址如桥梁的存在，其数量有所增加。现为金腰燕亚种。"},{"name":"棕嘴斑腰燕","english_name":"Rufous-bellied Swallow","scientific_name":"Cecropis badia","overview":"棕嘴斑腰燕（英文名：Rufous-bellied Swallow，学名：Cecropis badia），是雀形目燕科斑燕属的鸟类。分布于马来半岛。其深红褐色的下体略带条纹，臀部无条纹，通常被提升至物种级别，与近亲斑腰燕区别明显。","appearance":"该燕鸟上体呈现深邃的蓝黑色光泽，下体及臀部为鲜明的锈橙色，无条纹装饰。头部脸部亦呈锈橙色，与斑腰燕相比，缺乏后者特有的深蓝色领圈和白色尾翼斑点。","habits":"棕嘴斑腰燕飞行于多种生境之上，从开阔的田野到茂密的森林皆可见其身影，偏好丘陵地带。它们在不同环境中穿梭，展现灵活的飞行技巧。","identification":"与迁徙型的家燕tytleri亚种相似，但棕嘴斑腰燕缺乏深蓝色颈环及白色尾端斑点，这成为两者间重要的识别特征。","distribution":"主要分布在马来半岛，属于东洋界范围内的特有种。"},{"name":"红喉燕","english_name":"Red-throated Cliff Swallow","scientific_name":"Petrochelidon rufigula","overview":"红喉燕（英文名：Red-throated Cliff Swallow，学名：Petrochelidon rufigula），是雀形目燕科石燕属的鸟类。小型燕子，以其独特的红喉和蓝黑色的上部特征而闻名。分布于非洲中部，包括加蓬南部、刚果共和国、刚果民主共和国、安哥拉中部和赞比亚中部。","appearance":"红喉燕体长约12厘米，重约16克。其头部和上体呈深蓝色光泽，后颈和肩部有微弱的白色条纹，臀部红色；翅膀和尾巴为黑褐色，尾巴略微分叉，尾羽内侧有白色斑点（除了中间一对）。下巴、喉咙和上胸部为红色，下胸部、腹部、侧腹和翼下覆羽为淡黄色，较短的尾下覆羽为红色，较长的为黑色，边缘淡黄色。与非洲斑燕相比，体型更小，前额蓝色而非红色，喉咙纯红色。雄雌外观相似。幼鸟颜色较暗淡，棕色，红区颜色较浅，腹部有粉色晕染。","call":"红喉燕发出清脆的啾啾声，飞行时会发出尖锐的‘tre-tre-tre’叫声。","habits":"红喉燕栖息于开阔的草地和耕作地带，常靠近水源和悬崖。它们主要为居民或部分迁徙，东南部为迁徙种，出现在赞比亚的时间为4月至12月初。饮食以苍蝇等昆虫为主，通常成群觅食，与其它燕子和雨燕一起活动，飞行距离巢穴可达30公里。飞行姿态轻盈，常滑翔。","breeding":"繁殖期在安哥拉为7月至10月，在刚果民主共和国为4月和6月，在赞比亚为4月和9月至10月。红喉燕成群繁殖，形成数十到数百对的群体，巢穴紧挨着建造。巢穴封闭，有短管状入口，由泥球构成，内部铺有草，主要建在桥下或其它人造结构下，较少见于自然环境（如悬崖面、洞穴）。每窝产卵1-3枚；关于孵化和离巢期的信息未知。巢穴有时会被非洲白腰雨燕和小雨燕占据。","identification":"红喉燕与南非燕（Hirundo spilodera）的区别在于体型较小，前额蓝色，喉咙颜色纯红。南非燕体型更大，尾巴无白色，胸前有模糊的暗色围巾。","protection":"IUCN：LC（无危）","distribution":"红喉燕的分布范围主要在非洲中部，包括从加蓬南部至刚果民主共和国中部，南至安哥拉中部和赞比亚中部。","other":"自1970年代末起，红喉燕开始在加蓬定居并持续向北扩张，似乎也在赞比亚扩大其分布范围。这种扩展可能是因为筑巢地点的增加，如桥梁建设提供了更多栖息地。"},{"name":"普氏燕","english_name":"Preuss's Cliff Swallow","scientific_name":"Petrochelidon preussi","overview":"普氏燕（英文名：Preuss's Cliff Swallow，学名：Petrochelidon preussi），是雀形目燕科石燕属的鸟类。这种燕子在当地数量丰富，常见于桥梁、建筑物和涵洞附近，以其泥巢闻名。","appearance":"体长约12厘米，体重12至14克。头部深蓝色光泽，耳羽覆盖处亦然，眼后有一块锈色斑点。上体呈深蓝色，带有灰色条纹，臀部奶油色；翅膀和尾巴为黑褐色，尾巴略呈叉状，尾羽内侧有白色斑点（中央一对除外），外侧一对可能无斑点或斑点较小；喉咙、脸颊和下体，包括翼下覆羽，均为奶油色。雌雄相似，幼鸟较暗淡，棕色，下巴到胸部呈粉棕色，腹部白色带粉红色，下尾覆羽灰棕色。","call":"发出嘈杂的啾啾声；飞行中会发出‘prrp-prrp’的声音，以及‘pseep’的警报叫声。","habits":"生活在非洲西部至中部的地区，包括几内亚比绍、几内亚、塞拉利昂至尼日利亚东北部，喀麦隆和中非共和国，刚果民主共和国东北部。偏好桥梁、建筑物和涵洞周围的栖息环境。","breeding":"繁殖期在旱季末，主要为2月至6月；在马里为11月至7月；加纳为5月至6月，12月至1月，可能还包括2月至4月；多哥和尼日利亚为2月至7月。以成千上万对的形式形成群体，有时分为更小的集群，巢穴紧密相邻。巢由两性共同建造，形状似瓶，封闭，入口细长向下弯曲，由泥球构成，内部铺有草、种子和羽毛。通常建在水平面下，常位于水面上方的岩石、悬崖、涵洞、堤坝、矿井、桥或建筑物下。大型群体特别倾向于在桥下筑巢。每窝产2至3枚卵；孵化和离巢时间未有记录。河上的巢有时会被洪水破坏。","identification":"与西方毛脚燕相比，具有更深的奶油色臀部和下体，尾部有白色斑点，头部有锈色斑点。","protection":"IUCN状态未知。","distribution":"分布于非洲的几内亚比绍、几内亚、塞拉利昂至尼日利亚东北部，喀麦隆和中非共和国，刚果民主共和国东北部。"},{"name":"红海燕","english_name":"Red Sea Cliff Swallow","scientific_name":"Petrochelidon perdita","overview":"红海燕（英文名：Red Sea Cliff Swallow，学名：Petrochelidon perdita），是雀形目燕科石燕属的鸟类。仅知于1984年在苏丹东北部港口城市苏丹港附近的桑甘布发现一具死亡标本，其确切分布和生态至今鲜为人知。","appearance":"关于红海燕的外观描述非常有限，基于唯一已知标本，其特征包括喉部和上胸部分呈白色（而非蓝黑色），下巴深色（而非浅色），臀部淡红褐色至土黄色（而非灰色）。","habits":"由于资料稀缺，红海燕的生活习性和栖息环境仍是个谜，推测可能栖息于苏丹或厄立特里亚的红海山脉，或沙特阿拉伯西部沿海山区。","identification":"红海燕与同类物种的区别在于其独特的颜色模式，尤其是喉部、下巴和臀部的颜色，这在识别中至关重要。","protection":"IUCN：DD（数据缺乏）","distribution":"红海燕的分布极为不确定，仅记录于苏丹东部，可能的繁殖区域包括苏丹或厄立特里亚的红海山脉，以及沙特阿拉伯西部沿海山区北部（吉达以北）。"},{"name":"非洲斑燕","english_name":"South African Cliff Swallow","scientific_name":"Petrochelidon spilodera","overview":"非洲斑燕（英文名：South African Cliff Swallow，学名：Petrochelidon spilodera），是雀形目燕科石燕属的鸟类。体型健硕的燕科石燕属鸟类，拥有深蓝色与红褐色相间的羽毛，尾部呈锈色，腹部带暗纹，颈部有模糊的黑色领圈，可能不完整。该物种在南非、纳米比亚和津巴布韦的桥梁下、涵洞、采石场和偶尔的悬崖上形成10至1000对的群体繁殖，通常靠近水源。","appearance":"非洲斑燕具有独特的体态，其头部、背部和翅膀呈现深蓝色，腹部和臀部为红褐色，尾部下方和臀部锈色明显，颈部有一圈模糊的暗色环。与之相比，红喉燕较小且更纤细，尾巴有白色斑点，喉咙颜色均匀呈红褐色，胸部无暗色斑点。","habits":"非洲斑燕主要在草地、稀树草原和干旱灌木丛中寻找昆虫为食，它们在空中捕捉飞虫，展现出灵活的飞行技巧。迁徙期间，它们会从南半球的繁殖地迁移到刚果盆地过冬。","breeding":"繁殖季节在9月至次年4月间，非洲斑燕会在南非、纳米比亚和津巴布韦等地筑巢繁殖，巢穴建在桥梁下、涵洞内、采石场或悬崖下，通常选择靠近水体的地方。","identification":"与相似的红喉燕相比，非洲斑燕体型更大，色彩分布不同，尤其是尾部无白色斑点，且胸部有暗色斑点。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于非洲的纳米比亚、津巴布韦、博茨瓦纳东南部至南非南部。非繁殖期迁徙至刚果南部和刚果民主共和国中部。"},{"name":"黄额燕","english_name":"Streak-throated Swallow","scientific_name":"Petrochelidon fluvicola","overview":"黄额燕（英文名：Streak-throated Swallow，学名：Petrochelidon fluvicola），是雀形目燕科石燕属的小型燕类。其特征为头部和颈背呈暗栗色，背部光泽深蓝，带少量白色细纹，腹部淡黄色并带有黑色条纹，尤其是喉部和上胸部。分布于南亚，包括阿富汗东北部、巴基斯坦和印度等地。","appearance":"体长约11-12厘米，体重约8-12克。头部、颈背暗栗色，具微弱暗纹，背部光泽深蓝，翼和尾黑褐，尾端几乎方形。腹部淡黄色，带有黑色条纹，尤其在喉部、上胸和颈侧。幼鸟比成鸟更暗淡，羽缘带黄色，下体有模糊条纹。","call":"鸣声为啾啾声，常在栖息时发出。飞行中会发出尖锐的'trr trr'声。","habits":"栖息于开阔地带、山脚、农田和人类居住区，包括城镇，通常靠近水源，如运河、河流和湖泊。活动高度约1000米，主要在700米以下。以群体形式觅食，食物包括飞虫。飞行较弱，飘忽不定。","breeding":"繁殖期因地区而异，主要在3-6月北方，12月至翌年4月和7-10月南方。筑巢于悬崖、桥梁、涵洞、灌溉大坝或建筑物，巢由泥球构成，内部铺干草、马毛和羽毛。每窝产卵3-4枚，偶尔2枚，双亲共同孵化和喂养幼鸟。","identification":"与彩石燕相似，但头部更亮，颈侧有条纹。性成熟后无明显性别差异。幼鸟较成鸟暗淡，下体有模糊条纹。","protection":"IUCN：LC(无危)。在巴基斯坦常见，印度局部常见。由于与人类居住区相关的人工巢址增多，数量可能有所增加。","distribution":"繁殖于阿富汗东北部和喜马拉雅西北部，常年居留于巴基斯坦中部和东部、印度北部和中部至阿萨姆西部和卡纳塔克南部。冬季分布更南至印度南部。偶尔出现在马尔代夫、斯里兰卡和中东。"},{"name":"彩石燕","english_name":"Fairy Martin","scientific_name":"Petrochelidon ariel","overview":"彩石燕（英文名：Fairy Martin，学名：Petrochelidon ariel），是雀形目燕科石燕属的鸟类。小型燕子，分布于澳大利亚大部分地区，除塔斯马尼亚州和东南部部分地区。其独特之处在于群居筑巢，以泥巴构建独特的\"瓶状\"巢穴。","appearance":"彩石燕体型矮胖，尾部方形，平均体长12厘米，体重约11克。成鸟背部呈现虹彩般的蓝色，翅膀和尾巴为棕色，头顶和颈背呈红褐色，臀部白色。腹部颜色较淡，为灰白色。雄雌相似，但幼鸟色泽较为暗淡，前额色浅，背部和翼羽边缘颜色较淡。","call":"彩石燕发出响亮的\"chrrrr\"声和高音调的啾啾鸣叫，其叫声比树燕更为尖锐。","habits":"彩石燕栖息于靠近水源的开阔地带，常见于悬崖、涵洞或桥梁附近的巢址。它们迁徙至澳大利亚大部分地区过冬，部分个体会抵达新几内亚和印度尼西亚。在新西兰也有零星的游荡记录，甚至可能在此繁殖。","breeding":"彩石燕在8月至次年1月间繁殖，通常形成数十个巢的群体，最大记录为700个巢。巢建于树木死洞、河岸、悬崖或岩石裂缝中，越来越多地选择桥梁、涵洞、管道或建筑物上的人工地点。巢穴形状似烧瓶或瓶子，由上千个泥球构成，内部铺垫干草和羽毛，直径约15厘米，入口通道长5-30厘米。双亲共同筑巢、孵卵及育雏。每次产卵4枚，有时5枚，带有红褐色斑点的白色蛋，常进行二次或三次孵化。","identification":"彩石燕可通过其白色的臀部与澳大利亚其他燕子区分开来。最相近的物种——树燕，具有轻微分叉的尾巴和蓝黑色的头部与颈背。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于澳大利亚（除塔斯马尼亚州和澳大利亚东南部）。冬季迁徙至澳大利亚大部分地区，新几内亚和印度尼西亚也有分布记录。近年来，彩石燕在新西兰的游荡现象逐渐增加，可能已在此繁殖。","other":"当彩石燕的泥巢在繁殖季节结束后被废弃，可能成为几种微蝠的栖所，包括褶领蝠属（Chalinolobus）的物种和小长耳蝠（Nyctophilus geoffroyi）。"},{"name":"树燕","english_name":"Tree Martin","scientific_name":"Petrochelidon nigricans","overview":"树燕（英文名：Tree Martin，学名：Petrochelidon nigricans），是雀形目燕科石燕属的小型鸟类。拥有蓝黑色的背部和头部，棕色的翅膀和尾巴，以及白色的腹部。分布广泛，主要在澳大利亚南部地区，以及Timor岛，常见于开放林地近水处，亦适应城市环境。","appearance":"树燕长约13厘米，体重14至19克。成鸟有光泽深蓝色的冠、颈背，背部呈黑褐色，腹部白色，胸部略带灰色，两胁微泛淡锈色，尾部稍呈叉状。幼鸟较成鸟暗淡，羽色更偏向棕色，头部和翼部边缘颜色较浅。雌雄相似。","call":"树燕的叫声为清脆的啾啾声，其鸣唱则是一种高音调的啾啾声。","habits":"树燕栖息于开放林地靠近水源的地方，包括城市区域。它们会在树木周围、水域上空和农田上空觅食，有时甚至在海上捕食。树燕通常在6米以上高空快速飞行。","breeding":"繁殖季节一般为7月至次年1月，主要在8月至11月，雨后在干旱地区会额外繁殖。筑巢于树洞、悬崖、桥梁、建筑屋顶，有时利用巢箱。巢由干草、树叶构成，每窝产卵3至5枚，多为4枚。","identification":"树燕与彩石燕的区别在于尾形和臀部颜色，彩石燕的臀部较淡，头部和颈背呈锈色。","protection":"IUCN：LC（无危）","distribution":"树燕繁殖于澳大利亚南部及塔斯马尼亚，冬季迁徙至澳大利亚北部、新几内亚、小巽他群岛、摩鹿加群岛和所罗门群岛。偶尔作为迷鸟出现在新西兰和新喀里多尼亚。","other":"树燕偶尔会占据迎燕的巢穴，有时驱赶原主人以占据巢位。"},{"name":"美洲燕","english_name":"American Cliff Swallow","scientific_name":"Petrochelidon pyrrhonota","overview":"美洲燕（英文名：American Cliff Swallow，学名：Petrochelidon pyrrhonota），是雀形目燕科石燕属的鸟类。社会性极强的北美土地鸟，以群居繁殖而著称，单个巢穴群可达6,000个。原本栖息于西部山区岩石峭壁下的水平岩层，后随公路建设扩展至大平原和北美东部。以其每年3月19日返回Mission San Juan Capistrano的传说闻名。","appearance":"体长约13厘米，翼尖而宽，尾部方形。背部深褐色，具金属光泽，颊部砖红色，喉部暗色，腹部白色，臀部淡黄色。头部和颈部较其他北美燕子厚实。幼鸟颜色较淡，额头和喉部斑驳白色，个体间差异大。","habits":"栖息于近水区域，如田野、池塘附近。以飞行昆虫为食，常在空中优雅捕食。冬季迁徙至南美，如巴西南部、乌拉圭和阿根廷部分区域。","breeding":"春季归巢，通常选择桥梁、涵洞或建筑物下筑巢，巢由泥制成，呈葫芦状。每窝产卵3-4枚，雌雄共同育雏。存在寄生巢穴现象，雌鸟会将卵移入邻近巢穴。","identification":"与穴崖燕区别在于方形尾和淡黄色臀部，喉部颜色更深，前额淡色三角形斑纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布于北美和中美，非繁殖期迁徙至南美南部。","other":"其复杂的社会行为和适应性进化是生态学研究的重要对象，如群体规模的选择和快速环境适应性进化。"},{"name":"穴崖燕","english_name":"Cave Swallow","scientific_name":"Petrochelidon fulva","appearance":"穴崖燕体长约12至14厘米，平均体重约19克。最大亚种P. f. pallida翼展可达107.0至112.3毫米，而最小亚种P. f. aequatorialis翼展仅93.0至93.5毫米。雄雌两性外观相似，难以通过羽毛分辨。其上身呈灰蓝色，前额和喉部为棕色橙色。","call":"穴崖燕的叫声多样，包括歌曲、‘che’音符和三种类型的叽叽喳喳声，尤其是在繁殖季节的3月至8月间更为常见。成鸟会发出五种主要的鸣叫声，用于交流和警戒。","habits":"穴崖燕在开阔地带和水源附近觅食，主要以飞行中的昆虫为食。它们倾向于群居，特别是在繁殖期间。白天，它们会在巢穴附近的开放区域觅食。它们的春季和秋季迁徙路径尚不清楚，但一些南美和墨西哥的种群被认为是留鸟。","breeding":"繁殖发生在4月至8月之间，巢穴由泥和蝙蝠粪便构成，有时会利用旧的家燕巢。雌雄双方共同参与孵化，雌鸟会形成孵卵斑。每窝产3到5枚卵，孵化期约为20至22天。雏鸟为晚熟型，出生时盲眼，无法自给自足。","identification":"穴崖燕与悬崖燕极为相似，但可以通过较淡的喉部颜色、更鲜艳的侧面和腹侧以及更丰富的红褐色臀部来区分。在远处观察时，悬崖燕头部显得全黑，而穴崖燕则似乎有一个小的黑色帽顶，周围有明亮的领圈和苍白的脸部。","protection":"IUCN：LC（无危）","distribution":"穴崖燕在北美南部、加勒比海岛屿、墨西哥以及南美部分地区繁殖。它们在得克萨斯州、佛罗里达州、大安的列斯群岛以及墨西哥的某些地区有稳定的繁殖群体。南美种群主要分布在厄瓜多尔和秘鲁西北部。","other":"穴崖燕自1980年代以来在得克萨斯州南部过冬，显示了其适应性和扩散能力。"},{"name":"栗领崖燕","english_name":"Chestnut-collared Swallow","scientific_name":"Petrochelidon rufocollaris","overview":"栗领崖燕（英文名：Chestnut-collared Swallow，学名：Petrochelidon rufocollaris），是雀形目燕科石燕属的鸟类。居住在南美洲西部干燥地区的燕科石燕属鸟类，分布于厄瓜多尔西南部和秘鲁西部。其显著特征为深红栗色的颈环和前额，与类似物种区分明显。两个已知亚种分别分布在秘鲁和厄瓜多尔境内。这种燕子通常在城市和城镇周围集群生活，利用建筑屋檐筑巢。","appearance":"栗领崖燕体型中等，尾部呈方形或轻微凹陷，上体深蓝色，颈后具有一圈独特的红栗色颈环，臀部同色。下体白色，胸部带有红栗色带纹，两翼和尾部呈黑褐色。雌雄外观相似，幼鸟色泽较暗淡。","habits":"栗领崖燕偏好开阔地带，群居生活，常集体在空中捕食昆虫。它们的繁殖季节从一月持续到八月，期间会在悬崖或建筑屋檐下构建封闭式的泥巢。","breeding":"繁殖期在一月至八月，栗领崖燕会集群在适宜的地点，如悬崖或建筑物的屋檐下建造泥巢，进行繁殖活动。","identification":"与美洲燕相比，栗领崖燕具有红栗色的胸部带纹，而崖燕的喉部为暗栗色，无红栗色胸带。穴崖燕与之非常相似，但喉部和胸部为肉桂色，而非红栗色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于南美洲的厄瓜多尔西南部和秘鲁西部。"},{"name":"林燕","english_name":"Forest Swallow","scientific_name":"Atronanus fuliginosus","overview":"林燕（英文名：Forest Swallow，学名：Atronanus fuliginosus），是雀形目燕科 Atronanus 属的鸟类。属于 Atronanus 属，广泛分布在非洲喀麦隆、刚果（布）、赤道几内亚、加蓬和尼日利亚的低地雨林。其外观呈深灰色，成年雄鸟喉部常带有亮丽的红褐色，体型较小且紧凑，尾巴较短，末端近似方形。这种燕子能在密闭森林的树冠下像蝙蝠一样飞行，栖息地多样，包括雨林边缘和山脚地带。","appearance":"林燕整体呈现深黑色至棕色，头部乌黑并带有蓝绿色光泽，喉部锈褐色，尾部略带叉状。性别间外表相似，幼鸟外观类似成鸟。体长约11厘米，尾羽短而大多方正，区别于多数Psalidoprocne属物种。","call":"林燕的叫声通常为短促的嗡嗡声，飞行中也会发出‘wheet’和‘pitchri’的声音。","habits":"林燕主要生活在低地森林中，但在开阔地带、林间空地和村庄周围也能找到它们的身影。它们的迁徙习性尚不清楚，但在加蓬有记录显示可能是部分季节性迁移，而在刚果西北部有迷鸟记录。林燕通常成对或小群体觅食，飞行迅速且飘忽，常滑翔。","breeding":"繁殖习性了解不多，但在喀麦隆有记录显示繁殖季节为4月至6月，幼鸟出现时间为1月和11月。林燕巢由双亲共同建造，用时约两周，巢穴封闭，入口长管状，有时有两个入口，由泥团构成并内衬植物纤维。巢址多选在岩石悬垂处、洞穴壁面或建筑物天花板上。","identification":"林燕与方尾锯翅燕极为相似，但可通过其独特的蝙蝠般飞行和在良好光照下观察到的更偏棕色的羽毛及有时更红褐色的喉部来辨别。尽管外观与锯翼相似，但林燕与家燕关系更为密切。","protection":"IUCN：LC（无危）","distribution":"林燕的分布范围从尼日利亚东南部延伸至加蓬和刚果西北部，包括喀麦隆、刚果（布）、赤道几内亚等地。最近在安哥拉北部（Uíge省）也有发现，但具体状况未知。","other":"林燕原被归入Petrochelidon属内，后基于分子系统学研究，被De Silva等人（2018）重新分类至Atronanus属，成为该属唯一成员。"},{"name":"鳞胸鹪鹛","english_name":"Scaly-breasted Cupwing","scientific_name":"Pnoepyga albiventer","overview":"鳞胸鹪鹛（英文名：Scaly-breasted Cupwing，学名：Pnoepyga albiventer），是雀形目鳞胸鹪鹛科鳞胸鹪鹛属的鸟类。体型微小，主要分布在喜马拉雅山脉至缅甸及越南西北部。其特征为背部橄榄色，胸部带有明显的鳞状斑纹，几乎无尾，长度约9厘米，体重介于19至23克之间。栖息于海拔1500至3660米的山区森林，冬季会降至1100米，偏好靠近水源地带。","appearance":"该鸟身材娇小，背部呈现橄榄色调，胸部覆以精细的鳞状斑纹，这种斑纹在苍白型个体上表现为白色边缘环绕黑色“鳞片”，而在深色型个体上则为咖啡色边缘。头部、颈部及冠部点缀着细小的斑点，雌雄同形同色，存在两种形态：苍白型（白鳞型）和赭腹型（浅红褐色型）。苍白型个体的上体呈橄榄褐色，头侧有淡色条纹，喉部石白色，腹部石白色，每根羽毛中心有黑色或深棕色的V形斑点；赭腹型个体的上体底色为橄榄褐色，下体的白色被浅红褐色替代。","call":"鸣唱为一系列高音旋律混杂的颤音，比同属的小鳞胸鹪鹛更为复杂。","habits":"鳞胸鹪鹛栖息于湿润的山地森林，常见于多苔藓和蕨类植物的溪流附近。它进行地面觅食，偶尔在开阔地带的木头和岩石上停留，但不会停留在植被上。饮食以昆虫为主，有时也会食用种子。","breeding":"繁殖期为3月至8月，巢为球形，入口位于一侧三分之二处，由绿苔藓和根须制成，嵌入河岸或树干上的苔藓中。一窝2至5枚卵，白色，有时有少量红褐色斑点，双亲共同孵化，孵化期12至14天。","identification":"与小鳞胸鹪鹛相比，鳞胸鹪鹛的头部和颈背有更深的斑点，而与尼泊尔鹪鹛的区别在于后者上体和翅膀缺乏淡色斑点，下体的羽毛中心较长且暗色，给人一种条纹的感觉，尤其是胸部。两者的鸣唱差异显著。","protection":"IUCN状态未知。","distribution":"主要分布于喜马拉雅山脉至缅甸及越南西北部，具体覆盖区域包括但不限于中国西南部、尼泊尔、不丹、印度东北部、缅甸北部和越南西北部。","other":"台湾鹪鹛曾被视为其亚种，而中华鹪鹛已合并入该物种。"},{"name":"中华鹪鹛","english_name":"Chinese Cupwing","scientific_name":"Pnoepyga mutica","overview":"中华鹪鹛（英文名：Chinese Cupwing，学名：Pnoepyga mutica），是雀形目鳞胸鹪鹛科鳞胸鹪鹛属的小型鸟类，体长8.5至10厘米，体重约19至23克。其背部几乎无尾，橄榄色，下部呈淡斑纹状。分布于亚洲南部和东部的山区森林中，常近水边栖息。","appearance":"中华鹪鹛有两种形态，指名亚种为\"白鳞\"型，冠部和上体橄榄褐色，具模糊暗斑和小黄白色点，头部侧面橄榄褐色，带有黄白色的轴纹，喉部石白色，胸部和腹部石白色，每根羽毛中心有黑色或深棕色人字形图案，边缘较窄，形成明显的鳞片状外观，两翼同上，但白色部分被浅橄榄灰色替代；\"赭腹\"型上体底色橄榄褐色，下体则为棕黄色。雌雄相似，幼鸟上部暖赤褐色，下部灰橄榄色或金棕色。","call":"发出快速高音、甜美、叮当、杂乱的鸣唱，持续1.5至2秒，音似\"wisisititititiwi\"或\"wiswisiwitwisititui\"，音调先上升后突然停止，间隔时间较长。叫声为连续短促、响亮、略带爆炸感的\"tschik\"或\"tchik\"。","habits":"栖息于潮湿阴凉的阔叶林、冷杉、铁杉和桦木林下灌木丛中，靠近水源，如溪流旁、岩石斜坡、蕨类植物密集区。海拔高度在夏季位于2400至3900米，冬季降至最低275米。主要在地面活动，冬季独居，繁殖季节成对。以昆虫和种子为食。","breeding":"繁殖期为3月至8月，巢为球形，入口位于一侧三分之二处，由绿苔藓和根须制成，嵌入河岸或树干上的苔藓中。一窝2至5枚卵，白色，有时有少量红褐色斑点，双亲共同孵化，孵化期12至14天。","identification":"中华鹪鹛通过其特有的橄榄背和鳞片状下体羽毛与其他物种区分，尤其是两种形态的区别，以及其独特的鸣叫声。","protection":"IUCN：未评估。在不丹较为常见，尼泊尔和印度部分地区也有分布，但密度较低。","distribution":"分布于喜马拉雅山脉至东南亚的印度支那地区，夏季在2400至3900米之间，冬季下降至最低275米；在中国西藏1980至3660米，其他地区1500至3200米，冬季降至1100米；在东南亚1200至3000米，繁殖海拔高于2200米。","other":"已合并入鳞胸鹪鹛。"},{"name":"台湾鹪鹛","english_name":"Taiwan Cupwing","scientific_name":"Pnoepyga formosana","overview":"台湾鹪鹛（英文名：Taiwan Cupwing，学名：Pnoepyga formosana），是雀形目鳞胸鹪鹛科鳞胸鹪鹛属的特有种。极小型的鸣禽，外观似无尾，橄榄褐色的背部与鱼鳞状花纹的胸部为其显著特征，体型酷似一颗置于细筷子上的棕色乒乓球。分布仅限于台湾岛，曾长期被视为鳞胸鹪鹛的一个亚种。","appearance":"台湾鹪鹛长约8至9厘米，头部与背部呈黑褐色，带有淡褐色斑点，斑点在暗褐色的其余上体部分逐渐淡化。尾部极短，上翼深褐色，翼覆羽带有淡褐色斑点。下体白色，带有细窄的黑色边缘和宽大的刀形黑色中心，从胸部到腹部的白色减少，两侧和大腿处呈现淡黄色至淡赭色。眼睛深色，喙黑色，腿浅棕色。雄雌相似，雏鸟特征未详述。","call":"其鸣唱声为‘tz ti’tchu’ti’tzu’wi’，以单独的起始音开始，持续约1.5秒，间隔10至40秒后重复，比鳞胸鹪鹛的鸣声更短更慢。亦被描述为一系列高音快速的哨音‘piip, pipí-pi piip’，类似短趾旋木雀的声音，或‘dudí, du-du-du-du’，最后四个音节略降。","habits":"栖息于台湾的山地森林中，常在落叶覆盖的森林地面敏捷跳跃，迅速飞向树根下的阴暗处觅食。主要以昆虫、蜘蛛、蜗牛、种子和碎石为食。其觅食行为与鳞胸鹪鹛非常相似。","identification":"与鳞胸鹪鹛的苍白型态相比，台湾鹪鹛的翅膀和跗蹠明显较短，冠部的淡褐色斑点更为饱满且略带红褐色，下体颜色更深，因胸部和腹部的白色区域减少。两者分布不重叠。","protection":"IUCN：LC（无危）","distribution":"台湾岛为台湾鹪鹛的唯一分布地。"},{"name":"尼泊尔鹪鹛","english_name":"Nepal Cupwing","scientific_name":"Pnoepyga immaculata","overview":"尼泊尔鹪鹛（英文名：Nepal Cupwing，学名：Pnoepyga immaculata），是雀形目鳞胸鹪鹛科鳞胸鹪鹛属的小型鸟类。也被称为尼泊尔鹪鹩或无斑鳞胸鹪鹛。分布于喜马拉雅山脉的乌塔拉坎德邦、喜马偕尔邦、西藏和尼泊尔地区，常见于浓密的山地森林中。","appearance":"尼泊尔鹪鹛体长介于8.5至10厘米之间，是一种无尾、长腿的小型球状鸟。外观上，淡色型的个体呈橄榄褐色，背部有模糊的暗色鳞片状斑点，腹部白色，侧腹和下部逐渐转为橄榄灰色，从下巴向下有明显的暗色鳞片状斑纹；虹膜棕色，有狭窄的蓝灰色眼环；喙角棕色，下部较浅；腿为角棕色或棕肉色。深色型个体上部颜色更深，橄榄棕色，下部为深黄褐色。两性相似，幼鸟特征未详述。","call":"其鸣唱由8个高音刺耳音符组成，节奏较快，有时会略微加速，长度约2至2.5秒，间隔12至25秒重复，兴奋时每5至8秒重复一次。叫声为尖锐响亮的“tchit”，重复发出，与鳞胸鹪鹛和小鳞胸鹪鹛的叫声相似。","habits":"尼泊尔鹪鹛在开放的常绿阔叶林边缘和附近的溪流、河流旁的草本层和灌木丛中活动，偏好岩石和巨石附近。它以小型无脊椎动物为食，不特别害羞，经常在低矮植被和石头周围跳跃。","breeding":"关于尼泊尔鹪鹛的繁殖行为具体信息未提供。","identification":"与鳞胸鹪鹛和小鳞胸鹪鹛相比，尼泊尔鹪鹛的喙略长，上部和翅膀无斑点，下部的鳞片状斑纹更长，尤其是胸部，有暗色颊线和窄蓝眼环，帮助区分。","protection":"IUCN：LC（无危）","distribution":"尼泊尔鹪鹛主要分布于喜马拉雅山脉的印度至尼泊尔区域，包括中国西藏日喀则樟木一带。在海拔1730至3100米间繁殖，冬季最低可降至250米，同时出现在半落叶和落叶森林以及高草丛中。","other":"2010年，尼泊尔鹪鹛在中国西藏樟木首次被记录，成为中国的鸟类新纪录。"},{"name":"小鳞胸鹪鹛","english_name":"Pygmy Cupwing","scientific_name":"Pnoepyga pusilla","overview":"小鳞胸鹪鹛（英文名：Pygmy Cupwing，学名：Pnoepyga pusilla），是雀形目鳞胸鹪鹛科鳞胸鹪鹛属的鸟类。俗名: 小鹪鹛、小鳞鹪鹛，该鸟体型小巧，几乎无尾，外形类似老鼠，活跃于山林间的稠密灌木丛与竹林树根间。分布范围广泛，自尼泊尔延伸至中南半岛，南至印度尼西亚，台湾岛，中国大陆的云南、四川、广西、福建以及陕西北部。模式产地位于尼泊尔。","appearance":"小鳞胸鹪鹛体长约7.5至9厘米，体重约11至15克。背部橄榄色，腹部具白色鳞状斑纹；存在两种形态：指名亚种为\"白鳞\"形态，头部至臀部灰橄榄棕色，上翼较暗，肩羽、翼覆羽和三级飞羽有淡色亚端斑；头侧灰橄榄棕色，耳羽有模糊的淡色轴纹；下巴和喉咙偏白，带有窄的灰棕色鳞纹，胸部和腹部偏白，每根羽毛中心呈灰棕色人字形，边缘灰棕色（形成强烈鳞片效果），两胁橄榄棕色带淡橄榄鳞纹；\"赭腹\"形态背部橄榄棕色，每根羽毛有赭色滴点，腹部的白色被赭色取代。眼睛深棕色或棕色，喙黑色，下部较浅，腿浅暗棕色。幼鸟上体较单一，仅大翼覆羽和三级飞羽末端有暖棕色，下体亦单一，喉部和腹部白色渐变为胸部和两胁的深灰色。亚种annamensis比指名亚种为暗，头侧较黄，下体鳞纹更黑；harterti与前者相似，但头侧更暗；lepida上体更红棕色，头侧锈黄，胸部和两胁鳞纹边缘锈黄；rufa与后者相似，但头侧更暗，胸部和两胁鳞纹边缘不那么锈色；everetti上体黑褐，比其他亚种更暗，下体缺乏前一亚种个体普遍显示的黄晕，两胁羽毛中心更重、更深；timorensis与前两个亚种相似，但更暗淡，更苍白，鳞纹显著减少，头侧黄灰色。","call":"小鳞胸鹪鹛的叫声独特，发出高音的、间隔分明的尖锐哨声，如“ti—ti—tu”，持续约4秒，每隔3至5秒重复一次，有时最后两个音符间距更短。在印度次大陆，有时只发出一系列下降的“tseeeet”音符。叫声为重复的尖锐响亮的嘶嘶声“tchit”或“chit”。","habits":"小鳞胸鹪鹛栖息于常绿阔叶林的地面和下层，茂密植被覆盖的森林峡谷，苔藓覆盖的巨石，倒下的原木，密集的蕨类植物生长，以及丰饶的苔藓。在弗洛雷斯岛上，栖息于山区森林、Eupatrium灌木丛，偶尔出现在路边再生林和高大的次生林；在帝汶岛，栖息于大型岩石露头周围。在不丹，主要栖息于海拔1500至2000米的温暖阔叶林。通常在海拔200至3050米之间发现；在印度次大陆海拔1000至2850米，局部可达3050米，冬季低至200米；在中国海拔520至2800米；在东南亚海拔180至2565米，繁殖高度在750米以上；在苏门答腊海拔900至3000米；在爪哇海拔1300至3000米；在弗洛雷斯海拔900至1900米；在帝汶海拔1800至2000米。其栖息地海拔低于相似的鳞胸鹪鹛。","breeding":"繁殖季节在喜马拉雅山脉以北地区为3月至9月，主要鸣唱期在不丹为3月中旬至4月底，但有记录到7月末和9月的幼鸟；在东南亚为11月至8月，爪哇为7月至5月，苏门答腊为11月至12月。巢由两性共建，要么是小型的苔藓球，由根须、树皮碎片和叶片骨架构成，要么是由长条的鲜绿色苔藓制成的嵌入式结构，内部紧密编织形成小杯状，都衬有黑色或其他根须和纤维；放置在悬挂于树干、垂直岩石、倒木、步道旁的河岸或翻转的树根上的苔藓、兰花、蕨类或藤蔓中，通常距离地面0.5至2米（偶尔高达6米）。窝卵数2至6枚（在缅甸通常为3至5枚，在中国为4至6枚，在马来半岛和爪哇为两枚），蛋壳白色，偶尔可见一两个微弱的斑点。在苏门答腊记录到靠近巢穴进行断翅干扰展示的行为。","identification":"与非常相似的鳞胸鹪鹛相比，小鳞胸鹪鹛体型较小，头部无斑点。不同亚种间存在颜色和图案的差异，例如\"赭腹\"形态与\"白鳞\"形态在腹部颜色上的不同。","protection":"IUCN：LC（无危）","distribution":"广泛分布于东洋界，包括尼泊尔至中南半岛，南至印度尼西亚，台湾岛以及中国大陆的云南、四川、广西、福建和陕西北部。"},{"name":"须薮莺","english_name":"Moustached Grass Warbler","scientific_name":"Melocichla mentalis","overview":"须薮莺（英文名：Moustached Grass Warbler，学名：Melocichla mentalis），是雀形目长嘴莺科须薮莺属的鸟类。非洲长嘴莺科须薮莺属的鸟类，广泛分布于撒哈拉以南非洲，但在大陆南部较为罕见。其自然栖息地为湿润的草原和亚热带或热带湿润灌木丛。","appearance":"体型较大的须薮莺呈现出独特的棕色外观，拥有黑色的尾巴、浅色的眼睛和显著的黑色‘胡须’标记。在稀树草原和灌木丛中的高大茂密草丛中可见其身影。通常隐匿于草丛中，仅在唱歌时会短暂露面。相较于扇尾芦莺，其体型更大，具有浅色眼睛和黑色面部条纹。","call":"其鸣唱为快速连贯的啾啾声，节奏鲜明，音调多变。","habits":"栖息于湿润的草原和亚热带或热带湿润灌木丛中，偏好在高大密集的草丛中活动。","identification":"与扇尾芦莺相比，须薮莺在体型、眼色和面部特征上明显不同，尤其是其黑色的‘胡须’标记。","protection":"IUCN：LC（无危）","distribution":"非洲广泛分布，尤其在撒哈拉以南地区常见，但在非洲南部较不普遍。"},{"name":"草莺","english_name":"Cape Grassbird","scientific_name":"Sphenoeacus afer","overview":"草莺（英文名：Cape Grassbird，学名：Sphenoeacus afer），是雀形目长嘴莺科南非草莺属的鸟类。以它独特的锈色头部和翅膀著称。广泛分布在南非、莱索托、莫桑比克、斯威士兰，以及津巴布韦东部的孤立地区。","appearance":"草莺体型健壮，长度在19至23厘米之间，重量约为27至34克。其头部和翅膀呈暖褐色，带有明显的条纹，尾巴呈深棕色且略显凌乱。上体为褐色并有厚重的条纹，下体白色，带有黑色斑点。脸部两侧和头顶为锈色，眼周有白色羽毛，喉咙为白色并有黑色颊纹。雄雌相似，幼鸟比成鸟颜色较淡，头顶有条纹。","call":"草莺的歌声为一串杂乱而悦耳的音符，起初轻柔，逐渐增强，最后以拉长的颤音结束。它还有一种鼻音的“pheeeo”叫声。","habits":"草莺栖息于茂密的长草、芦苇丛或蕨类植物中，偏好有长草的山地草原、散落着灌木和普罗蒂亚树的沿海灌木丛生地带。它通常独居或成对活动，通过植被寻找昆虫和其他小型无脊椎动物。","breeding":"草莺在雨季繁殖，时间大致为10月至翌年2月，筑杯状巢于低矮植被中，由粗干叶子和草构成，内衬细草和纤维。每窝产2-3枚蛋，孵化期为14-17天，由双亲共同喂养雏鸟，育雏期为14-16天。","identification":"草莺可通过其长而尖的凌乱尾巴、栗色的帽顶和面部条纹来识别。与之相比，须薮莺背部无条纹，尾巴宽大，眼睛周围颜色较浅。","protection":"IUCN：LC（无危）。这种常见的鸟类拥有广阔的分布区，估计范围超过39万平方公里，种群数量被认为较大，未达到IUCN红色名录中定义的濒危标准。","distribution":"草莺主要分布在非洲南部，包括南非、莱索托、莫桑比克、斯威士兰，以及津巴布韦东部的孤立地区。","other":"草莺是Sphenoeacus属下的唯一物种，曾被归类于Sylviidae科，现归于Macroscphenidae科。"},{"name":"岩莺","english_name":"Rockrunner","scientific_name":"Achaetops pycnopygius","overview":"岩莺（英文名：Rockrunner，学名：Achaetops pycnopygius），是雀形目长嘴莺科岩莺属的鸟类。非洲特有的大型而结实的长嘴莺，属于单型属岩莺属。拥有白色的眼眉和喉部，条纹状胸部和赤褐色腹部，分布于安哥拉和纳米比亚的西南部。","appearance":"岩莺是一种引人注目的陆栖鸟类，体长约16至17厘米，体重24至34克，外观似八哥，黑白相间，具有橘黄色臀部和侧翼，尾羽深色。雄鸟成鸟的头部至肩部有细窄的黄褐色条纹，背部呈现紫色调，臀部变为橙红栗色；尾羽深棕色，飞羽暗红棕色边缘带肉桂色；上眼线黄白色，眼先黑褐色，眼后线黑褐色，耳羽暗肉桂色，带有白色和黑色条纹，下颊纹黄白色，脸颊到上腹黄白色，胸侧密布黑色斑点，下腹至肛门区变为鲜亮的橘红褐色。雌鸟相似但腹部更偏橘色。幼鸟比成鸟暗淡，标记较弱，尾羽较短。spadix亚种比指名亚种颜色更深，头部和背部颜色更暗，臀部颜色更深，最内侧尾羽更黑。","call":"岩莺的美丽歌声由两性在黎明和黄昏时发出，主要在繁殖季节，是一连串清澈的冒泡声和颤音，平均持续时间在2.2至3.2秒之间，每首歌之间有6至12秒的停顿。在领地争斗时会发出重复的柔和‘poew-perrít-poew’声。联络叫声为‘hoo-boy’，警报叫声则为刺耳的‘cheerrrrrrrr’。","habits":"岩莺栖息于斜坡岩石地带，石堆和露头，伴以分散的荆棘树，特别是在水道旁的干旱丘陵和山脉；极少在树木中活动，除非在歌唱或因惊恐而呼叫。在安哥拉，它们出现在靠近悬崖森林上方的岩石散布、湿润草地的山腰。","identification":"岩莺的特征鲜明，很难与它的小范围内其他物种混淆。它独特的黑白相间的羽毛，橘红色臀部和侧翼，以及特定的叫声，使其容易识别。","protection":"IUCN：LC（无危）","distribution":"岩莺分布于非洲西南部，具体在安哥拉和纳米比亚。"},{"name":"黄长嘴莺","english_name":"Yellow Longbill","scientific_name":"Macrosphenus flavicans","overview":"黄长嘴莺（英文名：Yellow Longbill，学名：Macrosphenus flavicans），是雀形目长嘴莺科长嘴莺属的鸟类。以独特的长喙和黄色的眼睛而著称，主要分布于非洲中部的热带雨林地带。","appearance":"平均体长13厘米，重11-16克，拥有中等体型。其特征为短尾和黑色的长直喙，喙尖有小钩。头部顶部呈暗橄榄灰色，上体颜色渐变为暗橄榄绿色，背部和臀部的长松散羽毛带有黄色调。下体为绿黄色，眼睛呈黄色。雄鸟与雌鸟羽毛相似，但雄鸟体型较大。平均寿命约为3.6年。","call":"黄长嘴莺的鸣唱独特，由一系列清晰的哨音组成，每个音符的音调略低于前一个，与大嘴蓬背鵙的模式类似，单个音符听起来非常像Batis的声音。","habits":"栖息于热带雨林中，偏好中层密集的缠结植被，常以成对或小群体的形式活动。食性为杂食，主要以蜘蛛和昆虫为食，如蛾类、毛虫和甲虫，同时也摄食一些水果。在旱季，它们更倾向于在较低的树冠区域觅食。","breeding":"关于繁殖行为的具体信息有限，但黄长嘴莺一般在雨季繁殖，筑巢于密林中。","identification":"与其他长嘴莺类相比，黄长嘴莺可通过其下体的色彩进行区分。在野外，良好的观察条件有助于将其与其他长嘴莺种类区分开来。","protection":"IUCN：LC（无危）","distribution":"分布在非洲中部，具体包括安哥拉、喀麦隆、中非共和国、刚果民主共和国、赤道几内亚、加蓬、尼日利亚、南苏丹、苏丹、坦桑尼亚联合共和国和乌干达。"},{"name":"肯氏长嘴莺","english_name":"Kemp's Longbill","scientific_name":"Macrosphenus kempi","overview":"肯氏长嘴莺（英文名：Kemp's Longbill，学名：Macrosphenus kempi），是雀形目长嘴莺科长嘴莺属的鸟类。独特的旧世界莺鸟，隶属于长嘴莺科（Macrosphenidae）。其主要分布在非洲西部，包括喀麦隆、象牙海岸、加纳、几内亚、利比里亚、尼日利亚和塞拉利昂。自然栖息地为亚热带或热带的湿润低地森林。","appearance":"肯氏长嘴莺拥有与众不同的外观，其最显著的特征是长而细的喙以及淡色的眼睛。上体呈淡色调，胸部模糊地带有灰色，而侧腹则呈现赤褐色。雌雄及幼鸟的羽毛颜色相似，但在细节上可能有所差异。","call":"其鸣叫声独特，是一系列哀婉、游离不定的哨音，音调既可下降也可上升，变化多端，听起来颇似知更鸟的歌声。","habits":"它们栖息于低海拔至中海拔的湿润森林，偏好密集的中层灌木丛。肯氏长嘴莺主要通过其特有的歌声被发现，而非视觉。","breeding":"关于肯氏长嘴莺的繁殖行为，现有资料较为有限，具体繁殖期、筑巢、产卵等细节尚待更多研究。","identification":"与其它长嘴莺种类相比，肯氏长嘴莺可通过下体的赤褐色加以区分。同时，它与红领太阳鸟有相似之处，但前者腹部颜色较暗，喙部更为笔直。","protection":"IUCN：LC（无危）","distribution":"肯氏长嘴莺的分布范围集中在非洲西部的多个国家，包括喀麦隆、象牙海岸、加纳、几内亚、利比里亚、尼日利亚和塞拉利昂。"},{"name":"灰长嘴莺","english_name":"Grey Longbill","scientific_name":"Macrosphenus concolor","overview":"灰长嘴莺（英文名：Grey Longbill，学名：Macrosphenus concolor），是雀形目长嘴莺科长嘴莺属的小型鸟类，通体呈灰绿色，拥有独特的长而直的喙。广泛分布于非洲几内亚至乌干达、卢旺达和刚果民主共和国东部的低海拔森林地带。","appearance":"体长约11-12厘米，体重约12-16克。全身被覆灰绿橄榄色羽毛，上部包括头部、背部、上翼覆羽和尾羽颜色较暗淡；下体呈淡灰橄榄色，喉部更浅，胸部侧面和两胁颜色稍深，臀部和后侧有较长的黄白色绒羽。虹膜为灰绿色带浅棕色边缘，喙角褐色至黑色，下颚较浅，腿色为浅棕色至粉红色。雌雄相似，幼鸟比成鸟色泽更淡，腹部泛白，胸部略带黄色。","call":"鸣唱欢快持续，由多样化的二音节短语组成，部分快速而富有节奏感，每组短语重复数次，如“hew hew whee whee, hew hew whee whee… weedly diddly, weedly diddly…”有时成对合唱，亦能模仿其他森林鸟的叫声。","habits":"栖息于低海拔的热带湿润森林，以昆虫为主食，包括蛾类、小毛虫（鳞翅目）和小型蚱蜢（直翅目）。活动范围覆盖林下植被至树冠下层，常在藤蔓和悬垂的枝条间觅食。通常成对或小群活动，常与其他鸟类混群。","identification":"与其他灰橄榄色莺类的区别在于其短而略长于翼尖的尾巴和长直喙。在飞行和栖息时容易辨认。","protection":"IUCN：LC（无危）。在许多地区常见，特别是在利比里亚的次生高密度森林中记录到较高密度。在加蓬东北部的密度约为7-10对/100公顷。广泛分布于西非和中非的低海拔森林。","distribution":"分布于西非的塞拉利昂、几内亚南部至加纳南部、尼日利亚南部和喀麦隆南部，包括比奥科岛，南至刚果和东至中非共和国西南部、刚果民主共和国（除东南部）、乌干达西部和南部以及安哥拉东北极区。2016年首次在坦桑尼亚记录。"},{"name":"普氏长嘴莺","english_name":"Pulitzer's Longbill","scientific_name":"Macrosphenus pulitzeri","overview":"普氏长嘴莺（英文名：Pulitzer's Longbill，学名：Macrosphenus pulitzeri），是雀形目长嘴莺科长嘴莺属的鸟类。主要分布在非洲中南部地区的安哥拉西部，以其独特的长而直的喙和淡色眼睛著称。体型较小，橄榄绿的羽毛略显暗淡，喉部呈黄色调，生活在低海拔至中海拔的干燥常绿森林中。","appearance":"该鸟约12厘米长，头部顶部、背部和尾巴橄榄褐色，头部侧面较灰，飞羽边缘同样橄榄褐色；下巴淡黄；腹部橄榄色，胸侧和胁部颜色更深，腹部更偏黄，大腿和下尾覆羽肉桂棕色；虹膜脏白色，上喙暗角质色，下喙基部粉红色；跗跖粉红。性别相似，幼鸟特征未详述。与近似的灰长嘴莺相比，普氏长嘴莺略大，尾巴较长。","call":"具有独特而低沉的两音节鸣声，重复的“peet-treeya”短语，易于识别。","habits":"栖息于安哥拉西部的干燥常绿森林，偏好密集的森林中层灌木丛，活动于中等高度的森林地带。具体觅食习性和食物组成尚未详细记录。","identification":"可能与camaropteras（未明确中文名）混淆，但体型更大，翅膀不具鲜艳绿色；也与某些绿鹎相似，但体型更小，尾巴更短。通过喙的形状和大小以及鸣声进行区分。","protection":"IUCN：EN（濒危）；全球估计数量不足1000只，栖息地表面面积和质量可能都在下降。受森林砍伐和咖啡种植园转变为刀耕火种农业的影响威胁。","distribution":"仅限于非洲安哥拉西部，分布于库安扎省南部（加贝拉）至南纳米比（卡穆库伊）的悬崖地带。","other":"曾被视为旧世界莺类，现归入神秘的非洲莺类家族Macrospenidae。"},{"name":"克氏长嘴莺","english_name":"Kretschmer's Longbill","scientific_name":"Macrosphenus kretschmeri","overview":"克氏长嘴莺（英文名：Kretschmer's Longbill，学名：Macrosphenus kretschmeri），是雀形目长嘴莺科长嘴莺属的鸟类。拥有长喙和淡色眼睛。其分布于非洲中东部的肯尼亚、莫桑比克和坦桑尼亚，栖息于低地和中海拔的湿润森林。","appearance":"体长约14至14.5厘米，体重约17.5至22克。外观似绿鹎，但具更长的喙和较短的尾巴。头部顶侧呈灰橄榄色，上体和上翼覆羽为暗橄榄绿色；飞羽和尾羽深棕色，边缘橄榄绿色；下体橄榄黄色带灰色调，颏部和喉部颜色较浅，中央胸部和腹部更黄；虹膜黄色或乳白色；喙上部暗角质色至黑色，下部白色或淡粉色；腿色从灰褐色至粉红色。雌雄相似，幼鸟头部颜色比成鸟更绿，眼睛淡褐色。","call":"叫声独特，通常由3至5个哨音组成的叽叽声，形成上下起伏的模式，间隔后重复，音质类似鹎的鸣叫。","habits":"栖息于低地和中海拔的湿润森林，常在密集的灌木丛中活动，成对或小群出现。偏好在林间中层的密集植被中觅食。","breeding":"繁殖信息未详细提及。","identification":"与绿鹎类相似，但可通过更长的喙和较短的尾巴加以区分。","protection":"IUCN状态未提供。","distribution":"分布于非洲中东部，具体包括肯尼亚、莫桑比克和坦桑尼亚。","other":"系统学历史未详细提及。"},{"name":"短尾森莺","english_name":"Northern Crombec","scientific_name":"Sylvietta brachyura","overview":"短尾森莺（英文名：Northern Crombec，学名：Sylvietta brachyura），是雀形目长嘴莺科森莺属的鸟类。小型非洲长嘴莺科森莺属鸟类。其特征为几乎无尾，背部灰褐色，腹部锈色，具有明显的灰褐色眼线。分布广泛，遍及东非、中非和西非的多个国家，如埃塞俄比亚、肯尼亚、坦桑尼亚等地，常见于干燥的灌木草原和森林地带。","appearance":"短尾森莺体型小巧，约8厘米长，体重介于5至9.6克之间。其头部顶部及上体呈均匀灰色，具显著的淡黄色眉纹和较窄的黑色眼线；上翼深棕色，边缘灰黄色；耳羽、脸颊和下体为丰富的浅黄褐色，与白色下巴和腹部中央形成对比；虹膜橙棕色；喙上部暗棕色，下部较浅；腿色从浅棕至粉棕色。雌雄相似，幼鸟翼覆羽边缘呈浅黄褐色。种族差异体现在颜色深浅上。","call":"鸣唱为快速、杂乱的口哨式短语，由4至6个音符组成，有时开头带有轻微的‘churr’声，其余音符沿音阶下降，类似柳莺的歌声。叫声包括干涩的‘trrr’声、尖锐的‘chit-chit’声和兴奋的‘chi-chi-chi-chi’声。","habits":"短尾森莺栖息于多种干燥的灌木草原和森林环境，偏好半干旱的荆棘丛和散布树木的耕地。海拔高度主要在1500米以下，但在乌干达和肯尼亚西部可达2000米，南苏丹高达2400米。多数种群定居，但在西非北部地区仅在雨季出现。以小无脊椎动物为食，包括鳞翅目昆虫的幼虫和卵、白蚁、蜘蛛等，通常低空觅食，单个或成对活动，频繁移动并鸣叫。","breeding":"繁殖期几乎涵盖全年，主要在雨季的6月至7月，筑巢活动在撒哈拉以南非洲的特定月份。一夫一妻制，领域性。巢穴为深而结实的口袋状，顶部延伸，几乎呈球形，入口较大，面向上方和侧方。巢材包括细小的植物茎、草和纤维，以蜘蛛网粘合，内部铺垫细根须和草穗，外表装饰以茧或小种子。巢悬挂在灌木或荆棘树的外枝上，主要借助蜘蛛网。每窝产2枚橄榄褐色、锈色或灰色斑点的白色卵，尺寸为16.2至18.5毫米×11.4至12.5毫米。尼日利亚的成年生存率估计约为87.5%，在肯尼亚西部曾观察到黑曼巴蛇捕食成鸟。","identification":"与红脸克罗姆贝克相比，短尾森莺具有更强烈的眼线，重叠区域常显示明亮的白色喉咙。鸣唱和叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于东非、中非和西非，包括埃塞俄比亚南部、肯尼亚、坦桑尼亚东北部等。在西非，局部地区密度为0.5只/公顷，几内亚比绍的红树林中密度可达2.7只/公顷。","other":"已知与棕红脸森莺杂交。"},{"name":"棕红脸森莺","english_name":"Red-faced Crombec","scientific_name":"Sylvietta whytii","overview":"棕红脸森莺（英文名：Red-faced Crombec，学名：Sylvietta whytii），是雀形目长嘴莺科森莺属的鸟类。曾被归类于柳莺科（Sylviidae）。分布于布隆迪、埃塞俄比亚、肯尼亚、马拉维、莫桑比克、纳米比亚、卢旺达、南苏丹、坦桑尼亚、乌干达和津巴布韦，其自然栖息地包括亚热带或热带的干燥森林、湿润山地森林以及干燥灌木地带。","appearance":"体型小巧，几乎无尾，背部呈灰色，腹部为赤褐色。脸部完全赤褐，给人以‘开放’的印象。与北方和长喙森莺相似，但可通过其脸部无眼纹的特征加以区分。","call":"歌声因地理位置而异，可以是柔和的颤音或连续的颤鸣。叫声为短促、快速、木制般的咔哒声。","habits":"栖息于多种草原和林地环境，特别是在南部范围内的Miombo林区最为常见。","identification":"与北方和长喙森莺区别明显，红脸森莺脸部无眼纹。","protection":"IUCN状态未提及。","distribution":"非洲东部，包括但不限于Burundi, Ethiopia, Kenya, Malawi, Mozambique, Namibia, Rwanda, South Sudan, Tanzania, Uganda, and Zimbabwe。","other":"系统学历史未详述，曾被错误分类。"},{"name":"短嘴森莺","english_name":"Philippa's Crombec","scientific_name":"Sylvietta philippae","overview":"短嘴森莺（英文名：Philippa's Crombec，学名：Sylvietta philippae），是雀形目长嘴莺科森莺属的鸟类。也被称为短嘴克姆贝克，非洲长嘴莺科的森莺属鸟类，主要分布于埃塞俄比亚东部和索马里干燥的荆棘灌丛地带。","appearance":"体型小巧，几乎无尾，背部呈灰色，腹部泛黄。头部上方和上体灰白，具有一条狭窄的白色眉纹，上翼和短小的尾巴为灰褐色，飞羽边缘略显淡色；下巴和喉部为白色，胸部至尾下覆羽呈淡黄色，胸侧和两胁带有灰棕色调；虹膜棕色；喙灰色，下颌基部粉红色；腿脚红棕色。雌雄相似。幼鸟特征尚未详述。","call":"鸣唱由快速的聊天式音符组成，包括重复的‘ti-chirr-cheesis’，中间音节较高；叫声有‘chirr’和响亮的‘chink’。","habits":"栖息于干旱灌木丛中的金合欢（Acacia）灌丛和Commiphora灌木丛，主要位于岩石地面或红沙土上，海拔高度约300米，最高可达900米。通常以小型甲虫（Coleoptera）和其他昆虫，包括小型毛虫为食。常以小组形式觅食，经常与其他莺鸟一同活动。在枝叶和花朵中搜寻食物，尤其是金合欢的花朵。","breeding":"繁殖季节为5月至6月，目前无更多信息。","identification":"与黄腹和黄腹Eremomelas类似，但下体颜色较暗淡，尾巴更短。与长嘴森莺相似，但喙较短。","protection":"IUCN：DD（数据缺乏）。在小而受限的范围内被认为相对常见，可能因燃料木收集或放牧导致的栖息地改变而受到威胁。缺乏关于其数量和对栖息地干扰敏感性的信息。","distribution":"主要分布在非洲东部的埃塞俄比亚和索马里，具体包括西北、中部和西南索马里（从Burao和Daba Dalol南至Wajit和Lugh附近）以及邻近的埃塞俄比亚南部和东南部。","other":"目前认为全球无威胁，但信息不足限制了对其保护状况的可靠评估。"},{"name":"棕长嘴森莺","english_name":"Long-billed Crombec","scientific_name":"Sylvietta rufescens","overview":"棕长嘴森莺（英文名：Long-billed Crombec，学名：Sylvietta rufescens），是雀形目长嘴莺科森莺属的鸟类。小型非洲战鸟，常见于南非至中非的广阔区域，包括坦桑尼亚、赞比亚、刚果民主共和国等地。拥有独特的橙色腹部和灰褐色背部，以及显著的黑眼线，形成可爱的淡黄色眉纹。该鸟种广泛分布于各种生境，包括灌木丛、开阔的森林、草原和干燥的金合欢树丛。","appearance":"棕长嘴森莺体型小巧，长度约10至11厘米，重量在9至14克之间。其上部呈灰色，下部带浅褐色或肉桂色调。标准种群的羽毛为棕色，具明显的淡黄白色眉纹和深灰色眼线；翅膀为灰褐色，边缘较淡；脸颊到喉部及胸部为淡黄色，腹部为肉桂色。虹膜为淡褐色，喙长而黑色，腿为红褐色至肉粉色。两性相似，幼鸟特征未详述。亚种在颜色深浅和喙长上有差异，北方亚种颜色较浅，喙较短，南方亚种颜色较深，喙较长。","call":"该鸟的鸣唱为响亮高音的颤音短语，反复多次，如“chree-chirrit, chree-chirrit...”，有时发出更长的“chirrit-chirrit titrr-trrt chip-chip tria-tria-tria chiploi-chiploi”。叫声为滚动的“trrrt trrrt”。","habits":"栖息于干燥的草原，带有浓密灌木或矮树丛的环境，偏好多种类型的次生和混合林地，高度可达2000米。主要以昆虫为食，包括螳螂、甲虫和毛虫，偶尔食用草籽。常单独或成对活动，但也参与多种物种的混群。觅食时，从底部到顶部敏捷跳跃，主要从细枝和叶片上寻找食物。","breeding":"繁殖季节因地区而异，如刚果民主共和国为1月，纳米比亚和南非主要在8月至3月。一夫一妻制，领域性强。巢穴为大型袋状结构，由纤维和干草制成，外饰以树叶、草、蜘蛛网和木屑，悬挂于地面不足1米处。每窝产卵1至3枚；孵化期14天；幼鸟至少由双亲喂养14天。巢常被Chrysococcyx klaaso寄生。","identification":"与红帽森莺相比，红帽森莺的上部颜色更浅，缺少眼线，面部更加开放，呈土黄色。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲中南部，从刚果民主共和国、赞比亚、坦桑尼亚向南延伸至南非，遍及多种生境，包括灌木丛、开阔的森林、草原和干燥的金合欢树丛。","other":"该物种在部分地区密度较高，可能因布拉奇斯特吉亚林地的破坏而在津巴布韦受益。"},{"name":"长嘴森莺","english_name":"Somali Crombec","scientific_name":"Sylvietta isabellina","overview":"长嘴森莺（英文名：Somali Crombec，学名：Sylvietta isabellina），是雀形目长嘴莺科森莺属的鸟类。非洲的长嘴莺科森莺属的小型鸟类。其特征为灰褐色背部，淡色腹部，拥有不寻常的长而略向下弯曲的喙。分布于埃塞俄比亚东部、索马里、肯尼亚及坦桑尼亚东北部。","appearance":"长嘴森莺体长约9.5厘米，体重约10克。头部和上体呈浅灰色，有窄白色眉纹，上方有一条明显的暗色眼纹，脸颊和耳羽淡灰色。翅膀灰色带棕，边缘较浅；腹部主要为淡黄色，两胁带浅褐色斑纹。眼睛棕色，喙黑色，腿为淡棕色或粉棕色。雌雄外观相似，幼鸟比成鸟颜色更暗淡，喉部有轻微斑点。","call":"鸣唱为反复的‘tichit-tichit-tiri-chirichiri chirichiri’声。","habits":"常居于干燥荆棘灌木丛和半干旱灌木林，偏好沿水道的金合欢树或更高大的树木。活动范围局限于特定区域，以昆虫幼虫、虫卵和蜘蛛为食，通常单独或成对在灌木顶部和低矮树冠层觅食。","breeding":"在埃塞俄比亚记录到3月筑巢，在索马里记录到4月，在肯尼亚记录到6月。巢为瓶状，装饰有蛛网和植物绒毛，悬挂在细枝上，每窝产2-3枚卵，其他繁殖信息不明。","identification":"与其他同域内的crombecs物种区别明显，主要通过其长而略微向下弯曲的喙来辨识。","protection":"IUCN：LC（无危）。在索马里南部局部常见，北部及肯尼亚较为少见。","distribution":"分布于东非的埃塞俄比亚南部（从阿瓦什谷地以南，奥莫河以东），索马里的西北部和南部，肯尼亚的北部和东部（从洛基塔翁格至萨姆布鲁和梅鲁，南至察沃河），以及坦桑尼亚的东北极小部分。","other":"已描述的gaekwari亚种由R.B. Sharpe命名，以纪念巴罗达大公Sayajirao Gaekwad III，但被认为是与指名亚种无法区分的。"},{"name":"红顶森莺","english_name":"Red-capped Crombec","scientific_name":"Sylvietta ruficapilla","overview":"红顶森莺（英文名：Red-capped Crombec，学名：Sylvietta ruficapilla），是雀形目长嘴莺科森莺属的小型鸟类，主要分布在非洲中南部，包括安哥拉、刚果共和国、刚果民主共和国、马拉维、莫桑比克、坦桑尼亚、赞比亚、津巴布韦，可能还包括博茨瓦纳。其最显著的特征是头部的红顶，以及灰白色的背部和带有锈色标记的颊部和胸部。","appearance":"红顶森莺体型小，几乎无尾，体长约为11至12厘米，体重约10至12克。头部前额灰色，冠至颈背、颊和耳羽呈栗褐色；背部灰色，上翼和尾暗灰棕色；下颏和喉部灰色带白色斑点，下方有浅栗色带；其余下体部分淡灰色；虹膜淡棕色到橙红色；喙上部深棕色，下部较浅；腿黄色至淡粉色。幼鸟比成鸟更白，喉咙和侧腹带锈色。不同亚种在色彩上有细微差异。","call":"红顶森莺的鸣唱为短暂的上下起伏的颤音。","habits":"栖息于米奥诺木林的树冠层，常见于混合物种的觅食群中。它们偏好亚热带或热带的干燥森林、干燥灌木丛和湿润灌木丛，活动范围广泛，以昆虫为食，包括蚂蚁、甲虫、毛虫和蜘蛛。","breeding":"红顶森莺在旱季末开始繁殖，它们是定居鸟类，使用草和蛛网建造杯状巢，通常在树上或偶尔在高而密的灌木丛中。它们对巢址具有领地性，每次产卵2至4枚，孵化期约为12天。","identification":"与其他Crombecs相比，红顶森莺可通过其头部的锈色脸颊和胸部斑块来识别。不同亚种在头冠颜色上有变化，从沙色到橄榄灰色不等。","protection":"IUCN：LC（无危）","distribution":"红顶森莺分布于非洲中南部，具体包括安哥拉、刚果共和国、刚果民主共和国、马拉维、莫桑比克、坦桑尼亚、赞比亚、津巴布韦，可能还包括博茨瓦纳。","other":"红顶森莺属于旧大陆莺类中的Sylviidae家族，曾被归类于Sylviidae科，现在属于长嘴莺科。"},{"name":"绿森莺","english_name":"Green Crombec","scientific_name":"Sylvietta virens","overview":"绿森莺（英文名：Green Crombec，学名：Sylvietta virens），是雀形目长嘴莺科森莺属的鸟类。其自然栖息地主要为非洲西部和中部的热带湿润低地森林及灌木地带。","appearance":"绿森莺体型小，几乎无尾，整体呈现橄榄绿色。头部略深色的帽状羽毛与浅色的眉纹形成对比。下体颜色因地理区域而异，从棕色混合灰色到淡黄色不等。与黄腹森莺相似，但体型稍大，喙更长，即使是腹部显黄色的亚种，其黄色也比黄腹森莺更暗淡。","call":"绿森莺通常因其歌声而被察觉，这是一种快速而富有音乐感的颤音，呈下降模式。","habits":"绿森莺常见于热带雨林的中层及下层植被中，栖息于次生林和灌木丛中，常以成对或小群体的形式出现。","identification":"与黄腹森莺相比，绿森莺体型更大，喙较长，即使腹部有黄色的亚种，其色彩也较暗淡。","distribution":"绿森莺广泛分布在非洲热带雨林区域，具体包括非洲西部和中部。"},{"name":"黄腹森莺","english_name":"Lemon-bellied Crombec","scientific_name":"Sylvietta denti","overview":"黄腹森莺（英文名：Lemon-bellied Crombec，学名：Sylvietta denti），是雀形目长嘴莺科森莺属的鸟类。是非洲热带雨林中的一种小型朴素的森莺。在非洲的西部和中部稀疏分布，栖息于亚热带或热带的湿润低地森林及湿润灌木丛。","appearance":"黄腹森莺是一种小巧的森林边缘鸟类，具有紧凑的体态，短尾，长度几乎与翼尖齐平，以及相对较长的喙。全身颜色均匀，上体橄榄绿，下体黄色带绿，喉部呈灰色。","call":"其鸣唱独特而尖锐，连续发出“suweet suweet suweet suweet suweet！”的叫声，长度变化不定。","habits":"黄腹森莺常在树叶和细枝间觅食，偏好生活在亚热带或热带的湿润森林环境中。","identification":"与其他森莺属鸟类相比，黄腹森莺的橄榄绿色上体和黄色带绿的下体是其显著特征。","distribution":"黄腹森莺的自然分布覆盖了非洲的西部和中部，包括亚热带或热带的湿润低地森林及湿润灌木丛。"},{"name":"白眉森莺","english_name":"White-browed Crombec","scientific_name":"Sylvietta leucophrys","overview":"白眉森莺（英文名：White-browed Crombec，学名：Sylvietta leucophrys），是雀形目长嘴莺科森莺属的鸟类。拥有明显的白眉纹和栗褐色冠羽，分布于非洲东部的山地森林中。","appearance":"体型小巧，约9至9.5厘米长，体重介于8至13.5克之间。成鸟具有宽阔的白色眉纹，与栗褐色的冠羽和眼后带形成鲜明对比。上体呈暗橄榄棕色，翼部和尾部为深棕色，边缘亮黄绿色。喉咙白色，下体灰色，腹部中央颜色更浅。虹膜暗红棕色，喙上部淡棕色，下部灰棕色，腿粉色。雌雄相似。幼鸟头部至喉部、胸部和两侧暗棕色，眉纹微黄，下体淡黄色。'chloronota'亚种比指名亚种更绿，脸颊和耳羽处栗褐色更广泛。","call":"歌声为一系列高低起伏的细小颤音，叫声低沉。","habits":"栖息于山地森林边缘和较为开阔的部分，偏好竹林地带的纠缠灌木丛。常在海拔1500至2800米间活动，有时低至1290米，高至3000米。以昆虫为主食，包括甲虫、毛虫和蜘蛛等。在低矮植被和附生植物中觅食，高度通常不超过6米，偶尔可达12米，常加入混种群。","breeding":"繁殖季节在6月至7月（刚果民主共和国）、8月和9月（卢旺达）、2月（布隆迪）、5月至6月（乌干达）、12月、1月和3月至7月（肯尼亚）。独居并具领域性。巢为袋状或篮状，由草和苔藓构成，内部铺有少量羽毛，通常悬挂于距地面约1米的叉枝、细枝或草丛中。有时会二次筑巢，使用附近的替代地点。每窝产2或3枚光泽白色或玫瑰粉色的蛋，大端散落着红色或紫红色斑点，尺寸约为14.9-15.3mm×11.8-12mm。","identification":"与Chapin's Crombec非常相似，但白眉森莺可通过其宽阔的白色眉纹轻松区分。","protection":"IUCN：LC（无危）。","distribution":"分布于刚果民主共和国的Lendu高原，以及布隆迪、卢旺达、坦桑尼亚、乌干达和肯尼亚的山地森林。","other":"虽然全球不处于威胁状态，但在Lendu高原的种群可能已极度稀少，甚至可能灭绝，由于森林破坏，目前仅剩约20公顷森林。"},{"name":"维氏短翅莺","english_name":"Victorin's Warbler","scientific_name":"Cryptillas victorini","overview":"维氏短翅莺（英文名：Victorin's Warbler，学名：Cryptillas victorini），是雀形目长嘴莺科维氏短翅莺属的鸟类。非洲特有的长嘴莺科鸟类，原归类于树莺科。隶属于单型属Cryptillas，以纪念瑞典旅行家Johan Fredrik Victorin，他曾到访南非。","appearance":"体长15至17厘米，体重约10克。具有短小的翅膀和由十根狭窄羽毛组成的楔形长尾。头部顶部和侧面呈灰色，眼上有一条不明显的肉桂色细纹；背部、上翼和尾部为深暖棕色；腹部全为肉桂棕色，喉咙和腹部中央颜色最浅，泛着肉桂色光泽；虹膜为红棕色至橙黄色；喙灰褐色，下颌基部较淡带黄色；跗跖灰褐色至粉红色。雄雌外观相似。幼鸟上半身暗灰棕色，颏至胸部淡赤棕色，但下体比成鸟更淡；眼睛灰色。","call":"其叫声独特，常被描述为响亮、悠扬、悦耳的‘sip-sip-silly-slip-slip’重复旋律，持续时间通常超过一分钟，结尾时会发出尖锐干燥的‘tsit-chirrit-chirrit’声或类似叫声。","habits":"偏好湿润的石楠灌丛环境，尤其在沼泽地带，周围有莎草和Berzelia植物，以及森林边缘蕨类植物茂盛的林间空地。活动时如同小鼠般蹑手蹑脚，通常首先通过其特征性的歌声被发现。","breeding":"具体繁殖信息未详述。","identification":"在同属中独树一帜，可通过其独特的灰色脸部图案，以及肉桂色下体和特定的叫声辨识。","protection":"IUCN状态未提及。","distribution":"主要分布于南非南部，具体为西开普省（自北Cedarberg山脉向南）沿岸地区（内陆延伸至约75公里）至东开普省（至乌伊滕哈格）。","other":"在8月至11月期间，当其最频繁地歌唱时，最容易观察到维氏短翅莺。"},{"name":"黄腹鹟莺","english_name":"Yellow-bellied Warbler","scientific_name":"Abroscopus superciliaris","overview":"黄腹鹟莺（英文名：Yellow-bellied Warbler，学名：Abroscopus superciliaris），是雀形目树莺科拟鹟莺属的鸟类。体型略小(约11厘米)的莺鸟，以其独特的橄榄绿上部和鲜明的黄色腹部为特征。分布于喜马拉雅山脉东段、中国南方、东南亚及大巽他群岛，偏好次生林，尤其是竹林丰富的地带。","appearance":"该鸟体长约9厘米，体重6-7克，拥有相对较大的喙，短的尾下覆羽和窄尾，闭合时形成独特的尾部外观。头部前额、顶冠和颈背呈暗灰色，眉纹延伸至眼后，耳羽暗色或棕灰色。上部橄榄绿色，臀部和尾上覆羽带淡黄色，翅膀和尾巴褐色，边缘橄榄绿色。下部柠檬黄色，喉部和胸部偏白。虹膜深棕色，有不显眼的白色环。喙部深棕色，下颌基部转为粉红色，腿脚淡粉棕色或浅粉色。幼鸟比成鸟暗淡，颜色较暗。不同亚种在色彩饱和度、头部和颈背颜色、胸白程度以及臀部黄色强度上有所差异。","call":"其鸣唱为一连串约6个高音尖锐的哨声，具有轻微颤音，中间部分尤为明显，音调逐渐升高，如“dee-dee-dir-rit-tit-deweet”。此旋律会重复三到四次，每次音调比前一次更高。此外，还有一种持续的低沉啾啾声，可能为接触叫声。","habits":"栖息于常绿森林的灌木层，尤其偏爱沿溪流的竹林地带，高度从低地至海拔1525米，甚至在不丹和尼泊尔记录到高达2200米和2285米。基本为留鸟，冬季会向较低海拔迁移，可能出现在平原的森林溪流旁。食物主要是微小的无脊椎动物，如蜘蛛、小型双翅目昆虫和蝴蝶卵。在非繁殖季节常结成小群，有时会加入混群，但不如同类物种频繁。","breeding":"繁殖季为4月初至6月，在印度东北部，3月下旬开始于北婆罗洲。巢由两性共同建造，以苔藓、纤维和根须构成，置于不超过2米高的地面，通常位于竹林中的空洞处，靠近溪流。每窝产卵2-5枚，两性共同孵化，孵化期未知，巢雏期资料未详。巢被普通杜鹃寄生。","identification":"黄腹鹟莺的橄榄绿色上部、明亮的黄色腹部、白色的眉纹和喉部组合在分布区内独一无二。不同亚种在色彩饱和度、头部和颈背颜色、胸白程度以及臀部黄色强度上有所差异，提供辨识依据。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界，从东南亚至婆罗洲和爪哇岛。在中国大陆，主要见于喜马拉雅山脉东段、南方地区。"},{"name":"棕脸鹟莺","english_name":"Rufous-faced Warbler","scientific_name":"Abroscopus albogularis","overview":"棕脸鹟莺（英文名：Rufous-faced Warbler，学名：Abroscopus albogularis），是雀形目树莺科拟鹟莺属的鸟类。分布于东洋界，自喜马拉雅山脉东部至东南亚，包括尼泊尔、中国南方及台湾等地。头部两侧呈现独特的橙色，背部为绿色，腹部白色，具有淡黄色的胸带和黑色侧冠纹，喉部散布着黑色斑纹。","appearance":"成年棕脸鹟莺体长约8-9厘米，体重约4.7-5克，拥有较宽的喙。雄雌相似，但雌鸟的喉咙更白，带有黑色斑点。幼鸟颜色比成鸟暗淡，头部的橙色被橄榄色冲淡，黑色的冠纹较淡，胸部几乎无黄色。该物种有几种亚种，其中emfulvifacies/em亚种颜色更深，emhugonis/em亚种上体颜色更暗绿。","call":"鸣唱声为一系列高亢、尖细的哨音，重复发出“tititiriiii”的哀婉长笛声，还有尖锐的推特声，可能作为联系信号。","habits":"栖息于海拔600米至1200米的常绿森林下层，尤其是竹林中，有时低至300米，高至1800米。它主要以小型无脊椎动物为食，活跃于下层植被中，会飞到树冠边缘觅食，然后返回下层，偶尔在飞行途中捕捉昆虫。非繁殖季节可能会散见于混种鸟群中。","breeding":"繁殖季在印度东北部为4月初至6月。巢由两性共同构建，主要材料为竹叶、纤维和根须，巢杯部分由苔藓构成，通常建在竹子的空洞中，靠近溪流。每窝产卵3-5枚，孵化由双亲共同承担。","identification":"与栗头鹟莺相比，棕脸鹟莺的头部两侧为栗色，白色眼圈不明显且无翼斑。不同亚种之间存在细微的颜色差异。","protection":"IUCN：LC（无危）；在某些地区如尼泊尔非常罕见，仅在Ilam区最近被重新发现。","distribution":"分布于东洋界，包括喜马拉雅山脉东部至东南亚，具体国家有孟加拉国、不丹、中国、老挝、缅甸、尼泊尔、台湾、泰国、越南。","other":"在繁殖季节外，可能参与多种物种的混群，尤其与叶莺混群。"},{"name":"黑脸鹟莺","english_name":"Black-faced Warbler","scientific_name":"Abroscopus schisticeps","appearance":"体长约10厘米，体重约6克。头灰，面部黑色，眼上具亮丽的黄色眉纹几乎相连于前额，喉咙鲜黄，腹部白色微带黄橄榄色。背部橄榄绿色，臀部最亮，翼褐色边缘略带黄橄榄色，尾褐色边缘黄橄榄色，最外侧两根尾羽内缘白色。下体黄白至黄橄榄色。虹膜红褐至深褐色，下喙尖端及上喙切割缘淡粉色，其余部分中棕色，腿淡粉色或灰棕色。幼鸟比成鸟颜色暗淡，头部灰色被橄榄色浸染，眉纹较淡且苍白，喉咙及下体黄色较淡。不同亚种主要在喉咙颜色和羽毛黄色强度上有差异。","call":"鸣唱细薄且空灵，高音颤音\"tirririr-tsii tirririr-tsii tirririr-tsii\"或\"tit sirriri-sirriri sirriri tit-sirriri\"等，低沉的\"tit\"声似乎是在觅食时发出的联系信号。","habits":"结小群生活在常绿山地林中的多苔藓棘丛，主要栖息于亚热带或热带湿润的低地森林和山地森林。","identification":"与黄喉雀鹛及黄腹扇尾鹟的区别在于其较小的尾巴没有明显的白色终端斑点，下体黄色不如后者均匀。黑脸鹟莺的头部图案极具特色，需注意区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域与非繁殖区域均位于喜马拉雅山脉中部至越南西北部，具体包括不丹、中国、印度、缅甸、尼泊尔和越南。"},{"name":"金头拟缝叶莺","english_name":"Mountain Tailorbird","scientific_name":"Phyllergates cucullatus","overview":"金头拟缝叶莺（英文名：Mountain Tailorbird，学名：Phyllergates cucullatus），是雀形目树莺科伪缝叶莺属的鸟类。曾归类于旧世界莺类，现置于树莺科（Cettiidae）的Phyllergates属中。这小巧的鸣禽，以亮黄色的下体、橙色的前额和头部以及橄榄绿色的上体为主要特征。分布于远东、澳新界，包括印尼苏拉威西岛，以及中国西南地区。","appearance":"这种小鸟身长10-12厘米，体重仅6-7克，拥有细长的喙和微微翘起的尾巴。其特征包括明亮的黄色下体，清晰但较短的眉纹，相对长且略向下弯曲的喙，以及逐渐变短的尾巴。成鸟的额头和前冠呈橙色，颈背灰色，上体橄榄绿色，翼部偏棕色，尾巴橄榄绿色，最外侧的尾羽内缘白色。喉部和胸部中心为灰白色，两胁和腹部至尾下覆羽为鲜亮的金丝雀黄色。幼鸟比成鸟暗淡，眼睛棕色。","call":"其歌声极为高亢，如同一系列清脆的哨音，具有超凡脱俗的音质。叫声包括高降的颤音和干燥的叽喳声。","habits":"栖息于山地森林、开阔的山地灌丛及茂密的竹丛中，偏好沿水道的灌木丛、竹林和挂满藤蔓的环境。海拔分布从1000米到2500米，季节性迁移，雨季时会下降至低海拔地区。","breeding":"繁殖季节在印度东北部为5月至7月，在东南亚为2月至4月，在苏拉威西岛为7月至8月，与雨季同步。巢由精细的草茎和干苔藓构成，内衬植物绒毛，位于1.5-6米高的藤蔓、小树或竹子上。巢可能被刷腹鹰鹃寄生。","identification":"与常见的或黑颈缝叶莺相比，金头拟缝叶莺体型更小，喙更长，眼纹黑色，前额亮橙色。不同亚种在羽色上有细微差别。","protection":"IUCN：LC（无危）","distribution":"分布于孟加拉国、不丹、柬埔寨、中国、印度、印度尼西亚、老挝、马来西亚、缅甸、菲律宾、泰国和越南。在中国，主要分布于西南地区。"},{"name":"褐头缝叶莺","english_name":"Rufous-headed Tailorbird","scientific_name":"Phyllergates heterolaemus","overview":"褐头缝叶莺（英文名：Rufous-headed Tailorbird，学名：Phyllergates heterolaemus），是雀形目树莺科伪缝叶莺属的特有种。仅分布于菲律宾南部的棉兰老岛山区，其最显著的特征是头部的橙褐色和腹部的鲜黄色。","appearance":"这种小型鸟类身长约11厘米，体重约6至7克。其背部、翅膀和尾巴呈橄榄色，腹部明亮黄色，头部红褐色，喉部和胸部淡黄色。嘴较长，稍向下弯曲。成年鸟的头部、颈侧橙红褐色，上体鲜艳的橄榄绿色，臀部和尾上覆羽泛黄。初级飞羽隐蔽部分为棕色，尾羽橄榄绿色，内缘大部分为棕色。两性相似，但幼鸟头部、颈部和前体橄榄绿色替代了红褐色。","call":"鸣唱由极短而间距较大的变化音节组成，音调较高，悠长的吹哨声。","habits":"栖息于棉兰老岛的山地森林和灌木丛中，常在较高海拔活动。具体生活习性细节有待进一步研究。","breeding":"繁殖习性等信息尚未详尽记载。","identification":"与棉兰老岛上的其他缝叶莺种类相比，具有较高的海拔分布，黄腹和红褐色头部，易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾南部的棉兰老岛，具体为阿波、布萨、基唐格拉德、马图图姆、梅奥和普廷巴托等山脉。"},{"name":"宽嘴鹟莺","english_name":"Broad-billed Warbler","scientific_name":"Tickellia hodgsoni","overview":"宽嘴鹟莺（英文名：Broad-billed Warbler，学名：Tickellia hodgsoni），是雀形目树莺科宽嘴鹟莺属的鸟类。拥有绿色背部、黄色腹部、灰色头部和栗色冠羽，与金头拟缝叶莺相似但具有明显较短的喙和更广泛的栗色头部。分布于喜马拉雅山脉东部至越南北部，包括不丹、中国、印度、老挝、缅甸、尼泊尔和越南。在云南东南部作为夏候鸟出现。","appearance":"宽嘴鹟莺长约10厘米，重4-5克，体型较为丰满，腿较长。额头和头顶呈栗色，眼先、头侧暗苍灰色，眉纹淡灰色。上体橄榄绿色，腰部略带黄色。尾羽暗褐色，边缘橄榄绿色，最外侧两对尾羽内侧全白。颏、喉、上胸灰色，其余下体鲜黄色。虹膜棕色，喙暗角质色，下颌基部淡黄色，腿肉黄色。","call":"其鸣唱由一系列高音‘tseeeee’和‘tsi-leeeeee’组成，以及较低沉的滚动声。还有兴奋的、快速的金属质感‘witiwiwititwi-chu-witiwitiwiti’叫声。","habits":"宽嘴鹟莺栖息于中到高山森林的浓密灌木丛中，常在竹林中活动。以昆虫为食，具体猎物种类未知。非常活跃，会从树木的枝条和近地面处悬停捕食昆虫。通常独居，但也可能形成小群体，非繁殖季节会加入混杂物种的游荡群。","breeding":"关于繁殖习性的具体信息未详述。","identification":"与金头拟缝叶莺的区别在于较短的喙、不渐变的尾羽、更广泛的栗色头部、较短的眉纹、灰色的喉和胸部，以及下方较暗淡的黄色。","protection":"IUCN状态未提及。","distribution":"分布于喜马拉雅山脉东部至越南北部的东洋界，包括中国云南东南部作为夏候鸟。"},{"name":"菲律宾树莺","english_name":"Philippine Bush Warbler","scientific_name":"Horornis seebohmi","overview":"菲律宾树莺（英文名：Philippine Bush Warbler，学名：Horornis seebohmi），是雀形目树莺科暗色树莺属的鸟类。此物种在菲律宾北部吕宋岛的山区特有，栖息于热带山地森林。其外观以褐色为主，具深色眼纹，胸部灰白，喉部近白色。","appearance":"体型小巧，上体和头部呈温暖的棕色，有明显的深色眼纹，下体颜色渐变为淡棕色至灰色胸腹，喉部几乎白色。与长尾短翅蝗莺相似，但尾部较短，下体更偏灰色而非深棕色。与本格特短翅蝗莺相似，但眉纹更为鲜明。","call":"其鸣唱由一段低沉的长哨音开始，随后是爆发性的哨音短语。叫声为尖锐的‘tsik！’。","habits":"栖息于海拔800米以上的热带山地松林中，常在森林下层及低矮灌木丛活动。对于其生态习性了解甚少。","identification":"与长尾短翅蝗莺和本格特短翅蝗莺相区别，主要通过尾长、下体颜色和眉纹的明显程度。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾吕宋岛北部的山区。"},{"name":"日本树莺","english_name":"Japanese Bush Warbler","scientific_name":"Horornis diphone","overview":"日本树莺（英文名：Japanese Bush Warbler，学名：Horornis diphone），是雀形目树莺科暗色树莺属的鸟类。常见于日本、库页岛至琉球群岛和中国东部、中部的亚洲树莺。其独特的春日鸣唱遍及日本各地，成为春季到来的象征。该鸟体长约15.5厘米，呈橄榄褐色，腹部偏灰暗色，眉纹淡雅。在日本文化中不仅是诗歌的常客，也是春天的使者。","appearance":"日本树莺体型较小，约15-18厘米，体重介于9-26.6克之间，雄鸟比雌鸟大。头部有锈色边缘，长长的奶油色或浅黄色眉纹，黑褐色的眼线，脸颊和耳羽带有不同程度的灰褐色斑点。背部、翅膀和尾巴橄榄棕色，飞羽有锈色边缘。腹部颜色从奶油色到带有淡黄色洗纹，两胁和下尾覆羽橄榄棕色。喙部棕色或角质色，腿脚粉红色或珍珠灰色。","call":"日本树莺的鸣唱始于春季，由一段悠长的笛音“hot-ket-kyot”和一系列下降的双哨音“pe-chew, pe-chew, pe-chew”组成，叫声为干涩的滴答声响。其鸣唱在白天从灌木丛或树木中发出，是其最显著的特征。","habits":"栖息于低山至高山的矮竹丛、高草丛和森林密生处，海拔可达3000米，偶尔出现在日本北部的海岸灌木丛。在非繁殖季节，它们出现在低地的类似栖息地，甚至城市和郊区的花园和公园中。日本树莺是居民和迁徙鸟类，部分亚种会迁往东南亚中国等地过冬。","breeding":"繁殖季为3月至8月，有时育两窝，因巢失败而重新筑巢的现象常见。巢为干草、植物纤维、叶子和毛发制成的球状，位于离地面不到1米的茂密植被中。雌鸟承担全部繁殖任务，包括筑巢、孵化和育雏，孵化期为16天，雏鸟离巢期为14天。巢穴易受寄生鸟如小杜鹃的侵扰。","identification":"与其他树莺相比，日本树莺上体颜色较淡，眉纹更突出，喙较大，下体颜色更白。与宽尾树莺的区别在于体型更大（尾巴更长）、喙更大、额头和头顶锈色，以及下体颜色差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区包括库页岛、日本、琉球群岛和中国东部、中部。非繁殖区则在中国南部、东南部、台湾和东南亚。在日本，分布广泛，但在北海道，主要在夏季出现。在夏威夷群岛也有引入种群。","other":"在日本文化中，它是诗歌的常见主题，与樱花一起象征着春天的到来。"},{"name":"远东树莺","english_name":"Manchurian Bush Warbler","scientific_name":"Horornis canturians","overview":"远东树莺（英文名：Manchurian Bush Warbler，学名：Horornis canturians），是雀形目树莺科暗色树莺属的鸟类。小型的暖棕色树莺，由罗伯特·斯温霍于1860年首次描述。其分布于中国东北部，活动于次生灌丛中，最高可达海拔1500米。繁殖季节在2月至7月间，歌声丰富，易于被其独特的鸣唱所吸引。","appearance":"成年远东树莺体长15-18厘米，体重雄鸟18.5-34.5克，雌鸟10-18.2克（指名亚种），雄鸟略大。上体色调明显红褐色，尤其是刚换羽时更为明显，头顶呈明亮的红褐色或肉桂色，臀部和飞羽边缘略显温暖和淡色。超长的浅色眉纹延伸至眼后方，深棕色眼线，耳羽淡而斑驳；下体一般为暗白色，胸部两侧、腹侧和尾下覆羽常带较强的土黄色。喙灰褐色，下颌基部淡粉色，尖端较暗；腿和脚为淡灰粉色，眼睛为棕色。雌雄相似，雄鸟明显较大。幼鸟与成鸟非常相似，但眉纹和下体带黄色调，喙裂淡粉色（成鸟为黄色），虹膜灰蓝色；翅膀和尾巴较短。","call":"远东树莺的鸣唱开始于低沉的滑音或呼噜声，随后是一连串丰富的音乐般的颤音，结束于流畅的‘tu-u-u-teedle-ee-tee’声。与厚嘴苇莺的鸣唱相比，速度略快，起始部分音量和强度逐渐增加，不包含典型的‘ket-kyot’短语。与日本树莺的差异在于引子更长、更安静、变化较少，结尾部分音符较少。每首歌持续约1-2秒，之后是较长的停顿，通常持续3-7秒，或在连续歌唱期间更长。繁殖季节，从2月中旬至少到7月，有时整天都在歌唱，直到雌鸟到达。","habits":"远东树莺通常单独或成对出现，活跃于早晨，主要在地面或离地2米以内觅食，食物主要是昆虫和幼虫。它栖息于高达海拔1500米的次生灌丛。","breeding":"远东树莺的繁殖习性尚需更多研究，已知的是它们在2月至7月间歌唱，可能是在求偶和繁殖期间。","identification":"远东树莺与厚嘴苇莺的区别在于眉纹色淡，体型较小，嘴细，头顶偏红，下体皮黄色较少。与日本树莺的区别在于颜色偏向棕色，下体两侧和尾下覆羽多为暗皮黄色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括中国中部、东部，西伯利亚东南部和朝鲜半岛。非繁殖期迁至中国南部、东南亚和菲律宾北部。","other":"远东树莺与日本树莺在体羽和鸣声上有细微差异，曾被视为日本树莺的一个亚种，但现在多数学者认为它是独立的物种。"},{"name":"帕劳树莺","english_name":"Palau Bush Warbler","scientific_name":"Horornis annae","overview":"帕劳树莺（英文名：Palau Bush Warbler，学名：Horornis annae），是雀形目树莺科暗色树莺属的鸟类。这体型较大的、色彩较为暗淡的树莺，以橄榄棕色为主调，腹部略显绿色或黄褐色。其最显著的特征是拥有长而鲜艳的橙色喙与橙色腿脚，常栖息于森林中的茂密灌木丛与藤蔓交织处。","appearance":"帕劳树莺身长约为14至15厘米，喙部细长呈锥形。头部特征明显，眼眉呈淡黄色至橄榄黄色，眼纹深色，脸颊与耳羽灰橄榄色；头顶至背部、翅膀与尾巴皆为灰橄榄色；腹部橄榄黄色，尤其在下巴与喉咙部位颜色最为鲜艳，尾下覆羽带橄榄色；虹膜深色；上颌角质棕色，下颌淡黄色或粉红色；跗跖为黄棕色至橙粉色。与所罗门树莺和斐济树莺相比，帕劳树莺体型更大，上体羽毛无锈色或肉桂色；与相似的日本树莺（亚种 cantans）的区别在于尾巴较短，喙较大，眼眉与下体为橄榄黄色而非灰色。雌雄羽毛相似，雌鸟体型略小于雄鸟。幼鸟外观似成鸟，但前额与头顶颜色较淡或微黄，背部与臀部呈棕色。","call":"其鸣唱为一连串长而类似笛声的哨音，音调或升或降，叫声则为责备式的叽叽喳喳。","habits":"生活在密集的森林底层植被中，偏好在藤蔓交错的环境中活动。","identification":"帕劳树莺通过其大型体型、橄榄黄色的眼眉与下体、以及长而锥形的橙色喙与橙色腿脚与近缘物种区分开来。","protection":"IUCN：LC（无危）","distribution":"帕劳树莺仅分布于帕劳群岛（包括Babelthaup、Koror、Garakayo、Peleliu和Ngabad等岛屿），位于加罗林群岛西部，密克罗尼西亚西部。"},{"name":"台岛树莺","english_name":"Tanimbar Bush Warbler","scientific_name":"Horornis carolinae","appearance":"塔宁巴树莺是一种中等体型的树莺，雄鸟体长12.5至13厘米，体重18.6至20.6克；雌鸟略小，体长11至11.5厘米，体重13.5至15克。其具有明亮的赤褐色冠羽，长长的浅色眉纹，边缘略带灰色，深棕色的面颊和眼线，耳羽斑驳的灰褐色。上体棕色，飞羽和尾羽边缘略显赤褐色。下体灰白色，喉咙和腹部中央更白，两侧灰或橄榄灰色，两胁和下尾覆羽变为淡黄色或橄榄褐色。虹膜深色，上喙黑色或暗角质色，下喙粉红或淡角质色，腿粉色至蓝角质色。雌雄羽毛相似，但雄鸟体型大于雌鸟。幼鸟特征未描述。","call":"塔宁巴树莺的歌声独特，属于典型的树莺鸣叫，开始时为逐渐升高的三音节哨声，第三个音符显著拉长，随后是杂乱的第四个音符：‘tu-tu-tuooooo-chyop’。此外，还会发出突然的‘chup’叫声。","habits":"这是一种栖息于森林浓密下层植被中的树栖物种，偏好竹林、灌木丛和森林边缘地带。其活动范围局限于Yamdena岛。","breeding":"具体繁殖细节未详述。","identification":"塔宁巴树莺与范围内其他类似褐色树莺的鸟类如棕顶大尾莺和Zitting及Golden-headed Cisticolas的区别在于其上体无条纹，独特的冠羽颜色和眉纹。","protection":"IUCN：NT（近危）","distribution":"仅分布于印尼摩鹿加群岛南部的Yamdena岛。"},{"name":"所罗门树莺","english_name":"Shade Bush Warbler","scientific_name":"Horornis parens","overview":"所罗门树莺（英文名：Shade Bush Warbler，学名：Horornis parens），是雀形目树莺科暗色树莺属的鸟类。仅分布于所罗门群岛的马基拉岛，是该岛特有种。其外观呈现三色调：腹部灰白，背部栗棕色，头部淡赤褐色，眼纹稍深。","appearance":"这种小型树莺具有典型的三色调外观，腹部颜色较淡，接近灰色，背部为鲜明的栗棕色，头部呈现出淡赤褐色，眼纹部分颜色较深。雌雄羽毛色彩基本一致，幼鸟的色彩可能更为柔和。","call":"其常见叫声为先上升后下降的哨音，这是它在林间活动时的标志性声音。","habits":"所罗门树莺偏好生活在海拔600米以上的森林环境中，尤其喜欢密集的灌木丛和林缘地带。它们主要以地面和低矮植被中的昆虫为食。","breeding":"关于其生长繁殖的详细信息尚待更多研究，但已知它们在热带湿润的低地森林和山地森林中筑巢繁殖。","identification":"与其他树莺相比，所罗门树莺的三色调特征明显，尤其是头部的淡赤褐色和眼纹的深色区别于同类物种。","protection":"IUCN：LC（无危）","distribution":"所罗门树莺仅分布于所罗门群岛的马基拉岛，具体位置在所罗门群岛的东南部。","other":"所罗门树莺是马基拉岛上特有的鸟类，对于研究该地区生物多样性具有重要意义。"},{"name":"布岛树莺","english_name":"Bougainville Bush Warbler","scientific_name":"Horornis haddeni","overview":"布岛树莺（英文名：Bougainville Bush Warbler，学名：Horornis haddeni），是雀形目树莺科暗色树莺属的鸟类。小型、圆身的树莺。其生存于所罗门群岛北端的布干维尔岛山区，仅在此特定区域发现。","appearance":"外观呈现三色调：腹部呈深灰色，背部为栗棕色，头部偏红褐色，眼纹略深。尾巴短小，常藏匿于密林下层或森林边缘的茂密灌丛中，高度通常超过600米，局部地区可能更低。","call":"鸣唱为高音哨声'oh-de-di'，同时会发出尖锐的斥责声。","habits":"偏好栖息在海拔600米以上的密集下层植被和森林边缘。以森林内的昆虫为主要食物来源。","breeding":"具体繁殖习性尚待更多研究确认。","identification":"其独特的三色调外观和高音鸣叫使其在同属物种中易于辨认。","protection":"IUCN：NT（近危）","distribution":"仅分布于所罗门群岛中的布干维尔岛山区，即澳新界布干维尔岛的山区。","other":"自20世纪70年代起，尽管因岛上内战曾一度中断外来访问，但通过声音被多名鸟类学家确认存在。2000年首次成功捕获个体，此后几个月内又捕获两例。"},{"name":"斐济树莺","english_name":"Fiji Bush Warbler","scientific_name":"Horornis ruficapilla","overview":"斐济树莺（英文名：Fiji Bush Warbler，学名：Horornis ruficapilla），是雀形目树莺科暗色树莺属的小型鸟类。具有亮橙色至红褐色头部，灰白色的下巴和喉咙，淡灰黄褐色的胸部和腹部，两翼和尾部橄榄棕色带红褐色调。主要分布于斐济群岛，包括除劳群岛（Lau Arch.）以外的所有主岛，是斐济特有种。","appearance":"斐济树莺体长12-13厘米，体重约12.7克。中等体型，羽毛颜色较为暗淡，尾羽较长，喙细长。头部和面部呈红褐色，有明显的深色眼纹；上体包括翅膀和尾巴呈灰橄榄棕色；下体颜色较浅，呈灰白至淡灰黄褐色；腿粉肉色。雌雄外观相似，幼鸟与成鸟相似，但下体颜色更暗或偏棕色。不同亚种在颜色上有细微差异，如badiceps亚种脸颊和耳羽灰色，castaneopterus亚种上体更偏棕色，funebris亚种体型较大，背部颜色更深。","call":"其叫声为短暂的‘che che’或‘tsic-tsic’。鸣唱时，通常从低矮植被发出，有时从较高的竹林或落叶树中响起，由单一个体或一对鸟进行二重唱。鸣声开始是一长串未修饰的哨音，音量逐渐升高，随后是一系列较短的乐句，如‘feee-e-e-e-fiddle-dee-dee’或响亮的颤音，融入‘tsic-tsic’叫声；响亮的颤音有时也会在没有前奏哨音的情况下发出；另一只鸟几乎立即以尖锐的‘tsic-tsic’回应，给人以一只鸟从不同地方歌唱的印象。","habits":"栖息于高地森林的浓密灌木丛和竹林中，偶尔低至海平面附近。主要食物为小型无脊椎动物。觅食时活跃但极为隐秘，很少在开阔地带或空中被观察到，有时在混合物种觅食群中出现。","identification":"与Megalurulus rufus相比，斐济树莺体型较小，下体呈灰白色而非红褐色或红棕色。不同亚种在颜色上存在细微差异，如badiceps亚种脸颊和耳羽灰色，castaneopterus亚种上体更偏棕色，funebris亚种体型较大，背部颜色更深。","protection":"IUCN状态未提及。","distribution":"主要分布于斐济群岛，包括除劳群岛（Lau Arch.）以外的所有主岛。"},{"name":"强脚树莺","english_name":"Brown-flanked Bush Warbler","scientific_name":"Horornis fortipes","overview":"强脚树莺（英文名：Brown-flanked Bush Warbler，学名：Horornis fortipes），是雀形目树莺科暗色树莺属的鸟类。直译: 棕胁树莺，该物种体长约为11-12.5厘米，羽色黯淡，上体呈深褐色，下体浅灰褐色，具长而皮黄色的眉纹。主要分布在喜马拉雅山脉至中国东部及台湾地区。","appearance":"该鸟体型小，长度在11-12.5厘米之间，重量约8-11.5克。头部特征不明显，具有窄而偏灰白或灰色的眉纹，模糊的棕色眼纹；上体橄榄褐色，飞羽边缘带有更多的赤褐色；下体灰橄榄色至腹部，侧翼橄榄褐色；眼睛颜色深暗；喙部暗褐色带粉红色下颚基部；腿为淡黄褐色或粉红褐色。雌雄相似，幼鸟与成鸟极为相像，但上体以橄榄色调为主，飞羽边缘暖褐色，下体带有黄色调。","call":"其鸣唱为一声响亮的哨音“weeeeeee”，随后是爆炸性的“chiwiyou”或“cliiwhichee”或响亮的“tyit tyu-tyu”。叫声为尖锐的“chuk”或“tchuk tchuk”，有时持续重复。","habits":"繁殖季节栖息于浓密的灌木丛、竹林丛及温带森林的中层，亦见于草边和开阔地带、山坡上的灌木丛（如小檗和栒子）、山脊、石坡、茶园边缘及偶尔出现在山谷底部较潮湿的地区；海拔高度在1200-1800米间，偶尔可达3300米。非繁殖季节主要活动于丘陵和平原边缘的灌木丛和芦苇床旁；通常在1200米以下，最低可至约215米，但有时仍会留在较高海拔，例如在尼泊尔可达2135米。","breeding":"繁殖季节为5月至8月，幼鸟自6月初开始离巢；可能有两次繁殖。一夫一妻制。巢由干草、叶子、Misacanthus穗状花序、植物纤维、苔藓和羽毛构成的球状或深杯状，放置于低矮的灌木、藤蔓或浓密植被中，通常离地面不到1米；领地面积可达300平方米。一窝产3-5枚卵；关于孵化期和雏鸟期的信息尚缺。","identification":"与淡脚树莺的区别在于橄榄色的上体、较暗的下体、较浅的腿色以及缺乏强烈的脸部图案。亚种pallidus的上体更冷色的棕色，眉纹为米黄色而非灰白色，喉咙和胸部为棕色，侧翼带有较浅的米黄色。亚种davidianus的喉咙至腹部中央更白。亚种robustipes脸部图案弱，眼纹深（尤其是眼前方），眉纹仅在眼前后略显白色，下体为淡黄褐色。","protection":"IUCN：LC（无危）。总体上常见或局部常见。在印度次大陆，巴基斯坦北部稀缺至常见，喜马拉雅中部更常见，东北部非常普遍。缅甸（如维多利亚山）和北印支半岛较为常见；在中国大陆和台湾也较为常见。","distribution":"分布于喜马拉雅山脉至中国东部及台湾地区。在中国大陆，常见于西南部如贵州等地。","other":"该物种在繁殖季节面临巢穴被寄生的风险，如在一项研究中发现约49%的巢穴被掠食，9%的巢穴受到小杜鹃的寄生。"},{"name":"喜山黄腹树莺","english_name":"Hume's Bush Warbler","scientific_name":"Horornis brunnescens","overview":"喜山黄腹树莺（英文名：Hume's Bush Warbler，学名：Horornis brunnescens），是雀形目树莺科暗色树莺属的鸟类。小型树莺科鸟类，名称纪念了英国自然学家Allan Octavian Hume，他在印度工作期间对其进行了描述。喜山黄腹树莺在形态、分子遗传学和声谱上与黄腹树莺有显著区别，因此被Alström等人（2007）从黄腹树莺中分离出来，成为一个独立物种。","appearance":"喜山黄腹树莺体长约11厘米，拥有略长而非常细的喙和方形尾端。成鸟头部从额头至颈背呈暖棕色，眉纹自喙基部延伸至耳羽顶缘，下方由深色眼纹衬托；背部为锈褐色，臀部转为橄榄绿色；上翼和尾巴较暗，边缘带有淡红褐色；喉部和胸部白色（有时部分泛淡灰色或黄色），腹部至尾下覆羽变为黄褐色；虹膜深色；喙角质暗色，下颌粉色灰色，可能有暗尖；腿为浅棕粉色。幼鸟上部橄榄色，下部带黄色调。","call":"喜山黄腹树莺的鸣唱极为独特，长达约18秒，由两部分组成：首先是3至5个均匀、拉长且略带嘶哑的单调哨音，音调逐渐升高，类似“wiiiiiiii wiiiiiiii wiiiiiiii wiiiiiiii”；然后突然转变为第二部分，一系列响亮、咔哒声的硬双音颤音，例如“witit-rr-r”，机械重复持续约15秒。叫声为干燥的颤音，反复发出；觅食时也会发出重复的“chuuurk”声。","habits":"喜山黄腹树莺偏好竹林密集区域，但也出现在其他类型茂密植被中。它在海拔2000-3600米的高度繁殖，冬季可能会下降到更低的高度。其习性和栖息地与黄腹树莺相似。","identification":"喜山黄腹树莺可通过其独特的鸣唱、白眉纹、淡色下体和温暖的棕色上体与黄腹树莺相区分。","protection":"IUCN：LC（无危）。虽然估计其种群数量正在减少，但下降速度似乎不足以引起严重关注。目前没有对其生存造成严重威胁的证据。","distribution":"喜山黄腹树莺分布于喜马拉雅山脉，从印度北部（北阿坎德邦）向东延伸至中国西南部（西藏东南部）。"},{"name":"黄腹树莺","english_name":"Yellow-bellied Bush Warbler","scientific_name":"Horornis acanthizoides","overview":"黄腹树莺（英文名：Yellow-bellied Bush Warbler，学名：Horornis acanthizoides），是雀形目树莺科暗色树莺属的鸟类。小型且较为害羞的树莺科暗色树莺属鸟类，主要分布在中国中部、东南部和台湾。其腹部显著的黄色为其重要特征之一。","appearance":"体长9.5-11厘米，体重约6克（指名亚种），4.3-6.6克（concolor亚种）。拥有小型精细的喙，眉纹白而鲜明，颊部和耳羽淡棕色。头顶至背部淡红棕色，肩背和臀部在新鲜羽毛时呈橄榄绿至橄榄色。翼羽和三级飞羽边缘红棕色，闭合翅膀时形成明显的红棕色面板，翼弯处通常可见白色。下体从灰色喉部渐变为淡硫磺黄色腹部和两胁，后胁和下尾覆羽淡黄白色。虹膜深色，上喙角质暗色，下喙粉色，腿色浅粉至粉棕。","call":"鸣声独特，由一系列拉长的、高音调的哨音组成，音调逐渐升高，随后是一段长而或降或直的快速颤音。叫声为干涩或嘶哑的‘brrrr’，有时连续发出‘chrrt chrrt chrrt’。","habits":"栖息于高草丛和密集的竹林中，包括常绿、混交和针叶林中的竹林，以及树线以上的矮小杜松和稀疏灌木。在中国繁殖于1500-2000米海拔，台湾则高于2440米；非繁殖季节可能降至1000米。","breeding":"繁殖季节为5月至7月。巢如喜山黄腹树莺，由干燥的草、竹叶、苔藓和蜘蛛网构成，衬以羽毛，置于低植被中（离地面最高50厘米），位于灌木或浓密的下层植被中。每窝产2-3枚卵；关于孵化和育雏期的信息未知。","identification":"与强脚树莺相比，体型更小，尾巴更短，下体颜色更淡，两胁黄色而非橄榄棕色，腿色更浅。与淡脚树莺的区别在于体型更小，喙更细，上体颜色更淡，翼上的红棕色面板，下体呈黄色而非白色。","protection":"IUCN：LC（无危）。在中国大陆和台湾普遍常见。尽管种群因持续的栖息地破坏而减少，但下降速度似乎不足以立即引起关注。","distribution":"分布于东洋界，包括中国中部、东南部和台湾。","other":"幼鸟与成鸟相似，但上体更红棕色，下体黄色更强烈。concolor亚种上体及翅尾呈橄榄棕色，头顶至肩部和二级飞羽边缘更红棕色，臀部染黄橄榄色，眉纹淡黄白色，下体淡黄白色至下方转为淡黄色。"},{"name":"马氏树莺","english_name":"Sunda Bush Warbler","scientific_name":"Horornis vulcanius","overview":"马氏树莺（英文名：Sunda Bush Warbler，学名：Horornis vulcanius），是雀形目树莺科暗色树莺属的鸟类。广泛分布于太平洋诸岛屿和华莱士区，常见于海拔较高的山地森林环境中。","appearance":"具体描述缺失。","call":"具体描述缺失。","habits":"偏好密集的蕨类植物丛、高草丛和茂密的低矮植被，常见于矮山林、苔藓森林和高山草甸中的矮灌丛；亦可见于开阔的松木森林和北婆罗洲的开放越桔（Vaccinium）灌木丛生地带。在苏门答腊，分布于2100米至3400米之间；在龙目岛，分布于625至3000米；在松巴哇岛，分布于1500至1850米；在巴拉望岛，高于1000米；在婆罗洲的基纳巴卢山，高达3800米；在帝汶岛，从海平面到2300米，大部分位于200米以上。在韦塔尔岛，从海平面到山区，特别是在森林地面层发达的地区，尤其是被臭千里光（Chromolaena odorata）包围的退化路边，以及泉边的莎草丛中。","breeding":"具体描述缺失。","identification":"具体描述缺失。","protection":"IUCN：LC（无危）。在苏门答腊常见或局部丰盛；在北婆罗洲普遍常见至局部常见；在爪哇和巴厘岛罕见，在龙目岛和松巴哇岛也不常见。在帝汶岛广泛且常见，但在岛东端较为罕见。2008-2009年首次在韦塔尔岛记录，发现局部常见。在巴拉望岛，仅限于曼塔林加詹山，数量常见。在婆罗洲的基纳巴卢国家公园（oreophila亚种）和爪哇的贡邦国家公园（指名亚种）中出现。","distribution":"分布于苏门答腊、北婆罗洲、爪哇、巴厘岛、龙目岛、松巴哇岛、帝汶岛、韦塔尔岛和巴拉望岛的特定海拔范围内。","other":"具体描述缺失。"},{"name":"异色树莺","english_name":"Aberrant Bush Warbler","scientific_name":"Horornis flavolivaceus","overview":"异色树莺（英文名：Aberrant Bush Warbler，学名：Horornis flavolivaceus），是雀形目树莺科暗色树莺属的鸟类。下体呈污黄色，具有淡黄色眉纹和狭窄眼圈。分布于中国中部和南部、缅甸北部及越南北部。其分布国家包括不丹、中国、印度、印尼、老挝、马来西亚、缅甸、尼泊尔、菲律宾、泰国、东帝汶和越南，可能也出现在孟加拉国东北部和东南部。","appearance":"异色树莺拥有短而圆的翅膀，上体为黄色橄榄绿，下体则为橄榄黄至黄褐色，胸部和侧翼颜色较深，喉部颜色较浅或更白。眼睛上方有明显的淡黄色眉纹，眼圈狭窄而白色，眼睛下方有暗色眼纹。虹膜深色，喙为暗角棕色，下颚基部淡粉色，腿色从黄色到尘粉色不等。雌雄相似，幼鸟的下体颜色较为均匀，呈黄褐色。","call":"其鸣唱由一系列细薄上升的音符组成，随后是较长的哨声，听起来像“it-it-uee’uee”或“dir dir-tee teee-weee”。报警时会发出柔软的颤音“brrrt-brrt”和尖锐的“chick”声，同时伴有快速的翅膀拍打。","habits":"异色树莺栖息于海拔1200至4900米的林间高草丛、灌木丛、竹林和荆棘丛，冬季则下降至700米左右。它在繁殖季节后会迁移到较低海拔处，为海拔迁移型鸟种。在非繁殖季节，通常会在山脚、低地和山谷地带活动，高度一般在1100米以上，但在孟加拉国冬季曾记录到250米的高度。它以昆虫和幼虫为食，在低矮密集的植被中觅食，性格害羞且隐秘。","breeding":"异色树莺在喜马拉雅山脉至越南北部和中国中部的山地和大、小巽他群岛及菲律宾西南部的帕拉旺岛繁殖。","identification":"与黄腹树莺和褐胁树莺非常相似，但异色树莺在喜马拉雅地区的繁殖个体背部更偏绿色，腹部带有强烈的黄色色调；在东部喜马拉雅地区与褐胁树莺重叠分布，总体颜色更偏棕色；在中国中部，与黄腹树莺重叠，后者喉部为灰白色而非黄褐色。","protection":"IUCN：LC（无危）","distribution":"异色树莺主要分布在喜马拉雅山脉至越南北部和中国中部，以及大、小巽他群岛和菲律宾西南部的帕拉旺岛。在中国大陆，它分布在云南、西藏等地。","other":"十三个亚种被认可，其中最后八个亚种有时被认为是一个独立物种——马氏树莺。"},{"name":"灰腹地莺","english_name":"Grey-bellied Tesia","scientific_name":"Tesia cyaniventer","overview":"灰腹地莺（英文名：Grey-bellied Tesia，学名：Tesia cyaniventer），是雀形目树莺科地莺属的鸟类。体长约9.5厘米，姿态直立，上体橄榄绿色，头冠略淡，眼上具明显的浅色眉纹，下体呈灰色，喉部及腹部中央几乎白色。分布于尼泊尔至东南亚，包括中国南部、印度东北部等地。","appearance":"体长9-10厘米，体重8-12克，是一种小型立姿直立、几乎无尾的地莺。上体为明亮的橄榄绿色，冠部稍浅，眼上具有亮绿色眉纹，宽黑眼线；下体灰色，喉部及腹部中心近乎白色。虹膜深色，喙部深色，基部三分之二下颌黄色；腿橄榄棕色至肉粉色。雄雌外观相似，幼鸟上体为淡橄榄色，下体较为暗淡，喉部及腹部中心颜色更淡或偏灰。","call":"发出响亮的‘trrrrrk’颤音叫声。其歌声在4月至5月间最为频繁，由一系列短促、响亮且模糊的乐句组成，先以几声高音单音开头，如'ji ji ju ju ju-chewit, ji ju’wiiwi, ji ji ji’wi-jui'，比金冠地莺的歌声音调慢，缺乏后者那种爆炸性的杂乱音符。","habits":"栖息于茂密的阔叶林下层，主要在湿润的山谷、湿地或溪流附近的蕨类、荨麻和矮竹丛中活动，海拔1500至2550米之间，大多高于1800米。非繁殖季节下降到较低海拔，低至60米。活跃于地面和植被中，偶尔会攀爬至离地约6米的高度。冬季会迁移到更低的地区，如印度阿萨姆邦北部。","breeding":"繁殖季节为5月至7月。巢为苔藓编织的球状结构，放置于离地不到0.5米的灌木、藤蔓或树侧的苔藓中。一窝产3-5枚蛋，关于孵化期和育雏期的信息尚未记录。","identification":"与非常相似的金冠地莺相比，灰腹地莺具有更淡的灰色下体、不那么黄色的顶冠和明显的浅色眉纹。","protection":"IUCN：LC（无危）。在印度北部、尼泊尔东部、中国南部、缅甸、老挝和越南北部常见，泰国西北部罕见。在柬埔寨卡达莫山脉可能是稀有留鸟或冬候鸟，在印度东北部阿萨姆邦纳美里国家公园为常见冬候鸟。","distribution":"分布于尼泊尔至东南亚，包括中国南部（西藏东南部、四川南部、云南、广西、湖南南部）、印度东北部（自北阿坎德邦向东）、孟加拉国、缅甸（除中部和南部）、泰国西北部、柬埔寨西南部、老挝北部和南部、越南（东京、中部和南部安南）。"},{"name":"金冠地莺","english_name":"Slaty-bellied Tesia","scientific_name":"Tesia olivea","overview":"金冠地莺（英文名：Slaty-bellied Tesia，学名：Tesia olivea），是雀形目树莺科地莺属的鸟类。一种小巧迷人的树莺科地莺属鸟类，以其鲜艳色彩著称，但因栖息于浓密灌木丛中而难以观测。上体橄榄黄，下体深灰，眼线深邃，头顶亮丽黄绿。分布于东洋界，自印度东北至越南北部，包括中国西南等地的低山森林。","appearance":"体长约9-10厘米，体重约6-9克。头部立直，尾巴看似极短，腿部修长。头部与颈背呈现黄绿色（有时较暗淡），眼后有明显的宽黑眼线；背部较暗的橄榄绿；腹部均匀的石板灰。眼睛深色，上喙深棕色，下喙亮橙色；腿棕色。与灰腹地莺的区别在于腹部颜色更均匀的石板灰，黄绿色的头顶，没有浅色眉纹。幼鸟与成鸟相似，但上体橄榄棕，下体灰白。","call":"发出尖锐的‘tchirik’叫声和连续的颤音‘trrrrt trrrrt trrrrt…’。鸣唱由4-11个平缓的哨音开始，随后是突然爆发、杂乱无章的音符串。","habits":"偏好阴湿环境，常见于溪流附近的茂密植被中。行动模式类似栗头地莺，有其独特的行为，觅食时会疯狂抛洒地面杂物并跳跃，沿树枝侧移，举翼高过头顶。","identification":"与非常相似的灰腹地莺区别在于腹部颜色更深，有独特的黄色眉纹和更暗的绿色头顶。","distribution":"繁殖区域从印度东北部至越南北部，冬季迁徙至较低海拔。在中国大陆，见于西南地区的低山森林。"},{"name":"褐冠地莺","english_name":"Russet-capped Tesia","scientific_name":"Tesia everetti","overview":"褐冠地莺（英文名：Russet-capped Tesia，学名：Tesia everetti），是雀形目树莺科地莺属的小型鸟类。其科学命名纪念了英国殖民地管理者兼动物收藏家Alfred Hart Everett。该物种以其独特的褐色冠羽和几乎无尾的特征而闻名，主要分布于印尼小巽他群岛的山区。","appearance":"这种小鸟体型小巧，约9至9.5厘米长，长腿几乎使它看起来无尾。拥有醒目的红褐色头冠，脸颊和耳羽呈灰色调，不甚明显的眼眉为淡棕色。上体颜色单一，为均匀的棕色，翅膀和尾巴则为更深的棕色。腹部白色，胸部和两侧略带灰色。眼睛深色，上喙棕色或角质棕色，下喙淡黄色，腿为浅橄榄棕色。雌雄外观相似，但雌鸟略小于雄鸟。幼鸟特征未详述。","call":"褐冠地莺的鸣唱由一系列急促上升再下降的七个音符组成，歌声嘹亮，具有连续的哨音，旋律起伏。此外，还发出尖锐的“chip”声作为其他叫声。","habits":"褐冠地莺通常单独活动，极其活跃，动作迅速，在地面、灌木丛及林下层寻找食物，有时在距地面约25米的藤蔓缠绕的树干上觅食。其饮食习惯尚未详细记录。","identification":"在小巽他群岛的山地环境中，它是唯一一种小型、红褐色顶冠且近似无尾的棕色鸣禽。与同类物种的区别在于其红褐色的冠羽和长腿特征。","protection":"IUCN状态未提及。","distribution":"褐冠地莺仅分布于印尼小巽他群岛的山区西部和中部。","other":"系统学历史信息未提供。"},{"name":"眉纹地莺","english_name":"Javan Tesia","scientific_name":"Tesia superciliaris","overview":"眉纹地莺（英文名：Javan Tesia，学名：Tesia superciliaris），是雀形目树莺科地莺属的鸟类。特有于印度尼西亚的爪哇岛。这种小鸟以长腿和几乎无尾著称，常在阔叶林的灌木层寻找昆虫为食。","appearance":"眉纹地莺体长约7厘米，非常小巧，尾部短小。其头部为灰黑色，冠羽和颈背呈黑褐色，有一条明显的灰白眼眉延伸至颈侧，眼周有黑色线条，耳羽宽大。上体橄榄绿色，下体淡灰白色，两胁带有橄榄色，腹部和臀部更白。虹膜深色，上喙暗角棕色或黑色，下喙黄色或淡黄色，腿脚棕色。雌雄外观相似，幼鸟特征未详述。","call":"鸣唱响亮而快速，由大约15个音符组成的系列。","habits":"栖息于海拔1000至3000米的山地森林中的密集灌木丛和荆棘丛，尤其偏爱倒伏的枯木周围。食谱主要包括虫蛹、蠕虫和蜗牛，推测也会摄食其他无脊椎动物及其幼虫。","identification":"眉纹地莺通过其独特的黑眼线和显著的眼眉，以及短尾和长腿的组合，与其它地莺物种区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于爪哇岛的西部和中部山区。"},{"name":"宽尾树莺","english_name":"Cetti's Warbler","scientific_name":"Cettia cetti","appearance":"宽尾树莺长约13.5-14.5厘米，雄鸟体重10-18.5克，雌鸟8-16.5克。具有圆头、短而圆的翅膀和尾巴，细长的喙。上身呈深红棕色，下身淡灰，有窄的眉纹。尾羽较宽，共十枚，比许多其他莺类的尾羽更长更宽。两性相似，但雄鸟比雌鸟重约26%-32%，翼展也稍长。幼鸟与成鸟相似，但有更新的羽毛和舌头上可见的暗色斑点。","call":"宽尾树莺以响亮的歌曲著称，其歌声爆发式、音节分明，通常由一系列清脆的音符组成，如“pwít-ptit-pit-chewit-chewit-chewit…”或“tí tipitipitipi ti-pi-ti-pi”。叫声包括尖锐的“pik!”，较低的“chup”，以及类似麻雀的干涩颤音。","habits":"栖息于湿地环境，如池塘、湖泊、沼泽和河流附近的浓密植被中。主要以昆虫为食，包括蜻蜓、蚜虫、蛾子、蜘蛛等。在繁殖季节，雄鸟会建立领地并发出响亮的歌声，而雌鸟负责筑巢和孵卵。夏季，雄鸟大部分时间用于保卫领地，较少参与照顾蛋和幼鸟。它们偏好低地栖息，但有时可上至海拔2450米。","breeding":"繁殖期为4月中旬至7月/8月，通常有两个窝。巢由雌鸟单独建造，位于浓密植被中，高约30-45厘米。一窝产2-4枚蛋，偶尔5枚，由雌鸟独自孵化，孵化期16-17天。雏鸟由雌鸟主要喂养，离巢期14-16天，之后至少15天由双亲共同喂养。幼鸟在30天左右独立，一岁时开始繁殖。","identification":"与其他莺类相比，宽尾树莺具有更圆的头部、较小的喙和更宽的尾巴。上体颜色深红棕色，下体淡灰色，有明显的眉纹。叫声独特，可作为识别特征。","protection":"IUCN：LC（无危）","distribution":"宽尾树莺在欧洲西部、南部及北非广泛分布，向东延伸至亚洲中部，最远至阿富汗和巴基斯坦西北部。在欧洲，常见于葡萄牙、意大利、土耳其等地。在英国和爱尔兰，数量自1960年代以来显著增加。","other":"自1970年以来，宽尾树莺的分布向北扩展至法国西北部和英格兰南部。1972年首次在英国繁殖，至1990年代中期，英国的繁殖种群约有570对。"},{"name":"大树莺","english_name":"Chestnut-crowned Bush Warbler","scientific_name":"Cettia major","overview":"大树莺（英文名：Chestnut-crowned Bush Warbler，学名：Cettia major），是雀形目树莺科树莺属的鸟类。具有显著的棕色顶冠和白色的上扬型眉纹。虽然具体数量不明，但由于栖息地破坏，其种群正在减少，但下降趋势并不急剧，因此被评估为‘最不关注’物种。","appearance":"大树莺为中至大型的树莺，体长约13厘米，体重约9.7克。头部特征明显，拥有温暖的棕色顶冠，眉纹前部为暖色或红棕色，眼后更白；短而模糊的暗色眼纹在眼后更为突出；脸颊和耳羽灰色，常带有棕色斑点；前额至颈背为栗色，背部较暗，呈橄榄棕色；下体白色，胸侧灰，两胁橄榄棕色。幼鸟缺乏栗色顶冠，上体深橄榄棕色，眼后灰黄色眉纹，胸侧灰橄榄色，喉部和胸部有斑驳，腹部泛黄。雄雌相似。","call":"大树莺的鸣唱为短暂的引子哨音后接3至4个急促尖锐的颤音，'i i-wi-wi-wirri-wi'。叫声为尖锐的‘tzip’、‘pseek’或‘pseet’，类似雀鹀的叫声。","habits":"大树莺栖息于海拔1500至2200米的山地，偏好茂密的灌木区域，尤其是在杜鹃花丛生的地方。冬季会下降到较低的山脚和低地带有灌木边缘的区域。","identification":"大树莺与日本树莺和棕顶树莺区别明显。日本树莺上体暖褐色，头顶颜色较浅，眼先皮黄；棕顶树莺体型较小，嘴细，下体白色少，无棕色眼先。大树莺眼先棕色，眉纹模糊。","protection":"IUCN：LC（最不关注）","distribution":"大树莺分布于喜马拉雅山脉和中国中部，繁殖季节位于较高海拔区域，冬季迁至更低的山脚和低地。"},{"name":"棕顶树莺","english_name":"Grey-sided Bush Warbler","scientific_name":"Cettia brunnifrons","overview":"棕顶树莺（英文名：Grey-sided Bush Warbler，学名：Cettia brunnifrons），是雀形目树莺科树莺属的鸟类。体小（约11厘米）、色彩丰富的树莺科鸟类。其特征在于明亮的赤褐色冠羽、灰色腹部和显眼的淡色眉纹。分布自喜马拉雅山脉至中国中部，常栖息于海拔2600至4300米的亚高山针叶林带。","appearance":"体长10-11厘米，体重雄鸟8-9克，雌鸟6-9克。外观小巧，喙小，拥有长而明显的浅色眉纹。头部侧边的冠羽温暖的栗色，上身单一棕色，翅膀颜色较背部更暖。下巴和喉咙白色，胸侧和两肋灰白至淡灰色，后两肋和尾下覆羽呈橄榄褐色。虹膜深色，上颚角质暗色，下颚黄色至亮黄色，有时尖端暗色；腿色淡棕色至粉灰色，有时稍深带紫色。幼鸟上身均匀的赤褐色，缺乏成年鸟的栗色冠羽，眉纹为赤褐色，下体暗褐色橄榄色，腹部黄色橄榄色。","call":"歌声为短暂的高音清脆音符串，随后是一连串嗡嗡的呼啸声。叫声包括高音的‘tseep’和‘tzzi’音。","habits":"栖息于海拔较高的森林边缘、开阔的灌木区和山地直至树线附近。冬季迁徙至较低的丘陵地带。活动时通常隐秘，但在茂密植被中或地面觅食，偶尔会公开现身，尤其在歌唱时。食性未知，但可能以昆虫为主。","breeding":"在春季至早夏期间繁殖，具体细节未知。","identification":"与栗顶树莺相比，体型较小，外观更纤细，喙更小，眉纹洁白而非赤褐色，下体灰色而非白色。幼鸟上体统一的赤褐，缺乏成鸟的栗色冠羽。","protection":"IUCN状态未知。","distribution":"繁殖于喜马拉雅山脉至中国中部，越冬于较低的丘陵地带。","other":"属于季节性迁徙，繁殖季节结束后会降至较低海拔。"},{"name":"栗头地莺","english_name":"Chestnut-headed Tesia","scientific_name":"Cettia castaneocoronata","overview":"栗头地莺（英文名：Chestnut-headed Tesia，学名：Cettia castaneocoronata），是雀形目树莺科树莺属的鸟类。色彩艳丽，独特的特征为头及颈背的栗色，上体绿色，下体黄色，眼后有一醒目白色斑点。分布于喜马拉雅山脉至越南北部的东洋界，偏好湿润山地森林环境。","appearance":"这种小鸟身长8-9.5厘米，体重8-10克，体态圆润，几乎无尾。雄雌外观相似，成鸟头部呈深肉桂棕色，眼睛周围有明亮的白色半月形纹路；背部橄榄绿，腹部鲜黄，仅侧胸和两肋稍带绿色。幼鸟头部无栗色，上体颜色偏暗橄榄绿，带些褐色调，下体为暗淡的红褐色，喉部和腹部带有黄色调。","call":"发出响亮、流利的“chee-leu-chee-wit”声，以及各种尖锐高音的鸣叫。兴奋或警觉时，会发出类似鹪鹩的上下摆动的动作。","habits":"栖息于海拔较高的森林，偏好植被茂密的湿润地带，常在溪流和沟壑附近。冬季则迁至较低的山脚林缘灌木丛中。在地面密集植被中积极觅食，很少暴露在开阔地带。主要以蜘蛛和其他无脊椎动物及其幼虫为食。","identification":"与其他树莺属鸟类相比，栗头地莺的头部和颈背的栗色、白色的耳后纹和鲜黄色的下体是显著的区别特征。","protection":"IUCN状态未提供。","distribution":"繁殖区域包括喜马拉雅山脉至越南北部的东洋界。","other":"曾被归类于旧世界莺科，现归入树莺科（Cettiidae）。"},{"name":"鳞头树莺","english_name":"Asian Stubtail","scientific_name":"Urosphena squameiceps","overview":"鳞头树莺（英文名：Asian Stubtail，学名：Urosphena squameiceps），是雀形目树莺科短尾莺属的鸟类。体小（约10厘米）且尾极短的树莺，以头顶具鳞状斑纹而得名。拥有长而醒目的白眉纹，全身呈褐色，活跃于东北亚地区的森林地带。繁殖季节主要在韩国、中国东北及日本，冬季迁徙至中国南方和东南亚。","appearance":"鳞头树莺体长9.5-10.5厘米，体重8-10克，身形圆胖，尾巴极短。喙尖细，具显著的淡黄色眉纹和宽黑眼线；上身均匀深红棕色，头顶有稍深的鳞状斑纹（野外不明显）；腹部白色，侧胸、两胁、腹下及尾下覆羽呈淡黄棕色；虹膜深色；上颌角质色，下颌粉红色；腿粉红或肉粉色。雌雄相似，幼鸟与成鸟外观相近，但背部更偏赤褐色，下体侧面颜色更暗淡。","call":"鸣唱声为高音的蝉鸣式“see-see-see...”，节奏逐渐加快加大，类似蝉或螽斯的声音。警戒叫声低沉或柔和的“sit”、“zik”或连续的“chip-chip-chip”。","habits":"繁殖期间，栖息于低地松林和常绿阔叶林的浓密灌木丛，包括低于1300米的针叶林，以及沿溪流的荨麻和桤木丛。非繁殖季节，活动于湿润地区的浓密常绿森林和开阔的灌丛地带，最高可达2100米。迁徙时可见于沿海灌丛、灌木、高草甸和沼泽地带。","breeding":"繁殖季节从4月底至7月，实行合作繁殖模式，有帮手参与。巢主要由叶子和干草茎构成，建于地面或灌木基部，藏于密集植被或倒木之下；领域大小取决于适宜生境的多少。每窝产5-7枚卵，孵化期13天；雏鸟抚育期未知。","identification":"与同属其他树莺相比，鳞头树莺最显著的特点是其极短的尾巴。此外，它的眉纹和眼纹对比强烈，有助于与其他树莺区分。","protection":"IUCN：LC（无危）。在俄罗斯远东地区和日本海沿岸普遍至局部丰盛；在日本南萨哈林岛罕见，日本本土不常见（北海道北部稀少）；在中国东北和朝鲜半岛较为常见。在非繁殖地，中国东南部罕见，整个东南亚越冬区局部常见。","distribution":"繁殖于俄罗斯东南部、中国东北部、朝鲜半岛及日本；非繁殖期分布于中国东南部、台湾及东南亚，北至缅甸东部、越南，南至马来半岛北部。在中国大陆，见于东北、河北、山东、四川、江苏、湖南、福建、云南、广东、海南等地。","other":"迁徙期间由于其隐秘和躲避的习性，经常被忽视。"},{"name":"印尼短尾莺","english_name":"Bornean Stubtail","scientific_name":"Urosphena whiteheadi","overview":"印尼短尾莺（英文名：Bornean Stubtail，学名：Urosphena whiteheadi），是雀形目树莺科短尾莺属的小型鸟类。其体型娇小，尾巴短小，活跃于婆罗洲中部山脉的森林地面及灌木丛中，以独特的橙色眉纹、棕色背部及灰色侧腹为显著特征。分布于婆罗洲的山地森林地带，海拔介于750至3150米之间。","appearance":"印尼短尾莺是一种极小型的莺鸟，体长9.5至10厘米，平均体重10.4克。头部上方及上身呈棕色，腹部灰白，侧腹转为灰色，腹部常带淡黄褐色。其最明显的特征是长而橙色的眉纹，搭配深灰色的眼纹及细薄的黄色眼环。脸颊及耳羽为橙色，腿色偏淡粉红，喙部深褐黑色，虹膜呈深黑色。雌雄外观相似。","call":"其鸣叫特征包括几乎无声的高音单音符，持续0.3至0.5秒，以及最高音的\"tsit-tst tseee\"或\"tzi-tzi-tzeeee\"，长度约1.4秒，此外还有较低的颤音\"piririt\"，持续约0.7秒。","habits":"印尼短尾莺栖息于婆罗洲的山地森林地面，偏好在密集的灌木丛中活动，以昆虫为主食，尤其是绿色蚜虫。它们以类似鼠类的方式觅食，动作隐秘，但有时也会表现得好奇且温顺。","breeding":"巢穴由红色植物纤维构成，筑于苔藓覆盖的斜坡上。孵化期平均为24天，较同类物种长，因父母每日会离开巢穴6至8小时。","identification":"印尼短尾莺以其独特的外观和行为与其他鸟类区分开来，特别是其短尾和长腿，以及在地面活动时的鼠类行为。","protection":"IUCN：LC（无危）","distribution":"印尼短尾莺分布于婆罗洲的山地，包括基纳巴卢山南至梁坤邦和穆勒山脉，最近在岛东南部的梅拉图斯山脉也有发现。","other":"印尼短尾莺的名字来源于古希腊语，意味着楔尾，是对这种鸟短尾特征的描绘。"},{"name":"帝汶短尾莺","english_name":"Timor Stubtail","scientific_name":"Urosphena subulata","overview":"帝汶短尾莺（英文名：Timor Stubtail，学名：Urosphena subulata），是雀形目树莺科短尾莺属的小型鸟类。其最显著的特征是极短的尾巴、修长的双腿和喙，全身呈褐色，拥有淡色的眼眉和腹部。分布于帝汶岛、罗地岛至Wetar岛以及Babar岛（小巽他群岛东部）。","appearance":"帝汶短尾莺体型小巧，拥有非常短的尾巴、细长的腿和喙，体羽呈棕色，眼上方有一条淡色的眼纹，下体颜色较浅。幼鸟的上部色彩更丰富，眼纹较为暗淡，下体颜色也不如成鸟鲜明。雌雄两性的外观相似。","call":"鸣声极为高亢，几乎听不见，音调逐渐升高，表现为‘tzeee’。","habits":"这种鸟喜欢隐秘的生活方式，常栖息于低地和山丘的森林地面及灌木丛中，通常单独或成对出现。它们以昆虫为主食，通过在地面搜索来觅食。","breeding":"关于帝汶短尾莺的繁殖信息较少，但它们可能在适宜的季节筑巢，产卵并孵化，具体的繁殖行为需进一步研究。","identification":"在其有限的分布范围内，帝汶短尾莺是唯一一种几乎没有尾巴的小型鸟类，这使得它很容易被识别。","protection":"IUCN：LC（无危）。帝汶短尾莺在剩余的森林斑块中常见于帝汶和Wetar岛上；在Babar岛上的advena亚种自1905年采集到标本后，目前状况未知。","distribution":"分布于澳新界，具体包括罗地岛至Wetar岛、帝汶岛和Babar岛（小巽他群岛东部）。","other":"系统学历史未详，但该物种为限制范围物种，出现在帝汶和Wetar EBA及Banda Sea Islands EBA。"},{"name":"淡脚树莺","english_name":"Pale-footed Bush Warbler","scientific_name":"Hemitesia pallidipes","overview":"淡脚树莺（英文名：Pale-footed Bush Warbler，学名：Hemitesia pallidipes），是雀形目树莺科 Hemitesia 属的鸟类。眉纹皮黄色，下体白色，两胁及臀部呈淡皮黄色。脚部颜色浅肉色，尾巴近似方形。该物种分布广泛，见于南亚地区的森林边缘、山坡林区和开阔地带。","appearance":"体型略小，长约11-12.5厘米，拥有方形尾端，翅膀短圆，主翼羽突出短小。上体冷橄榄褐色，眉纹长且呈淡白色，眼纹显著且深色；闭合翅膀弯曲处可见白色（来自翼下覆羽）；下体非常洁白，仅胸侧和两胁带淡橄榄褐色。虹膜暗色，上喙棕角质色，下喙淡粉色或粉红色；跗跖浅粉色。幼鸟上体较成鸟更暖色调的棕色。","call":"其叫声独特，以尖锐音符开始，随后快速连串的叽叽喳喳和尖叫，这是其显著的识别特征。","habits":"栖息于密集植被的森林边缘、轻度林木覆盖的斜坡和山区的开阔地带，偏好有茂密地面植被的环境。它是一种极为害羞的鸟种，善于隐匿，主要活动于低矮的灌木丛和草丛中，很少飞行超过一米高度，通常在地面觅食。主要食物为昆虫。","breeding":"繁殖期从5月持续至7月，筑巢于低矮的灌木丛或草丛中，一般单独或成对出现。","identification":"与鳞头树莺相比，淡脚树莺的眉纹和两胁不沾染棕色；与强脚树莺相比，其尾部较长，冠羽无深色边缘。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉以西的Dehradun到尼泊尔东北部印度，以及缅甸、老挝、越南北部和中国南部。在泰国，其栖息地为海拔1800米以下的草地和灌木丛；在中国，海拔上限为1525米的林地。","other":"淡脚树莺在斯里兰卡曾有一次记录。"},{"name":"纽氏丛莺","english_name":"Neumann's Warbler","scientific_name":"Hemitesia neumanni","overview":"纽氏丛莺（英文名：Neumann's Warbler，学名：Hemitesia neumanni），是雀形目树莺科 Hemitesia 属的鸟类。最显著特征为头部的大胆黑白橄榄绿条纹，以及短小的尾巴。主要栖息于中非的刚果民主共和国东部、乌干达西南部、卢旺达西部及布隆迪西部的亚热带或热带湿润山地森林中。","appearance":"体长10至11厘米，体重约11.3克。头部宽大，头上有独特的条纹图案，尾巴非常短。眉线宽，颜色变化多样，从前眼处的灰棕色到眼后转为白色，覆盖耳羽；黑色条纹从喙基延伸至颈侧；冠部至颈中部呈灰色，较宽的黑色眼纹延续至耳羽后方；背部从颈侧向后呈暗橄榄绿色，飞羽和尾羽更偏褐色；下巴至颈部侧面、喉咙和胸部颜色变化，可能为黄色（乌干达）或淡绿色（卢旺达西部和布隆迪西部），侧翼逐渐变为橄榄绿色，腹部白色，下尾羽黄色；虹膜深棕色；上喙棕黑色，下喙黄或粉红色；腿色为棕色至粉棕色。雌雄外观相似，幼鸟特征未详述。","call":"声音响亮而急促，但短暂，如“tee-tiyoo-tee”，“tee-tyer-tyii”，“tyoowi-tyee”，“tee-teeyoo-tyoowi”或“tay-tiyoo-tay”，间杂几乎听不见的低语声，间隔规律地重复。","habits":"通常独居或成对出现，性格隐秘难以发现（通常通过歌声被察觉）。在地面或低矮植被中觅食，偶尔混入多种物种的觅食群中。食物主要包括甲虫和其他小型无脊椎动物。","breeding":"繁殖信息未详述。","identification":"与绿莺最为相似，但后者尾巴较长。","protection":"IUCN：LC（无危）","distribution":"繁殖区域与非繁殖区域相同：刚果民主共和国东部，乌干达西南部，卢旺达西部和布隆迪西部。","other":"纽氏丛莺是Cettiidae科中唯一在非洲发现的物种。"},{"name":"纹鹪莺","english_name":"Streaked Scrub Warbler","scientific_name":"Scotocerca inquieta","overview":"纹鹪莺（英文名：Streaked Scrub Warbler，学名：Scotocerca inquieta），是雀形目纹鹪莺科纹鹪莺属的鸟类。小型的沙漠雀形目鸟类，活跃于北非至西亚的干燥地带，偏好沙漠边缘的灌木丛和草丛生境。具有鲜明的黑色眼纹和灰褐色羽毛，腹部略呈白色，两翼和背部带有细密的深色条纹。","appearance":"纹鹪莺体型小巧，全长约10厘米，体重6-10克。其羽毛呈淡沙褐色，有显著的黑色眼纹，尾羽较长，末端白色。上部羽毛鼠灰色，头部有黑色条纹，下体颜色较淡，胸部有模糊的暗色斑点。雌雄相似，幼鸟色彩较淡，条纹不明显，腹部泛黄。存在多个亚种，颜色和条纹强度有所不同。","call":"雄性纹鹪莺的歌声由一系列颤音和乐音组成，类似山雀的声音，如“tsi-tsi-tsi-tsi-tsi-hue”或“pip-pip-prrr”。还常发出清晰的‘che-wee’或‘te-hee’叫声，有时是较长的下降音调‘peeeooo’或‘chi-ti-teeeooooo’。伴侣间通过‘chreet’或‘chiii’保持联系。","habits":"纹鹪莺栖息于干旱的灌木和草地，包括沙地排水线森林、植被丰富的河床、岩石斜坡上的灌木丛和草原。它们主要在自然植被中活动，避免耕作区。以昆虫为主食，如毛虫、甲虫、蝉、蜘蛛等，冬季会吃种子。通常单独或成对觅食，有时加入混合物种群。","breeding":"繁殖季节从2月持续到6月，筑巢于低矮灌木中，巢呈穹顶状，有侧入口，内部铺垫羽毛和植物纤维。每窝产卵2-5枚，平均3-4枚，双亲共同孵卵，孵化期13-15天。雏鸟孵化后13-15天离巢，若受干扰可能提前。幼鸟与父母共处约20-30天。","identification":"与优雅山鹪莺相比，纹鹪莺更适应干旱环境。不同亚种之间在颜色和条纹上有细微差别，如saahrae亚种色彩较浅，而buryi亚种条纹更重。","protection":"IUCN：LC（无危）","distribution":"纹鹪莺广泛分布于欧亚大陆中南部和非洲北部，包括以色列沙漠地区和阿拉伯半岛。在乌兹别克斯坦，冬季会向低海拔迁移，在也门海岸仅在晚冬出现。","other":"纹鹪莺在一些地区的密度不均匀，每平方公里6-100对。以色列的种群在1980年代有所减少，可能由于栖息地丧失。"},{"name":"黄红鹟","english_name":"Little Yellow Flycatcher","scientific_name":"Erythrocercus holochlorus","overview":"黄红鹟（英文名：Little Yellow Flycatcher，学名：Erythrocercus holochlorus），是雀形目红鹟科红鹟属的小型鸟类。主要分布在非洲的索马里东南部、肯尼亚东部和坦桑尼亚东北部，栖息于低地森林中。","appearance":"黄红鹟体型小巧，约9厘米长，重5至7克。上体橄榄黄色，下体鲜亮黄色，脸部中央有明显的暗色眼纹。前额至上背、肩到臀部呈橄榄黄色；翅膀上覆羽和尾部棕色，边缘泛着亮丽的黄色；眉纹、眼圈、颊、颏、喉部及下体为明亮的金黄色。虹膜棕色，喙全为肉粉色，或上喙深棕色而下喙较淡或粉红色；腿为浅棕色至肉粉色。雌雄相似，幼鸟外观与成鸟相似，但略显苍白且更蓬松。","call":"其鸣唱为急促高音的一系列啾啾声或颤鸣音，如“wee-see-seeu si-seeu-weet”或“sweeti-seeu-see-seeuo”，以数个短促的“chip”或叽叽喳喳的“ttrrrrrrrrr-wichi-see-see”音节开头或结尾，随后是一串下降的清晰、悦耳的音符。联系叫声为响亮的“cheu”或“chip”，觅食时频繁发出（如歌曲开始时）；也可能发出哀怨的“zee-zee”。","habits":"黄红鹟常出现在低地森林的树冠层，加入混杂物种的鸟群。它的栖息地与黄喉莺不同，后者体型更大且栖息环境各异。黄红鹟的活动范围、觅食方式和食物偏好尚未详细记录。","breeding":"关于黄红鹟的繁殖信息目前资料有限，包括繁殖期、求偶行为、筑巢、交配、产卵、孵化和育雏的具体细节。","identification":"与黄喉莺相比，黄红鹟明显更小且栖息环境不同。与利文斯通鵙鹟相比，尽管它们的分布区几乎没有重叠，但通过橄榄绿色而非赤褐色的尾巴可以轻松区分。","protection":"IUCN：LC（无危）","distribution":"黄红鹟的分布限于非洲的特定区域，包括索马里东南部、肯尼亚东部和坦桑尼亚东北部。"},{"name":"栗顶红鹟","english_name":"Chestnut-capped Flycatcher","scientific_name":"Erythrocercus mccallii","overview":"栗顶红鹟（英文名：Chestnut-capped Flycatcher，学名：Erythrocercus mccallii），是雀形目红鹟科红鹟属的鸟类。这小型活跃的飞禽，常以小群或混合物种群体的形式出现在森林底层或树木丛中，频繁鸣叫并摆动其尾巴。具有独特的红褐色脸庞、帽状头冠和小尖顶，以及红褐色臀部和尾巴。外形让人联想到非洲蓝鹟、非洲冠纹鹟等物种，但通过其特有的图案和鸣声可以加以区分。","appearance":"体型约为10厘米，体重6至8克。拥有短小的冠羽和鲜艳的栗色头冠及尾巴。成年鸟的前额至头顶中央为明亮的栗色，细纹间杂着淡黄色；后冠至颈背和肩部为鼠灰色；臀部灰中带肉桂色，尾上覆羽和尾巴则更显深栗色；翅膀上覆羽如同背部颜色，边缘略带赤褐色；初级飞羽暗棕色，边缘暖黄色；脸颊至胸部温暖的黄褐色或赤黄色，侧面带灰；腹部和两胁白色，尾下覆羽浅黄色；虹膜红褐色；上喙深棕色，下喙淡角质色；腿脚棕色或棕肉色。雌雄相似。幼鸟与成鸟类似，但上体和翼羽边缘呈更暖的橄榄色，喉咙淡棕色。","call":"鸣唱是一系列短促高音的乐句，音符间隔变化，例如“pit pit pit-pit-pit pit-ptit-ptilililililili”或“ptit ptit-ptit-ptit ptilululululu”。在领地防卫时几乎不间断地歌唱。觅食群体中的成员发出几乎连续的尖细叫声和柔和的‘it’或‘chip’接触音，这些声音有时会融入短暂、无旋律但嘶嘶作响的鸣唱中。","habits":"生活在亚热带或热带的沼泽地和湿润山林中，广泛分布于非洲中部和西部的多个国家。以小型无脊椎动物为食，包括蚂蚁、小蜂、白蚁、甲虫、蚱蜢、蝉、蜘蛛和蛾类等。通常成对或小群活动，积极地在树冠层和树下灌木丛中觅食。通过跳跃移动并展开尾巴扫荡昆虫。","breeding":"未提供具体繁殖信息。","identification":"与非洲蓝鹟、非洲冠纹鹟等物种相比，栗顶红鹟的头部和尾部颜色更为独特，鸣声也有所不同。","protection":"IUCN状态未知。","distribution":"分布于非洲中部和西部，包括安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、加纳、几内亚、利比里亚、马里、尼日利亚、塞拉利昂和乌干达。","other":"未提供其他重要信息。"},{"name":"利氏红鹟","english_name":"Livingstone's Flycatcher","scientific_name":"Erythrocercus livingstonei","overview":"利氏红鹟（英文名：Livingstone's Flycatcher，学名：Erythrocercus livingstonei），是雀形目红鹟科红鹟属的鸟类。以其橄榄色上部、黄色下部和带有黑色带纹的赤褐色尾巴而著称。其分布局限于非洲东南部的河流与沿海森林及灌丛。","appearance":"这种小鸟体型小巧，约10至12厘米长，优雅而独特。成鸟的额头至后颈、眼周和耳羽呈淡灰色，上身黄绿色，下背硫磺黄色，逐渐变为淡褐色或浅赤褐色至上尾覆羽；赤褐色的尾巴上有独立的黑色斑点（形成不连续的次端带纹）；上翼覆羽深棕色，边缘泛黄绿；飞羽深棕色，边缘微黄绿；下巴和喉咙白色或灰白，下身鲜黄色；眼睛深色；上喙深棕色，下喙较浅棕色或乳白色角质；腿色变异，从粉红到棕或黑。雌雄外观相似。幼鸟头部更黄，内侧大覆羽略带栗色，尾巴通常缺乏黑色次端带纹（可能在外侧羽毛上留有轻微痕迹）。francisi亚种颜色略暗，上身偏绿，尾部亮赤褐色或赤褐带橙，具完整黑色次端带纹；thomsoni亚种头部和面部黄绿色，与上身同色，眼周白色，脸颊至喉咙淡黄色，下巴白色，下身深金黄色，尾部图案介于两者之间。","call":"鸣唱为短暂的颤音系列，由4至6个音符组成，似“switterweedlewii”，可能单独发出或以短“chup”或叽叽喳喳声引出。叫声双音节，第二音节常滑落或下降，如“tsi-tsreea”，常重复数次；还有几个短促的“zert”、“chip”音符，以及飞行中的“sweet”声。","habits":"利氏红鹟的饮食主要未知，推测以小型无脊椎动物为主。通常成对或小家庭群活动，在非繁殖季节可能加入混合物种觅食群体。觅食活动主要在树冠中上层和最浓密的叶丛中进行，通过快速持续的动作，拍打翅膀和展开尾巴，进行短距离冲刺捕捉昆虫；同时也会在空中追逐昆虫。","identification":"利氏红鹟与非常相似的Erythrocercus holochrous的区别在于前者脸部更淡的灰色和赤褐色的尾巴。不同亚种间存在细微的色彩差异。","protection":"IUCN状态未知，未列入华盛顿公约(CITES)附录或中国国家重点保护野生动物名录。","distribution":"利氏红鹟的分布限于非洲东南部，具体包括马拉维、莫桑比克、坦桑尼亚、赞比亚和津巴布韦。"},{"name":"格氏丛莺","english_name":"Grauer's Warbler","scientific_name":"Graueria vittata","overview":"格氏丛莺（英文名：Grauer's Warbler，学名：Graueria vittata），是雀形目苇莺科格氏丛莺属的鸟类。其分布局限于非洲东部的阿尔伯丁裂谷山区森林，包括刚果民主共和国东部、乌干达西南部、卢旺达西部和布隆迪西北部。该鸟种以其独特的外观和声音被识别，纪念奥地利动物学家Rudolf Grauer。","appearance":"格氏丛莺长约14厘米，体重14至18克，体色呈暗淡的绿橄榄色，头部顶部为深灰橄榄色，具淡色斑点；上体、上翼和尾巴均为绿色橄榄色；头部侧面至胸上部有黑色和黄白色条纹；其余下体为绿色橄榄色，腹部中央有宽幅的灰白色横纹；虹膜红褐色；喙上部黑色，下部蓝灰色；腿蓝灰色。雌雄相似，幼鸟描述不明。","call":"其声音独特，发出类似轻轻上升的“hrrrrrrrrrr”摩擦声，持续约1.5秒，每3至4秒重复一次；还发出柔和的下滑哨音“feeeu”，作为警报声。","habits":"格氏丛莺栖息于阿尔伯丁裂谷的山地森林，偏好茂密的灌木丛。通常通过其独特的声音被发现，这声音更像昆虫而非鸟类。生活在海拔较高的地区。","breeding":"具体繁殖细节未知，但可能遵循典型的苇莺科鸟类繁殖模式，包括营巢、产卵和育雏。","identification":"与绿背拱翅莺最易混淆，但格氏丛莺体型更大，眼睛颜色更深，下体具有细密的条纹。","protection":"IUCN状态未知。","distribution":"分布于非洲东部，包括刚果民主共和国东部（爱德华湖西侧高地至伊托姆贝地区）、乌干达西南部（布温迪不可穿越森林）、卢旺达西部（尼翁盖韦森林）和布隆迪西北部。"},{"name":"马岛薮莺","english_name":"Malagasy Brush Warbler","scientific_name":"Nesillas typica","overview":"马岛薮莺（英文名：Malagasy Brush Warbler，学名：Nesillas typica），是雀形目苇莺科薮莺属的鸟类。马达加斯加与科摩罗群岛特有的中型薮莺，栖于森林下层及浓密的灌丛。该种体型修长，尾长呈楔形，上体橄榄褐，下体淡黄，常单独或成对活动，性隐蔽，先闻其声后见其身。分类上含4–5个亚种，其中3个分布于马达加斯加，2个在科摩罗群岛。","appearance":"体长17–18厘米，雄鸟体重17–22克，雌鸟14.5–18克。整体为纤细的橄榄褐色莺类，具短圆翅与长而渐尖的尾（尾羽10–12枚）。头低平，可微翘成短冠。上体自额至尾橄榄褐带绿色泽；眉纹淡黄，过眼后逐渐消失；眼纹暗褐。飞羽及尾羽暗褐，羽缘带橄榄色。下体淡黄白，喉至胸具柔软的灰褐色纵纹，两胁及尾下覆羽转暖褐色。幼鸟上体及两胁较成鸟更暖褐，胸斑纹不显。喙长而粗，上嘴暗灰至近黑，下嘴粉灰具暗端；眼暗褐至红褐；脚铅灰。","call":"鸣声为连续悦耳的哨音串。常见叫声在马达加斯加为尖锐断续的“krak-trak-trak…”及响亮的“trrrrrrrk”颤音；在昂儒昂岛则为更高频的“pirrik-pirrik-pik-pik-pik”及粗哑的“trkk”声。","habits":"留鸟，栖于马达加斯加及科摩罗群岛的原始林、次生林、灌丛、河谷灌丛、花园及种植园，海拔从海平面至2750 米。常见于中海拔常绿林下层，亦见于石灰岩森林及湿地边缘。在莫埃利岛限于400 m以上常绿林，在昂儒昂岛则遍布各种具浓密下层的生境。单独或成对在低处觅食，偶尔落地，以叶面和枝条上扫取昆虫及蜘蛛为食，食物包括蟑螂、甲虫、蝇类、毛虫及蜜蜂等。","breeding":"繁殖期7–12月，马达加斯加主高峰9–11月；科摩罗群岛9月–翌年2月。巢筑于地面0.2–1 m处的草丛、灌木或藤蔓中，为干草编成的深杯状巢，内衬细草。每窝2–3枚卵，卵色淡粉褐至灰粉，具细密的灰、紫或红褐斑。孵化期及育雏期尚未报道。","identification":"与马岛沼泽莺（马岛沼泽苇莺）相比，后者下体更淡，胸喉纵纹更显，眼红褐，喙更长且鸣声更复杂。与荒漠薮莺相比，后者羽色更淡，鸣声迥异，分布基本异域。与绿马岛莺相比，后者头灰、翼尾具亮绿缘，嘴更强，鸣声不同。与莫埃利薮莺（科摩罗薮莺）相比，后者体型更小、尾更短，颜色更绿，无眉纹，眼圈红，鸣声不同。亚种间差异：obscura色暗、体型大；longicaudata稍淡、尾较长；moheliensis上体更暖褐、下体更黄、胸纹更重。","protection":"IUCN: LC（无危）。全球种群稳定，数量未量化但被认为不接近受威胁阈值。马达加斯加及科摩罗群岛均常见至丰富。","distribution":"繁殖区：马达加斯加除极干旱西南外的广大区域，以及科摩罗群岛的莫埃利岛与昂儒昂岛。非繁殖区：留鸟，无迁徙记录。","other":"系统分类曾将本种与荒漠薮莺及戈岛薮莺视为同种，现均已独立。安岛薮莺（亚种longicaudata）曾被提议为独立种，现多处理为亚种。moheliensis亦曾被建议独立，目前仍保留在本种内。"},{"name":"荒漠薮莺","english_name":"Subdesert Brush Warbler","scientific_name":"Nesillas lantzii","overview":"荒漠薮莺（英文名：Subdesert Brush Warbler，学名：Nesillas lantzii），是雀形目苇莺科薮莺属的旧世界苇莺。该物种仅在马达加斯加西南部的干燥刺灌丛和灌木丛中发现，是当地的特有种。","appearance":"荒漠薮莺是一种中等体型、淡棕色的鸟，尾部长而尖锐，由十二根羽毛组成。头部顶部和侧面呈淡灰褐色，具有明显的浅黄色眉纹，窄白眼环，眼过条较暗；背部和翅膀覆羽呈淡灰褐色，臀部和上尾覆羽更显橙色；飞羽和尾羽深灰褐色，边缘略带灰黄色；下体浅黄色，两胁灰色，胸部有短暂模糊的暗色条纹；虹膜中褐色；喙上部暗褐色，下部淡褐色或粉红色，尖端暗色；跗跖深蓝灰色。雄雌相似，幼鸟比成鸟更暗淡，全身更均匀的灰褐色。","call":"发出一系列尖锐的音符，其歌声为一系列的哨声；声音结构与马岛薮莺相似，但音调更高，更薄，摩擦感较少。","habits":"栖息于亚沙漠森林、大戟林和低矮沿海灌木丛；低地常绿森林边缘和退化森林；海拔从海平面至500米。活动范围局限于低矮植被和下层林冠，单独或成对觅食昆虫。","breeding":"繁殖季节从8月至2月，主要集中在10月至12月。巢筑于地面附近的草丛或灌木丛中；每窝产卵2枚。无其他繁殖信息。","identification":"与马达加斯加刷莺相比，颜色更淡，叫声音调更高，分布范围几乎没有重叠。与马达加斯加沼泽莺相似，但颜色更浅，胸部条纹不明显，有白色眉纹，通常出现在灌木丛或刺灌丛而非沼泽中。","protection":"IUCN：LC（无危）；在马达加斯加西南部干旱亚沙漠地区常见到非常常见。","distribution":"仅分布在非洲的马达加斯加西南部。"},{"name":"安岛薮莺","english_name":"Anjouan Brush Warbler","scientific_name":"Nesillas longicaudata","overview":"安岛薮莺（英文名：Anjouan Brush Warbler，学名：Nesillas longicaudata），是雀形目苇莺科薮莺属的鸟类。拥有细长的身体、短翼和十根长而狭窄的尾羽。","appearance":"安岛薮莺头部上方、背部和翅膀覆羽呈橄榄褐色带绿调；眉纹淡黄色至黄白色，延伸至眼后；眼线暗色不明显；上体橄榄绿褐色，尾羽十根，深棕色，边缘绿色；下体浅黄白色，腹部更偏橄榄褐色，两侧有灰色条纹至胸部。嘴部颜色为暗灰至黑褐色，脚部灰粉色或角白色，尖端暗色；虹膜橙黄色。","call":"其典型叫声与马岛薮莺相似，但音调更高，表现为连续的‘pirrik-pirrik-pik-pik-pik’颤音，节奏多变，同时伴有简单、刺耳的‘trkk’或‘chkkk’声。","habits":"栖息于各种植被密集地带，包括本土森林、异域种植园、海岸灌木丛、湿地周边的水生植物区及城镇乡村附近。它们主要以昆虫为食，如甲虫、苍蝇、毛虫和蜘蛛。在低矮灌木丛内部或浓密灌木丛中单独或成对觅食，偶尔在地面行走。","breeding":"繁殖期至少在9月至10月，巢为松散但深的杯状结构，由粗干草制成，内衬精细草料，建于离地约1米的攀援植物或草丛中。每窝产卵2枚，极少数1枚，蛋壳淡紫色或淡红橙色，有光泽，带有巧克力色和深棕色的划痕、条纹或斑点。","identification":"在安岛上无其他Nesillas属物种，且Acrocephalus属亦不存在，故不会混淆。与马岛薮莺相比，叫声更高更急促。","protection":"IUCN：未评估（目前被BirdLife International视为马岛薮莺的亚种）。在安岛上常见。","distribution":"该物种仅分布于科摩罗群岛的安岛（Anjouan）。","other":"现为马岛薮莺亚种。"},{"name":"戈岛薮莺","english_name":"Grande Comore Brush Warbler","scientific_name":"Nesillas brevicaudata","overview":"戈岛薮莺（英文名：Grande Comore Brush Warbler，学名：Nesillas brevicaudata），是雀形目苇莺科薮莺属的中等体型的鸟类，主要分布在印度洋的戈岛（Grand Comoro），即西北部的科摩罗群岛中的Njazidja。","appearance":"这是一种体格健壮、棕色的中型鸟类，其显著特征是拥有一条长而尖锐的尾巴。它在中高海拔的湿润森林中活动，包括灌木丛、开阔地带、边缘以及高海拔的树丛中。","call":"其鸣叫特征包括一系列的“chek”和“veet”音符，通常连续发出，使其在隐蔽的环境中也能被识别。","habits":"戈岛薮莺是一种隐秘生活的鸟类，常在茂密的植被中活动，偏好中高海拔的湿润森林环境。","identification":"在戈岛上，由于没有相似的莺类，因此戈岛薮莺的识别相对简单。","distribution":"戈岛薮莺的分布仅限于非洲的科摩罗群岛中的戈岛（Grand Comoro），即Njazidja，位于西北部的科摩罗群岛。"},{"name":"科摩罗薮莺","english_name":"Moheli Brush Warbler","scientific_name":"Nesillas mariae","overview":"科摩罗薮莺（英文名：Moheli Brush Warbler，学名：Nesillas mariae），是雀形目苇莺科薮莺属的鸟类。主要分布在科摩罗群岛的Moheli岛。其自然栖息地位于亚热带或热带湿润的山地森林。","appearance":"该鸟具有较长的尾巴，全身呈现黄色至棕色调。雌雄鸟的羽毛颜色相似，主要以中间层次和树冠下部为活动范围。","call":"鸣唱为一系列类似太阳鸟的刮擦音和尖叫声，但音调较低。常见叫声包括‘chek’和‘veet’，通常连续发出。","habits":"科摩罗薮莺栖息在残存的山地森林碎片中，也会出现在低海拔的次生生境。它与马达加斯加薮莺共存，但较少在灌木丛中潜行。主要在树冠中部和下部觅食。","breeding":"关于科摩罗薮莺的繁殖习性的具体信息较为有限。","identification":"与马达加斯加薮莺相比，科摩罗薮莺具有较短的尾巴，颜色更淡且更均匀的黄色，胸部没有明显的条纹。","protection":"IUCN：EN（濒危）","distribution":"仅分布于科摩罗群岛的Moheli岛（Mwali），位于印度洋西部。","other":"科摩罗薮莺是Moheli岛上特有的物种，对于当地生态系统的健康至关重要。"},{"name":"阿达薮莺","english_name":"Aldabra Brush Warbler","scientific_name":"Nesillas aldabrana","overview":"阿达薮莺（英文名：Aldabra Brush Warbler，学名：Nesillas aldabrana），是雀形目苇莺科薮莺属的鸟类。是塞舌尔阿尔达布拉群岛特有种，现已灭绝。阿达薮莺以它独特的长尾和暖棕色上部羽毛著称，生活在密林中。","appearance":"阿达薮莺是一种体型较大的鸟类，长度约为18至20厘米，体重约19.5克。其头部和上身呈温暖的棕色，臀部和上尾覆羽更显肉桂棕色。头部侧面为灰褐色，具有一条明显的灰色眉纹。翅膀为深棕色，边缘略带浅黄褐色，尾巴为黄褐色。腹部下方为灰白色，胸部颜色较深，两胁和下尾覆羽呈淡黄褐色。虹膜颜色从中褐色到红褐色不等，喙上部为暗角质色，下部为浅角质色或粉色；跗跖为灰色。雄雌外观相似，幼鸟特征尚未详细描述。","call":"阿达薮莺的鸣叫未曾被记录，但其叫声被描述为鼻音的三音节啾啾声。","habits":"阿达薮莺是一种害羞而隐秘的鸟类，常在密集的灌木丛中生活，很难直接观察到。它们最易通过其独特的鼻音啾啾叫声被发现。","breeding":"1967年，由英国鸟类学家Constantine Walter Benson、Malcolm Penny和Tony Diamond首次发现，并于1968年由Benson和Penny基于一公一母及三个蛋的巢穴进行了描述。之后，直到1974年至1976年间Robert Prys-Jones的调查才再次见到这种鸟，当时仅发现了六只雄鸟。","identification":"阿达薮莺的独特之处在于其较长的渐尖尾羽和特定的叫声，这有助于与其他鸟类区分开来。","protection":"IUCN：EX（已灭绝）。自1994年起，正式宣布其灭绝。","distribution":"阿达薮莺的分布限于非洲的马尔巴岛（Malabar），位于塞舌尔阿尔达布拉群岛西北部。","other":"阿达薮莺的灭绝可能与岛上引入的鼠、猫和山羊有关。"}];
